        <Suspense fallback={<PageLoader />}>
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 overflow-y-auto">
            <PriceAlerts
              userId={user?.id || ''}
              onClose={() => setIsPriceAlertsOpen(false)}
            />
          </div>
        </Suspense>
      )}

      {isSmartRecommendationsOpen && (
        <Suspense fallback={<PageLoader />}>
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 overflow-y-auto">
            <SmartRecommendations
              userId={user?.id}
              onEquipmentSelect={(eq) => {
                setSelectedEquipment(eq);
                setIsSmartRecommendationsOpen(false);
              }}
              onClose={() => setIsSmartRecommendationsOpen(false)}
            />
          </div>
        </Suspense>
      )}

      {isQRCodeScannerOpen && (
        <Suspense fallback={<PageLoader />}>
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <QRCodeScanner
              isOpen={isQRCodeScannerOpen}
              onScan={(data) => {
                console.log('QR Code scanned:', data);
                // Handle QR code data (could be equipment ID, booking code, etc.)
                alert(`QR Code scanned: ${data}`);
                setIsQRCodeScannerOpen(false);
              }}
              onClose={() => setIsQRCodeScannerOpen(false)}
            />
          </div>
        </Suspense>
      )}

      {isAchievementsOpen && (
        <Suspense fallback={<PageLoader />}>
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 overflow-y-auto">
            <AchievementsSystem
              userId={user?.id || ''}
              onClose={() => setIsAchievementsOpen(false)}
            />
          </div>
        </Suspense>
      )}
      {/* Cookie Consent */}
      {showBanner && (
        <CookieConsentBanner
          onAccept={acceptAll}
          onDecline={declineAll}
          onCustomize={() => setShowSettings(true)}
        />
      )}

      <CookieSettingsModal
        isOpen={showSettings}
        onClose={() => setShowSettings(false)}
        settings={settings}
        onSettingsChange={setSettings}
        onSave={saveSettings}
      />
    </div>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <AuthProvider>
        <AppContent />
      </AuthProvider>
    </ErrorBoundary>
  );
}

export default App;

