];

export default function AIAssistantEnhanced() {
  const [isOpen, setIsOpen] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [showQuickActions, setShowQuickActions] = useState(true);
  const [feedbackGiven, setFeedbackGiven] = useState<Set<string>>(new Set());
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'assistant',
      content: "👋 Hi! I'm **Kayd**, your AI equipment assistant powered by advanced language models. I can:\n\n• 🔍 Find equipment with natural language\n• 🎤 Understand voice commands\n• 📸 Analyze images to identify equipment\n• 💰 Compare prices across listings\n• 📅 Check real-time availability\n• 🤖 Learn your preferences\n\nHow can I help you today?",
      timestamp: new Date(),
      suggestions: [
        'Find construction equipment near me',
        'Compare camera rental prices',
        'What do I need for a home renovation?',
        'Show trending equipment this week',
      ],
    },
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  const [context, setContext] = useState<ConversationContext>({});
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Persist user preference for AI assistant (local override of env flag)
  const [aiEnabledByUser, setAiEnabledByUser] = useLocalStorage<boolean>('ai_assistant_enabled', true);
  const aiIsEnabled = GLOBAL_AI_ENABLED && aiEnabledByUser;
  
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const synthesisRef = useRef<SpeechSynthesisUtterance | null>(null);

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  // Initialize speech recognition
  useEffect(() => {
    if ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event) => {
        const transcript = Array.from(event.results)
          .map(result => result[0].transcript)
          .join('');
        setInput(transcript);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleVoiceInput = () => {
    if (!recognitionRef.current) {
      alert('Speech recognition not supported in this browser');
      return;
    }

    if (isListening) {
      recognitionRef.current.stop();
      setIsListening(false);
    } else {
      recognitionRef.current.start();
      setIsListening(true);
    }
  };

  const speakResponse = useCallback((text: string) => {
    if (!voiceEnabled || !window.speechSynthesis) return;

    const cleanText = text.replace(/\*\*/g, '').replace(/[#*_]/g, '');
    
    window.speechSynthesis.cancel();
    synthesisRef.current = new SpeechSynthesisUtterance(cleanText);
    synthesisRef.current.rate = 1;
    synthesisRef.current.pitch = 1;
    
    synthesisRef.current.onstart = () => setIsSpeaking(true);
    synthesisRef.current.onend = () => setIsSpeaking(false);
    
    window.speechSynthesis.speak(synthesisRef.current);
  }, [voiceEnabled]);

  const stopSpeaking = () => {
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      setUploadedImage(event.target?.result as string);
    };
    reader.readAsDataURL(file);
  };

  const analyzeImage = async () => {
    if (!uploadedImage) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: '📸 [Uploaded an image for analysis]',
      timestamp: new Date(),
      metadata: { imageUrl: uploadedImage },
    };

    setMessages(prev => [...prev, userMessage]);
    setUploadedImage(null);
    setIsTyping(true);

    await new Promise(resolve => setTimeout(resolve, 2000));

    const responseMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'assistant',
      content: "🔍 **Image Analysis Complete**\n\nI can see this appears to be construction/power equipment. Based on my analysis:\n\n**Identified Equipment:**\n• Type: Power Tool / Heavy Equipment\n• Condition: Appears to be in good condition\n• Category: Construction\n\n**Similar Rentals Available:**\n• DeWalt 20V Combo Kit - $75/day\n• Milwaukee M18 Impact - $45/day\n• Makita Circular Saw - $35/day\n\nWould you like me to find exact matches or similar equipment near you?",
      timestamp: new Date(),
      suggestions: ['Find exact match', 'Show similar equipment', 'Get price comparison', 'Search by brand'],
      metadata: { type: 'recommendation', processingTime: 2000 },
    };

    setMessages(prev => [...prev, responseMessage]);
    setIsTyping(false);
  };

  const getContextualResponses = useCallback((userMessage: string): { content: string; suggestions: string[]; type: string } => {
    const lowerMessage = userMessage.toLowerCase();
    
    if (lowerMessage.includes('excavator') || lowerMessage.includes('bulldozer')) {
      setContext(prev => ({ ...prev, equipmentType: 'heavy', topic: 'construction' }));
    }
    if (lowerMessage.includes('camera') || lowerMessage.includes('photo')) {
      setContext(prev => ({ ...prev, equipmentType: 'camera', topic: 'photography' }));
    }

    if (lowerMessage.includes('trending') || lowerMessage.includes('popular') || lowerMessage.includes('hot')) {
      return {
        content: "📈 **Trending This Week**\n\nHere's what's hot on Islakayd:\n\n🔥 **#1** Mini Excavator (32% more rentals)\n🔥 **#2** DJI Mavic 3 Drone (28% more rentals)\n🔥 **#3** Sony A7IV Camera (25% more rentals)\n🔥 **#4** DeWalt 20V Combo Kit (22% more rentals)\n🔥 **#5** Party Tent 20x40 (wedding season!)\n\n**Rising Categories:**\n• Landscaping equipment +45%\n• Event supplies +38%\n• Photography gear +32%\n\nWant me to show details on any of these?",
        suggestions: ['Show mini excavators', 'View drone options', 'Camera rental deals', 'Event equipment'],
        type: 'recommendation'
      };
    }

    if (lowerMessage.includes('recommend') || lowerMessage.includes('suggest') || lowerMessage.includes('what should')) {
      if (context.topic === 'construction') {
        return {
          content: "🏗️ **Smart Recommendation**\n\nBased on your interest in construction equipment, here's what I suggest:\n\n**Essential Package:**\n1. Mini Excavator (1-3 ton) - $250/day\n2. Skid Steer Loader - $200/day\n3. Concrete Mixer - $50/day\n\n**Add-ons:**\n• Safety equipment (PPE) - $25/day\n• Generator - $75/day\n\n**💡 Pro Tip:** Rent weekly for 30% savings!\n\nTotal estimate: ~$500/day or $2,800/week\n\nWant me to check availability?",
          suggestions: ['Check availability', 'Get weekly rate', 'Add safety equipment', 'View alternatives'],
          type: 'recommendation'
        };
      }
    }

    if (lowerMessage.includes('near me') || lowerMessage.includes('nearby') || lowerMessage.includes('my area')) {
      return {
        content: "📍 **Equipment Near You**\n\nI've found 47 listings within 10 miles:\n\n**Top Rated Nearby:**\n⭐ 4.9 - CAT 320 Excavator (2.3 mi) - $450/day\n⭐ 4.9 - Sony A7IV Kit (1.8 mi) - $125/day\n⭐ 4.8 - DeWalt Power Tools (0.8 mi) - $75/day\n⭐ 4.8 - DJ Equipment (3.1 mi) - $295/day\n\n**Available Today:**\n✅ 12 power tools\n✅ 8 cameras\n✅ 5 heavy equipment\n✅ 15 event supplies\n\nWould you like me to filter by category or price?",
        suggestions: ['Filter by category', 'Cheapest first', 'Available today', 'Show on map'],
        type: 'search'
      };
    }

    if (lowerMessage.includes('compare') || lowerMessage.includes('price') || lowerMessage.includes('cheapest') || lowerMessage.includes('best deal')) {
      return {
        content: "💰 **Price Comparison Tool**\n\nI'll help you find the best deals! Here's a sample comparison:\n\n**Excavator Rentals (20 ton class):**\n\n| Owner | Daily | Weekly | Rating |\n|-------|-------|--------|--------|\n| Heavy Equip LLC | $450 | $2,800 | ⭐4.9 |\n| ProRent Co | $425 | $2,650 | ⭐4.7 |\n| BuildRight | $475 | $2,900 | ⭐4.8 |\n\n**Best Value:** ProRent Co saves you $25/day\n**Best Rated:** Heavy Equip LLC (47 reviews)\n\n💡 **Kayd's Pick:** Heavy Equip LLC - worth $25 extra for reliability\n\nWhich would you like to book?",
        suggestions: ['Book Heavy Equip LLC', 'Book ProRent Co', 'See more options', 'Check availability'],
        type: 'info'
      };
    }

    if (lowerMessage.includes('book') || lowerMessage.includes('reserve') || lowerMessage.includes('rent')) {
      return {
        content: "📅 **Let's Book Your Rental**\n\nI'll help you complete your booking! Just tell me:\n\n**1. Equipment** - What do you need?\n**2. Dates** - When do you need it?\n**3. Location** - Where should we look?\n\nOr if you've already browsed:\n• Say the equipment name\n• I'll check availability\n• Guide you through checkout\n\n💡 **Quick Book:** Reply with something like:\n*\"Book the CAT excavator for next Monday to Friday\"*",
        suggestions: ['Book excavator', 'Check camera availability', 'Reserve power tools', 'See my saved items'],
        type: 'booking'
      };
    }

    if (lowerMessage.includes('weather') || lowerMessage.includes('rain') || lowerMessage.includes('outdoor')) {
      return {
        content: "🌤️ **Weather-Smart Recommendations**\n\nI see you're planning outdoor work! Here's what I suggest:\n\n**Rainy Day Essentials:**\n• Covered trailer - keeps equipment dry\n• Tarps & covers - $15/day\n• Indoor lighting kit - $45/day\n\n**All-Weather Equipment:**\n• Waterproof power tools available\n• Enclosed cab excavators\n• Climate-controlled storage trailers\n\n**Forecast for your area:**\n☀️ Mon-Wed: Clear (great for rentals!)\n🌧️ Thu-Fri: Rain expected\n\nShall I find weather-appropriate equipment?",
        suggestions: ['Show weatherproof tools', 'Find covered equipment', 'Indoor alternatives', 'Check forecast'],
        type: 'info'
      };
    }

    return {
      content: "I'd love to help you find the perfect equipment! 🎯\n\nTo give you personalized recommendations, tell me:\n\n• **What** - Type of equipment or project\n• **When** - Your rental dates\n• **Where** - Your location\n• **Budget** - Price range (optional)\n\nOr try:\n• 📸 Upload an image of equipment you need\n• 🎤 Use voice to describe your project\n• 💡 Ask for trending equipment\n\nI'm here to help!",
      suggestions: ['Browse trending', 'Equipment near me', 'Compare prices', 'Voice search'],
      type: 'info'
    };
  }, [context]);

  const simulateResponse = useCallback(async (userMessage: string) => {
    setIsTyping(true);
    setShowQuickActions(false);

    const startTime = Date.now();

    // If AI is disabled by environment or user preference, use local rule-based responses
    if (!aiIsEnabled) {
      await new Promise(resolve => setTimeout(resolve, 700 + Math.random() * 800));
      const response = getContextualResponses(userMessage);
      const newMessage: Message = {
        id: Date.now().toString(),
        role: 'assistant',
        content: response.content + "\n\n_(AI disabled — using offline mode)_",
        timestamp: new Date(),
        suggestions: response.suggestions,
        metadata: { type: response.type as 'search' | 'alert' | 'success' | 'booking' | 'info' | 'recommendation' },
      };
      setMessages((prev) => [...prev, newMessage]);
      setIsTyping(false);
      return;
    }

    try {
      // Build conversation history for context
      const conversationHistory = messages
        .filter(m => m.id !== '1' && m.role !== 'system')
        .slice(-6)
        .map(m => ({
          role: m.role as 'user' | 'assistant',
          content: m.content,
        }));

      // Add current message
      conversationHistory.push({
        role: 'user' as const,
        content: userMessage,
      });

      // Insert placeholder assistant message so we can stream into it
      const placeholderId = Date.now().toString();
      setMessages(prev => [...prev, {
        id: placeholderId,
        role: 'assistant',
        content: '',
        timestamp: new Date(),
        suggestions: [],
      }]);

      // track text locally so it's available after streaming completes
      let streamedText = '';
      await streamMessage(
        conversationHistory,
        {},
        (chunk) => {
          streamedText = chunk;
          setMessages(prev => prev.map(m =>
            m.id === placeholderId ? { ...m, content: chunk } : m
          ));
        },
        (suggestions) => {
          setMessages(prev => prev.map(m =>
            m.id === placeholderId ? { ...m, suggestions } : m
          ));
        },
        (err) => {
          console.error('AI stream error:', err);
        }
      );

      if (voiceEnabled) {
        speakResponse(streamedText);
      }

      // re-enable quick actions after a brief delay so the user sees them
      setTimeout(() => setShowQuickActions(true), 200);
      setIsTyping(false);
    } catch (error) {
      console.error('AI service error:', error);
      // Fallback to generic offline response
      const processingTime = Date.now() - startTime;
      const fallbackContent = "I'm having trouble connecting right now. Please try again in a moment.";

      const newMessage: Message = {
        id: Date.now().toString(),
        role: 'assistant',
        content: fallbackContent + "\n\n_(Using offline mode)_",
        timestamp: new Date(),
        suggestions: [],
        metadata: { 
          type: 'info',
          processingTime,
        },
      };

      setMessages((prev) => [...prev, newMessage]);

      if (voiceEnabled) {
        speakResponse(fallbackContent);
      }
    } finally {
      setIsTyping(false);
    }
  }, [messages, getContextualResponses, voiceEnabled, speakResponse, aiIsEnabled]);

  const handleFeedback = (messageId: string, isPositive: boolean) => {
    setFeedbackGiven((prev) => new Set([...prev, messageId]));
    console.log(`Feedback for message ${messageId}: ${isPositive ? 'positive' : 'negative'}`);
  };

  const handleSend = useCallback(() => {
    if (!input.trim() && !uploadedImage) return;

    if (uploadedImage) {
      analyzeImage();
      return;
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date(),
      metadata: { isVoice: isListening },
    };

    setMessages((prev) => [...prev, userMessage]);
    const messageToSend = input;
    setInput('');
    simulateResponse(messageToSend);
  }, [input, uploadedImage, isListening, simulateResponse]);

  const handleSuggestionClick = useCallback((suggestion: string) => {
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: suggestion,
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMessage]);
    simulateResponse(suggestion);
  }, [simulateResponse]);

  const clearConversation = () => {
    setMessages([{
      id: '1',
      role: 'assistant',
      content: "👋 Conversation cleared! How can I help you?",
      timestamp: new Date(),
      suggestions: ['Find equipment', 'Check prices', 'Book a rental', 'Get recommendations'],
    }]);
    setContext({});
    setShowQuickActions(true);
  };

  return (
    <>
      <button
        onClick={() => setIsOpen(true) aria-label="Open AI assistant"
        className={`fixed bottom-6 right-6 z-50 group ${isOpen ? 'hidden' : ''}`}
      >
        <div className="relative">
          <div className="absolute inset-0 bg-gradient-to-r from-teal-500 to-emerald-500 rounded-full blur-lg opacity-50 group-hover:opacity-75 transition-opacity animate-pulse" />
          <div className="relative w-16 h-16 bg-gradient-to-r from-teal-500 to-emerald-500 rounded-full flex items-center justify-center shadow-xl hover:shadow-2xl transition-all duration-300 hover:scale-110">
            <Bot className="w-8 h-8 text-white" />
            <Sparkles className="w-4 h-4 text-white absolute -top-1 -right-1 animate-bounce" />
          </div>
          <div className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full flex items-center justify-center animate-pulse">
            <span className="text-xs text-white font-bold">AI</span>
          </div>
        </div>
              
        >
          <div className="flex items-center justify-between px-6 py-4 bg-gradient-to-r from-teal-500 to-emerald-500 rounded-t-3xl">
            <div className="flex items-center gap-3">
              <div className="relative">
                <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
                  <Bot className="w-6 h-6 text-white" />
                </div>
                <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-400 rounded-full border-2 border-white" />
              </div>
              <div>
                <h3 className="font-semibold text-white flex items-center gap-2">
                  Kayd AI
                  <span className="px-2 py-0.5 bg-white/20 rounded-full text-xs">Pro</span>
                </h3>
                <p className="text-sm text-white/80 flex items-center gap-1">
                  <Zap className="w-3 h-3" />
                  Powered by Advanced AI
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button
                  onClick={() => setShowSettings(!showSettings) aria-label={showSettings ? 'Close settings' : 'Open settings'}
                  className="w-9 h-9 rounded-full bg-white/20 flex items-center justify-center text-white hover:bg-white/30"
                >
                <Settings className="w-5 h-5" />
              </button>
              <button
                aria-label="Icon button" onClick={() => setIsExpanded(!isExpanded)}
                className="w-9 h-9 rounded-full bg-white/20 flex items-center justify-center text-white hover:bg-white/30"
                aria-label={isExpanded ? 'Minimize assistant' : 'Maximize assistant'}
              >
                {isExpanded ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
              </button>
                  onClick={() => setIsExpanded(!isExpanded) aria-label={isExpanded ? 'Collapse assistant' : 'Expand assistant'}
                  className="w-9 h-9 rounded-full bg-white/20 flex items-center justify-center text-white hover:bg-white/30"
                >
              >
                <X className="w-5 h-5" />
              </button>
            </div>
          </div>

          {showSettings && (
            <div className="p-4 bg-gray-50 border-b border-gray-200 space-y-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Volume2 className="w-5 h-5 text-gray-600" />
                  <span className="text-sm font-medium">Voice Responses</span>
                </div>
                <button
                  aria-label="Icon button" onClick={() => setVoiceEnabled(!voiceEnabled)}
                  className={`w-12 h-6 rounded-full transition-colors ${voiceEnabled ? 'bg-teal-500' : 'bg-gray-300'} aria-label="Toggle voice responses"
                  aria-pressed={!!voiceEnabled}
                >
                  <div className={`w-5 h-5 bg-white rounded-full shadow transition-transform ${voiceEnabled ? 'translate-x-6' : 'translate-x-0.5'}`} />
                </button>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Bot className="w-5 h-5 text-gray-600" />
                  <div>
                    <div className="text-sm font-medium">Enable LLM (Kayd AI)</div>
                    <div className="text-xs text-gray-400">Use the cloud LLM for richer assistant responses</div>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <button
                    onClick={async () = aria-label="Icon button"> {
                      const newVal = !aiEnabledByUser;
                      setAiEnabledByUser(prev => !prev);

                      // persist to server if signed in
                      try {
                        // dynamic require to avoid circular imports in module graph
                         
                        const { useAuth } = await import('../../contexts/AuthContext');
                        const auth = useAuth ? useAuth() : null;
                        if (auth?.user?.id) {
                           
                          const db = await import('../../services/database');
                          await db.updateProfile(auth.user.id, { ai_assistant_enabled: newVal });
                          await auth.refreshProfile();
                        }
                      } catch (err) {
                        // ignore — preference still saved to localStorage
                        console.error('Failed to persist AI preference:', err);
                      }
                    }}
                    disabled={!GLOBAL_AI_ENABLED}
                    className={`w-12 h-6 rounded-full transition-colors ${aiEnabledByUser && GLOBAL_AI_ENABLED ? 'bg-teal-500' : 'bg-gray-300'} ${!GLOBAL_AI_ENABLED ? 'opacity-50 cursor-not-allowed' : ''} aria-pressed={!!(aiEnabledByUser && GLOBAL_AI_ENABLED)} aria-label="Toggle LLM (Kayd AI)"
                  >
                    <div className={`w-5 h-5 bg-white rounded-full shadow transition-transform ${aiEnabledByUser && GLOBAL_AI_ENABLED ? 'translate-x-6' : 'translate-x-0.5'}`} />
                  </button>
                  {!GLOBAL_AI_ENABLED && (
                    <span className="text-xs text-gray-400">Disabled by server</span>
                  )}
                </div>
              </div>

              <button onClick={clearConversation} className="mt-1 w-full py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition-colors" aria-label="Icon button">
                Clear Conversation
              </button>
            </div>
          )}

          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {!aiIsEnabled && (
              <div className="text-center text-xs text-gray-500 mb-2">
                AI is currently disabled; using offline response rules.
              </div>
            )}
            {messages.map((message) => (
              <div key={message.id} className={`flex gap-3 ${message.role === 'user' ? 'flex-row-reverse' : ''}`}>
                <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${message.role === 'user' ? 'bg-gray-200' : 'bg-gradient-to-br from-teal-500 to-emerald-500'}`}>
                  {message.role === 'user' ? (
                    message.metadata?.isVoice ? <Mic className="w-4 h-4 text-gray-600" /> : <User className="w-5 h-5 text-gray-600" />
                  ) : (
                    <Bot className="w-5 h-5 text-white" />
                  )}
                </div>
                <div className={`max-w-[80%] ${message.role === 'user' ? 'text-right' : ''}`}>
                  {message.metadata?.imageUrl && (
                    <img src={message.metadata.imageUrl} alt="Uploaded" className="w-32 h-32 object-cover rounded-xl mb-2" />
                  )}
                  <div className={`px-4 py-3 rounded-2xl ${message.role === 'user' ? 'bg-teal-500 text-white rounded-tr-sm' : 'bg-gray-100 text-gray-800 rounded-tl-sm'}`}>
                    <div className="text-sm whitespace-pre-line">
                      {message.content.split('\n').map((line, i) => {
                        // Escape HTML to prevent XSS
                        const escapeHtml = (text: string) => {
                          const htmlMap: Record<string, string> = {
                            '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;',
                          };
                          return text.replace(/[&<>"']/g, (m) => htmlMap[m] || m);
                        };
                        const safe = escapeHtml(line).replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
                        return <span key={i} dangerouslySetInnerHTML={{ __html: safe }} className="block" />;
                      })}
                    </div>
                  </div>
                  
                  {message.role === 'assistant' && (
                    <div className="flex items-center gap-2 mt-2 ml-1">
                      {!feedbackGiven.has(message.id) ? (
                        <>
                          <button aria-label="Give thumbs up feedback" onClick={() => handleFeedback(message.id, true)} className="p-1.5 rounded-lg hover:bg-green-50 text-gray-400 hover:text-green-600"><ThumbsUp className="w-4 h-4" /></button>
                          <button aria-label="Give thumbs down feedback" onClick={() => handleFeedback(message.id, false)} className="p-1.5 rounded-lg hover:bg-red-50 text-gray-400 hover:text-red-600"><ThumbsDown className="w-4 h-4" /></button>
                          {isSpeaking ? (
                            <button aria-label="Stop speech" onClick={stopSpeaking} className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-400"><VolumeX className="w-4 h-4" /></button>
                          ) : (
                            <button aria-label="Play speech" onClick={() => speakResponse(message.content)} className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-400"><Volume2 className="w-4 h-4" /></button>
                          )}
                        </>
                      ) : (
                        <span className="text-xs text-green-600 flex items-center gap-1"><CheckCircle2 className="w-3 h-3" /> Thanks!</span>
                      )}
                      {message.metadata?.processingTime && (
                        <span className="text-xs text-gray-400 flex items-center gap-1"><Clock className="w-3 h-3" /> {message.metadata.processingTime}ms</span>
                      )}
                    </div>
                  )}

                  {message.suggestions && message.suggestions.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-3">
                      {message.suggestions.map((suggestion, index) => (
                        <button key={index} aria-label="Icon button" onClick={() => handleSuggestionClick(suggestion)} className="px-3 py-1.5 bg-white border border-gray-200 rounded-full text-sm text-gray-700 hover:border-teal-300 hover:bg-teal-50">
                          {suggestion}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}

            {isTyping && (
              <div className="flex gap-3">
                <div className="w-8 h-8 rounded-full flex items-center justify-center bg-gradient-to-br from-teal-500 to-emerald-500">
                  <Bot className="w-5 h-5 text-white" />
                </div>
                <div className="px-4 py-3 bg-gray-100 rounded-2xl rounded-tl-sm">
                  <div className="flex items-center gap-2">
                    <Loader2 className="w-4 h-4 text-teal-500 animate-spin" />
                    <span className="text-sm text-gray-500">Kayd is thinking...</span>
                  </div>
                </div>
              </div>
            )}

            {showQuickActions && messages.length === 1 && (
              <div className="space-y-3">
                <p className="text-xs text-gray-400 text-center flex items-center justify-center gap-1">
                  <Sparkles className="w-3 h-3" /> Quick Actions
                </p>
                <div className="grid grid-cols-2 gap-2">
                  {quickActions.map((action, index) => (
                    <button key={index} aria-label="Icon button" onClick={() => handleSuggestionClick(action.query)} className="flex items-center gap-2 p-3 bg-white border border-gray-200 rounded-xl text-sm text-gray-700 hover:border-teal-300 hover:bg-teal-50 text-left">
                      <span className={`w-8 h-8 rounded-lg ${action.color} flex items-center justify-center text-white`}>{action.icon}</span>
                      {action.label}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {uploadedImage && (
            <div className="px-4 pb-2">
              <div className="relative inline-block">
                <img src={uploadedImage} alt="Upload preview" className="w-20 h-20 object-cover rounded-xl" />
                <button aria-label="Remove uploaded image" onClick={() => setUploadedImage(null)} className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center">
                  <X className="w-4 h-4" />
                </button>
              </div>
            </div>
          )}

          <div className="p-4 border-t border-gray-100">
            <div className="flex items-center justify-center gap-4 mb-3 text-xs text-gray-400">
              <span className="flex items-center gap-1"><Search className="w-3 h-3" /> Search</span>
              <span className="flex items-center gap-1"><Mic className="w-3 h-3" /> Voice</span>
              <span className="flex items-center gap-1"><ImageIcon className="w-3 h-3" /> Image</span>
              <span className="flex items-center gap-1"><TrendingUp className="w-3 h-3" /> Trending</span>
            </div>
            <div className="flex items-center gap-2 bg-gray-50 rounded-2xl p-2">
              <input aria-label="Upload an image" type="file" ref={fileInputRef} accept="image/*" onChange={handleImageUpload} className="hidden" />
              <button aria-label="Upload an image" onClick={() => fileInputRef.current?.click()} className="p-2 rounded-xl text-gray-400 hover:text-gray-600 hover:bg-gray-100">
                <Paperclip className="w-5 h-5" />
              </button>
              <input
                ref={inputRef}
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && !e.shiftKey && handleSend()}
                placeholder={isListening ? 'Listening...' : aiIsEnabled ? 'Ask Kayd anything...' : 'AI disabled (offline mode)'}
                className={`flex-1 bg-transparent text-gray-800 placeholder-gray-400 focus:outline-none text-sm ${isListening ? 'text-teal-600' : ''}`}
              />
              <button onClick={toggleVoiceInput} disabled={!aiIsEnabled} title={!aiIsEnabled ? 'Voice requires AI enabled' : undefined aria-label={isListening ? 'Stop voice input' : 'Start voice input'} className={`p-2 rounded-xl ${isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100'} ${!aiIsEnabled ? 'opacity-50 cursor-not-allowed' : ''}`}>
                {isListening ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
              </button>
              <button onClick={handleSend} disabled={(!input.trim() && !uploadedImage) || isTyping} className="p-2 rounded-xl bg-gradient-to-r from-teal-500 to-emerald-500 text-white disabled:opacity-50" aria-label="Send message">
                <Send className="w-5 h-5" />
              </button>
            </div>
            <p className="text-xs text-center text-gray-400 mt-3 flex items-center justify-center gap-1">
              <Sparkles className="w-3 h-3" /> Powered by Advanced AI • <Star className="w-3 h-3" /> Pro Features
            </p>
          </div>
        </div>
      )}
    </>
  );
}

// SpeechRecognition types for voice input
interface SpeechRecognitionAlternative {
  readonly transcript: string;
  readonly confidence: number;
}

interface SpeechRecognitionResult {
  readonly length: number;
  item(index: number): SpeechRecognitionAlternative;
  [index: number]: SpeechRecognitionAlternative;
}

interface SpeechRecognitionResultList {
  readonly length: number;
  item(index: number): SpeechRecognitionResult;
  [index: number]: SpeechRecognitionResult;
}

interface SpeechRecognitionEvent extends Event {
  readonly results: SpeechRecognitionResultList;
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onresult: ((event: SpeechRecognitionEvent) => void) | null;
  onend: (() => void) | null;
  onerror: (() => void) | null;
  start(): void;
  stop(): void;
}

declare global {
  interface Window {
    SpeechRecognition: new () => SpeechRecognition;
    webkitSpeechRecognition: new () => SpeechRecognition;
  }
}

import { useState, useEffect } from 'react';
import { Brain, Cpu, Zap, TrendingUp, Target, Eye, BarChart3, Activity } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { getEquipment, getBookings } from '../../services/database';
import type { Equipment, Booking } from '../../types';

interface AIPrediction {
  equipmentId: string;
  confidence: number;
  predictedDemand: number;
  optimalPrice: number;
  maintenanceRisk: number;
  recommendation: string;
}

interface MLInsights {
  totalPredictions: number;
  accuracy: number;
  revenueImpact: number;
  topPerformingEquipment: string[];
  marketTrends: string[];
}

export default function AIMachineLearningHub() {
  const { user } = useAuth();
  const [predictions, setPredictions] = useState<AIPrediction[]>([]);
  const [insights, setInsights] = useState<MLInsights | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'predictions' | 'insights' | 'training'>('predictions');

  useEffect(() => {
    if (user) {
      loadAIPredictions();
      loadMLInsights();
    }
  }, [user]);

  const loadAIPredictions = async () => {
    if (!user) return;

    try {
      const [equipmentData, bookingsData] = await Promise.all([
        getEquipment({ ownerId: user.id }),
        getBookings({ ownerId: user.id })
      ]);

      const equipment = Array.isArray(equipmentData) ? equipmentData : ((equipmentData as { data?: Equipment[] })?.data ?? []);
      const bookings = Array.isArray(bookingsData) ? bookingsData : ((bookingsData as { data?: Booking[] })?.data ?? []);

      // Simulate AI predictions (in real app, this would call ML service)
      const aiPredictions = equipment.map((eq: Equipment) => {
        const eqBookings = bookings.filter((b: Booking) => b.equipment_id === eq.id);
        const recentBookings = eqBookings.filter((b: Booking) => {
          const bookingDate = new Date(b.created_at);
          const daysAgo = (Date.now() - bookingDate.getTime()) / (1000 * 60 * 60 * 24);
          return daysAgo <= 30;
        });

        const demandScore = Math.min(10, recentBookings.length * 0.5 + (eq.rating || 4) * 0.8);
        const confidence = Math.random() * 0.3 + 0.7; // 70-100% confidence
        const optimalPrice = (eq.daily_rate || 50) * (1 + demandScore * 0.1);
        const maintenanceRisk = Math.random() * 30; // 0-30% risk

        let recommendation = 'Monitor performance';
        if (demandScore > 8) recommendation = 'High demand - consider price increase';
        else if (demandScore < 3) recommendation = 'Low demand - marketing needed';
        else if (maintenanceRisk > 20) recommendation = 'Schedule maintenance soon';

        return {
          equipmentId: eq.id,
          confidence,
          predictedDemand: demandScore,
          optimalPrice: Math.round(optimalPrice),
          maintenanceRisk,
          recommendation,
        };
      });

      setPredictions(aiPredictions);
    } catch (error) {
      console.error('Failed to load AI predictions:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadMLInsights = async () => {
    // Simulate ML insights (in real app, this would come from ML service)
    const mockInsights: MLInsights = {
      totalPredictions: 156,
      accuracy: 87.3,
      revenueImpact: 12450,
      topPerformingEquipment: ['Excavator XL-2000', 'Forklift Pro-500', 'Generator MaxPower'],
      marketTrends: [
        'Construction equipment demand up 15%',
        'Weekend rentals increasing 22%',
        'Urban areas showing 30% growth'
      ]
    };

    setInsights(mockInsights);
  };

  const retrainModel = async () => {
    // Simulate model retraining
    setLoading(true);
    await new Promise(resolve => setTimeout(resolve, 3000));
    await loadAIPredictions();
    await loadMLInsights();
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-500"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto p-6 space-y-6">
      {/* Header */}
      <div className="bg-gradient-to-r from-purple-600 to-blue-600 rounded-xl p-6 text-white">
        <div className="flex items-center gap-3 mb-4">
          <Brain className="w-8 h-8" />
          <h1 className="text-2xl font-bold">AI Machine Learning Hub</h1>
        </div>
        <p className="text-purple-100">
          Advanced AI predictions, market insights, and automated optimization for your equipment rental business
        </p>
      </div>

      {/* Navigation Tabs */}
      <div className="flex border-b border-gray-200">
        {[
          { id: 'predictions', label: 'AI Predictions', icon: Target },
          { id: 'insights', label: 'ML Insights', icon: BarChart3 },
          { id: 'training', label: 'Model Training', icon: Cpu }
        ].map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setActiveTab(id as 'predictions' | 'insights' | 'training') aria-label={`Switch to ${label}`}
            className={`flex items-center gap-2 px-6 py-3 border-b-2 font-medium text-sm ${
              activeTab === id
                ? 'border-teal-500 text-teal-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            <Icon className="w-4 h-4" />
            {label}
          </button>
        ))}
      </div>

      {/* Content */}
      {activeTab === 'predictions' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {predictions.map((prediction) => (
            <div key={prediction.equipmentId} className="bg-white rounded-lg shadow-sm border p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <TrendingUp className="w-5 h-5 text-teal-500" />
                  <span className="font-semibold text-gray-900">AI Prediction</span>
                </div>
                <div className="flex items-center gap-1">
                  <Eye className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500">
                    {Math.round(prediction.confidence * 100)}% confidence
                  </span>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Predicted Demand</span>
                  <div className="flex items-center gap-2">
                    <Activity className="w-4 h-4 text-blue-500" />
                    <span className="font-semibold">{prediction.predictedDemand.toFixed(1)}/10</span>
                  </div>
                </div>

                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Optimal Price</span>
                  <div className="flex items-center gap-2">
                    <Zap className="w-4 h-4 text-green-500" />
                    <span className="font-semibold">${prediction.optimalPrice}/day</span>
                  </div>
                </div>

                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">Maintenance Risk</span>
                  <div className="flex items-center gap-2">
                    <Activity className="w-4 h-4 text-red-500" />
                    <span className="font-semibold">{prediction.maintenanceRisk.toFixed(1)}%</span>
                  </div>
                </div>
              </div>

              <div className="mt-4 p-3 bg-gray-50 rounded-lg">
                <p className="text-sm text-gray-700">{prediction.recommendation}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {activeTab === 'insights' && insights && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Performance Metrics */}
          <div className="bg-white rounded-lg shadow-sm border p-6">
            <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <BarChart3 className="w-5 h-5 text-teal-500" />
              Performance Metrics
            </h3>
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-gray-600">Total Predictions</span>
                <span className="font-semibold text-2xl">{insights.totalPredictions}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-600">Model Accuracy</span>
                <span className="font-semibold text-2xl text-green-600">{insights.accuracy}%</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-600">Revenue Impact</span>
                <span className="font-semibold text-2xl text-blue-600">${insights.revenueImpact.toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* Market Trends */}
          <div className="bg-white rounded-lg shadow-sm border p-6">
            <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-purple-500" />
              Market Trends
            </h3>
            <div className="space-y-3">
              {insights.marketTrends.map((trend, index) => (
                <div key={index} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                  <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                  <span className="text-sm text-gray-700">{trend}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Top Performing Equipment */}
          <div className="bg-white rounded-lg shadow-sm border p-6 lg:col-span-2">
            <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <Target className="w-5 h-5 text-orange-500" />
              Top Performing Equipment
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {insights.topPerformingEquipment.map((equipment, index) => (
                <div key={index} className="p-4 bg-gradient-to-r from-teal-50 to-blue-50 rounded-lg border">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-8 h-8 bg-teal-500 rounded-full flex items-center justify-center text-white font-bold">
                      {index + 1}
                    </div>
                    <span className="font-medium text-gray-900">{equipment}</span>
                  </div>
                  <div className="text-sm text-gray-600">
                    High demand • Optimal pricing • Low maintenance
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {activeTab === 'training' && (
        <div className="bg-white rounded-lg shadow-sm border p-6">
          <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Cpu className="w-5 h-5 text-indigo-500" />
            Model Training & Optimization
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div className="p-4 border rounded-lg">
                <h4 className="font-medium mb-2">Training Data</h4>
                <div className="text-sm text-gray-600 space-y-1">
                  <div>Historical bookings: 2,450</div>
                  <div>Equipment records: 156</div>
                  <div>User interactions: 8,320</div>
                  <div>Market data points: 15,600</div>
                </div>
              </div>

              <div className="p-4 border rounded-lg">
                <h4 className="font-medium mb-2">Model Performance</h4>
                <div className="text-sm text-gray-600 space-y-1">
                  <div>Accuracy: 87.3%</div>
                  <div>Precision: 84.1%</div>
                  <div>Recall: 89.2%</div>
                  <div>F1 Score: 86.6%</div>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <div className="p-4 border rounded-lg">
                <h4 className="font-medium mb-2">Retraining Options</h4>
                <div className="space-y-2">
                  <button
                    onClick={retrainModel}
                    className="w-full px-4 py-2 bg-teal-500 text-white rounded-lg hover:bg-teal-600 transition-colors"
                   aria-label="Icon button">
                    Retrain Model
                  </button>
                  <p className="text-xs text-gray-500">
                    Last trained: 2 hours ago • Next scheduled: 6 hours
                  </p>
                </div>
              </div>

              <div className="p-4 border rounded-lg">
                <h4 className="font-medium mb-2">Advanced Features</h4>
                <div className="space-y-2 text-sm text-gray-600">
                  <div>• Real-time learning</div>
                  <div>• A/B testing framework</div>
                  <div>• Custom model deployment</div>
                  <div>• Performance monitoring</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import {
  Bell,
  BellOff,
  TrendingDown,
  DollarSign,
  Check,
  Plus,
  Trash2,
  ChevronRight,
  Sparkles,
  Zap,
} from 'lucide-react';
import type { Equipment } from '../../types';

interface PriceAlert {
  id: string;
  equipmentId: string;
  equipmentTitle: string;
  equipmentImage: string;
  currentPrice: number;
  targetPrice: number;
  createdAt: Date;
  isActive: boolean;
  notifyEmail: boolean;
  notifyPush: boolean;
  triggered?: boolean;
  triggeredAt?: Date;
}

interface PriceAlertsProps {
  equipment?: Equipment;
  existingAlerts?: PriceAlert[];
  onCreateAlert: (alert: Omit<PriceAlert, 'id' | 'createdAt'>) => void;
  onDeleteAlert: (alertId: string) => void;
  onToggleAlert: (alertId: string, isActive: boolean) => void;
  className?: string;
}

const sampleAlerts: PriceAlert[] = [
  {
    id: '1',
    equipmentId: 'eq1',
    equipmentTitle: 'CAT 320 Excavator',
    equipmentImage: 'https://images.pexels.com/photos/2058128/pexels-photo-2058128.jpeg',
    currentPrice: 450,
    targetPrice: 380,
    createdAt: new Date(Date.now() - 86400000 * 3),
    isActive: true,
    notifyEmail: true,
    notifyPush: true,
  },
  {
    id: '2',
    equipmentId: 'eq2',
    equipmentTitle: 'Sony A7IV Camera Kit',
    equipmentImage: 'https://images.pexels.com/photos/51383/photo-camera-subject-photographer-51383.jpeg',
    currentPrice: 125,
    targetPrice: 100,
    createdAt: new Date(Date.now() - 86400000 * 7),
    isActive: true,
    notifyEmail: true,
    notifyPush: false,
    triggered: true,
    triggeredAt: new Date(Date.now() - 3600000),
  },
  {
    id: '3',
    equipmentId: 'eq3',
    equipmentTitle: 'DeWalt Power Tool Kit',
    equipmentImage: 'https://images.pexels.com/photos/1249611/pexels-photo-1249611.jpeg',
    currentPrice: 75,
    targetPrice: 60,
    createdAt: new Date(Date.now() - 86400000 * 14),
    isActive: false,
    notifyEmail: true,
    notifyPush: true,
  },
];

export default function PriceAlerts({
  equipment,
  existingAlerts = sampleAlerts,
  onCreateAlert,
  onDeleteAlert,
  onToggleAlert,
  className = '',
}: PriceAlertsProps) {
  const [alerts, setAlerts] = useState<PriceAlert[]>(existingAlerts);
  const [isCreating, setIsCreating] = useState(!!equipment);
  const [newAlert, setNewAlert] = useState({
    targetPrice: equipment ? Math.floor(equipment.daily_rate * 0.8) : 0,
    notifyEmail: true,
    notifyPush: true,
  });
  const [showSuccess, setShowSuccess] = useState(false);

  // Calculate price drop percentage
  const getDropPercentage = (current: number, target: number) => {
    return Math.round(((current - target) / current) * 100);
  };

  const handleCreateAlert = () => {
    if (!equipment) return;

    const alert: PriceAlert = {
      id: Date.now().toString(),
      equipmentId: equipment.id,
      equipmentTitle: equipment.title,
      equipmentImage: equipment.images[0],
      currentPrice: equipment.daily_rate,
      targetPrice: newAlert.targetPrice,
      createdAt: new Date(),
      isActive: true,
      notifyEmail: newAlert.notifyEmail,
      notifyPush: newAlert.notifyPush,
    };

    setAlerts(prev => [alert, ...prev]);
    onCreateAlert(alert);
    setIsCreating(false);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const handleDeleteAlert = (id: string) => {
    setAlerts(prev => prev.filter(a => a.id !== id));
    onDeleteAlert(id);
  };

  const handleToggleAlert = (id: string) => {
    setAlerts(prev => prev.map(a => 
      a.id === id ? { ...a, isActive: !a.isActive } : a
    ));
    const alert = alerts.find(a => a.id === id);
    if (alert) {
      onToggleAlert(id, !alert.isActive);
    }
  };

  const activeAlertsCount = alerts.filter(a => a.isActive).length;
  const triggeredAlertsCount = alerts.filter(a => a.triggered).length;

  return (
    <div className={`bg-white rounded-2xl shadow-lg overflow-hidden ${className}`}>
      {/* Header */}
      <div className="bg-gradient-to-r from-orange-500 to-red-500 text-white p-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-xl bg-white/20 flex items-center justify-center">
              <Bell className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Price Alerts</h2>
              <p className="text-white/80 text-sm">Get notified when prices drop</p>
            </div>
          </div>
          
          {!isCreating && (
            <button
              onClick={() => setIsCreating(true) aria-label="Create price alert"
              className="flex items-center gap-2 px-4 py-2 bg-white/20 hover:bg-white/30 rounded-xl transition-colors"
            >
              <Plus className="w-5 h-5" />
              New Alert
            </button>
          )}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-3 gap-4">
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold">{alerts.length}</div>
            <div className="text-xs text-white/70">Total Alerts</div>
          </div>
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold">{activeAlertsCount}</div>
            <div className="text-xs text-white/70">Active</div>
          </div>
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <div className="text-2xl font-bold">{triggeredAlertsCount}</div>
            <div className="text-xs text-white/70">Triggered</div>
          </div>
        </div>
      </div>

      {/* Success notification */}
      {showSuccess && (
        <div className="mx-4 mt-4 p-4 bg-green-50 border border-green-200 rounded-xl flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-green-100 flex items-center justify-center">
            <Check className="w-5 h-5 text-green-600" />
          </div>
          <div>
            <p className="font-medium text-green-900">Alert Created!</p>
            <p className="text-sm text-green-600">We'll notify you when the price drops</p>
          </div>
        </div>
      )}

      {/* Create new alert form */}
      {isCreating && equipment && (
        <div className="p-4 border-b border-gray-100">
          <div className="bg-gray-50 rounded-xl p-4">
            <div className="flex items-start gap-4 mb-4">
              <img
                src={equipment.images[0]}
                alt={equipment.title}
                className="w-20 h-20 rounded-xl object-cover"
              />
              <div className="flex-1">
                <h3 className="font-semibold text-gray-900">{equipment.title}</h3>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-lg font-bold text-gray-900">${equipment.daily_rate}</span>
                  <span className="text-gray-500">/day</span>
                </div>
              </div>
            </div>

            {/* Target price slider */}
            <div className="mb-4">
              <div className="flex items-center justify-between mb-2">
                <label htmlFor="target-price-range" className="text-sm font-medium text-gray-700">Target Price</label>
                <div className="flex items-center gap-2">
                  <span className="text-2xl font-bold text-orange-600">${newAlert.targetPrice}</span>
                  <span className="text-sm text-gray-500">/day</span>
                  <span className="px-2 py-0.5 bg-orange-100 text-orange-700 rounded-full text-xs font-medium">
                    {getDropPercentage(equipment.daily_rate, newAlert.targetPrice)}% off
                  </span>
                </div>
              </div>
              <input
                id="target-price-range"
                type="range"
                min={Math.floor(equipment.daily_rate * 0.5)}
                max={equipment.daily_rate - 1}
                value={newAlert.targetPrice}
                onChange={(e) = "target-price-range" onClick={() => setNewAlert(prev => ({ ...prev, targetPrice: Number(e.target.value)}))}
                className="w-full h-2 bg-gray-200 rounded-full appearance-none cursor-pointer accent-orange-500"
                aria-label="Target price slider"
                title="Adjust target price"
              />
              <div className="flex justify-between text-xs text-gray-500 mt-1">
                <span>50% off (${Math.floor(equipment.daily_rate * 0.5)})</span>
                <span>Current (${equipment.daily_rate})</span>
              </div>
            </div>

            {/* Notification options */}
            <div className="flex items-center gap-4 mb-4">
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  checked={newAlert.notifyEmail}
                  onChange={(e) => setNewAlert(prev => ({ ...prev, notifyEmail: e.target.checked }))}
                  className="w-4 h-4 text-orange-500 rounded border-gray-300 focus:ring-orange-500"
                />
                <span className="text-sm text-gray-700">Email</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  checked={newAlert.notifyPush}
                  onChange={(e) => setNewAlert(prev => ({ ...prev, notifyPush: e.target.checked }))}
                  className="w-4 h-4 text-orange-500 rounded border-gray-300 focus:ring-orange-500"
                />
                <span className="text-sm text-gray-700">Push Notification</span>
              </label>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-3">
              <button
                onClick={handleCreateAlert}
                className="flex-1 flex items-center justify-center gap-2 py-3 bg-gradient-to-r from-orange-500 to-red-500 text-white font-medium rounded-xl hover:shadow-lg transition-all"
               aria-label="Icon button">
                <Bell className="w-5 h-5" />
                Create Alert
              </button>
              <button
                aria-label="Icon button" onClick={() => setIsCreating(false)}
                className="px-6 py-3 bg-gray-100 text-gray-700 font-medium rounded-xl hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Alerts list */}
      <div className="divide-y divide-gray-100">
        {alerts.length > 0 ? (
          alerts.map(alert => (
            <div
              key={alert.id}
              className={`p-4 flex items-center gap-4 transition-colors ${
                alert.triggered ? 'bg-green-50' : alert.isActive ? '' : 'bg-gray-50 opacity-60'
              }`}
            >
              <div className="relative">
                <img
                  src={alert.equipmentImage}
                  alt={alert.equipmentTitle}
                  className="w-16 h-16 rounded-xl object-cover"
                />
                {alert.triggered && (
                  <div className="absolute -top-1 -right-1 w-6 h-6 bg-green-500 rounded-full flex items-center justify-center">
                    <TrendingDown className="w-3 h-3 text-white" />
                  </div>
                )}
              </div>

              <div className="flex-1 min-w-0">
                <h4 className="font-medium text-gray-900 truncate">{alert.equipmentTitle}</h4>
                
                <div className="flex items-center gap-3 mt-1">
                  <div className="flex items-center gap-1">
                    <DollarSign className="w-4 h-4 text-gray-400" />
                    <span className="text-gray-500">{alert.currentPrice}</span>
                    <ChevronRight className="w-4 h-4 text-gray-400" />
                    <span className={`font-semibold ${alert.triggered ? 'text-green-600' : 'text-orange-600'}`}>
                      ${alert.targetPrice}
                    </span>
                  </div>
                  <span className="px-2 py-0.5 bg-orange-100 text-orange-700 rounded-full text-xs font-medium">
                    {getDropPercentage(alert.currentPrice, alert.targetPrice)}% off
                  </span>
                </div>

                {alert.triggered && alert.triggeredAt && (
                  <div className="flex items-center gap-1.5 mt-1.5 text-sm text-green-600">
                    <Zap className="w-4 h-4" />
                    Price dropped! {new Date(alert.triggeredAt).toLocaleDateString()}
                  </div>
                )}
              </div>

              <div className="flex items-center gap-2">
                <button
                  aria-label="Icon button" onClick={() => handleToggleAlert(alert.id)}
                  className={`p-2 rounded-lg transition-colors ${
                    alert.isActive
                      ? 'bg-orange-100 text-orange-600 hover:bg-orange-200'
                      : 'bg-gray-100 text-gray-400 hover:bg-gray-200'
                  }`}
                  title={alert.isActive ? 'Pause alert' : 'Activate alert'}
                >
                  {alert.isActive ? <Bell className="w-5 h-5" /> : <BellOff className="w-5 h-5" />}
                </button>
                <button
                  aria-label="Icon button" onClick={() => handleDeleteAlert(alert.id)}
                  className="p-2 rounded-lg bg-gray-100 text-gray-400 hover:bg-red-100 hover:text-red-600 transition-colors"
                  title="Delete alert"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="py-12 text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Bell className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">No price alerts yet</h3>
            <p className="text-gray-500 mb-4">Create alerts to get notified when prices drop</p>
            <button
              aria-label="Icon button" onClick={() => setIsCreating(true)}
              className="inline-flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-orange-500 to-red-500 text-white font-medium rounded-xl hover:shadow-lg transition-all"
            >
              <Plus className="w-5 h-5" />
              Create Your First Alert
            </button>
          </div>
        )}
      </div>

      {/* Pro tip */}
      {alerts.length > 0 && (
        <div className="p-4 bg-gradient-to-r from-orange-50 to-red-50 border-t border-orange-100">
          <div className="flex items-start gap-3">
            <div className="w-8 h-8 rounded-full bg-orange-100 flex items-center justify-center flex-shrink-0">
              <Sparkles className="w-4 h-4 text-orange-600" />
            </div>
            <div>
              <p className="text-sm font-medium text-gray-900">Pro Tip</p>
              <p className="text-sm text-gray-600">
                Set alerts for 15-25% below current prices for the best chance of getting notified about genuine deals.
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import {
  Bell,
  BellRing,
  Settings,
  X,
  AlertTriangle,
  DollarSign,
  Calendar,
  Wrench,
  TrendingDown,
  Clock,
  Filter,
  Search,
  MoreVertical,
  BellOff,
  Smartphone,
  Mail,
  MessageSquare,
  ChevronRight,
  Star,
  Package,
} from 'lucide-react';

interface SmartAlertsSystemProps {
  userId?: string;
  onClose?: () => void;
}

type AlertType = 
  | 'price_drop'
  | 'maintenance_due'
  | 'booking_reminder'
  | 'return_reminder'
  | 'new_review'
  | 'payment_due'
  | 'availability_change'
  | 'weather_warning'
  | 'warranty_expiring'
  | 'promotion';

type AlertPriority = 'high' | 'medium' | 'low';
type AlertStatus = 'unread' | 'read' | 'dismissed';

interface SmartAlert {
  id: string;
  type: AlertType;
  title: string;
  message: string;
  priority: AlertPriority;
  status: AlertStatus;
  equipment_id?: string;
  equipment_name?: string;
  booking_id?: string;
  created_at: string;
  action_url?: string;
  action_label?: string;
  data?: Record<string, unknown>;
}

interface AlertPreference {
  type: AlertType;
  label: string;
  description: string;
  enabled: boolean;
  channels: {
    push: boolean;
    email: boolean;
    sms: boolean;
  };
}

