// Alert preferences
const defaultPreferences: AlertPreference[] = [
  {
    type: 'price_drop',
    label: 'Price Drops',
    description: 'When equipment you\'ve viewed drops in price',
    enabled: true,
    channels: { push: true, email: true, sms: false },
