];

export default function SmartAlertsSystem({ userId, onClose }: SmartAlertsSystemProps) {
  void userId; // For future API integration
  const [alerts, setAlerts] = useState<SmartAlert[]>(mockAlerts);
  const [preferences, setPreferences] = useState<AlertPreference[]>(defaultPreferences);
  const [activeView, setActiveView] = useState<'alerts' | 'settings'>('alerts');
  const [filterType, setFilterType] = useState<AlertType | 'all'>('all');
  const [filterPriority, setFilterPriority] = useState<AlertPriority | 'all'>('all');
  const [showFilters, setShowFilters] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Get icon for alert type
  const getAlertIcon = (type: AlertType) => {
    switch (type) {
      case 'price_drop':
        return <TrendingDown className="w-5 h-5" />;
      case 'maintenance_due':
        return <Wrench className="w-5 h-5" />;
      case 'booking_reminder':
        return <Calendar className="w-5 h-5" />;
      case 'return_reminder':
        return <Clock className="w-5 h-5" />;
      case 'new_review':
        return <Star className="w-5 h-5" />;
      case 'payment_due':
        return <DollarSign className="w-5 h-5" />;
      case 'availability_change':
        return <Package className="w-5 h-5" />;
      case 'weather_warning':
        return <AlertTriangle className="w-5 h-5" />;
      case 'warranty_expiring':
        return <AlertTriangle className="w-5 h-5" />;
      case 'promotion':
        return <DollarSign className="w-5 h-5" />;
      default:
        return <Bell className="w-5 h-5" />;
    }
  };

  // Get color for alert type
  const getAlertColor = (type: AlertType, priority: AlertPriority) => {
    if (priority === 'high') return 'bg-red-100 text-red-600';
    switch (type) {
      case 'price_drop':
        return 'bg-green-100 text-green-600';
      case 'maintenance_due':
        return 'bg-orange-100 text-orange-600';
      case 'booking_reminder':
        return 'bg-blue-100 text-blue-600';
      case 'return_reminder':
        return 'bg-purple-100 text-purple-600';
      case 'new_review':
        return 'bg-yellow-100 text-yellow-600';
      case 'promotion':
        return 'bg-teal-100 text-teal-600';
      default:
        return 'bg-gray-100 text-gray-600';
    }
  };

  // Format time ago
  const formatTimeAgo = (date: string) => {
    const now = new Date();
    const alertDate = new Date(date);
    const diffMs = now.getTime() - alertDate.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return alertDate.toLocaleDateString();
  };

  // Filter alerts
  const filteredAlerts = alerts.filter((alert) => {
    if (alert.status === 'dismissed') return false;
    if (filterType !== 'all' && alert.type !== filterType) return false;
    if (filterPriority !== 'all' && alert.priority !== filterPriority) return false;
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      return (
        alert.title.toLowerCase().includes(query) ||
        alert.message.toLowerCase().includes(query) ||
        alert.equipment_name?.toLowerCase().includes(query)
      );
    }
    return true;
  });

  // Count unread
  const unreadCount = alerts.filter((a) => a.status === 'unread').length;

  // Mark as read
  const markAsRead = (id: string) => {
    setAlerts((prev) =>
      prev.map((a) => (a.id === id ? { ...a, status: 'read' as AlertStatus } : a))
    );
  };

  // Mark all as read
  const markAllAsRead = () => {
    setAlerts((prev) => prev.map((a) => ({ ...a, status: 'read' as AlertStatus })));
  };

  // Dismiss alert
  const dismissAlert = (id: string) => {
    setAlerts((prev) =>
      prev.map((a) => (a.id === id ? { ...a, status: 'dismissed' as AlertStatus } : a))
    );
  };

  // Toggle preference
  const togglePreference = (type: AlertType) => {
    setPreferences((prev) =>
      prev.map((p) => (p.type === type ? { ...p, enabled: !p.enabled } : p))
    );
  };

  // Toggle channel
  const toggleChannel = (type: AlertType, channel: 'push' | 'email' | 'sms') => {
    setPreferences((prev) =>
      prev.map((p) =>
        p.type === type
          ? { ...p, channels: { ...p.channels, [channel]: !p.channels[channel] } }
          : p
      )
    );
  };

  return (
    <div className="bg-white rounded-xl shadow-lg max-w-2xl w-full max-h-[90vh] overflow-hidden">
      {/* Header */}
      <div className="bg-gradient-to-r from-teal-600 to-teal-700 p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative">
              <Bell className="w-6 h-6 text-white" />
              {unreadCount > 0 && (
                <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full text-xs text-white flex items-center justify-center">
                  {unreadCount}
                </span>
              )}
            </div>
            <h2 className="text-lg font-semibold text-white">Smart Alerts</h2>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setActiveView(activeView === 'alerts' ? 'settings' : 'alerts') aria-label="Toggle alerts view"
              className="p-2 hover:bg-white/10 rounded-lg transition-colors"
            >
              {activeView === 'alerts' ? (
                <Settings className="w-5 h-5 text-white" />
              ) : (
                <BellRing className="w-5 h-5 text-white" />
              )}
            </button>
            {onClose && (
              <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
                <X className="w-5 h-5 text-white" />
              </button>
            )}
          </div>
        </div>
      </div>

      {activeView === 'alerts' ? (
        <>
          {/* Search & Filters */}
          <div className="p-4 border-b">
            <div className="flex items-center gap-2">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search alerts..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                />
              </div>
              <button
                onClick={() => setShowFilters(!showFilters) aria-label={showFilters ? 'Hide filters' : 'Show filters'}
                className={`p-2 border rounded-lg hover:bg-gray-50 transition-colors ${
                  showFilters ? 'bg-teal-50 border-teal-200' : ''
                }`}
              >
                <Filter className="w-5 h-5 text-gray-600" />
              </button>
              {unreadCount > 0 && (
                <button
                  onClick={markAllAsRead}
                  className="px-3 py-2 text-sm text-teal-600 hover:bg-teal-50 rounded-lg transition-colors"
                 aria-label="Icon button">
                  Mark all read
                </button>
              )}
            </div>

            {showFilters && (
              <div className="mt-3 flex flex-wrap gap-2">
                <select
                  value={filterType}
                  onChange={(e) => setFilterType(e.target.value as AlertType | 'all')}
                  className="px-3 py-1.5 border rounded-lg text-sm focus:ring-2 focus:ring-teal-500"
                >
                  <option value="all">All Types</option>
                  <option value="price_drop">Price Drops</option>
                  <option value="maintenance_due">Maintenance</option>
                  <option value="booking_reminder">Bookings</option>
                  <option value="return_reminder">Returns</option>
                  <option value="new_review">Reviews</option>
                  <option value="warranty_expiring">Warranties</option>
                  <option value="promotion">Promotions</option>
                </select>
                <select
                  value={filterPriority}
                  onChange={(e) => setFilterPriority(e.target.value as AlertPriority | 'all')}
                  className="px-3 py-1.5 border rounded-lg text-sm focus:ring-2 focus:ring-teal-500"
                >
                  <option value="all">All Priorities</option>
                  <option value="high">High Priority</option>
                  <option value="medium">Medium Priority</option>
                  <option value="low">Low Priority</option>
                </select>
              </div>
            )}
          </div>

          {/* Alerts List */}
          <div className="overflow-y-auto max-h-[500px]">
            {filteredAlerts.length === 0 ? (
              <div className="p-8 text-center">
                <BellOff className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                <p className="text-gray-500">No alerts to show</p>
                <p className="text-sm text-gray-400">We'll notify you when something important happens</p>
              </div>
            ) : (
              <div className="divide-y">
                {filteredAlerts.map((alert) => (
                  <div
                    key={alert.id}
                    className={`p-4 hover:bg-gray-50 transition-colors ${
                      alert.status === 'unread' ? 'bg-teal-50/30' : ''
                    }`}
                    onClick={() => markAsRead(alert.id)}
                  >
                    <div className="flex gap-3">
                      <div className={`p-2 rounded-lg ${getAlertColor(alert.type, alert.priority)}`}>
                        {getAlertIcon(alert.type)}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-2">
                          <div>
                            <h4 className={`font-medium ${alert.status === 'unread' ? 'text-gray-900' : 'text-gray-700'}`}>
                              {alert.title}
                            </h4>
                            {alert.equipment_name && (
                              <p className="text-xs text-teal-600 mt-0.5">{alert.equipment_name}</p>
                            )}
                          </div>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-gray-400 whitespace-nowrap">
                              {formatTimeAgo(alert.created_at)}
                            </span>
                            {alert.status === 'unread' && (
                              <div className="w-2 h-2 bg-teal-500 rounded-full" />
                            )}
                          </div>
                        </div>
                        <p className="text-sm text-gray-600 mt-1 line-clamp-2">{alert.message}</p>
                        <div className="flex items-center justify-between mt-3">
                          {alert.action_url && (
                            <button className="text-sm text-teal-600 hover:text-teal-700 font-medium flex items-center gap-1" aria-label="Icon button">
                              {alert.action_label}
                              <ChevronRight className="w-4 h-4" />
                            </button>
                          )}
                          <div className="flex items-center gap-2">
                            <button
                              onClick={(e) = aria-label="Icon button"> {
                                e.stopPropagation();
                                dismissAlert(alert.id);
                              }}
                              className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded transition-colors"
                              title="Dismiss"
                            >
                              <X className="w-4 h-4" />
                            </button>
                            <button
                              className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded transition-colors"
                              title="More options"
                            >
                              <MoreVertical className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      ) : (
        /* Settings View */
        <div className="overflow-y-auto max-h-[600px]">
          <div className="p-4 border-b bg-gray-50">
            <h3 className="font-medium text-gray-900">Notification Preferences</h3>
            <p className="text-sm text-gray-500">Choose how you want to be notified</p>
          </div>

          {/* Channel Legend */}
          <div className="p-4 border-b flex items-center gap-4 text-sm text-gray-500">
            <span className="flex items-center gap-1">
              <Smartphone className="w-4 h-4" /> Push
            </span>
            <span className="flex items-center gap-1">
              <Mail className="w-4 h-4" /> Email
            </span>
            <span className="flex items-center gap-1">
              <MessageSquare className="w-4 h-4" /> SMS
            </span>
          </div>

          <div className="divide-y">
            {preferences.map((pref) => (
              <div key={pref.type} className="p-4">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <h4 className="font-medium text-gray-900">{pref.label}</h4>
                      <button
                        aria-label="Icon button" onClick={() => togglePreference(pref.type)}
                        className={`relative w-10 h-5 rounded-full transition-colors ${
                          pref.enabled ? 'bg-teal-600' : 'bg-gray-300'
                        }`}
                      >
                        <div
                          className={`absolute top-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform ${
                            pref.enabled ? 'translate-x-5' : 'translate-x-0.5'
                          }`}
                        />
                      </button>
                    </div>
                    <p className="text-sm text-gray-500 mt-0.5">{pref.description}</p>
                  </div>
                </div>

                {pref.enabled && (
                  <div className="mt-3 flex gap-3">
                    <button
                      aria-label="Icon button" onClick={() => toggleChannel(pref.type, 'push')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-colors ${
                        pref.channels.push
                          ? 'bg-teal-100 text-teal-700'
                          : 'bg-gray-100 text-gray-400'
                      }`}
                    >
                      <Smartphone className="w-4 h-4" />
                      Push
                    </button>
                    <button
                      aria-label="Icon button" onClick={() => toggleChannel(pref.type, 'email')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-colors ${
                        pref.channels.email
                          ? 'bg-teal-100 text-teal-700'
                          : 'bg-gray-100 text-gray-400'
                      }`}
                    >
                      <Mail className="w-4 h-4" />
                      Email
                    </button>
                    <button
                      aria-label="Icon button" onClick={() => toggleChannel(pref.type, 'sms')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-colors ${
                        pref.channels.sms
                          ? 'bg-teal-100 text-teal-700'
                          : 'bg-gray-100 text-gray-400'
                      }`}
                    >
                      <MessageSquare className="w-4 h-4" />
                      SMS
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Quick Actions */}
          <div className="p-4 border-t bg-gray-50">
            <div className="flex gap-3">
              <button className="flex-1 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg transition-colors" aria-label="Icon button">
                Turn all off
              </button>
              <button className="flex-1 py-2 text-sm text-teal-600 hover:bg-teal-50 rounded-lg transition-colors" aria-label="Icon button">
                Reset to defaults
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <div className="border-t p-4 bg-gray-50">
        <div className="flex items-center justify-between text-sm text-gray-500">
          <span>{filteredAlerts.length} alerts</span>
          <span>{unreadCount} unread</span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import {
  TrendingUp,
  TrendingDown,
  DollarSign,
  BarChart3,
  PieChart,
  Activity,
  Calendar,
  Users,
  Target,
  Zap,
  Star,
} from 'lucide-react';
import type { Equipment, Booking, UserAnalytics } from '../../types';
import { getUserAnalytics, getBookings, getEquipment } from '../../services/database';
import { useAuth } from '../../contexts/AuthContext';

interface AnalyticsDashboardProps {
  className?: string;
}

interface MetricCard {
  title: string;
  value: string | number;
  change: number;
  changeLabel: string;
  icon: typeof DollarSign;
  color: string;
}

interface ChartData {
  name: string;
  value: number;
  color: string;
}

export default function AnalyticsDashboard({ className = '' }: AnalyticsDashboardProps) {
  const { user } = useAuth();
  const [analytics, setAnalytics] = useState<UserAnalytics | null>(null);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [equipment, setEquipment] = useState<Equipment[]>([]);
  const [loading, setLoading] = useState(true);
  const [timeRange, setTimeRange] = useState<'7d' | '30d' | '90d' | '1y'>('30d');

  useEffect(() => {
    const loadAnalytics = async () => {
      if (!user) return;

      try {
        const [analyticsData, bookingsData, equipmentData] = await Promise.all([
          getUserAnalytics(user.id),
          getBookings({ ownerId: user.id }),
          getEquipment({ ownerId: user.id }),
        ]);

        setAnalytics(analyticsData);
        setBookings(bookingsData);
        setEquipment(equipmentData.data);
      } catch (error) {
        console.error('Failed to load analytics:', error);
      } finally {
        setLoading(false);
      }
    };

    loadAnalytics();
  }, [user]);

  const metrics = useMemo((): MetricCard[] => {
    if (!analytics || !bookings) return [];

    const totalRevenue = bookings
      .filter(b => b.status === 'completed')
      .reduce((sum, b) => sum + b.total_amount, 0);

    const activeBookings = bookings.filter(b =>
      b.status === 'active' || b.status === 'confirmed'
    ).length;

    const utilizationRate = equipment.length > 0
      ? (activeBookings / equipment.length) * 100
      : 0;

    const avgRating = equipment.reduce((sum, eq) => sum + eq.rating, 0) / equipment.length;

    return [
      {
        title: 'Total Revenue',
        value: `$${totalRevenue.toLocaleString()}`,
        change: 12.5,
        changeLabel: 'vs last month',
        icon: DollarSign,
        color: 'text-green-600',
      },
      {
        title: 'Active Bookings',
        value: activeBookings,
        change: 8.2,
        changeLabel: 'vs last month',
        icon: Calendar,
        color: 'text-blue-600',
      },
      {
        title: 'Equipment Utilization',
        value: `${utilizationRate.toFixed(1)}%`,
        change: -2.1,
        changeLabel: 'vs last month',
        icon: Activity,
        color: 'text-purple-600',
      },
      {
        title: 'Average Rating',
        value: avgRating.toFixed(1),
        change: 0.3,
        changeLabel: 'vs last month',
        icon: Star,
        color: 'text-amber-600',
      },
    ];
  }, [analytics, bookings, equipment]);

  const revenueData = useMemo((): ChartData[] => {
    const monthlyRevenue: Record<string, number> = {};

    bookings
      .filter(b => b.status === 'completed')
      .forEach(booking => {
        const month = new Date(booking.created_at).toLocaleDateString('en-US', {
          month: 'short',
          year: 'numeric'
        });
        monthlyRevenue[month] = (monthlyRevenue[month] || 0) + booking.total_amount;
      });

    return Object.entries(monthlyRevenue).map(([month, revenue]) => ({
      name: month,
      value: revenue,
      color: '#14b8a6',
    }));
  }, [bookings]);

  const categoryData = useMemo((): ChartData[] => {
    const categoryCount: Record<string, number> = {};

    bookings.forEach(booking => {
      const category = booking.equipment?.category?.name || 'Uncategorized';
      categoryCount[category] = (categoryCount[category] || 0) + 1;
    });

    const colors = ['#14b8a6', '#06b6d4', '#8b5cf6', '#f59e0b', '#ef4444'];
    return Object.entries(categoryCount).map(([category, count], index) => ({
      name: category,
      value: count,
      color: colors[index % colors.length],
    }));
  }, [bookings]);

  if (loading) {
    return (
      <div className={`animate-pulse ${className}`}>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="bg-white rounded-xl p-6 border border-gray-100">
              <div className="h-4 bg-gray-200 rounded w-3/4 mb-2"></div>
              <div className="h-8 bg-gray-200 rounded w-1/2 mb-2"></div>
              <div className="h-3 bg-gray-200 rounded w-1/4"></div>
            </div>
          ))}
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-white rounded-xl p-6 border border-gray-100">
            <div className="h-6 bg-gray-200 rounded w-1/3 mb-4"></div>
            <div className="h-64 bg-gray-200 rounded"></div>
          </div>
          <div className="bg-white rounded-xl p-6 border border-gray-100">
            <div className="h-6 bg-gray-200 rounded w-1/3 mb-4"></div>
            <div className="h-64 bg-gray-200 rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Time Range Selector */}
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-gray-900">Analytics Dashboard</h2>
        <div className="flex items-center gap-2">
          {(['7d', '30d', '90d', '1y'] as const).map((range) => (
            <button
              key={range}
              onClick={() => setTimeRange(range) aria-label={`Set time range ${range}`}
              className={`px-3 py-1.5 text-sm font-medium rounded-lg transition-colors ${
                timeRange === range
                  ? 'bg-teal-100 text-teal-700'
                  : 'text-gray-600 hover:bg-gray-100'
              }`}
            >
              {range === '7d' ? '7 Days' :
               range === '30d' ? '30 Days' :
               range === '90d' ? '90 Days' : '1 Year'}
            </button>
          ))}
        </div>
      </div>

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {metrics.map((metric, index) => {
          const Icon = metric.icon;
          return (
            <div key={index} className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <div className={`p-2 rounded-lg bg-gray-50`}>
                  <Icon className={`w-6 h-6 ${metric.color}`} />
                </div>
                <div className={`flex items-center gap-1 text-sm ${
                  metric.change >= 0 ? 'text-green-600' : 'text-red-600'
                }`}>
                  {metric.change >= 0 ? (
                    <TrendingUp className="w-4 h-4" />
                  ) : (
                    <TrendingDown className="w-4 h-4" />
                  )}
                  {Math.abs(metric.change)}%
                </div>
              </div>
              <div className="space-y-1">
                <p className="text-sm text-gray-600">{metric.title}</p>
                <p className="text-2xl font-bold text-gray-900">{metric.value}</p>
                <p className="text-xs text-gray-500">{metric.changeLabel}</p>
              </div>
            </div>
          );
        })}
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Revenue Chart */}
        <div className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
          <div className="flex items-center gap-2 mb-6">
            <BarChart3 className="w-5 h-5 text-teal-600" />
            <h3 className="text-lg font-semibold text-gray-900">Revenue Trends</h3>
          </div>
          <div className="h-64 flex items-end justify-between gap-2">
            {revenueData.slice(-6).map((data, index) => (
              <div key={index} className="flex-1 flex flex-col items-center">
                <div
                  className="w-full bg-teal-500 rounded-t"
                  style={{
                    height: `${(data.value / Math.max(...revenueData.map(d => d.value))) * 200}px`,
                    minHeight: '4px'
                  }}
                ></div>
                <p className="text-xs text-gray-500 mt-2">{data.name}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Category Distribution */}
        <div className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
          <div className="flex items-center gap-2 mb-6">
            <PieChart className="w-5 h-5 text-purple-600" />
            <h3 className="text-lg font-semibold text-gray-900">Bookings by Category</h3>
          </div>
          <div className="space-y-4">
            {categoryData.map((data, index) => (
              <div key={index} className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div
                    className="w-3 h-3 rounded-full"
                    style={{ backgroundColor: data.color }}
                  ></div>
                  <span className="text-sm text-gray-700">{data.name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-20 bg-gray-200 rounded-full h-2">
                    <div
                      className="h-2 rounded-full"
                      style={{
                        width: `${(data.value / Math.max(...categoryData.map(d => d.value))) * 100}%`,
                        backgroundColor: data.color
                      }}
                    ></div>
                  </div>
                  <span className="text-sm font-medium text-gray-900">{data.value}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Insights */}
      <div className="mt-8 bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
        <div className="flex items-center gap-2 mb-6">
          <Zap className="w-5 h-5 text-amber-600" />
          <h3 className="text-lg font-semibold text-gray-900">AI Insights</h3>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="p-4 bg-blue-50 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <Target className="w-4 h-4 text-blue-600" />
              <span className="text-sm font-medium text-blue-800">Optimization Opportunity</span>
            </div>
            <p className="text-sm text-blue-700">
              Increase prices by 5-10% for high-demand equipment during peak seasons.
            </p>
          </div>
          <div className="p-4 bg-green-50 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <TrendingUp className="w-4 h-4 text-green-600" />
              <span className="text-sm font-medium text-green-800">Growth Trend</span>
            </div>
            <p className="text-sm text-green-700">
              Construction equipment bookings are up 15% this month.
            </p>
          </div>
          <div className="p-4 bg-purple-50 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <Users className="w-4 h-4 text-purple-600" />
              <span className="text-sm font-medium text-purple-800">Customer Insight</span>
            </div>
            <p className="text-sm text-purple-700">
              70% of customers return within 3 months for additional rentals.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import {
  Camera,
  X,
  RotateCcw,
  ZoomIn,
  ZoomOut,
  Move,
  Info,
  Maximize2,
  Download,
  Share2,
  Check,
  Loader2,
  Smartphone,
  Ruler,
  Box,
  Eye,
} from 'lucide-react';
import type { Equipment } from '../../types';

interface ARPreviewProps {
  equipment: Equipment;
  onClose: () => void;
  className?: string;
}

interface Transform {
  x: number;
  y: number;
  scale: number;
  rotation: number;
}

export default function ARPreview({ equipment, onClose, className = '' }: ARPreviewProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  
  const [isLoading, setIsLoading] = useState(true);
  const [hasPermission, setHasPermission] = useState<boolean | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [transform, setTransform] = useState<Transform>({ x: 50, y: 50, scale: 1, rotation: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [showControls, setShowControls] = useState(true);
  const [showInfo, setShowInfo] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [activeMode, setActiveMode] = useState<'place' | 'measure' | 'view'>('place');

  // Initialize camera
  const initCamera = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);
      
      const stream = await navigator.mediaDevices.getUserMedia({
        video: {
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 },
        },
      });

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }

      setHasPermission(true);
      setIsLoading(false);
    } catch (err) {
      console.error('Camera error:', err);
      setHasPermission(false);
      setError('Camera access denied. Please enable camera permissions to use AR preview.');
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    const video = videoRef.current;
    initCamera();

    return () => {
      // Cleanup camera stream
      if (video?.srcObject) {
        const tracks = (video.srcObject as MediaStream).getTracks();
        tracks.forEach(track => track.stop());
      }
    };
  }, [initCamera]);

  // Handle drag
  const handleMouseDown = (e: React.MouseEvent) => {
    if (activeMode !== 'place') return;
    setIsDragging(true);
    e.preventDefault();
  };

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!isDragging || !containerRef.current || activeMode !== 'place') return;
    
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;
    
    setTransform(prev => ({
      ...prev,
      x: Math.max(10, Math.min(90, x)),
      y: Math.max(10, Math.min(90, y)),
    }));
  }, [isDragging, activeMode]);

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // Touch handlers for mobile
  const handleTouchStart = (e: React.TouchEvent) => {
    if (activeMode !== 'place') return;
    setIsDragging(true);
    e.preventDefault();
  };

  const handleTouchMove = useCallback((e: React.TouchEvent) => {
    if (!isDragging || !containerRef.current || activeMode !== 'place') return;
    
    const touch = e.touches[0];
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((touch.clientX - rect.left) / rect.width) * 100;
    const y = ((touch.clientY - rect.top) / rect.height) * 100;
    
    setTransform(prev => ({
      ...prev,
      x: Math.max(10, Math.min(90, x)),
      y: Math.max(10, Math.min(90, y)),
    }));
  }, [isDragging, activeMode]);

  const handleTouchEnd = () => {
    setIsDragging(false);
  };

  // Controls
  const handleZoomIn = () => {
    setTransform(prev => ({ ...prev, scale: Math.min(prev.scale + 0.2, 3) }));
  };

  const handleZoomOut = () => {
    setTransform(prev => ({ ...prev, scale: Math.max(prev.scale - 0.2, 0.3) }));
  };

  const handleRotate = () => {
    setTransform(prev => ({ ...prev, rotation: (prev.rotation + 45) % 360 }));
  };

  const handleReset = () => {
    setTransform({ x: 50, y: 50, scale: 1, rotation: 0 });
  };

  // Capture image
  const handleCapture = () => {
    if (!videoRef.current || !canvasRef.current) return;
    
    const canvas = canvasRef.current;
    const video = videoRef.current;
    const ctx = canvas.getContext('2d');
    
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    
    // Draw video frame
    ctx.drawImage(video, 0, 0);
    
    // Draw equipment overlay
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.src = equipment.images[0];
    
    img.onload = () => {
      const x = (transform.x / 100) * canvas.width - (200 * transform.scale) / 2;
      const y = (transform.y / 100) * canvas.height - (200 * transform.scale) / 2;
      
      ctx.save();
      ctx.translate(x + (200 * transform.scale) / 2, y + (200 * transform.scale) / 2);
      ctx.rotate((transform.rotation * Math.PI) / 180);
      ctx.drawImage(img, -(200 * transform.scale) / 2, -(200 * transform.scale) / 2, 200 * transform.scale, 200 * transform.scale);
      ctx.restore();
      
      setCapturedImage(canvas.toDataURL('image/png'));
    };
  };

  const handleDownload = () => {
    if (!capturedImage) return;
    const link = document.createElement('a');
    link.download = `ar-preview-${equipment.title.replace(/\s+/g, '-').toLowerCase()}.png`;
    link.href = capturedImage;
    link.click();
  };

  const handleShare = async () => {
    if (!capturedImage) return;
    
    try {
      const blob = await (await fetch(capturedImage)).blob();
      const file = new File([blob], 'ar-preview.png', { type: 'image/png' });
      
      if (navigator.share) {
        await navigator.share({
          title: `AR Preview: ${equipment.title}`,
          text: `Check out this ${equipment.title} in my space!`,
          files: [file],
        });
      }
    } catch (err) {
      console.error('Share failed:', err);
    }
  };

  const modes = [
    { id: 'place', label: 'Place', icon: Move },
    { id: 'measure', label: 'Measure', icon: Ruler },
    { id: 'view', label: 'View', icon: Eye },
  ];

  return (
    <div className={`fixed inset-0 z-[200] bg-black flex flex-col ${className}`}>
      {/* Camera View */}
      <div
        ref={containerRef}
        className="relative flex-1 overflow-hidden"
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      >
        {/* Video feed */}
        <video
          ref={videoRef}
          className="absolute inset-0 w-full h-full object-cover"
          playsInline
          muted
        />

        {/* Loading state */}
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-black">
            <div className="text-center">
              <Loader2 className="w-12 h-12 text-teal-500 animate-spin mx-auto mb-4" />
              <p className="text-white text-lg">Initializing camera...</p>
            </div>
          </div>
        )}

        {/* Error state */}
        {error && (
          <div className="absolute inset-0 flex items-center justify-center bg-black p-8">
            <div className="text-center max-w-md">
              <div className="w-20 h-20 rounded-full bg-red-500/20 flex items-center justify-center mx-auto mb-6">
                <Camera className="w-10 h-10 text-red-500" />
              </div>
              <h3 className="text-xl font-semibold text-white mb-3">Camera Access Required</h3>
              <p className="text-gray-400 mb-6">{error}</p>
              <div className="flex gap-3 justify-center">
                <button
                  onClick={initCamera}
                  className="px-6 py-3 bg-teal-500 text-white rounded-xl font-medium hover:bg-teal-600 transition-colors"
                 aria-label="Icon button">
                  Try Again
                </button>
                <button
                  onClick={onClose}
                  className="px-6 py-3 bg-gray-800 text-white rounded-xl font-medium hover:bg-gray-700 transition-colors"
                 aria-label="Icon button">
                  Close
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Equipment overlay */}
        {hasPermission && !isLoading && (
          <div
            className="absolute cursor-move select-none"
            style={{
              left: `${transform.x}%`,
              top: `${transform.y}%`,
              transform: `translate(-50%, -50%) scale(${transform.scale}) rotate(${transform.rotation}deg)`,
              transition: isDragging ? 'none' : 'transform 0.1s ease-out',
            }}
            onMouseDown={handleMouseDown}
            onTouchStart={handleTouchStart}
          >
            <div className="relative">
              <img
                src={equipment.images[0]}
                alt={equipment.title}
                className="w-48 h-48 object-contain drop-shadow-2xl"
                style={{
                  filter: 'drop-shadow(0 10px 30px rgba(0,0,0,0.5))',
                }}
                draggable={false}
              />
              
              {/* Placement indicator */}
              {activeMode === 'place' && (
                <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 w-32 h-2 bg-teal-500/30 rounded-full blur-sm" />
              )}

              {/* Measurement guides */}
              {activeMode === 'measure' && equipment.specifications && (
                <div className="absolute -right-4 top-0 bottom-0 flex items-center">
                  <div className="w-px h-full bg-teal-500 relative">
                    <div className="absolute -top-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-teal-500 rounded-full" />
                    <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-teal-500 rounded-full" />
                    <div className="absolute top-1/2 left-3 -translate-y-1/2 bg-black/70 px-2 py-1 rounded text-xs text-white whitespace-nowrap">
                      {equipment.specifications.height || 'Size varies'}
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* AR Grid overlay */}
        {hasPermission && !isLoading && activeMode === 'place' && (
          <div className="absolute inset-0 pointer-events-none">
            <svg className="w-full h-full opacity-20">
              <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
                  <path d="M 40 0 L 0 0 0 40" fill="none" stroke="white" strokeWidth="0.5" />
                </pattern>
              </defs>
              <rect width="100%" height="100%" fill="url(#grid)" />
            </svg>
          </div>
        )}

        {/* Captured image preview */}
        {capturedImage && (
          <div className="absolute inset-0 bg-black flex items-center justify-center p-4">
            <div className="relative max-w-2xl w-full">
              <img src={capturedImage} alt="Captured" className="w-full rounded-2xl shadow-2xl" />
              
              <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-3">
                <button
                  onClick={() => setCapturedImage(null) aria-label="Close captured image"
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                >
                  <X className="w-6 h-6" />
                </button>
                <button
                  onClick={handleDownload}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                >
                  <Download className="w-6 h-6" />
                </button>
                <button
                  onClick={handleShare}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                 aria-label="Icon button">
                  <Share2 className="w-6 h-6" />
                </button>
                <button
                  onClick={() => setCapturedImage(null) aria-label="Clear captured image"
                  className="flex items-center gap-2 px-6 py-3 bg-teal-500 text-white rounded-full font-medium hover:bg-teal-600 transition-colors"
                >
                  <Check className="w-5 h-5" />
                  Done
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Header */}
        {!capturedImage && (
          <div className="absolute top-0 left-0 right-0 p-4 flex items-center justify-between bg-gradient-to-b from-black/70 to-transparent">
            <button
              onClick={onClose}
              className="p-2.5 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
            >
              <X className="w-6 h-6" />
            </button>
            
            <div className="text-center">
              <h3 className="text-white font-semibold">{equipment.title}</h3>
              <p className="text-white/70 text-sm">${equipment.daily_rate}/day</p>
            </div>

            <button
              aria-label="Icon button" onClick={() => setShowInfo(!showInfo)}
              className="p-2.5 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
            >
              <Info className="w-6 h-6" />
            </button>
          </div>
        )}

        {/* Info panel */}
        {showInfo && !capturedImage && (
          <div className="absolute top-20 right-4 bg-black/80 backdrop-blur-sm rounded-2xl p-4 text-white max-w-xs">
            <h4 className="font-semibold mb-2">{equipment.title}</h4>
            <p className="text-sm text-white/70 mb-3">{equipment.description?.slice(0, 100)}...</p>
            {equipment.specifications && (
              <div className="space-y-1 text-sm">
                {Object.entries(equipment.specifications).slice(0, 4).map(([key, value]) => (
                  <div key={key} className="flex justify-between">
                    <span className="text-white/50 capitalize">{key}</span>
                    <span>{value}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Mode selector */}
        {hasPermission && !isLoading && !capturedImage && (
          <div className="absolute bottom-32 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-black/50 backdrop-blur-sm rounded-full p-1">
            {modes.map(mode => (
              <button
                key={mode.id}
                aria-label="Icon button" onClick={() => setActiveMode(mode.id as typeof activeMode)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
                  activeMode === mode.id
                    ? 'bg-teal-500 text-white'
                    : 'text-white/70 hover:text-white'
                }`}
              >
                <mode.icon className="w-4 h-4" />
                {mode.label}
              </button>
            ))}
          </div>
        )}

        {/* Controls */}
        {hasPermission && !isLoading && !capturedImage && showControls && (
          <div className="absolute bottom-4 left-0 right-0 px-4">
            <div className="flex items-center justify-between max-w-lg mx-auto">
              {/* Transform controls */}
              <div className="flex items-center gap-2">
                <button
                  onClick={handleZoomOut}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                >
                  <ZoomOut className="w-6 h-6" />
                </button>
                <button
                  onClick={handleZoomIn}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                 aria-label="Icon button">
                  <ZoomIn className="w-6 h-6" />
                </button>
                <button
                  onClick={handleRotate}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                >
                  <RotateCcw className="w-6 h-6" />
                </button>
              </div>

              {/* Capture button */}
              <button
                onClick={handleCapture}
                className="w-20 h-20 rounded-full bg-white flex items-center justify-center hover:scale-105 transition-transform shadow-lg"
              >
                <div className="w-16 h-16 rounded-full border-4 border-gray-300" />
              </button>

              {/* Right controls */}
              <div className="flex items-center gap-2">
                <button
                  onClick={handleReset}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                 aria-label="Icon button">
                  <Maximize2 className="w-6 h-6" />
                </button>
                <button
                  aria-label="Icon button" onClick={() => setShowControls(!showControls)}
                  className="p-3 bg-white/10 backdrop-blur-sm rounded-full text-white hover:bg-white/20 transition-colors"
                >
                  <Box className="w-6 h-6" />
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Instructions */}
        {hasPermission && !isLoading && !capturedImage && activeMode === 'place' && (
          <div className="absolute bottom-44 left-1/2 -translate-x-1/2 text-center">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-black/50 backdrop-blur-sm rounded-full text-white text-sm">
              <Smartphone className="w-4 h-4" />
              Drag to position • Pinch to resize
            </div>
          </div>
        )}
      </div>

      {/* Hidden canvas for capture */}
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Camera, RotateCcw, ZoomIn, ZoomOut, Eye, Play, Maximize } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { getEquipment } from '../../services/database';
import type { Equipment } from '../../types';

interface ARVRSession {
  id: string;
  equipmentId: string;
  type: 'ar' | 'vr';
  status: 'active' | 'paused' | 'completed';
  startTime: Date;
  duration: number;
  interactions: ARVRInteraction[];
}

interface ARVRInteraction {
  id: string;
  type: 'view' | 'rotate' | 'zoom' | 'inspect' | 'measure';
  timestamp: Date;
  data?: Record<string, unknown>;
}

interface VirtualTour {
  id: string;
  equipmentId: string;
  title: string;
  description: string;
  duration: number;
  waypoints: VirtualWaypoint[];
  media: {
    images: string[];
    videos: string[];
    models: string[];
  };
}

interface VirtualWaypoint {
  id: string;
  title: string;
  description: string;
  position: { x: number; y: number; z: number };
  rotation: { x: number; y: number; z: number };
  media: string[];
  hotspots: VirtualHotspot[];
}

interface VirtualHotspot {
  id: string;
  position: { x: number; y: number; z: number };
  type: 'info' | 'measurement' | 'damage' | 'feature';
  title: string;
  content: string;
  media?: string;
}

export default function ARVRExperience() {
  const { user } = useAuth();
  const [equipment, setEquipment] = useState<Equipment[]>([]);
  const [selectedEquipment, setSelectedEquipment] = useState<Equipment | null>(null);
  const [activeSession, setActiveSession] = useState<ARVRSession | null>(null);
  const [virtualTours, setVirtualTours] = useState<VirtualTour[]>([]);
  const [currentTour, setCurrentTour] = useState<VirtualTour | null>(null);
  const [currentWaypoint, setCurrentWaypoint] = useState<VirtualWaypoint | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'preview' | 'tours' | 'sessions'>('preview');
  const [arSupported, setArSupported] = useState(false);
  const [vrSupported, setVrSupported] = useState(false);

  // AR/VR controls
  const [isFullscreen, setIsFullscreen] = useState(false);
  void isFullscreen;
  const [zoom, setZoom] = useState(1);
  const [rotation, setRotation] = useState({ x: 0, y: 0, z: 0 });

  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (user) {
      loadEquipment();
      checkARVRSupport();
    }
  }, [user]);

  const loadEquipment = async () => {
    if (!user) return;

    try {
      const equipmentData = await getEquipment({ ownerId: user.id });
      const equipmentList = Array.isArray(equipmentData) ? equipmentData : equipmentData.data || [];
      setEquipment(equipmentList);

      // Load virtual tours (simulated)
      const mockTours: VirtualTour[] = equipmentList.slice(0, 3).map((eq: Equipment, index: number) => ({
        id: `tour-${eq.id}`,
        equipmentId: eq.id,
        title: `${eq.title} Virtual Inspection`,
        description: `Complete virtual tour of the ${eq.title} with detailed inspection points`,
        duration: 300 + index * 60, // 5-8 minutes
        waypoints: [
          {
            id: 'wp-1',
            title: 'Exterior Overview',
            description: 'Complete exterior inspection from all angles',
            position: { x: 0, y: 0, z: 5 },
            rotation: { x: 0, y: 0, z: 0 },
            media: [`https://example.com/360/${eq.id}/exterior.jpg`],
            hotspots: [
              {
                id: 'hs-1',
                position: { x: 1, y: 0, z: 0 },
                type: 'info',
                title: 'Engine Compartment',
                content: 'Access panel for engine maintenance'
              }
            ]
          },
          {
            id: 'wp-2',
            title: 'Interior Controls',
            description: 'Dashboard and control systems inspection',
            position: { x: 0, y: 1, z: 0 },
            rotation: { x: 0, y: 90, z: 0 },
            media: [`https://example.com/360/${eq.id}/interior.jpg`],
            hotspots: []
          }
        ],
        media: {
          images: [`https://example.com/360/${eq.id}/exterior.jpg`, `https://example.com/360/${eq.id}/interior.jpg`],
          videos: [`https://example.com/videos/${eq.id}/demo.mp4`],
          models: [`https://example.com/models/${eq.id}/3d.glb`]
        }
      }));

      setVirtualTours(mockTours);
    } catch (error) {
      console.error('Failed to load equipment:', error);
    } finally {
      setLoading(false);
    }
  };

  const checkARVRSupport = () => {
    // Check for WebXR support
    if ('xr' in navigator) {
      const xr = (navigator as unknown as { xr?: { isSessionSupported: (mode: string) => Promise<boolean> } }).xr;
      if (xr) {
        xr.isSessionSupported('immersive-ar').then((supported: boolean) => setArSupported(supported));
        xr.isSessionSupported('immersive-vr').then((supported: boolean) => setVrSupported(supported));
      }
    }
  };

  const startARSession = async (equipment: Equipment) => {
    if (!arSupported) {
      alert('AR is not supported on this device');
      return;
    }

    try {
      const xr = (navigator as unknown as { xr?: { requestSession?: (mode: string) => Promise<void> } }).xr;
      if (!xr || !xr.requestSession) throw new Error('WebXR not available');
      await xr.requestSession('immersive-ar');
      setSelectedEquipment(equipment);
      setActiveSession({
        id: `ar-${Date.now()}`,
        equipmentId: equipment.id,
        type: 'ar',
        status: 'active',
        startTime: new Date(),
        duration: 0,
        interactions: []
      });
    } catch (error) {
      console.error('Failed to start AR session:', error);
    }
  };

  const startVRSession = async (equipment: Equipment) => {
    if (!vrSupported) {
      alert('VR is not supported on this device');
      return;
    }

    try {
      const xr = (navigator as unknown as { xr?: { requestSession?: (mode: string) => Promise<void> } }).xr;
      if (!xr || !xr.requestSession) throw new Error('WebXR not available');
      await xr.requestSession('immersive-vr');
      setSelectedEquipment(equipment);
      setActiveSession({
        id: `vr-${Date.now()}`,
        equipmentId: equipment.id,
        type: 'vr',
        status: 'active',
        startTime: new Date(),
        duration: 0,
        interactions: []
      });
    } catch (error) {
      console.error('Failed to start VR session:', error);
    }
  };

  const startVirtualTour = (tour: VirtualTour) => {
    setCurrentTour(tour);
    setCurrentWaypoint(tour.waypoints[0]);
    setSelectedEquipment(equipment.find(eq => eq.id === tour.equipmentId) || null);
  };

  const nextWaypoint = () => {
    if (!currentTour || !currentWaypoint) return;

    const currentIndex = currentTour.waypoints.findIndex(wp => wp.id === currentWaypoint.id);
    if (currentIndex < currentTour.waypoints.length - 1) {
      setCurrentWaypoint(currentTour.waypoints[currentIndex + 1]);
    }
  };

  const previousWaypoint = () => {
    if (!currentTour || !currentWaypoint) return;

    const currentIndex = currentTour.waypoints.findIndex(wp => wp.id === currentWaypoint.id);
    if (currentIndex > 0) {
      setCurrentWaypoint(currentTour.waypoints[currentIndex - 1]);
    }
  };

  const handleZoom = (direction: 'in' | 'out') => {
    setZoom(prev => Math.max(0.5, Math.min(3, prev + (direction === 'in' ? 0.1 : -0.1))));
  };

  const handleRotate = (axis: 'x' | 'y' | 'z', delta: number) => {
    setRotation(prev => ({
      ...prev,
      [axis]: prev[axis] + delta
    }));
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-500"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto p-6 space-y-6">
      {/* Header */}
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-xl p-6 text-white">
        <div className="flex items-center gap-3 mb-4">
          <Eye className="w-8 h-8" />
          <h1 className="text-2xl font-bold">AR/VR Experience</h1>
        </div>
        <p className="text-indigo-100">
          Immersive equipment inspection and virtual tours with augmented and virtual reality
        </p>
      </div>

      {/* Device Support */}
      <div className="bg-white rounded-lg shadow-sm border p-4">
        <h3 className="font-semibold mb-3">Device Capabilities</h3>
        <div className="flex gap-4">
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-sm ${
            arSupported ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-600'
          }`}>
            <Eye className="w-4 h-4" />
            AR {arSupported ? 'Supported' : 'Not Supported'}
          </div>
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-sm ${
            vrSupported ? 'bg-blue-100 text-blue-800' : 'bg-gray-100 text-gray-600'
          }`}>
            <Eye className="w-4 h-4" />
            VR {vrSupported ? 'Supported' : 'Not Supported'}
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="flex border-b border-gray-200">
        {[
          { id: 'preview', label: '3D Preview', icon: Eye },
          { id: 'tours', label: 'Virtual Tours', icon: Camera },
          { id: 'sessions', label: 'AR/VR Sessions', icon: Play }
        ].map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setActiveTab(id as 'preview' | 'tours' | 'sessions') aria-label={`Switch to ${label}`}
            className={`flex items-center gap-2 px-6 py-3 border-b-2 font-medium text-sm ${
              activeTab === id
                ? 'border-teal-500 text-teal-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            <Icon className="w-4 h-4" />
            {label}
          </button>
        ))}
      </div>

      {/* Content */}
      {activeTab === 'preview' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Equipment Selection */}
          <div className="bg-white rounded-lg shadow-sm border p-6">
            <h3 className="text-lg font-semibold mb-4">Select Equipment</h3>
            <div className="space-y-3 max-h-96 overflow-y-auto">
              {equipment.map(eq => (
                <div
                  key={eq.id}
                  className={`p-4 border rounded-lg cursor-pointer transition-colors ${
                    selectedEquipment?.id === eq.id ? 'border-teal-500 bg-teal-50' : 'border-gray-200 hover:border-gray-300'
                  }`}
                  onClick={() => setSelectedEquipment(eq)}
                >
                  <div className="flex items-center justify-between">
                    <div>
                      <h4 className="font-medium">{eq.title}</h4>
                      <p className="text-sm text-gray-600">{eq.brand} {eq.model}</p>
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          startARSession(eq);
                        } aria-label={`Start AR session for ${eq.brand} ${eq.model}`}
                        disabled={!arSupported}
                        className="px-3 py-1 bg-purple-500 text-white rounded text-sm hover:bg-purple-600 disabled:opacity-50"
                      >
                        AR
                      </button>
                      <button
                        onClick={(e) = aria-label="Icon button"> {
                          e.stopPropagation();
                          startVRSession(eq);
                        }}
                        disabled={!vrSupported}
                        className="px-3 py-1 bg-blue-500 text-white rounded text-sm hover:bg-blue-600 disabled:opacity-50"
                      >
                        VR
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* 3D Preview */}
          <div className="bg-white rounded-lg shadow-sm border p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold">
                {selectedEquipment ? `${selectedEquipment.title} Preview` : '3D Preview'}
              </h3>
              <div className="flex gap-2">
                <button
                  aria-label="Icon button" onClick={() => handleZoom('out')}
                  className="p-2 border rounded hover:bg-gray-50"
                  title="Zoom Out"
                >
                  <ZoomOut className="w-4 h-4" />
                </button>
                <button
                  aria-label="Icon button" onClick={() => handleZoom('in')}
                  className="p-2 border rounded hover:bg-gray-50"
                  title="Zoom In"
                >
                  <ZoomIn className="w-4 h-4" />
                </button>
                <button
                  aria-label="Icon button" onClick={() => setRotation({ x: 0, y: 0, z: 0 })}
                  className="p-2 border rounded hover:bg-gray-50"
                  title="Reset View"
                >
                  <RotateCcw className="w-4 h-4" />
                </button>
                <button
                  onClick={toggleFullscreen}
                  className="p-2 border rounded hover:bg-gray-50"
                  title="Fullscreen"
                >
                  <Maximize className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="relative bg-gray-100 rounded-lg overflow-hidden" style={{ height: '400px' }}>
              <canvas
                ref={canvasRef}
                className="w-full h-full"
                style={{
                  transform: `scale(${zoom}) rotateX(${rotation.x}deg) rotateY(${rotation.y}deg) rotateZ(${rotation.z}deg)`
                }}
              />

              {selectedEquipment ? (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="text-center">
                    <div className="w-32 h-32 bg-gradient-to-br from-teal-400 to-blue-500 rounded-lg mx-auto mb-4 flex items-center justify-center">
                      <Camera className="w-12 h-12 text-white" />
                    </div>
                    <p className="text-gray-600">3D Model Preview</p>
                    <p className="text-sm text-gray-500 mt-1">
                      {selectedEquipment.brand} {selectedEquipment.model}
                    </p>
                  </div>
                </div>
              ) : (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="text-center text-gray-500">
                    <Eye className="w-12 h-12 mx-auto mb-4" />
                    <p>Select equipment to preview in 3D</p>
                  </div>
                </div>
              )}

              {/* Rotation Controls */}
              <div className="absolute bottom-4 left-4 flex gap-2">
                <button
                  aria-label="Icon button" onClick={() => handleRotate('y', -15)}
                  className="p-2 bg-white rounded shadow hover:bg-gray-50"
                  title="Rotate Left"
                >
                  ←
                </button>
                <button
                  aria-label="Icon button" onClick={() => handleRotate('y', 15)}
                  className="p-2 bg-white rounded shadow hover:bg-gray-50"
                  title="Rotate Right"
                >
                  →
                </button>
                <button
                  aria-label="Icon button" onClick={() => handleRotate('x', -15)}
                  className="p-2 bg-white rounded shadow hover:bg-gray-50"
                  title="Rotate Up"
                >
                  ↑
                </button>
                <button
                  aria-label="Icon button" onClick={() => handleRotate('x', 15)}
                  className="p-2 bg-white rounded shadow hover:bg-gray-50"
                  title="Rotate Down"
                >
                  ↓
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'tours' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {virtualTours.map(tour => (
              <div key={tour.id} className="bg-white rounded-lg shadow-sm border overflow-hidden">
                <div className="p-4 bg-gradient-to-r from-teal-500 to-blue-500 text-white">
                  <Camera className="w-6 h-6 mb-2" />
                  <h3 className="font-bold">{tour.title}</h3>
                </div>

                <div className="p-4">
                  <p className="text-sm text-gray-600 mb-4">{tour.description}</p>

                  <div className="flex items-center justify-between text-sm text-gray-600 mb-4">
                    <span>{tour.waypoints.length} waypoints</span>
                    <span>{Math.floor(tour.duration / 60)} min</span>
                  </div>

                  <button
                    aria-label="Icon button" onClick={() => startVirtualTour(tour)}
                    className="w-full px-4 py-2 bg-teal-500 text-white rounded-lg hover:bg-teal-600 transition-colors"
                  >
                    Start Tour
                  </button>
                </div>
              </div>
            ))}
          </div>

          {/* Current Tour */}
          {currentTour && currentWaypoint && (
            <div className="bg-white rounded-lg shadow-sm border p-6">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h3 className="text-lg font-semibold">{currentTour.title}</h3>
                  <p className="text-sm text-gray-600">{currentWaypoint.title}</p>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={previousWaypoint}
                    className="px-3 py-1 border rounded hover:bg-gray-50"
                    disabled={currentTour.waypoints[0].id === currentWaypoint.id aria-label="Icon button">
                    Previous
                  </button>
                  <button
                    onClick={nextWaypoint}
                    className="px-3 py-1 bg-teal-500 text-white rounded hover:bg-teal-600"
                    disabled={currentTour.waypoints[currentTour.waypoints.length - 1].id === currentWaypoint.id aria-label="Icon button">
                    Next
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div>
                  <div className="bg-gray-100 rounded-lg h-64 flex items-center justify-center mb-4">
                    <Camera className="w-12 h-12 text-gray-400" />
                  </div>
                  <p className="text-sm text-gray-700">{currentWaypoint.description}</p>
                </div>

                <div>
                  <h4 className="font-medium mb-3">Hotspots</h4>
                  <div className="space-y-2">
                    {currentWaypoint.hotspots.map(hotspot => (
                      <div key={hotspot.id} className="p-3 bg-gray-50 rounded-lg">
                        <div className="flex items-center gap-2 mb-1">
                          <div className={`w-3 h-3 rounded-full ${
                            hotspot.type === 'info' ? 'bg-blue-500' :
                            hotspot.type === 'measurement' ? 'bg-green-500' :
                            hotspot.type === 'damage' ? 'bg-red-500' : 'bg-purple-500'
                          }`}></div>
                          <span className="font-medium text-sm">{hotspot.title}</span>
                        </div>
                        <p className="text-sm text-gray-600">{hotspot.content}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'sessions' && (
        <div className="bg-white rounded-lg shadow-sm border">
          <div className="p-6 border-b">
            <h3 className="text-lg font-semibold">AR/VR Session History</h3>
            <p className="text-sm text-gray-600">Track your immersive equipment inspection sessions</p>
          </div>

          <div className="p-6">
            {activeSession ? (
