                { id: '2', type: 'VR', equipment: 'Forklift Pro-500', duration: 320, date: new Date(Date.now() - 172800000) },
                { id: '3', type: 'AR', equipment: 'Generator MaxPower', duration: 180, date: new Date(Date.now() - 259200000) }
