                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                        deliveryOption === 'delivery' ? 'bg-teal-500 text-white' : 'bg-gray-100 text-gray-600'
                      }`}>
                        <Truck className="w-5 h-5" />
