export default function BulkBookingSystem({ initialEquipment = [], onComplete, onClose }: BulkBookingSystemProps) {
  const [cartItems, setCartItems] = useState<CartItem[]>(() => {
    return initialEquipment.map((eq) => ({
      equipment: eq,
      quantity: 1,
      startDate: '',
      endDate: '',
      rentalDays: 0,
      subtotal: 0,
    }));
  });
  const [step, setStep] = useState<'cart' | 'dates' | 'review' | 'payment' | 'complete'>('cart');
  const [isLoading, setIsLoading] = useState(false);
  const [showEquipmentPicker, setShowEquipmentPicker] = useState(false);
  const [globalStartDate, setGlobalStartDate] = useState('');
  const [globalEndDate, setGlobalEndDate] = useState('');
  const [useSameDates, setUseSameDates] = useState(true);
  const [paymentMethod, setPaymentMethod] = useState<'card' | 'bank' | 'split'>('card');
  void paymentMethod; void setPaymentMethod; // For future payment integration

  // Calculate rental days
  const calculateDays = (start: string, end: string): number => {
    if (!start || !end) return 0;
    const startDate = new Date(start);
    const endDate = new Date(end);
    const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
  };

  // Calculate item subtotal
  const calculateSubtotal = (equipment: Equipment, days: number): number => {
    if (days >= 30 && equipment.monthly_rate) {
      const months = Math.floor(days / 30);
      const remainingDays = days % 30;
      return months * equipment.monthly_rate + remainingDays * equipment.daily_rate;
    }
    if (days >= 7 && equipment.weekly_rate) {
      const weeks = Math.floor(days / 7);
      const remainingDays = days % 7;
      return weeks * equipment.weekly_rate + remainingDays * equipment.daily_rate;
    }
    return days * equipment.daily_rate;
  };

  // Get applicable discount
  const getApplicableDiscount = (itemCount: number): BulkDiscount | null => {
    const sortedDiscounts = [...bulkDiscounts].sort((a, b) => b.minItems - a.minItems);
    return sortedDiscounts.find((d) => itemCount >= d.minItems) || null;
  };

  // Calculate totals
  const totals = useMemo(() => {
    const itemsWithDates = cartItems.map((item) => {
      const start = useSameDates ? globalStartDate : item.startDate;
      const end = useSameDates ? globalEndDate : item.endDate;
      const days = calculateDays(start, end);
      const subtotal = calculateSubtotal(item.equipment, days) * item.quantity;
      return { ...item, rentalDays: days, subtotal };
    });

    const subtotal = itemsWithDates.reduce((sum, item) => sum + item.subtotal, 0);
    const totalItems = itemsWithDates.reduce((sum, item) => sum + item.quantity, 0);
    const discount = getApplicableDiscount(totalItems);
    const discountAmount = discount ? (subtotal * discount.discount) / 100 : 0;
    const serviceFee = (subtotal - discountAmount) * 0.05; // 5% service fee
    const totalDeposit = itemsWithDates.reduce((sum, item) => sum + item.equipment.deposit_amount * item.quantity, 0);
    const totalAmount = subtotal - discountAmount + serviceFee;

    return {
      items: itemsWithDates,
      subtotal,
      totalItems,
      discount,
      discountAmount,
      serviceFee,
      totalDeposit,
      totalAmount,
    };
  }, [cartItems, globalStartDate, globalEndDate, useSameDates]);

  // Add item to cart
  const addToCart = (equipment: Equipment) => {
    const existingIndex = cartItems.findIndex((item) => item.equipment.id === equipment.id);
    if (existingIndex >= 0) {
      const updated = [...cartItems];
      updated[existingIndex].quantity += 1;
      setCartItems(updated);
    } else {
      setCartItems([
        ...cartItems,
        {
          equipment,
          quantity: 1,
          startDate: globalStartDate,
          endDate: globalEndDate,
          rentalDays: 0,
          subtotal: 0,
        },
      ]);
    }
    setShowEquipmentPicker(false);
  };

  // Update item quantity
  const updateQuantity = (equipmentId: string, delta: number) => {
    setCartItems(
      cartItems
        .map((item) =>
          item.equipment.id === equipmentId ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
        )
        .filter((item) => item.quantity > 0)
    );
  };

  // Remove item from cart
  const removeFromCart = (equipmentId: string) => {
    setCartItems(cartItems.filter((item) => item.equipment.id !== equipmentId));
  };

  // Update item dates
  const updateItemDates = (equipmentId: string, startDate: string, endDate: string) => {
    setCartItems(
      cartItems.map((item) =>
        item.equipment.id === equipmentId ? { ...item, startDate, endDate } : item
      )
    );
  };

  // Process booking
  const processBooking = async () => {
    setIsLoading(true);
    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 2000));
    setIsLoading(false);
    setStep('complete');
    
    if (onComplete) {
      const mockBooking: BulkBooking = {
        id: Date.now().toString(),
        renter_id: 'current_user',
        booking_ids: totals.items.map((_, idx) => `booking_${idx}`),
        total_equipment: totals.totalItems,
        subtotal: totals.subtotal,
        bulk_discount: totals.discountAmount,
        service_fee: totals.serviceFee,
        total_amount: totals.totalAmount,
        status: 'confirmed',
        payment_status: 'paid',
        notes: null,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      };
      onComplete(mockBooking);
    }
  };

  // Render cart step
  const renderCart = () => (
    <div className="space-y-4">
      {/* Discount Banner */}
      <div className="bg-gradient-to-r from-amber-500 to-orange-500 text-white p-4 rounded-lg">
        <div className="flex items-center gap-2 mb-2">
          <Tag className="w-5 h-5" />
          <span className="font-semibold">Bulk Booking Discounts</span>
        </div>
        <div className="flex flex-wrap gap-3 text-sm">
          {bulkDiscounts.map((d) => (
            <span
              key={d.minItems}
              className={`px-2 py-1 rounded ${
                totals.discount?.minItems === d.minItems
                  ? 'bg-white text-orange-600 font-semibold'
                  : 'bg-white/20'
              }`}
            >
              {d.label}
            </span>
          ))}
        </div>
      </div>

      {/* Cart Items */}
      {cartItems.length === 0 ? (
        <div className="text-center py-12 border-2 border-dashed rounded-lg">
          <ShoppingCart className="w-12 h-12 mx-auto text-gray-300 mb-3" />
          <p className="text-gray-500 mb-4">Your cart is empty</p>
          <button
            onClick={() => setShowEquipmentPicker(true) aria-label="Add equipment"
            className="px-4 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors"
          >
            <Plus className="w-4 h-4 inline mr-1" />
            Add Equipment
          </button>
        </div>
      ) : (
        <div className="space-y-3">
          {totals.items.map((item) => (
            <div key={item.equipment.id} className="border rounded-lg overflow-hidden">
              <div className="flex items-center gap-4 p-4">
                <img
                  src={item.equipment.images[0] || 'https://via.placeholder.com/80'}
                  alt={item.equipment.title}
                  className="w-20 h-20 object-cover rounded-lg"
                />
                <div className="flex-1">
                  <h4 className="font-medium text-gray-900">{item.equipment.title}</h4>
                  <p className="text-sm text-gray-500">{item.equipment.brand} {item.equipment.model}</p>
                  <div className="flex items-center gap-4 mt-1 text-sm text-gray-500">
                    <span className="flex items-center gap-1">
                      <MapPin className="w-3 h-3" />
                      {item.equipment.location}
                    </span>
                    <span className="flex items-center gap-1">
                      <DollarSign className="w-3 h-3" />
                      ${item.equipment.daily_rate}/day
                    </span>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <button
                    aria-label="Icon button" onClick={() => updateQuantity(item.equipment.id, -1)}
                    className="p-1 hover:bg-gray-100 rounded"
                  >
                    <Minus className="w-4 h-4" />
                  </button>
                  <span className="w-8 text-center font-medium">{item.quantity}</span>
                  <button
                    aria-label="Icon button" onClick={() => updateQuantity(item.equipment.id, 1)}
                    className="p-1 hover:bg-gray-100 rounded"
                  >
                    <Plus className="w-4 h-4" />
                  </button>
                </div>
                <div className="text-right">
                  <p className="font-semibold text-gray-900">
                    ${item.subtotal.toLocaleString()}
                  </p>
                  {item.rentalDays > 0 && (
                    <p className="text-xs text-gray-500">{item.rentalDays} days</p>
                  )}
                </div>
                <button
                  aria-label="Icon button" onClick={() => removeFromCart(item.equipment.id)}
                  className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}

          <button
            aria-label="Icon button" onClick={() => setShowEquipmentPicker(true)}
            className="w-full py-3 border-2 border-dashed rounded-lg text-gray-500 hover:border-teal-500 hover:text-teal-600 transition-colors flex items-center justify-center gap-2"
          >
            <Plus className="w-4 h-4" />
            Add More Equipment
          </button>
        </div>
      )}

      {/* Equipment Picker Modal */}
      {showEquipmentPicker && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-2xl w-full max-h-[80vh] overflow-hidden">
            <div className="p-4 border-b flex items-center justify-between">
              <h3 className="font-semibold">Add Equipment to Cart</h3>
              <button aria-label="Icon button" onClick={() => setShowEquipmentPicker(false)} className="p-2 hover:bg-gray-100 rounded-lg">
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-4 overflow-y-auto max-h-96 space-y-3">
              {mockAvailableEquipment
                .filter((eq) => !cartItems.find((item) => item.equipment.id === eq.id))
                .map((equipment) => (
                  <div
                    key={equipment.id}
                    className="flex items-center gap-4 p-3 border rounded-lg hover:border-teal-500 cursor-pointer transition-colors"
                    onClick={() => addToCart(equipment)}
                  >
                    <img
                      src={equipment.images[0] || 'https://via.placeholder.com/60'}
                      alt={equipment.title}
                      className="w-16 h-16 object-cover rounded-lg"
                    />
                    <div className="flex-1">
                      <h4 className="font-medium">{equipment.title}</h4>
                      <p className="text-sm text-gray-500">{equipment.location}</p>
                    </div>
                    <div className="text-right">
                      <p className="font-semibold text-teal-600">${equipment.daily_rate}/day</p>
                      <p className="text-xs text-gray-500">Deposit: ${equipment.deposit_amount}</p>
                    </div>
                    <Plus className="w-5 h-5 text-teal-600" />
                  </div>
                ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );

  // Render dates step
  const renderDates = () => (
    <div className="space-y-6">
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={useSameDates}
            onChange={(e) => setUseSameDates(e.target.checked)}
            className="w-4 h-4 text-teal-600 rounded focus:ring-teal-500"
          />
          <span className="font-medium text-blue-900">Use same dates for all equipment</span>
        </label>
        <p className="text-sm text-blue-700 mt-1 ml-6">
          This simplifies booking and may qualify for weekly/monthly rates
        </p>
      </div>

      {useSameDates ? (
        <div className="bg-white border rounded-lg p-6">
          <h3 className="font-semibold mb-4 flex items-center gap-2">
            <Calendar className="w-5 h-5 text-teal-600" />
            Rental Period (All Equipment)
          </h3>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
              <input
                type="date"
                value={globalStartDate}
                min={new Date().toISOString().split('T')[0]}
                onChange={(e) => setGlobalStartDate(e.target.value)}
                className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-teal-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
              <input
                type="date"
                value={globalEndDate}
                min={globalStartDate || new Date().toISOString().split('T')[0]}
                onChange={(e) => setGlobalEndDate(e.target.value)}
                className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-teal-500"
              />
            </div>
          </div>
          {globalStartDate && globalEndDate && (
            <div className="mt-4 p-3 bg-teal-50 rounded-lg">
              <div className="flex items-center justify-between">
                <span className="text-teal-800">Total Rental Period:</span>
                <span className="font-semibold text-teal-900">
                  {calculateDays(globalStartDate, globalEndDate)} days
                </span>
              </div>
            </div>
          )}
        </div>
      ) : (
        <div className="space-y-4">
          {cartItems.map((item) => (
            <div key={item.equipment.id} className="border rounded-lg p-4">
              <div className="flex items-center gap-3 mb-4">
                <img
                  src={item.equipment.images[0] || 'https://via.placeholder.com/40'}
                  alt={item.equipment.title}
                  className="w-10 h-10 object-cover rounded"
                />
                <div>
                  <h4 className="font-medium">{item.equipment.title}</h4>
                  <p className="text-sm text-gray-500">Qty: {item.quantity}</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
                  <input
                    type="date"
                    value={item.startDate}
                    min={new Date().toISOString().split('T')[0]}
                    onChange={(e) => updateItemDates(item.equipment.id, e.target.value, item.endDate)}
                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-teal-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
                  <input
                    type="date"
                    value={item.endDate}
                    min={item.startDate || new Date().toISOString().split('T')[0]}
                    onChange={(e) => updateItemDates(item.equipment.id, item.startDate, e.target.value)}
                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-teal-500"
                  />
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );

  // Render review step
  const renderReview = () => (
    <div className="space-y-6">
      {/* Order Summary */}
      <div className="border rounded-lg overflow-hidden">
        <div className="bg-gray-50 px-4 py-3 border-b">
          <h3 className="font-semibold">Order Summary</h3>
        </div>
        <div className="divide-y">
          {totals.items.map((item) => (
            <div key={item.equipment.id} className="p-4 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <img
                  src={item.equipment.images[0] || 'https://via.placeholder.com/40'}
                  alt={item.equipment.title}
                  className="w-12 h-12 object-cover rounded"
                />
                <div>
                  <h4 className="font-medium">{item.equipment.title}</h4>
                  <p className="text-sm text-gray-500">
                    {item.quantity}x • {item.rentalDays} days @ ${item.equipment.daily_rate}/day
                  </p>
                </div>
              </div>
              <span className="font-semibold">${item.subtotal.toLocaleString()}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Price Breakdown */}
      <div className="border rounded-lg p-4 space-y-3">
        <div className="flex justify-between text-gray-600">
          <span>Subtotal ({totals.totalItems} items)</span>
          <span>${totals.subtotal.toLocaleString()}</span>
        </div>
        {totals.discount && (
          <div className="flex justify-between text-green-600">
            <span className="flex items-center gap-1">
              <Percent className="w-4 h-4" />
              Bulk Discount ({totals.discount.label})
            </span>
            <span>-${totals.discountAmount.toLocaleString()}</span>
          </div>
        )}
        <div className="flex justify-between text-gray-600">
          <span>Service Fee (5%)</span>
          <span>${totals.serviceFee.toFixed(2)}</span>
        </div>
        <div className="flex justify-between text-gray-500 text-sm">
          <span className="flex items-center gap-1">
            <Shield className="w-4 h-4" />
            Security Deposit (refundable)
          </span>
          <span>${totals.totalDeposit.toLocaleString()}</span>
        </div>
        <div className="border-t pt-3 flex justify-between text-lg font-bold">
          <span>Total Due Today</span>
          <span className="text-teal-600">
            ${(totals.totalAmount + totals.totalDeposit).toLocaleString()}
          </span>
        </div>
      </div>

      {/* Payment Method */}
      <div className="border rounded-lg p-4">
        <h4 className="font-semibold mb-3">Payment Method</h4>
        <div className="space-y-2">
          {[
            { id: 'card', label: 'Credit/Debit Card', icon: CreditCard },
            { id: 'bank', label: 'Bank Transfer', icon: DollarSign },
            { id: 'split', label: 'Split Payment', icon: Package },
          ].map(({ id, label, icon: Icon }) => (
            <label
              key={id}
              className={`flex items-center gap-3 p-3 border rounded-lg cursor-pointer transition-colors ${
                paymentMethod === id ? 'border-teal-500 bg-teal-50' : 'hover:border-gray-300'
              }`}
            >
              <input
                type="radio"
                name="payment"
                value={id}
                checked={paymentMethod === id}
                onChange={(e) = "payment" onClick={() => setPaymentMethod(e.target.value as typeof paymentMethod)}
                className="w-4 h-4 text-teal-600"
              />
              <Icon className="w-5 h-5 text-gray-500" />
              <span className="font-medium">{label}</span>
            </label>
          ))}
        </div>
      </div>
    </div>
  );

  // Render complete step
  const renderComplete = () => (
    <div className="text-center py-12">
      <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
        <CheckCircle className="w-8 h-8 text-green-600" />
      </div>
      <h3 className="text-xl font-bold text-gray-900 mb-2">Booking Confirmed!</h3>
      <p className="text-gray-600 mb-6">
        Your bulk booking has been successfully processed. You'll receive a confirmation email shortly.
      </p>
      <div className="bg-gray-50 rounded-lg p-4 max-w-sm mx-auto mb-6">
        <div className="text-sm text-gray-500 mb-1">Booking Reference</div>
        <div className="text-lg font-mono font-bold text-gray-900">BULK-{Date.now().toString(36).toUpperCase()}</div>
      </div>
      <div className="flex justify-center gap-4">
        <button className="px-4 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors" aria-label="Icon button">
          View Bookings
        </button>
        <button
          onClick={onClose}
          className="px-4 py-2 border rounded-lg hover:bg-gray-50 transition-colors"
         aria-label="Icon button">
          Close
        </button>
      </div>
    </div>
  );

  const canProceed = useMemo(() => {
    switch (step) {
      case 'cart':
        return cartItems.length > 0;
      case 'dates':
        if (useSameDates) {
          return globalStartDate && globalEndDate && calculateDays(globalStartDate, globalEndDate) > 0;
        }
        return cartItems.every(
          (item) => item.startDate && item.endDate && calculateDays(item.startDate, item.endDate) > 0
        );
      case 'review':
        return true;
      default:
        return false;
    }
  }, [step, cartItems, useSameDates, globalStartDate, globalEndDate]);

  return (
    <div className="bg-white rounded-xl shadow-lg max-w-4xl mx-auto overflow-hidden">
      {/* Header */}
      <div className="bg-gradient-to-r from-teal-600 to-teal-700 text-white p-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-white/20 rounded-lg">
              <Package className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Bulk Booking System</h2>
              <p className="text-teal-100 text-sm">Book multiple equipment and save with bulk discounts</p>
            </div>
          </div>
          {onClose && (
            <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-lg transition-colors">
              <X className="w-5 h-5" />
            </button>
          )}
        </div>

        {/* Steps */}
        <div className="flex items-center justify-between mt-6">
          {['cart', 'dates', 'review', 'payment', 'complete'].map((s, idx, arr) => (
            <div key={s} className="flex items-center">
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center font-semibold ${
                  step === s
                    ? 'bg-white text-teal-600'
                    : arr.indexOf(step) > idx
                    ? 'bg-teal-400 text-white'
                    : 'bg-teal-500/50 text-teal-200'
                }`}
              >
                {arr.indexOf(step) > idx ? <CheckCircle className="w-4 h-4" /> : idx + 1}
              </div>
              {idx < arr.length - 1 && (
                <div
                  className={`w-16 h-0.5 ${
                    arr.indexOf(step) > idx ? 'bg-teal-400' : 'bg-teal-500/50'
                  }`}
                />
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {step === 'cart' && renderCart()}
        {step === 'dates' && renderDates()}
        {step === 'review' && renderReview()}
        {step === 'complete' && renderComplete()}
      </div>

      {/* Footer */}
      {step !== 'complete' && (
        <div className="p-6 border-t bg-gray-50 flex items-center justify-between">
          <div>
            {totals.totalItems > 0 && (
              <div className="text-sm text-gray-500">
                {totals.totalItems} items • ${totals.totalAmount.toLocaleString()} total
                {totals.discount && (
                  <span className="text-green-600 ml-2">
                    (Save ${totals.discountAmount.toLocaleString()})
                  </span>
                )}
              </div>
            )}
          </div>
          <div className="flex gap-3">
            {step !== 'cart' && (
              <button
                aria-label="Icon button"> {
                  const steps: ('cart' | 'dates' | 'review' | 'payment' | 'complete')[] = ['cart', 'dates', 'review', 'payment'];
                  const currentIndex = steps.indexOf(step);
                  if (currentIndex > 0) setStep(steps[currentIndex - 1]);
                }}
                className="px-4 py-2 border rounded-lg hover:bg-gray-100 transition-colors"
              >
                Back
              </button>
            )}
            {step === 'review' ? (
              <button
                onClick={processBooking}
                disabled={isLoading}
                className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2 disabled:opacity-50"
               aria-label="Icon button">
                {isLoading ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Processing...
                  </>
                ) : (
                  <>
                    <CreditCard className="w-4 h-4" />
                    Confirm & Pay ${(totals.totalAmount + totals.totalDeposit).toLocaleString()}
                  </>
                )}
              </button>
            ) : (
              <button
                aria-label="Icon button"> {
                  const steps: ('cart' | 'dates' | 'review' | 'payment' | 'complete')[] = ['cart', 'dates', 'review'];
                  const currentIndex = steps.indexOf(step);
                  if (currentIndex < steps.length - 1) setStep(steps[currentIndex + 1]);
                }}
                disabled={!canProceed}
                className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Continue
                <ArrowRight className="w-4 h-4" />
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars */
import { useState, useEffect } from 'react';
import { Shield, DollarSign, AlertTriangle, CheckCircle, FileText, Camera } from 'lucide-react';

interface DamageReportWizardProps {
  bookingId: string;
  equipmentTitle: string;
  equipmentImages: string[];
  depositAmount: number;
  onComplete: (report: DamageReport) => void;
  onClose: () => void;
}

interface DamageReport {
  id: string;
  bookingId: string;
  reportedAt: Date;
  severity: 'none' | 'minor' | 'moderate' | 'severe';
  description: string;
  photos: string[];
  estimatedCost: number;
  resolution: 'pending' | 'approved' | 'disputed' | 'resolved';
}

interface ChecklistItem {
  id: string;
  label: string;
  description: string;
  status: 'unchecked' | 'ok' | 'issue';
  photo?: string;
  notes?: string;
}

export default function DamageReportWizard({
  bookingId,
  equipmentTitle,
  equipmentImages: _equipmentImages,
  depositAmount,
  onComplete,
  onClose,
}: DamageReportWizardProps) {
  // equipmentImages reserved for comparison view
  const [step, setStep] = useState(1);
  const [checklist, setChecklist] = useState<ChecklistItem[]>([
    { id: '1', label: 'Physical Condition', description: 'Check for dents, scratches, or cracks', status: 'unchecked' },
    { id: '2', label: 'Functionality', description: 'Verify all features work correctly', status: 'unchecked' },
    { id: '3', label: 'Accessories', description: 'Confirm all accessories are present', status: 'unchecked' },
    { id: '4', label: 'Cleanliness', description: 'Check if equipment is clean', status: 'unchecked' },
    { id: '5', label: 'Safety Features', description: 'Verify safety mechanisms work', status: 'unchecked' },
  ]);
  const [photos, setPhotos] = useState<string[]>([]);
  const [description, setDescription] = useState('');
  const [severity, setSeverity] = useState<'none' | 'minor' | 'moderate' | 'severe'>('none');
  const [estimatedCost, setEstimatedCost] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const issueCount = checklist.filter((item) => item.status === 'issue').length;
  const checkedCount = checklist.filter((item) => item.status !== 'unchecked').length;

  // Auto-calculate severity based on issues
  useEffect(() => {
    if (issueCount === 0) {
      setSeverity('none');
      setEstimatedCost(0);
    } else if (issueCount === 1) {
      setSeverity('minor');
      setEstimatedCost(Math.min(depositAmount * 0.1, 50));
    } else if (issueCount <= 3) {
      setSeverity('moderate');
      setEstimatedCost(Math.min(depositAmount * 0.3, 200));
    } else {
      setSeverity('severe');
      setEstimatedCost(Math.min(depositAmount * 0.5, 500));
    }
  }, [issueCount, depositAmount]);

  const updateChecklistItem = (id: string, status: 'ok' | 'issue', notes?: string) => {
    setChecklist((prev) =>
      prev.map((item) => (item.id === id ? { ...item, status, notes } : item))
    );
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      // In production, you'd upload to storage and get URLs
      const newPhotos = Array.from(files).map((file) => URL.createObjectURL(file));
      setPhotos((prev) => [...prev, ...newPhotos]);
    }
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    
    // Simulate API call
    await new Promise((resolve) => setTimeout(resolve, 1500));
    
    const report: DamageReport = {
      id: `dmg-${Date.now()}`,
      bookingId,
      reportedAt: new Date(),
      severity,
      description,
      photos,
      estimatedCost,
      resolution: severity === 'none' ? 'resolved' : 'pending',
    };
    
    onComplete(report);
    setIsSubmitting(false);
  };

  const getSeverityColor = (sev: string) => {
    switch (sev) {
      case 'none':
        return 'text-green-600 bg-green-100';
      case 'minor':
        return 'text-yellow-600 bg-yellow-100';
      case 'moderate':
        return 'text-orange-600 bg-orange-100';
      case 'severe':
        return 'text-red-600 bg-red-100';
      default:
        return 'text-gray-600 bg-gray-100';
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-6 border-b border-gray-200 bg-gradient-to-r from-blue-50 to-indigo-50">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center">
                <Shield className="w-6 h-6 text-white" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-900">Equipment Return Check</h2>
                <p className="text-gray-600">{equipmentTitle}</p>
              </div>
            </div>
            <button
              onClick={onClose}
              className="p-2 hover:bg-gray-200 rounded-lg transition-colors"
             aria-label="Icon button">
              ✕
            </button>
          </div>

          {/* Progress */}
          <div className="mt-4">
            <div className="flex justify-between text-sm text-gray-600 mb-1">
              <span>Step {step} of 3</span>
              <span>{checkedCount}/{checklist.length} items checked</span>
            </div>
            <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
              <div
                className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 transition-all duration-300"
                style={{ width: `${(step / 3) * 100}%` }}
              />
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Step 1: Checklist */}
          {step === 1 && (
            <div className="space-y-4">
              <h3 className="font-semibold text-gray-900 mb-4">Inspection Checklist</h3>
              
              {checklist.map((item) => (
                <div
                  key={item.id}
                  className={`p-4 rounded-xl border-2 transition-all ${
                    item.status === 'ok'
                      ? 'border-green-200 bg-green-50'
                      : item.status === 'issue'
                      ? 'border-red-200 bg-red-50'
                      : 'border-gray-200 bg-gray-50'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="font-medium text-gray-900">{item.label}</div>
                      <div className="text-sm text-gray-500">{item.description}</div>
                    </div>
                    
                    <div className="flex gap-2">
                      <button
                        aria-label="Icon button" onClick={() => updateChecklistItem(item.id, 'ok')}
                        className={`p-2 rounded-lg transition-all ${
                          item.status === 'ok'
                            ? 'bg-green-500 text-white'
                            : 'bg-gray-200 text-gray-600 hover:bg-green-100'
                        }`}
                      >
                        <CheckCircle className="w-5 h-5" />
                      </button>
                      <button
                        aria-label="Icon button" onClick={() => updateChecklistItem(item.id, 'issue')}
                        className={`p-2 rounded-lg transition-all ${
                          item.status === 'issue'
                            ? 'bg-red-500 text-white'
                            : 'bg-gray-200 text-gray-600 hover:bg-red-100'
                        }`}
                      >
                        <AlertTriangle className="w-5 h-5" />
                      </button>
                    </div>
                  </div>

                  {item.status === 'issue' && (
                    <textarea
                      placeholder="Describe the issue..."
                      value={item.notes || ''}
                      onChange={(e) => updateChecklistItem(item.id, 'issue', e.target.value)}
                      className="mt-3 w-full p-3 border border-red-200 rounded-lg text-sm resize-none"
                      rows={2}
                    />
                  )}
                </div>
              ))}
            </div>
          )}

          {/* Step 2: Photos & Details */}
          {step === 2 && (
            <div className="space-y-6">
              <h3 className="font-semibold text-gray-900">Photo Documentation</h3>
              
              {/* Photo Upload */}
              <div className="border-2 border-dashed border-gray-300 rounded-xl p-6 text-center">
                <input
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={handlePhotoUpload}
                  className="hidden"
                  id="photo-upload"
                / aria-label="photo-upload">
                <label
                  htmlFor="photo-upload"
                  className="cursor-pointer flex flex-col items-center"
                >
                  <Camera className="w-12 h-12 text-gray-400 mb-3" />
                  <span className="text-gray-600">Click to upload photos</span>
                  <span className="text-sm text-gray-400">or drag and drop</span>
                </label>
              </div>

              {/* Photo Grid */}
              {photos.length > 0 && (
                <div className="grid grid-cols-3 gap-3">
                  {photos.map((photo, index) => {
                    // Sanitize photo URL to prevent javascript: or data: URLs
                    const safePhotoUrl = photo.startsWith('http://') || photo.startsWith('https://') || photo.startsWith('blob:') || photo.startsWith('data:image/')
                      ? photo
                      : '';
                    return (
                      <div key={index} className="relative aspect-square rounded-lg overflow-hidden">
                        <img src={safePhotoUrl} alt={`Photo ${index + 1}`} className="w-full h-full object-cover" />
                        <button
                          aria-label="Icon button"> setPhotos((prev) => prev.filter((_, i) => i !== index))}
                          className="absolute top-2 right-2 w-6 h-6 bg-red-500 text-white rounded-full text-xs"
                        >
                          ✕
                        </button>
                      </div>
                    );
                  })}
                </div>
              )}

              {/* Description */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Additional Notes
                </label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="Add any additional details about the equipment condition..."
                  className="w-full p-4 border border-gray-200 rounded-xl resize-none"
                  rows={4}
                />
              </div>
            </div>
          )}

          {/* Step 3: Review & Submit */}
          {step === 3 && (
            <div className="space-y-6">
              <h3 className="font-semibold text-gray-900">Review & Submit</h3>

              {/* Summary */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-gray-50 rounded-xl">
                  <div className="text-sm text-gray-500 mb-1">Condition Assessment</div>
                  <div className={`inline-flex px-3 py-1 rounded-full text-sm font-medium capitalize ${getSeverityColor(severity)}`}>
                    {severity === 'none' ? 'No Issues' : `${severity} Damage`}
                  </div>
                </div>
                
                <div className="p-4 bg-gray-50 rounded-xl">
                  <div className="text-sm text-gray-500 mb-1">Estimated Cost</div>
                  <div className="text-2xl font-bold text-gray-900">
                    ${estimatedCost.toFixed(2)}
                  </div>
                </div>
              </div>

              {/* Deposit Info */}
              <div className="p-4 bg-blue-50 rounded-xl border border-blue-100">
                <div className="flex items-center gap-2 text-blue-700 mb-2">
                  <DollarSign className="w-5 h-5" />
                  <span className="font-medium">Deposit Information</span>
                </div>
                <div className="text-sm text-blue-600">
                  Deposit: ${depositAmount.toFixed(2)}
                  {severity === 'none' ? (
                    <span className="ml-2 text-green-600">→ Full refund pending</span>
                  ) : (
                    <span className="ml-2 text-orange-600">→ ${(depositAmount - estimatedCost).toFixed(2)} refund pending</span>
                  )}
                </div>
              </div>

              {/* Issues Summary */}
              {issueCount > 0 && (
                <div className="p-4 bg-red-50 rounded-xl border border-red-100">
                  <div className="flex items-center gap-2 text-red-700 mb-2">
                    <AlertTriangle className="w-5 h-5" />
                    <span className="font-medium">{issueCount} Issue(s) Reported</span>
                  </div>
                  <ul className="text-sm text-red-600 space-y-1">
                    {checklist
                      .filter((item) => item.status === 'issue')
                      .map((item) => {
                        const safeLabel = String(item.label).replace(/[<>&"']/g, '');
                        const safeNotes = String(item.notes || 'No details provided').replace(/[<>&"']/g, '');
                        return (
                          <li key={item.id}>• {safeLabel}: {safeNotes}</li>
                        );
                      })}
                  </ul>
                </div>
              )}

              {/* Photos */}
              {photos.length > 0 && (
                <div>
                  <div className="text-sm font-medium text-gray-700 mb-2">{photos.length} Photo(s) Attached</div>
                  <div className="flex gap-2">
                    {photos.slice(0, 4).map((photo, index) => {
                      // Sanitize photo URL to prevent javascript: or data: URLs
                      const safePhotoUrl = photo.startsWith('http://') || photo.startsWith('https://') || photo.startsWith('blob:') || photo.startsWith('data:image/')
                        ? photo
                        : '';
                      return (
                        <div key={index} className="w-16 h-16 rounded-lg overflow-hidden">
                          <img src={safePhotoUrl} alt="Equipment photo" className="w-full h-full object-cover" />
                        </div>
                      );
                    })}
                    {photos.length > 4 && (
                      <div className="w-16 h-16 rounded-lg bg-gray-100 flex items-center justify-center text-gray-500 text-sm">
                        +{photos.length - 4}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-gray-200 flex justify-between">
          {step > 1 ? (
            <button
              aria-label="Icon button" onClick={() => setStep(step - 1)}
              className="px-6 py-2 text-gray-600 hover:text-gray-900 transition-colors"
            >
              Back
            </button>
          ) : (
            <div />
          )}

          {step < 3 ? (
            <button
              aria-label="Icon button" onClick={() => setStep(step + 1)}
              disabled={step === 1 && checkedCount < checklist.length}
              className="px-6 py-2 bg-gradient-to-r from-blue-500 to-indigo-600 text-white rounded-lg font-medium hover:from-blue-600 hover:to-indigo-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Continue
            </button>
          ) : (
            <button
              onClick={handleSubmit}
              disabled={isSubmitting}
              className="px-6 py-2 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-lg font-medium hover:from-green-600 hover:to-emerald-700 transition-all disabled:opacity-50 flex items-center gap-2"
             aria-label="Icon button">
              {isSubmitting ? (
                <>
                  <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Submitting...
                </>
              ) : (
                <>
                  <FileText className="w-4 h-4" />
                  Submit Report
                </>
              )}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars */
import { useState } from 'react';
import {
  Users,
  Trash2,
  Calendar,
  Clock,
  Package,
  DollarSign,
  UserPlus,
  CheckCircle2,
  ChevronRight,
  Share2,
  XCircle,
  Building2,
  Tag,
  Loader2,
} from 'lucide-react';

interface GroupBookingProps {
  equipmentId: string;
  equipmentTitle: string;
  dailyRate: number;
  maxQuantity?: number;
  onComplete?: (booking: GroupBookingData) => void;
  onClose: () => void;
}

interface TeamMember {
  id: string;
  name: string;
  email: string;
  phone?: string;
  role: 'organizer' | 'member';
  confirmed: boolean;
}

interface GroupBookingData {
  id: string;
  equipmentId: string;
  teamName: string;
  members: TeamMember[];
  startDate: Date;
  endDate: Date;
  quantity: number;
  totalDays: number;
  subtotal: number;
  groupDiscount: number;
  totalAmount: number;
  notes: string;
}

export default function GroupBooking({
  equipmentId,
  equipmentTitle,
  dailyRate,
  maxQuantity = 10,
  onComplete,
  onClose,
}: GroupBookingProps) {
  const [step, setStep] = useState<'team' | 'schedule' | 'review'>('team');
  const [teamName, setTeamName] = useState('');
  const [members, setMembers] = useState<TeamMember[]>([
    {
      id: '1',
      name: 'You (Organizer)',
      email: 'organizer@example.com',
      role: 'organizer',
      confirmed: true,
    },
  ]);
  const [newMember, setNewMember] = useState({ name: '', email: '', phone: '' });
  const [showAddMember, setShowAddMember] = useState(false);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [notes, setNotes] = useState('');
  const [_shareLink, setShareLink] = useState(''); // Reserved for share feature
  const [submitting, setSubmitting] = useState(false);

  const addMember = () => {
    if (!newMember.name || !newMember.email) {
      alert('Please enter name and email');
      return;
    }

    const member: TeamMember = {
      id: Date.now().toString(),
      name: newMember.name,
      email: newMember.email,
      phone: newMember.phone,
      role: 'member',
      confirmed: false,
    };

    setMembers([...members, member]);
    setNewMember({ name: '', email: '', phone: '' });
    setShowAddMember(false);
  };

  const removeMember = (id: string) => {
    if (id === '1') return; // Can't remove organizer
    setMembers(members.filter(m => m.id !== id));
  };

  const calculatePricing = () => {
    if (!startDate || !endDate) return null;

    const start = new Date(startDate);
    const end = new Date(endDate);
    const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;

    if (days <= 0) return null;

    const subtotal = dailyRate * quantity * days;
    
    // Group discounts
    let discountPercent = 0;
    if (members.length >= 3) discountPercent = 5;
    if (members.length >= 5) discountPercent = 10;
    if (members.length >= 10) discountPercent = 15;
    if (days >= 7) discountPercent += 5;

    const discount = subtotal * (discountPercent / 100);
    const total = subtotal - discount;

    return {
      days,
      subtotal,
      discountPercent,
      discount,
      total,
    };
  };

  const pricing = calculatePricing();

  const generateShareLink = () => {
    const link = `https://islakayd.com/group/${equipmentId}/${Date.now().toString(36)}`;
    setShareLink(link);
    navigator.clipboard.writeText(link);
    alert('Invite link copied to clipboard!');
  };

  const handleSubmit = async () => {
    if (!pricing) return;

    setSubmitting(true);

    // Simulate booking creation
    await new Promise(resolve => setTimeout(resolve, 2000));

    const bookingData: GroupBookingData = {
      id: Date.now().toString(),
      equipmentId,
      teamName,
      members,
      startDate: new Date(startDate),
      endDate: new Date(endDate),
      quantity,
      totalDays: pricing.days,
      subtotal: pricing.subtotal,
      groupDiscount: pricing.discount,
      totalAmount: pricing.total,
      notes,
    };

    if (onComplete) {
      onComplete(bookingData);
    }

    setSubmitting(false);
    onClose();
  };

  const canProceedToSchedule = teamName.trim() !== '' && members.length >= 1;
  const canProceedToReview = startDate && endDate && pricing && pricing.days > 0;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm overflow-y-auto">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl my-8">
        {/* Header */}
        <div className="p-6 bg-gradient-to-r from-orange-500 to-amber-500 rounded-t-3xl text-white">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
                <Users className="w-6 h-6" />
              </div>
              <div>
                <h2 className="text-xl font-bold">Group Booking</h2>
                <p className="text-sm text-white/80">Book for your team</p>
              </div>
            </div>
            <button
              onClick={onClose}
              className="p-2 hover:bg-white/20 rounded-full transition-colors"
            >
              <XCircle className="w-6 h-6" />
            </button>
          </div>

          {/* Steps */}
          <div className="flex items-center gap-2">
            {(['team', 'schedule', 'review'] as const).map((s, index) => (
              <div key={s} className="flex items-center gap-2 flex-1">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                  step === s
                    ? 'bg-white text-orange-500'
                    : index < ['team', 'schedule', 'review'].indexOf(step)
                    ? 'bg-white/30 text-white'
                    : 'bg-white/10 text-white/50'
                }`}>
                  {index + 1}
                </div>
                <span className={`text-sm hidden sm:block ${
                  step === s ? 'text-white font-medium' : 'text-white/70'
                }`}>
                  {s.charAt(0).toUpperCase() + s.slice(1)}
                </span>
                {index < 2 && (
                  <ChevronRight className="w-4 h-4 text-white/30 ml-auto" />
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Content */}
        <div className="p-6">
          {step === 'team' && (
            <>
              {/* Team Name */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Team / Organization Name
                </label>
                <div className="relative">
                  <Building2 className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                  <input
                    type="text"
                    value={teamName}
                    onChange={(e) => setTeamName(e.target.value)}
                    placeholder="Enter team or company name"
                    className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500"
                  />
                </div>
              </div>

              {/* Team Members */}
              <div className="mb-6">
                <div className="flex items-center justify-between mb-3">
                  <label className="text-sm font-medium text-gray-700">
                    Team Members ({members.length})
                  </label>
                  {members.length >= 3 && (
                    <span className="text-sm text-green-600 flex items-center gap-1">
                      <Tag className="w-4 h-4" />
                      Group discount applied!
                    </span>
                  )}
                </div>

                <div className="space-y-2 mb-4">
                  {members.map((member) => (
                    <div
                      key={member.id}
                      className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl"
                    >
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                        member.role === 'organizer'
                          ? 'bg-orange-100 text-orange-600'
                          : 'bg-gray-200 text-gray-600'
                      }`}>
                        {member.name.charAt(0).toUpperCase()}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="font-medium text-gray-900 truncate">{member.name}</p>
                          {member.role === 'organizer' && (
                            <span className="px-2 py-0.5 bg-orange-100 text-orange-600 text-xs rounded-full">
                              Organizer
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-gray-500 truncate">{member.email}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        {member.confirmed ? (
                          <CheckCircle2 className="w-5 h-5 text-green-500" />
                        ) : (
                          <Clock className="w-5 h-5 text-amber-500" />
                        )}
                        {member.role !== 'organizer' && (
                          <button
                            aria-label="Icon button" onClick={() => removeMember(member.id)}
                            className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>

                {showAddMember ? (
                  <div className="bg-gray-50 rounded-xl p-4">
                    <h4 className="font-medium text-gray-900 mb-3">Add Team Member</h4>
                    <div className="grid grid-cols-2 gap-3 mb-3">
                      <input
                        type="text"
                        value={newMember.name}
                        onChange={(e) => setNewMember({ ...newMember, name: e.target.value })}
                        placeholder="Name"
                        className="px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500"
                      />
                      <input
                        type="email"
                        value={newMember.email}
                        onChange={(e) => setNewMember({ ...newMember, email: e.target.value })}
                        placeholder="Email"
                        className="px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500"
                      />
                    </div>
                    <input
                      type="tel"
                      value={newMember.phone}
                      onChange={(e) => setNewMember({ ...newMember, phone: e.target.value })}
                      placeholder="Phone (optional)"
                      className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500 mb-3"
                    />
                    <div className="flex gap-2">
                      <button
                        aria-label="Icon button" onClick={() => setShowAddMember(false)}
                        className="flex-1 py-2.5 border border-gray-300 text-gray-700 rounded-xl hover:bg-gray-100"
                      >
                        Cancel
                      </button>
                      <button
                        onClick={addMember}
                        className="flex-1 py-2.5 bg-orange-500 text-white rounded-xl hover:bg-orange-600"
                       aria-label="Icon button">
                        Add Member
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="flex gap-3">
                    <button
                      aria-label="Icon button" onClick={() => setShowAddMember(true)}
                      className="flex-1 py-3 border-2 border-dashed border-gray-200 text-gray-500 rounded-xl hover:border-orange-300 hover:text-orange-500 flex items-center justify-center gap-2"
                    >
                      <UserPlus className="w-5 h-5" />
                      Add Member
                    </button>
                    <button
                      onClick={generateShareLink}
                      className="flex-1 py-3 border-2 border-dashed border-gray-200 text-gray-500 rounded-xl hover:border-orange-300 hover:text-orange-500 flex items-center justify-center gap-2"
                     aria-label="Icon button">
                      <Share2 className="w-5 h-5" />
                      Share Invite Link
                    </button>
                  </div>
                )}
              </div>

              {/* Group Discount Info */}
              <div className="bg-amber-50 rounded-xl p-4 mb-6">
                <div className="flex items-start gap-3">
                  <Tag className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="font-medium text-amber-800">Group Discounts</p>
                    <ul className="text-sm text-amber-700 mt-1 space-y-1">
                      <li>• 3+ members: 5% off</li>
                      <li>• 5+ members: 10% off</li>
                      <li>• 10+ members: 15% off</li>
                      <li>• 7+ days: Additional 5% off</li>
                    </ul>
                  </div>
                </div>
              </div>

              <button
                aria-label="Icon button" onClick={() => setStep('schedule')}
                disabled={!canProceedToSchedule}
                className="w-full py-4 bg-gradient-to-r from-orange-500 to-amber-500 text-white font-semibold rounded-xl disabled:opacity-50 flex items-center justify-center gap-2"
              >
                Continue to Schedule
                <ChevronRight className="w-5 h-5" />
              </button>
            </>
          )}

          {step === 'schedule' && (
            <>
              {/* Equipment Info */}
              <div className="bg-gray-50 rounded-xl p-4 mb-6">
                <div className="flex items-center gap-3">
                  <Package className="w-5 h-5 text-gray-400" />
                  <div>
                    <p className="font-medium text-gray-900">{equipmentTitle}</p>
                    <p className="text-sm text-gray-500">${dailyRate}/day per unit</p>
                  </div>
                </div>
              </div>

              {/* Date Selection */}
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Start Date
                  </label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                    <input
                      type="date"
                      value={startDate}
                      onChange={(e) => setStartDate(e.target.value)}
                      min={new Date().toISOString().split('T')[0]}
                      className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    End Date
                  </label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                    <input
                      type="date"
                      value={endDate}
                      onChange={(e) => setEndDate(e.target.value)}
                      min={startDate || new Date().toISOString().split('T')[0]}
                      className="w-full pl-10 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500"
                    />
                  </div>
                </div>
              </div>

              {/* Quantity */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Number of Units
                </label>
                <div className="flex items-center gap-4">
                  <button
                    aria-label="Icon button"> setQuantity(Math.max(1, quantity - 1))}
                    className="w-12 h-12 rounded-xl border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-50"
                  >
                    -
                  </button>
                  <span className="text-2xl font-bold text-gray-900 w-16 text-center">
                    {quantity}
                  </span>
                  <button
                    aria-label="Icon button"> setQuantity(Math.min(maxQuantity, quantity + 1))}
                    className="w-12 h-12 rounded-xl border border-gray-200 flex items-center justify-center text-gray-600 hover:bg-gray-50"
                  >
                    +
                  </button>
                  <span className="text-sm text-gray-500">Max: {maxQuantity}</span>
                </div>
              </div>

              {/* Notes */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Special Requests (Optional)
                </label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Any special requirements for your group..."
                  rows={3}
                  className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:border-orange-500 resize-none"
                />
              </div>

              {/* Pricing Preview */}
              {pricing && (
                <div className="bg-gray-50 rounded-xl p-4 mb-6">
                  <h4 className="font-medium text-gray-900 mb-3">Pricing Summary</h4>
                  <div className="space-y-2 text-sm">
                    <div className="flex justify-between">
                      <span className="text-gray-600">
                        ${dailyRate} × {quantity} unit{quantity > 1 ? 's' : ''} × {pricing.days} day{pricing.days > 1 ? 's' : ''}
                      </span>
                      <span className="text-gray-900">${pricing.subtotal.toFixed(2)}</span>
                    </div>
                    {pricing.discountPercent > 0 && (
                      <div className="flex justify-between text-green-600">
                        <span>Group discount ({pricing.discountPercent}%)</span>
                        <span>-${pricing.discount.toFixed(2)}</span>
                      </div>
                    )}
                    <div className="flex justify-between pt-2 border-t border-gray-200 text-lg font-semibold">
                      <span className="text-gray-900">Total</span>
                      <span className="text-orange-600">${pricing.total.toFixed(2)}</span>
                    </div>
                    <p className="text-xs text-gray-500">
                      Split between {members.length} member{members.length > 1 ? 's' : ''}: ~${(pricing.total / members.length).toFixed(2)} each
                    </p>
                  </div>
                </div>
              )}

              <div className="flex gap-3">
                <button
                  aria-label="Icon button" onClick={() => setStep('team')}
                  className="flex-1 py-4 border border-gray-300 text-gray-700 font-medium rounded-xl hover:bg-gray-50"
                >
                  Back
                </button>
                <button
                  aria-label="Icon button" onClick={() => setStep('review')}
                  disabled={!canProceedToReview}
                  className="flex-1 py-4 bg-gradient-to-r from-orange-500 to-amber-500 text-white font-semibold rounded-xl disabled:opacity-50 flex items-center justify-center gap-2"
                >
                  Review Booking
                  <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            </>
          )}

          {step === 'review' && pricing && (
            <>
              {/* Booking Summary */}
              <div className="space-y-4 mb-6">
                <div className="bg-gray-50 rounded-xl p-4">
                  <h4 className="font-medium text-gray-900 mb-3 flex items-center gap-2">
                    <Building2 className="w-5 h-5 text-gray-400" />
                    Team Details
                  </h4>
                  <p className="text-gray-700">{teamName}</p>
                  <p className="text-sm text-gray-500">{members.length} team member{members.length > 1 ? 's' : ''}</p>
                </div>

                <div className="bg-gray-50 rounded-xl p-4">
                  <h4 className="font-medium text-gray-900 mb-3 flex items-center gap-2">
                    <Package className="w-5 h-5 text-gray-400" />
                    Equipment
                  </h4>
                  <p className="text-gray-700">{equipmentTitle}</p>
                  <p className="text-sm text-gray-500">{quantity} unit{quantity > 1 ? 's' : ''}</p>
                </div>

                <div className="bg-gray-50 rounded-xl p-4">
                  <h4 className="font-medium text-gray-900 mb-3 flex items-center gap-2">
                    <Calendar className="w-5 h-5 text-gray-400" />
                    Schedule
                  </h4>
                  <p className="text-gray-700">
                    {new Date(startDate).toLocaleDateString()} - {new Date(endDate).toLocaleDateString()}
                  </p>
                  <p className="text-sm text-gray-500">{pricing.days} day{pricing.days > 1 ? 's' : ''}</p>
                </div>

                <div className="bg-orange-50 rounded-xl p-4">
                  <h4 className="font-medium text-orange-900 mb-3 flex items-center gap-2">
                    <DollarSign className="w-5 h-5 text-orange-500" />
                    Payment Summary
                  </h4>
                  <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-orange-700">Subtotal</span>
                      <span className="text-orange-900">${pricing.subtotal.toFixed(2)}</span>
                    </div>
                    {pricing.discountPercent > 0 && (
                      <div className="flex justify-between text-sm text-green-600">
                        <span>Group Discount ({pricing.discountPercent}%)</span>
                        <span>-${pricing.discount.toFixed(2)}</span>
                      </div>
                    )}
                    <div className="flex justify-between pt-2 border-t border-orange-200 font-semibold">
                      <span className="text-orange-900">Total</span>
                      <span className="text-orange-600 text-lg">${pricing.total.toFixed(2)}</span>
                    </div>
                  </div>
                </div>
              </div>

              {notes && (
                <div className="bg-gray-50 rounded-xl p-4 mb-6">
                  <h4 className="font-medium text-gray-900 mb-2">Special Requests</h4>
                  <p className="text-gray-600 text-sm">{notes}</p>
                </div>
              )}

              <div className="flex gap-3">
                <button
                  aria-label="Icon button" onClick={() => setStep('schedule')}
                  className="flex-1 py-4 border border-gray-300 text-gray-700 font-medium rounded-xl hover:bg-gray-50"
                >
                  Back
                </button>
                <button
                  onClick={handleSubmit}
                  disabled={submitting}
                  className="flex-1 py-4 bg-gradient-to-r from-orange-500 to-amber-500 text-white font-semibold rounded-xl disabled:opacity-50 flex items-center justify-center gap-2"
                 aria-label="Icon button">
                  {submitting ? (
                    <>
                      <Loader2 className="w-5 h-5 animate-spin" />
                      Processing...
                    </>
                  ) : (
                    <>
                      <CheckCircle2 className="w-5 h-5" />
                      Confirm Group Booking
                    </>
                  )}
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import {
  Users,
  Plus,
  Trash2,
  Mail,
  User,
  Calendar,
  DollarSign,
  Split,
  Check,
  AlertCircle,
  ChevronDown,
  ChevronUp,
  Link,
  MessageCircle,
  Sparkles,
  CreditCard,
} from 'lucide-react';

interface GroupMember {
  id: string;
  name: string;
  email: string;
  phone?: string;
  role: 'organizer' | 'member';
  status: 'pending' | 'accepted' | 'declined';
  paymentStatus: 'pending' | 'paid' | 'partial';
  shareAmount: number;
  paidAmount: number;
  invitedAt: Date;
  respondedAt?: Date;
}

interface Equipment {
  id: string;
  name: string;
  image: string;
  dailyRate: number;
}

interface GroupBookingDetails {
  id: string;
  name: string;
  startDate: Date;
  endDate: Date;
  equipment: Equipment[];
  totalCost: number;
  splitMethod: 'equal' | 'custom' | 'by_usage';
  depositRequired: number;
  depositCollected: number;
  members: GroupMember[];
  organizerId: string;
  status: 'planning' | 'inviting' | 'confirmed' | 'active' | 'completed';
  createdAt: Date;
  notes?: string;
}

interface GroupBookingCoordinatorProps {
  bookingId?: string;
  onInviteMember?: (email: string) => void;
  onRemoveMember?: (memberId: string) => void;
  className?: string;
}

// Demo data
const demoBooking: GroupBookingDetails = {
  id: 'GB-001',
  name: 'Highway 101 Project Team',
  startDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000),
  endDate: new Date(Date.now() + 21 * 24 * 60 * 60 * 1000),
  equipment: [
    {
      id: 'E1',
      name: 'CAT 320 Excavator',
      image: 'https://images.unsplash.com/photo-1580901368919-7738efb0f87e?w=100',
      dailyRate: 450,
    },
    {
      id: 'E2',
      name: 'Komatsu D65 Bulldozer',
      image: 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=100',
      dailyRate: 550,
    },
  ],
  totalCost: 7000,
  splitMethod: 'equal',
  depositRequired: 3500,
  depositCollected: 1750,
  members: [
    {
      id: 'M1',
      name: 'John Smith',
      email: 'john@example.com',
      phone: '+1 555-0123',
      role: 'organizer',
      status: 'accepted',
      paymentStatus: 'paid',
      shareAmount: 1750,
      paidAmount: 1750,
      invitedAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
      respondedAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
    },
    {
      id: 'M2',
      name: 'Sarah Johnson',
      email: 'sarah@example.com',
      phone: '+1 555-0456',
      role: 'member',
      status: 'accepted',
      paymentStatus: 'pending',
      shareAmount: 1750,
      paidAmount: 0,
      invitedAt: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000),
      respondedAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000),
    },
    {
      id: 'M3',
      name: 'Mike Wilson',
      email: 'mike@example.com',
      role: 'member',
      status: 'pending',
      paymentStatus: 'pending',
      shareAmount: 1750,
      paidAmount: 0,
      invitedAt: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
    },
    {
      id: 'M4',
      name: 'Emily Brown',
      email: 'emily@example.com',
      role: 'member',
      status: 'accepted',
      paymentStatus: 'partial',
      shareAmount: 1750,
      paidAmount: 875,
      invitedAt: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000),
      respondedAt: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
    },
  ],
  organizerId: 'M1',
  status: 'inviting',
  createdAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
  notes: 'Coordination for the highway expansion project. Need equipment for one week.',
};

export default function GroupBookingCoordinator({
  bookingId: _bookingId,
  onInviteMember,
  onRemoveMember,
  className = '',
}: GroupBookingCoordinatorProps) {
  void _bookingId;
  const [booking, setBooking] = useState<GroupBookingDetails>(demoBooking);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);
  const [newMemberEmail, setNewMemberEmail] = useState('');
  const [newMemberName, setNewMemberName] = useState('');
  const [expandedSection, setExpandedSection] = useState<string>('members');
  const [copySuccess, setCopySuccess] = useState(false);

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  };

  const formatDate = (date: Date) => {
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
    });
  };

  const totalCollected = booking.members.reduce((sum, m) => sum + m.paidAmount, 0);
  const acceptedMembers = booking.members.filter(m => m.status === 'accepted').length;
  const pendingMembers = booking.members.filter(m => m.status === 'pending').length;

  const handleInvite = () => {
    if (newMemberEmail && newMemberName) {
      const newMember: GroupMember = {
        id: `M${booking.members.length + 1}`,
        name: newMemberName,
        email: newMemberEmail,
        role: 'member',
        status: 'pending',
        paymentStatus: 'pending',
        shareAmount: booking.totalCost / (booking.members.length + 1),
        paidAmount: 0,
        invitedAt: new Date(),
      };

      setBooking(prev => ({
        ...prev,
        members: [...prev.members, newMember],
      }));

      // Recalculate shares for equal split
      if (booking.splitMethod === 'equal') {
        const newShareAmount = booking.totalCost / (booking.members.length + 1);
        setBooking(prev => ({
          ...prev,
          members: prev.members.map(m => ({ ...m, shareAmount: newShareAmount })),
        }));
      }

      onInviteMember?.(newMemberEmail);
      setNewMemberEmail('');
      setNewMemberName('');
      setShowInviteModal(false);
    }
  };

  const removeMember = (memberId: string) => {
    if (booking.members.find(m => m.id === memberId)?.role === 'organizer') return;

    setBooking(prev => ({
      ...prev,
      members: prev.members.filter(m => m.id !== memberId),
    }));
    onRemoveMember?.(memberId);
  };

  const copyInviteLink = () => {
    navigator.clipboard.writeText(`${window.location.origin}/join/${booking.id}`);
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  const getStatusBadge = (status: GroupMember['status']) => {
    const badges = {
      pending: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300',
      accepted: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300',
      declined: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300',
    };
    return badges[status];
  };

  const getPaymentBadge = (status: GroupMember['paymentStatus']) => {
    const badges = {
      pending: 'bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-400',
      partial: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300',
      paid: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300',
    };
    return badges[status];
  };

  return (
    <div className={`bg-white dark:bg-gray-800 rounded-2xl shadow-xl overflow-hidden ${className}`}>
      {/* Header */}
      <div className="p-6 border-b dark:border-gray-700">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900/30 rounded-xl flex items-center justify-center">
              <Users className="w-6 h-6 text-purple-600" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                {booking.name}
              </h2>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Group Booking #{booking.id}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <button
              onClick={copyInviteLink}
              className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg relative"
             aria-label="Icon button">
              {copySuccess ? (
                <Check className="w-5 h-5 text-green-500" />
              ) : (
                <Link className="w-5 h-5" />
              )}
            </button>
            <button
              aria-label="Icon button" onClick={() => setShowInviteModal(true)}
              className="px-4 py-2 bg-purple-600 text-white rounded-lg font-medium hover:bg-purple-700 flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Invite
            </button>
          </div>
        </div>

        {/* Summary Stats */}
        <div className="grid grid-cols-4 gap-4">
          <div className="p-3 bg-gray-50 dark:bg-gray-700/50 rounded-xl text-center">
            <p className="text-2xl font-bold text-gray-900 dark:text-white">
              {booking.members.length}
            </p>
            <p className="text-xs text-gray-500 dark:text-gray-400">Members</p>
          </div>
          <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-xl text-center">
            <p className="text-2xl font-bold text-green-600">{acceptedMembers}</p>
            <p className="text-xs text-gray-500 dark:text-gray-400">Confirmed</p>
          </div>
          <div className="p-3 bg-amber-50 dark:bg-amber-900/20 rounded-xl text-center">
            <p className="text-2xl font-bold text-amber-600">{pendingMembers}</p>
            <p className="text-xs text-gray-500 dark:text-gray-400">Pending</p>
          </div>
          <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-center">
            <p className="text-2xl font-bold text-blue-600">
              {Math.round((totalCollected / booking.totalCost) * 100)}%
            </p>
            <p className="text-xs text-gray-500 dark:text-gray-400">Collected</p>
          </div>
        </div>
      </div>

      {/* Booking Details */}
      <div className="p-4 border-b dark:border-gray-700 bg-gray-50 dark:bg-gray-700/30">
        <div className="flex flex-wrap gap-4 text-sm">
          <div className="flex items-center gap-2">
            <Calendar className="w-4 h-4 text-gray-400" />
            <span className="text-gray-600 dark:text-gray-300">
              {formatDate(booking.startDate)} - {formatDate(booking.endDate)}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <DollarSign className="w-4 h-4 text-gray-400" />
            <span className="text-gray-600 dark:text-gray-300">
              Total: {formatCurrency(booking.totalCost)}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <Split className="w-4 h-4 text-gray-400" />
            <span className="text-gray-600 dark:text-gray-300 capitalize">
              {booking.splitMethod.replace('_', ' ')} Split
            </span>
          </div>
        </div>
      </div>

      {/* Equipment List */}
      <div className="p-4 border-b dark:border-gray-700">
        <div className="flex items-center gap-2 mb-3">
          <Sparkles className="w-4 h-4 text-gray-400" />
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
            Equipment ({booking.equipment.length})
          </span>
        </div>
        <div className="flex gap-2 overflow-x-auto pb-2">
          {booking.equipment.map(eq => (
            <div
              key={eq.id}
              className="flex items-center gap-3 p-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg min-w-[200px]"
            >
              <img
                src={eq.image}
                alt={eq.name}
                className="w-12 h-12 rounded-lg object-cover"
              />
              <div>
                <p className="font-medium text-gray-900 dark:text-white text-sm">
                  {eq.name}
                </p>
                <p className="text-xs text-gray-500 dark:text-gray-400">
                  {formatCurrency(eq.dailyRate)}/day
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Payment Progress */}
      <div className="p-4 border-b dark:border-gray-700">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm text-gray-600 dark:text-gray-400">
            Payment Collection
          </span>
          <span className="text-sm font-medium text-gray-900 dark:text-white">
            {formatCurrency(totalCollected)} / {formatCurrency(booking.totalCost)}
          </span>
        </div>
        <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
          <div
            className="h-full bg-gradient-to-r from-green-500 to-emerald-500 transition-all duration-500"
            style={{ width: `${(totalCollected / booking.totalCost) * 100}%` }}
          />
        </div>
        <div className="flex justify-between mt-2 text-xs text-gray-500 dark:text-gray-400">
          <span>Deposit: {formatCurrency(booking.depositCollected)} / {formatCurrency(booking.depositRequired)}</span>
          <span>{formatCurrency(booking.totalCost - totalCollected)} remaining</span>
        </div>
      </div>

      {/* Members List */}
      <div className="p-4">
        <div
          className="flex items-center justify-between cursor-pointer mb-4"
          onClick={() => setExpandedSection(expandedSection === 'members' ? '' : 'members')}
        >
          <h3 className="font-semibold text-gray-900 dark:text-white flex items-center gap-2">
            <User className="w-5 h-5" />
            Group Members
          </h3>
          {expandedSection === 'members' ? (
            <ChevronUp className="w-5 h-5 text-gray-400" />
          ) : (
            <ChevronDown className="w-5 h-5 text-gray-400" />
          )}
        </div>

        {expandedSection === 'members' && (
          <div className="space-y-3">
            {booking.members.map(member => (
              <div
                key={member.id}
                className={`p-4 border dark:border-gray-700 rounded-xl ${
                  member.role === 'organizer' ? 'bg-purple-50 dark:bg-purple-900/10 border-purple-200 dark:border-purple-900/30' : ''
                }`}
              >
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-gray-200 dark:bg-gray-700 rounded-full flex items-center justify-center">
                      <User className="w-5 h-5 text-gray-500" />
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <span className="font-medium text-gray-900 dark:text-white">
                          {member.name}
                        </span>
                        {member.role === 'organizer' && (
                          <span className="text-xs px-2 py-0.5 bg-purple-100 dark:bg-purple-900/30 text-purple-600 rounded-full">
                            Organizer
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-gray-500 dark:text-gray-400">
                        {member.email}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`text-xs px-2 py-1 rounded-full ${getStatusBadge(member.status)}`}>
                      {member.status}
                    </span>
                    {member.role !== 'organizer' && (
                      <button
                        aria-label="Icon button" onClick={() => removeMember(member.id)}
                        className="p-1 text-gray-400 hover:text-red-500"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                </div>

                <div className="flex items-center justify-between p-3 bg-white dark:bg-gray-800 rounded-lg">
                  <div>
                    <p className="text-xs text-gray-500 dark:text-gray-400">Share Amount</p>
                    <p className="font-semibold text-gray-900 dark:text-white">
                      {formatCurrency(member.shareAmount)}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs text-gray-500 dark:text-gray-400">Paid</p>
                    <p className="font-semibold text-gray-900 dark:text-white">
                      {formatCurrency(member.paidAmount)}
                    </p>
                  </div>
                  <span className={`text-xs px-2 py-1 rounded-full ${getPaymentBadge(member.paymentStatus)}`}>
                    {member.paymentStatus === 'partial'
                      ? `${Math.round((member.paidAmount / member.shareAmount) * 100)}% paid`
                      : member.paymentStatus}
                  </span>
                </div>

                {member.status === 'pending' && (
                  <div className="mt-3 flex gap-2">
                    <button className="flex-1 py-2 text-sm border dark:border-gray-600 text-gray-600 dark:text-gray-400 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center justify-center gap-1" aria-label="Icon button">
                      <Mail className="w-4 h-4" />
                      Resend Invite
                    </button>
                    <button className="flex-1 py-2 text-sm border dark:border-gray-600 text-gray-600 dark:text-gray-400 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center justify-center gap-1" aria-label="Icon button">
                      <MessageCircle className="w-4 h-4" />
                      Send Reminder
                    </button>
                  </div>
                )}

                {member.status === 'accepted' && member.paymentStatus !== 'paid' && (
                  <div className="mt-3">
                    <button
                      className="w-full py-2 text-sm bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center justify-center gap-1"
                     aria-label="Icon button">
                      <CreditCard className="w-4 h-4" />
                      Request Payment
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="p-4 bg-gray-50 dark:bg-gray-700/50 border-t dark:border-gray-700">
        <div className="flex gap-3">
          <button
            aria-label="Icon button" onClick={() => setShowSplitModal(true)}
            className="flex-1 py-3 border dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl font-medium hover:bg-white dark:hover:bg-gray-700 flex items-center justify-center gap-2"
          >
            <Split className="w-5 h-5" />
            Adjust Split
          </button>
          <button
            disabled={pendingMembers  aria-label="Icon button"> 0 || totalCollected < booking.depositRequired}
            className="flex-1 py-3 bg-purple-600 text-white rounded-xl font-medium hover:bg-purple-700 disabled:bg-gray-300 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            <Check className="w-5 h-5" />
            Confirm Booking
          </button>
        </div>
        {(pendingMembers > 0 || totalCollected < booking.depositRequired) && (
          <p className="text-sm text-amber-600 text-center mt-3 flex items-center justify-center gap-1">
            <AlertCircle className="w-4 h-4" />
            {pendingMembers > 0
              ? `Waiting for ${pendingMembers} member${pendingMembers > 1 ? 's' : ''} to respond`
              : 'Deposit not yet collected'}
          </p>
        )}
      </div>

      {/* Invite Modal */}
      {showInviteModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-md w-full">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
              Invite Member
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1">
                  Name
                </label>
                <input
                  type="text"
                  value={newMemberName}
                  onChange={(e) => setNewMemberName(e.target.value)}
                  placeholder="Enter name"
                  className="w-full p-3 border dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 dark:text-white"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-500 dark:text-gray-400 mb-1">
                  Email
                </label>
                <input
                  type="email"
                  value={newMemberEmail}
                  onChange={(e) => setNewMemberEmail(e.target.value)}
                  placeholder="Enter email address"
                  className="w-full p-3 border dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 dark:text-white"
                />
              </div>
            </div>

            <div className="mt-4 p-3 bg-blue-50 dark:bg-blue-900/20 rounded-xl">
              <p className="text-sm text-blue-700 dark:text-blue-300">
                They will receive an email invitation to join this group booking.
              </p>
            </div>

            <div className="flex gap-3 mt-6">
              <button
                aria-label="Icon button" onClick={() => setShowInviteModal(false)}
                className="flex-1 py-3 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl"
              >
                Cancel
              </button>
              <button
                onClick={handleInvite}
                disabled={!newMemberEmail || !newMemberName}
                className="flex-1 py-3 bg-purple-600 text-white rounded-xl font-medium disabled:bg-gray-300"
               aria-label="Icon button">
                Send Invite
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Split Modal */}
      {showSplitModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-md w-full">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
              Adjust Payment Split
            </h3>

            <div className="space-y-3 mb-4">
              {['equal', 'custom', 'by_usage'].map(method => (
                <button
                  key={method}
                  aria-label="Icon button"> setBooking(prev => ({ ...prev, splitMethod: method as GroupBookingDetails['splitMethod'] }))}
                  className={`w-full p-4 border-2 rounded-xl text-left ${
                    booking.splitMethod === method
                      ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20'
                      : 'border-gray-200 dark:border-gray-700'
                  }`}
                >
                  <p className="font-medium text-gray-900 dark:text-white capitalize">
                    {method.replace('_', ' ')} Split
                  </p>
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    {method === 'equal' && 'Divide total equally among all members'}
                    {method === 'custom' && 'Set custom amounts for each member'}
                    {method === 'by_usage' && 'Split based on equipment usage days'}
                  </p>
                </button>
              ))}
            </div>

            {booking.splitMethod === 'custom' && (
              <div className="space-y-2 max-h-40 overflow-y-auto mb-4">
                {booking.members.map(member => (
                  <div key={member.id} className="flex items-center justify-between p-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg">
                    <span className="text-sm text-gray-700 dark:text-gray-300">
                      {member.name}
                    </span>
                    <input
                      type="number"
                      value={member.shareAmount}
                      onChange={(e) => {
                        const newAmount = parseFloat(e.target.value) || 0;
                        setBooking(prev => ({
                          ...prev,
                          members: prev.members.map(m =>
                            m.id === member.id ? { ...m, shareAmount: newAmount } : m
                          ),
                        }));
                      }}
                      className="w-24 p-2 border dark:border-gray-600 rounded bg-white dark:bg-gray-700 dark:text-white text-right"
                    />
                  </div>
                ))}
              </div>
            )}

            <div className="flex gap-3">
              <button
                aria-label="Icon button" onClick={() => setShowSplitModal(false)}
                className="flex-1 py-3 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-xl"
              >
                Cancel
              </button>
              <button
                aria-label="Icon button" onClick={() => setShowSplitModal(false)}
                className="flex-1 py-3 bg-purple-600 text-white rounded-xl font-medium"
              >
                Apply Changes
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable react-refresh/only-export-components */
import { useState, useEffect, useRef, useCallback } from 'react';

interface LogoAnimatedProps {
  className?: string;
  showText?: boolean;
  variant?: 'default' | 'light' | 'dark' | 'mono' | 'gradient';
  size?: 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';
  animated?: boolean;
  interactive?: boolean;
  loading?: boolean;
  showTagline?: boolean;
  onLoadComplete?: () => void;
  reducedMotion?: boolean;
  iconOnly?: boolean;
  glowIntensity?: 'none' | 'low' | 'medium' | 'high';
}

type AnimationState = 'idle' | 'intro' | 'hover' | 'loading' | 'pulse';

export default function LogoAnimated({
  className = '',
  showText = true,
  variant = 'default',
  size = 'md',
  animated = true,
  interactive = true,
  loading = false,
  showTagline = false,
  onLoadComplete,
  reducedMotion = false,
  iconOnly = false,
  glowIntensity = 'medium',
}: LogoAnimatedProps) {
  const [animationState, setAnimationState] = useState<AnimationState>('intro');
  const [isHovered, setIsHovered] = useState(false);
  const [isPressed, setIsPressed] = useState(false);
  const [introComplete, setIntroComplete] = useState(!animated);
  const containerRef = useRef<HTMLDivElement>(null);

  // Handle intro animation completion
  useEffect(() => {
    if (!animated || reducedMotion) {
      setIntroComplete(true);
      setAnimationState('idle');
      return;
    }

    const timer = setTimeout(() => {
      setIntroComplete(true);
      setAnimationState('idle');
      onLoadComplete?.();
    }, 1800);

    return () => clearTimeout(timer);
  }, [animated, reducedMotion, onLoadComplete]);

  // Handle loading state
  useEffect(() => {
    if (loading) {
      setAnimationState('loading');
    } else if (introComplete) {
      setAnimationState(isHovered ? 'hover' : 'idle');
    }
  }, [loading, introComplete, isHovered]);

  // Periodic subtle pulse
  useEffect(() => {
    if (!animated || loading || !introComplete || reducedMotion) return;

    const interval = setInterval(() => {
      if (!isHovered) {
        setAnimationState('pulse');
        setTimeout(() => setAnimationState('idle'), 800);
      }
    }, 10000);

    return () => clearInterval(interval);
  }, [animated, loading, introComplete, isHovered, reducedMotion]);

  const handleMouseEnter = useCallback(() => {
    if (!interactive) return;
    setIsHovered(true);
    if (introComplete && !loading) setAnimationState('hover');
  }, [interactive, introComplete, loading]);

  const handleMouseLeave = useCallback(() => {
    if (!interactive) return;
    setIsHovered(false);
    setIsPressed(false);
    if (introComplete && !loading) setAnimationState('idle');
  }, [interactive, introComplete, loading]);

  const sizes = {
    xs: { icon: 24, text: 'text-sm', tagline: 'text-[7px]', gap: 'gap-1.5', stroke: 2.2 },
    sm: { icon: 32, text: 'text-lg', tagline: 'text-[8px]', gap: 'gap-2', stroke: 2.4 },
    md: { icon: 40, text: 'text-xl', tagline: 'text-[9px]', gap: 'gap-2.5', stroke: 2.5 },
    lg: { icon: 52, text: 'text-2xl', tagline: 'text-[10px]', gap: 'gap-3', stroke: 2.8 },
    xl: { icon: 64, text: 'text-3xl', tagline: 'text-xs', gap: 'gap-3.5', stroke: 3 },
    '2xl': { icon: 80, text: 'text-4xl', tagline: 'text-sm', gap: 'gap-4', stroke: 3.2 },
  };

  const variants = {
    default: {
      primary: '#0d9488',
      secondary: '#14b8a6',
      accent: '#5eead4',
      text: 'text-gray-900',
      highlight: 'text-teal-600',
    },
    light: {
      primary: '#ffffff',
      secondary: '#f8fafc',
      accent: '#e2e8f0',
      text: 'text-white',
      highlight: 'text-white/80',
    },
    dark: {
      primary: '#0f172a',
      secondary: '#1e293b',
      accent: '#334155',
      text: 'text-slate-900',
      highlight: 'text-slate-700',
    },
    mono: {
      primary: '#18181b',
      secondary: '#27272a',
      accent: '#3f3f46',
      text: 'text-zinc-900',
      highlight: 'text-zinc-700',
    },
    gradient: {
      primary: '#0d9488',
      secondary: '#059669',
      accent: '#34d399',
      text: 'text-gray-900',
      highlight: 'text-emerald-600',
    },
  };

  const glowSettings = {
    none: 0,
    low: 4,
    medium: 8,
    high: 14,
  };

  const currentSize = sizes[size];
  const currentVariant = variants[variant];
  const glowBlur = glowSettings[glowIntensity];
  // Use crypto for secure random UID
  function getRandomUID() {
    if (typeof window !== 'undefined' && window.crypto && window.crypto.getRandomValues) {
      const arr = new Uint32Array(1);
      window.crypto.getRandomValues(arr);
      return 'ik-' + arr[0].toString(36).slice(0, 6);
    }
    return 'ik-' + Math.random().toString(36).slice(2, 8);
  }
  const uid = getRandomUID();

  const iconSize = currentSize.icon;
  const strokeW = currentSize.stroke;
  const showIntro = animationState === 'intro' && animated && !reducedMotion;

  return (
    <div
      ref={containerRef}
      className={`flex items-center ${currentSize.gap} ${className} select-none cursor-pointer`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onMouseDown={() => interactive && setIsPressed(true)}
      onMouseUp={() => interactive && setIsPressed(false)}
      role="img"
      aria-label="Islakayd - Equipment Rental"
    >
      {/* Icon Container */}
      <div
        className="relative flex-shrink-0"
        style={{
          width: iconSize,
          height: iconSize,
          transform: isPressed ? 'scale(0.94)' : isHovered ? 'scale(1.04)' : 'scale(1)',
          transition: 'transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1)',
        }}
      >
        {/* Glow layer */}
        {glowIntensity !== 'none' && (
          <div
            className="absolute inset-0 rounded-full transition-all duration-500"
            style={{
              background: `radial-gradient(circle, ${currentVariant.primary}40 0%, transparent 70%)`,
              filter: `blur(${glowBlur}px)`,
              opacity: isHovered ? 0.9 : 0.5,
              transform: animationState === 'pulse' ? 'scale(1.15)' : 'scale(1)',
            }}
          />
        )}

        <svg
          viewBox="0 0 48 48"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          className="w-full h-full relative"
          style={{ overflow: 'visible' }}
        >
          <defs>
            {/* Primary Gradient */}
            <linearGradient id={`${uid}-main`} x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor={currentVariant.primary}>
                {animated && !reducedMotion && (
                  <animate
                    attributeName="stop-color"
                    values={`${currentVariant.primary};${currentVariant.secondary};${currentVariant.primary}`}
                    dur="6s"
                    repeatCount="indefinite"
                  />
                )}
              </stop>
              <stop offset="100%" stopColor={currentVariant.secondary}>
                {animated && !reducedMotion && (
                  <animate
                    attributeName="stop-color"
                    values={`${currentVariant.secondary};${currentVariant.accent};${currentVariant.secondary}`}
                    dur="6s"
                    repeatCount="indefinite"
                  />
                )}
              </stop>
            </linearGradient>

            {/* Shimmer Gradient */}
            <linearGradient id={`${uid}-shimmer`} x1="-200%" y1="0%" x2="200%" y2="0%">
              <stop offset="0%" stopColor="white" stopOpacity="0" />
              <stop offset="50%" stopColor="white" stopOpacity="0.3" />
              <stop offset="100%" stopColor="white" stopOpacity="0" />
              {animated && !reducedMotion && (
                <animateTransform
                  attributeName="gradientTransform"
                  type="translate"
                  from="-2 0"
                  to="2 0"
                  dur="3s"
                  repeatCount="indefinite"
                />
              )}
            </linearGradient>

            {/* Soft Shadow */}
            <filter id={`${uid}-shadow`} x="-25%" y="-25%" width="150%" height="150%">
              <feDropShadow dx="0" dy="2" stdDeviation="3" floodColor={currentVariant.primary} floodOpacity="0.3" />
            </filter>
          </defs>

          {/* Background Circle - Clean like Airbnb */}
          <circle
            cx="24"
            cy="24"
            r="23"
            fill={`url(#${uid}-main)`}
            filter={`url(#${uid}-shadow)`}
            style={{
              opacity: showIntro ? 0 : 1,
              transform: showIntro ? 'scale(0)' : animationState === 'pulse' ? 'scale(1.02)' : 'scale(1)',
              transformOrigin: '24px 24px',
              transition: 'transform 0.4s ease-out, opacity 0.4s ease-out',
            }}
          >
            {showIntro && (
              <>
                <animate attributeName="opacity" from="0" to="1" dur="0.5s" fill="freeze" begin="0.1s" />
                <animateTransform
                  attributeName="transform"
                  type="scale"
                  from="0"
                  to="1"
                  dur="0.6s"
                  fill="freeze"
                  begin="0.1s"
                  calcMode="spline"
                  keySplines="0.34, 1.56, 0.64, 1"
                />
              </>
            )}
          </circle>

          {/* Shimmer overlay */}
          <circle
            cx="24"
            cy="24"
            r="23"
            fill={`url(#${uid}-shimmer)`}
            style={{
              opacity: showIntro ? 0 : isHovered ? 0.8 : 0.4,
              transition: 'opacity 0.3s ease',
            }}
          />

          {/* The Symbol - Minimalist "IK" Monogram */}
          <g>
            {/* Left bar (I) */}
            <line
              x1="15"
              y1="14"
              x2="15"
              y2="34"
              stroke="white"
              strokeWidth={strokeW}
              strokeLinecap="round"
              style={{
                strokeDasharray: 20,
                strokeDashoffset: showIntro ? 20 : 0,
                transition: 'stroke-dashoffset 0.5s ease-out 0.4s',
              }}
            />

            {/* Connecting Flow (represents sharing/transfer) */}
            <path
              d="M15 24 Q24 14, 33 24 Q24 34, 15 24"
              stroke="white"
              strokeWidth={strokeW * 0.9}
              strokeLinecap="round"
              strokeLinejoin="round"
              fill="none"
              style={{
                strokeDasharray: 70,
                strokeDashoffset: showIntro ? 70 : 0,
                transition: 'stroke-dashoffset 0.8s ease-out 0.6s',
              }}
            />

            {/* Right bar (K stem) */}
            <line
              x1="33"
              y1="14"
              x2="33"
              y2="34"
              stroke="white"
              strokeWidth={strokeW}
              strokeLinecap="round"
              style={{
                strokeDasharray: 20,
                strokeDashoffset: showIntro ? 20 : 0,
                transition: 'stroke-dashoffset 0.5s ease-out 0.5s',
              }}
            />

            {/* Node dots - represent equipment connection points */}
            {[[15, 14], [15, 34], [33, 14], [33, 34]].map(([cx, cy], i) => (
              <circle
                key={i}
                cx={cx}
                cy={cy}
                r={strokeW * 0.9}
                fill="white"
                style={{
                  opacity: showIntro ? 0 : 1,
                  transform: isHovered ? 'scale(1.25)' : 'scale(1)',
                  transformOrigin: `${cx}px ${cy}px`,
                  transition: `opacity 0.3s ease ${1 + i * 0.08}s, transform 0.25s ease ${i * 0.04}s`,
                }}
              />
            ))}

            {/* Center flow indicator */}
            <circle
              cx="24"
              cy="24"
              r={strokeW * 0.7}
              fill="white"
              style={{
                opacity: showIntro ? 0 : isHovered ? 1 : 0.9,
                transform: isHovered ? 'scale(1.3)' : 'scale(1)',
                transformOrigin: '24px 24px',
                transition: 'all 0.3s ease 1.4s',
              }}
            >
              {animated && !reducedMotion && (
                <animate
                  attributeName="opacity"
                  values="0.9;1;0.9"
                  dur="2s"
                  repeatCount="indefinite"
                />
              )}
            </circle>
          </g>

          {/* Loading State */}
          {loading && (
            <g style={{ transformOrigin: '24px 24px' }} className="animate-spin">
              <circle
                cx="24"
                cy="24"
                r="20"
                fill="none"
                stroke="white"
                strokeWidth="2"
                strokeDasharray="25 75"
                strokeLinecap="round"
                opacity="0.9"
              />
            </g>
          )}

          {/* Hover ring */}
          {isHovered && animated && !reducedMotion && (
            <circle
              cx="24"
              cy="24"
              r="26"
              fill="none"
              stroke={currentVariant.accent}
              strokeWidth="1.5"
              opacity="0.6"
              className="animate-ping"
              style={{ animationDuration: '2s' }}
            />
          )}
        </svg>
      </div>

      {/* Wordmark */}
      {showText && !iconOnly && (
        <div className="flex flex-col overflow-hidden">
          {/* Brand name with staggered reveal */}
          <div className={`font-semibold tracking-tight ${currentSize.text} flex`}>
            {'Islakayd'.split('').map((char, i) => {
              const isHighlight = i >= 4;
              return (
                <span
                  key={i}
                  className={`inline-block transition-all duration-300 ${isHighlight ? currentVariant.highlight : currentVariant.text}`}
                  style={{
                    opacity: showIntro ? 0 : 1,
                    transform: showIntro ? 'translateY(100%)' : isHovered ? 'translateY(-1px)' : 'translateY(0)',
                    transitionDelay: showIntro ? `${0.9 + i * 0.05}s` : `${i * 0.015}s`,
                  }}
                >
                  {char}
                </span>
              );
            })}
          </div>

          {/* Tagline */}
          {showTagline && (
            <span
              className={`tracking-[0.15em] uppercase font-medium ${currentSize.tagline} ${
                variant === 'light' ? 'text-white/50' : 'text-gray-400'
              } transition-all duration-500`}
              style={{
                opacity: showIntro ? 0 : isHovered ? 1 : 0.7,
                transform: showIntro ? 'translateY(8px)' : 'translateY(0)',
                transitionDelay: showIntro ? '1.4s' : '0s',
              }}
            >
              Rent Anything
            </span>
          )}
        </div>
      )}

      {/* Accessibility: Reduced motion support */}
      <style>{`
        @media (prefers-reduced-motion: reduce) {
          *, *::before, *::after {
            animation-duration: 0.01ms !important;
            animation-iteration-count: 1 !important;
            transition-duration: 0.01ms !important;
          }
        }
      `}</style>
    </div>
  );
}

// Named exports for consumers
export const logoVariants = ['default', 'light', 'dark', 'mono', 'gradient'] as const;
export const logoSizes = ['xs', 'sm', 'md', 'lg', 'xl', '2xl'] as const;
export type LogoVariant = typeof logoVariants[number];
export type LogoSize = typeof logoSizes[number];

import { useState, useDeferredValue, useMemo } from 'react';
import {
  Search,
  MapPin,
  SlidersHorizontal,
  Grid,
  List,
  X,
  Star,
  Heart,
  Shield,
  Clock,
  ArrowLeft,
  Map,
} from 'lucide-react';
import type { Equipment, Category } from '../../types';
import EquipmentMap from '../map/EquipmentMap';

interface BrowsePageProps {
  equipment: Equipment[];
  categories: Category[];
  initialQuery?: string;
  initialCategory?: string;
  onEquipmentClick: (equipment: Equipment) => void;
  onFavoriteClick: (equipmentId: string) => void;
  favorites: Set<string>;
  onBack: () => void;
}

export default function BrowsePage({
  equipment,
  categories,
  initialQuery = '',
  initialCategory = '',
  onEquipmentClick,
  onFavoriteClick,
  favorites,
  onBack,
}: BrowsePageProps) {
  const [searchQuery, setSearchQuery] = useState(initialQuery);
  const [selectedCategory, setSelectedCategory] = useState(initialCategory);
  const [location, setLocation] = useState('');
  const [priceRange, setPriceRange] = useState<[number, number]>([0, 1000]);
  const [condition, setCondition] = useState('');
  const [sortBy, setSortBy] = useState('featured');
  const [viewMode, setViewMode] = useState<'grid' | 'list' | 'map'>('grid');
  const [showFilters, setShowFilters] = useState(false);
  const [selectedMapEquipment, setSelectedMapEquipment] = useState<string | undefined>();

  // Use deferred value for search to improve performance during typing
  const deferredSearchQuery = useDeferredValue(searchQuery);

  // Memoize filtered equipment for better performance
  const filteredEquipment = useMemo(() => {
    let filtered = [...equipment];

    if (deferredSearchQuery) {
      const query = deferredSearchQuery.toLowerCase();
      filtered = filtered.filter(
        (item) =>
          item.title.toLowerCase().includes(query) ||
          item.description?.toLowerCase().includes(query) ||
          item.brand?.toLowerCase().includes(query)
      );
    }

    if (selectedCategory) {
      filtered = filtered.filter((item) => {
        const category = categories.find((c) => c.id === item.category_id);
        return category?.slug === selectedCategory || category?.name === selectedCategory;
      });
    }

    if (location) {
      filtered = filtered.filter((item) =>
        item.location?.toLowerCase().includes(location.toLowerCase())
      );
    }

    filtered = filtered.filter(
      (item) => item.daily_rate >= priceRange[0] && item.daily_rate <= priceRange[1]
    );

    if (condition) {
      filtered = filtered.filter((item) => item.condition === condition);
    }

    switch (sortBy) {
      case 'price-low':
        filtered.sort((a, b) => a.daily_rate - b.daily_rate);
        break;
      case 'price-high':
        filtered.sort((a, b) => b.daily_rate - a.daily_rate);
        break;
      case 'rating':
        filtered.sort((a, b) => b.rating - a.rating);
        break;
      case 'newest':
        filtered.sort(
          (a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
        );
        break;
      default:
        filtered.sort((a, b) => (b.is_featured ? 1 : 0) - (a.is_featured ? 1 : 0));
    }

    return filtered;
  }, [deferredSearchQuery, selectedCategory, location, priceRange, condition, sortBy, equipment, categories]);

  const clearFilters = () => {
    setSearchQuery('');
    setSelectedCategory('');
    setLocation('');
    setPriceRange([0, 1000]);
    setCondition('');
    setSortBy('featured');
  };

  const activeFiltersCount = [
    searchQuery,
    selectedCategory,
    location,
    condition,
    priceRange[0] > 0 || priceRange[1] < 1000,
  ].filter(Boolean).length;

  return (
    <div className="min-h-screen bg-gray-50 pt-20">
      <div className="bg-white border-b border-gray-200 sticky top-20 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center gap-4 mb-4">
            <button
              onClick={onBack}
              className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
             aria-label="Icon button">
              <ArrowLeft className="w-5 h-5" />
              <span className="hidden sm:inline">Back</span>
            </button>

            <div className="flex-1 flex items-center gap-3 bg-gray-50 rounded-xl px-4 py-3">
              <Search className="w-5 h-5 text-gray-400" />
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search equipment..."
                className="flex-1 bg-transparent text-gray-900 placeholder-gray-500 focus:outline-none"
              />
              {searchQuery && (
                <button aria-label="Icon button" onClick={() => setSearchQuery('')}>
                  <X className="w-5 h-5 text-gray-400 hover:text-gray-600" />
                </button>
              )}
            </div>

            <div className="hidden md:flex items-center gap-3 bg-gray-50 rounded-xl px-4 py-3">
              <MapPin className="w-5 h-5 text-gray-400" />
              <input
                type="text"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                placeholder="Location"
                className="bg-transparent text-gray-900 placeholder-gray-500 focus:outline-none w-32"
              />
            </div>
          </div>

          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-2 overflow-x-auto pb-2 -mb-2">
              <button
                aria-label="Icon button" onClick={() => setSelectedCategory('')}
                className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                  !selectedCategory
                    ? 'bg-teal-500 text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                All
              </button>
              {categories.slice(0, 6).map((category) => (
                <button
                  key={category.id}
                  aria-label="Icon button" onClick={() => setSelectedCategory(category.slug)}
                  className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                    selectedCategory === category.slug
                      ? 'bg-teal-500 text-white'
                      : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                  }`}
                >
                  {category.name}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-2">
              <button
                aria-label="Icon button" onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl border transition-colors ${
                  showFilters || activeFiltersCount > 0
                    ? 'border-teal-500 bg-teal-50 text-teal-700'
                    : 'border-gray-200 text-gray-600 hover:border-gray-300'
                }`}
              >
                <SlidersHorizontal className="w-4 h-4" />
                <span className="hidden sm:inline">Filters</span>
                {activeFiltersCount > 0 && (
                  <span className="w-5 h-5 rounded-full bg-teal-500 text-white text-xs flex items-center justify-center">
                    {activeFiltersCount}
                  </span>
                )}
              </button>

              <div className="hidden sm:flex items-center gap-1 border border-gray-200 rounded-xl p-1">
                <button
                  aria-label="Icon button" onClick={() => setViewMode('grid')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'grid' ? 'bg-gray-100 text-gray-900' : 'text-gray-400'
                  }`}
                  title="Grid view"
                >
                  <Grid className="w-4 h-4" />
                </button>
                <button
                  aria-label="Icon button" onClick={() => setViewMode('list')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'list' ? 'bg-gray-100 text-gray-900' : 'text-gray-400'
                  }`}
                  title="List view"
                >
                  <List className="w-4 h-4" />
                </button>
                <button
                  aria-label="Icon button" onClick={() => setViewMode('map')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'map' ? 'bg-gray-100 text-gray-900' : 'text-gray-400'
                  }`}
                  title="Map view"
                >
                  <Map className="w-4 h-4" />
                </button>
              </div>

              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="px-4 py-2 rounded-xl border border-gray-200 text-gray-600 bg-white focus:outline-none focus:border-teal-500"
              >
                <option value="featured">Featured</option>
                <option value="price-low">Price: Low to High</option>
                <option value="price-high">Price: High to Low</option>
                <option value="rating">Highest Rated</option>
                <option value="newest">Newest</option>
              </select>
            </div>
          </div>
        </div>

        {showFilters && (
          <div className="border-t border-gray-100 bg-gray-50">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Category
                  </label>
                  <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                  >
                    <option value="">All Categories</option>
                    {categories.map((category) => (
                      <option key={category.id} value={category.slug}>
                        {category.name}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Price Range (per day)
                  </label>
                  <div className="flex items-center gap-2">
                    <input
                      type="number"
                      value={priceRange[0]}
                      onChange={(e) =>
                        setPriceRange([Number(e.target.value), priceRange[1]])
                      }
                      placeholder="Min"
                      className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                    />
                    <span className="text-gray-400">-</span>
                    <input
                      type="number"
                      value={priceRange[1]}
                      onChange={(e) =>
                        setPriceRange([priceRange[0], Number(e.target.value)])
                      }
                      placeholder="Max"
                      className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Condition
                  </label>
                  <select
                    value={condition}
                    onChange={(e) => setCondition(e.target.value)}
                    className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                  >
                    <option value="">Any Condition</option>
                    <option value="new">New</option>
                    <option value="excellent">Excellent</option>
                    <option value="good">Good</option>
                    <option value="fair">Fair</option>
                  </select>
                </div>

                <div className="flex items-end">
                  <button
                    onClick={clearFilters}
                    className="w-full px-4 py-2.5 rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-100 transition-colors"
                   aria-label="Icon button">
                    Clear All Filters
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex items-center justify-between mb-6">
          <p className="text-gray-600">
            <span className="font-semibold text-gray-900">{filteredEquipment.length}</span>{' '}
            results found
            {searchQuery && (
              <span>
                {' '}
                for "<span className="font-medium">{searchQuery}</span>"
              </span>
            )}
          </p>
        </div>

        {filteredEquipment.length === 0 ? (
          <div className="text-center py-16">
            <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <Search className="w-10 h-10 text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No equipment found</h3>
            <p className="text-gray-600 mb-6">
              Try adjusting your filters or search terms
            </p>
            <button
              onClick={clearFilters}
              className="px-6 py-3 bg-teal-500 text-white font-semibold rounded-xl hover:bg-teal-600 transition-colors"
             aria-label="Icon button">
              Clear All Filters
            </button>
          </div>
        ) : viewMode === 'map' ? (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="h-[600px] lg:h-[calc(100vh-280px)] lg:sticky lg:top-40">
              <EquipmentMap
                equipment={filteredEquipment}
                onEquipmentClick={(item) => {
                  setSelectedMapEquipment(item.id);
                  onEquipmentClick(item);
                }}
                selectedId={selectedMapEquipment}
                className="h-full"
              />
            </div>
            <div className="space-y-4 max-h-[calc(100vh-280px)] overflow-y-auto">
