            {renderStatusStep('Renter Signs', status.renterSigned, signing)}
            <ChevronRight className="w-4 h-4 text-white/50" />
            {renderStatusStep('Owner Signs', status.ownerSigned, false)}
            <ChevronRight className="w-4 h-4 text-white/50" />
