            </span>
            <span>•</span>
            <span className="flex items-center gap-1">
              <Lock className="w-3 h-3" />
              End-to-end encrypted
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useCallback } from 'react';
import {
  Camera,
  X,
  Upload,
  AlertTriangle,
  CheckCircle,
  ChevronLeft,
  ChevronRight,
  Trash2,
  MapPin,
  FileText,
  Send,
  Loader2,
  Image as ImageIcon,
  ZoomIn,
} from 'lucide-react';

// Icons available: Camera, ChevronLeft, ChevronRight for future use

interface DamagePhoto {
  id: string;
  url: string;
  file?: File;
  annotation?: string;
  timestamp: Date;
}

interface DamageLocation {
  area: string;
  description: string;
}

interface DamageReportProps {
  equipmentId: string;
  equipmentName: string;
  bookingId?: string;
  onSubmit: (report: DamageReportData) => Promise<void>;
  onClose: () => void;
  className?: string;
}

export interface DamageReportData {
  equipmentId: string;
  bookingId?: string;
  severity: 'minor' | 'moderate' | 'major' | 'critical';
  description: string;
  damageLocations: DamageLocation[];
  photos: DamagePhoto[];
  estimatedCost?: number;
  reportedAt: Date;
  gpsLocation?: { lat: number; lng: number };
}

const severityConfig = {
  minor: {
    label: 'Minor',
    description: 'Cosmetic damage, scratches, small dents',
    color: 'bg-yellow-100 text-yellow-700 border-yellow-200',
    icon: '🟡',
  },
  moderate: {
    label: 'Moderate',
    description: 'Functional issues, medium damage',
    color: 'bg-orange-100 text-orange-700 border-orange-200',
    icon: '🟠',
  },
  major: {
    label: 'Major',
    description: 'Significant damage affecting operation',
    color: 'bg-red-100 text-red-700 border-red-200',
    icon: '🔴',
  },
  critical: {
    label: 'Critical',
    description: 'Equipment non-operational or safety hazard',
    color: 'bg-red-200 text-red-800 border-red-300',
    icon: '⛔',
  },
};

const damageAreas = [
  'Body/Frame',
  'Engine/Motor',
  'Hydraulics',
  'Electrical',
  'Tires/Tracks',
  'Controls/Cabin',
  'Attachments',
  'Safety Features',
  'Lights/Signals',
  'Other',
];

export default function DamageReport({
  equipmentId,
  equipmentName,
  bookingId,
  onSubmit,
  onClose,
  className = '',
}: DamageReportProps) {
  const [step, setStep] = useState(1);
  const [severity, setSeverity] = useState<DamageReportData['severity']>('minor');
  const [description, setDescription] = useState('');
  const [damageLocations, setDamageLocations] = useState<DamageLocation[]>([]);
  const [photos, setPhotos] = useState<DamagePhoto[]>([]);
  const [estimatedCost, setEstimatedCost] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [selectedPhoto, setSelectedPhoto] = useState<DamagePhoto | null>(null);
  const [gpsLocation, setGpsLocation] = useState<{ lat: number; lng: number } | null>(null);
  
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  // Get GPS location
  const getLocation = useCallback(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setGpsLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => console.error('Location error:', error)
      );
    }
  }, []);

  // Handle file upload
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    
    files.forEach((file) => {
      if (file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = () => {
          const newPhoto: DamagePhoto = {
            id: `photo-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            url: reader.result as string,
            file,
            timestamp: new Date(),
          };
          setPhotos((prev) => [...prev, newPhoto]);
        };
        reader.readAsDataURL(file);
      }
    });

    // Reset input
    e.target.value = '';
  };

  // Remove photo
  const removePhoto = (id: string) => {
    setPhotos((prev) => prev.filter((p) => p.id !== id));
  };

  // Add damage location
  const addDamageLocation = (area: string) => {
    if (!damageLocations.find((d) => d.area === area)) {
      setDamageLocations((prev) => [...prev, { area, description: '' }]);
    }
  };

  // Remove damage location
  const removeDamageLocation = (area: string) => {
    setDamageLocations((prev) => prev.filter((d) => d.area !== area));
  };

  // Update damage location description
  const updateLocationDescription = (area: string, description: string) => {
    setDamageLocations((prev) =>
      prev.map((d) => (d.area === area ? { ...d, description } : d))
    );
  };

  // Submit report
  const handleSubmit = async () => {
    setIsSubmitting(true);
    
    try {
      const report: DamageReportData = {
        equipmentId,
        bookingId,
        severity,
        description,
        damageLocations,
        photos,
        estimatedCost: estimatedCost ? parseFloat(estimatedCost) : undefined,
        reportedAt: new Date(),
        gpsLocation: gpsLocation || undefined,
      };

      await onSubmit(report);
      onClose();
    } catch (error) {
      console.error('Failed to submit damage report:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const canProceed = () => {
    switch (step) {
      case 1:
        return severity;
      case 2:
        return photos.length > 0;
      case 3:
        return damageLocations.length > 0;
      case 4:
        return description.length >= 20;
      default:
        return true;
    }
  };

  return (
    <div className={`fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4 ${className}`}>
      <div className="bg-white dark:bg-gray-800 rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="p-4 border-b dark:border-gray-700 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-red-100 dark:bg-red-900/30 rounded-xl flex items-center justify-center">
              <AlertTriangle className="w-5 h-5 text-red-600" />
            </div>
            <div>
              <h2 className="font-bold text-gray-900 dark:text-white">Report Damage</h2>
              <p className="text-sm text-gray-500 dark:text-gray-400">{equipmentName}</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center justify-center"
          >
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        {/* Progress */}
        <div className="px-6 pt-4">
          <div className="flex items-center gap-2">
            {[1, 2, 3, 4, 5].map((s) => (
              <div
                key={s}
                className={`flex-1 h-1.5 rounded-full transition-colors ${
                  s <= step ? 'bg-emerald-500' : 'bg-gray-200 dark:bg-gray-700'
                }`}
              />
            ))}
          </div>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-2">
            Step {step} of 5: {
              step === 1 ? 'Severity' :
              step === 2 ? 'Photos' :
              step === 3 ? 'Damage Location' :
              step === 4 ? 'Description' :
              'Review'
            }
          </p>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Step 1: Severity */}
          {step === 1 && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                How severe is the damage?
              </h3>
              <div className="grid grid-cols-2 gap-3">
                {Object.entries(severityConfig).map(([key, config]) => (
                  <button
                    key={key}
                    aria-label="Icon button" onClick={() => setSeverity(key as DamageReportData['severity'])}
                    className={`p-4 rounded-xl border-2 text-left transition-all ${
                      severity === key
                        ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                        : 'border-gray-200 dark:border-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-2xl">{config.icon}</span>
                      <span className="font-semibold text-gray-900 dark:text-white">{config.label}</span>
                    </div>
                    <p className="text-sm text-gray-500 dark:text-gray-400">{config.description}</p>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Step 2: Photos */}
          {step === 2 && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                Take or upload photos of the damage
              </h3>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Please provide clear photos from multiple angles. This helps with accurate assessment.
              </p>

              {/* Photo Grid */}
              <div className="grid grid-cols-3 gap-3">
                {photos.map((photo) => (
                  <div
                    key={photo.id}
                    className="relative aspect-square rounded-xl overflow-hidden group cursor-pointer"
                    onClick={() => setSelectedPhoto(photo)}
                  >
                    <img
                      src={photo.url}
                      alt="Damage photo"
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                      <button className="w-8 h-8 bg-white/90 rounded-full flex items-center justify-center">
                        <ZoomIn className="w-4 h-4 text-gray-700" />
                      </button>
                      <button
                        onClick={(e) = aria-label="Icon button"> {
                          e.stopPropagation();
                          removePhoto(photo.id);
                        }}
                        className="w-8 h-8 bg-red-500 rounded-full flex items-center justify-center"
                      >
                        <Trash2 className="w-4 h-4 text-white" />
                      </button>
                    </div>
                  </div>
                ))}

                {/* Add Photo Buttons */}
                {photos.length < 9 && (
                  <>
                    <button
                      aria-label="Icon button"> cameraInputRef.current?.click()}
                      className="aspect-square rounded-xl border-2 border-dashed border-gray-300 dark:border-gray-600 flex flex-col items-center justify-center gap-2 hover:border-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-colors"
                    >
                      <Camera className="w-6 h-6 text-gray-400" />
                      <span className="text-xs text-gray-500">Camera</span>
                    </button>
                    <button
                      aria-label="Icon button"> fileInputRef.current?.click()}
                      className="aspect-square rounded-xl border-2 border-dashed border-gray-300 dark:border-gray-600 flex flex-col items-center justify-center gap-2 hover:border-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-colors"
                    >
                      <Upload className="w-6 h-6 text-gray-400" />
                      <span className="text-xs text-gray-500">Upload</span>
                    </button>
                  </>
                )}
              </div>

              {/* Hidden inputs */}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                multiple
                onChange={handleFileChange}
                className="hidden"
              />
              <input
                ref={cameraInputRef}
                type="file"
                accept="image/*"
                capture="environment"
                onChange={handleFileChange}
                className="hidden"
              />

              {photos.length === 0 && (
                <div className="p-4 bg-amber-50 dark:bg-amber-900/20 rounded-xl flex items-start gap-3">
                  <ImageIcon className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="text-sm text-amber-800 dark:text-amber-200">
                      At least one photo is required
                    </p>
                    <p className="text-xs text-amber-600 dark:text-amber-400 mt-1">
                      Clear photos help process your claim faster
                    </p>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Step 3: Damage Location */}
          {step === 3 && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                Where is the damage located?
              </h3>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                Select all affected areas and add specific details.
              </p>

              <div className="flex flex-wrap gap-2">
                {damageAreas.map((area) => {
                  const isSelected = damageLocations.some((d) => d.area === area);
                  return (
                    <button
                      key={area}
                      aria-label="Icon button"> isSelected ? removeDamageLocation(area) : addDamageLocation(area)}
                      className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                        isSelected
                          ? 'bg-emerald-600 text-white'
                          : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
                      }`}
                    >
                      {isSelected && <CheckCircle className="w-4 h-4 inline mr-1" />}
                      {area}
                    </button>
                  );
                })}
              </div>

              {/* Selected Locations Details */}
              {damageLocations.length > 0 && (
                <div className="space-y-3 mt-4">
                  <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                    Add details for each area:
                  </p>
                  {damageLocations.map((location) => (
                    <div key={location.area} className="p-3 bg-gray-50 dark:bg-gray-700/50 rounded-xl">
                      <div className="flex items-center justify-between mb-2">
                        <span className="font-medium text-gray-900 dark:text-white">{location.area}</span>
                        <button
                          aria-label="Icon button" onClick={() => removeDamageLocation(location.area)}
                          className="text-gray-400 hover:text-red-500"
                        >
                          <X className="w-4 h-4" />
                        </button>
                      </div>
                      <textarea
                        value={location.description}
                        onChange={(e) => updateLocationDescription(location.area, e.target.value)}
                        placeholder={`Describe damage to ${location.area}...`}
                        className="w-full p-2 text-sm border rounded-lg resize-none dark:bg-gray-800 dark:border-gray-600"
                        rows={2}
                      />
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Step 4: Description */}
          {step === 4 && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                Describe what happened
              </h3>
              <textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Provide details about how the damage occurred, when you noticed it, and any relevant circumstances..."
                className="w-full p-4 border rounded-xl resize-none dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                rows={6}
              />
              <p className={`text-sm ${description.length >= 20 ? 'text-green-600' : 'text-gray-500'}`}>
                {description.length}/20 minimum characters
              </p>

              {/* Estimated Cost */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Estimated Repair Cost (optional)
                </label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                  <input
                    type="number"
                    value={estimatedCost}
                    onChange={(e) => setEstimatedCost(e.target.value)}
                    placeholder="0.00"
                    className="w-full pl-8 pr-4 py-3 border rounded-xl dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                  />
                </div>
              </div>

              {/* GPS Location */}
              <div className="p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <MapPin className="w-5 h-5 text-gray-400" />
                    <div>
                      <p className="text-sm font-medium text-gray-900 dark:text-white">Location</p>
                      <p className="text-xs text-gray-500">
                        {gpsLocation
                          ? `${gpsLocation.lat.toFixed(4)}, ${gpsLocation.lng.toFixed(4)}`
                          : 'Not captured'}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={getLocation}
                    className="px-3 py-1.5 bg-emerald-100 text-emerald-700 rounded-lg text-sm font-medium hover:bg-emerald-200"
                   aria-label="Icon button">
                    {gpsLocation ? 'Update' : 'Capture'}
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Step 5: Review */}
          {step === 5 && (
            <div className="space-y-6">
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                Review your report
              </h3>

              {/* Summary Card */}
              <div className="border dark:border-gray-700 rounded-xl overflow-hidden">
                {/* Severity */}
                <div className="p-4 border-b dark:border-gray-700">
                  <div className="flex items-center justify-between">
                    <span className="text-sm text-gray-500">Severity</span>
                    <span className={`px-3 py-1 rounded-full text-sm font-medium ${severityConfig[severity].color}`}>
                      {severityConfig[severity].icon} {severityConfig[severity].label}
                    </span>
                  </div>
                </div>

                {/* Photos */}
                <div className="p-4 border-b dark:border-gray-700">
                  <span className="text-sm text-gray-500 block mb-2">Photos ({photos.length})</span>
                  <div className="flex gap-2 overflow-x-auto">
                    {photos.map((photo) => (
                      <img
                        key={photo.id}
                        src={photo.url}
                        alt="Damage"
                        className="w-16 h-16 object-cover rounded-lg flex-shrink-0"
                      />
                    ))}
                  </div>
                </div>

                {/* Locations */}
                <div className="p-4 border-b dark:border-gray-700">
                  <span className="text-sm text-gray-500 block mb-2">Affected Areas</span>
                  <div className="flex flex-wrap gap-1">
                    {damageLocations.map((loc) => (
                      <span
                        key={loc.area}
                        className="px-2 py-1 bg-gray-100 dark:bg-gray-700 rounded text-sm"
                      >
                        {loc.area}
                      </span>
                    ))}
                  </div>
                </div>

                {/* Description */}
                <div className="p-4 border-b dark:border-gray-700">
                  <span className="text-sm text-gray-500 block mb-2">Description</span>
                  <p className="text-gray-900 dark:text-white text-sm">{description}</p>
                </div>

                {/* Additional Info */}
                <div className="p-4 grid grid-cols-2 gap-4">
                  <div>
                    <span className="text-sm text-gray-500 block">Estimated Cost</span>
                    <span className="font-medium text-gray-900 dark:text-white">
                      {estimatedCost ? `$${estimatedCost}` : 'Not provided'}
                    </span>
                  </div>
                  <div>
                    <span className="text-sm text-gray-500 block">Location</span>
                    <span className="font-medium text-gray-900 dark:text-white">
                      {gpsLocation ? 'Captured' : 'Not captured'}
                    </span>
                  </div>
                </div>
              </div>

              {/* Disclaimer */}
              <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl flex items-start gap-3">
                <FileText className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm text-blue-800 dark:text-blue-200">
                    By submitting this report, you confirm that the information provided is accurate
                    and complete to the best of your knowledge.
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t dark:border-gray-700 flex items-center justify-between">
          <button
            aria-label="Icon button"> step > 1 ? setStep(step - 1) : onClose()}
            className="flex items-center gap-2 px-4 py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
          >
            <ChevronLeft className="w-5 h-5" />
            {step > 1 ? 'Back' : 'Cancel'}
          </button>

          {step < 5 ? (
            <button
              aria-label="Icon button" onClick={() => setStep(step + 1)}
              disabled={!canProceed()}
              className="flex items-center gap-2 px-6 py-2 bg-emerald-600 text-white rounded-lg font-medium hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Next
              <ChevronRight className="w-5 h-5" />
            </button>
          ) : (
            <button
              onClick={handleSubmit}
              disabled={isSubmitting}
              className="flex items-center gap-2 px-6 py-2 bg-red-600 text-white rounded-lg font-medium hover:bg-red-700 disabled:opacity-50"
             aria-label="Icon button">
              {isSubmitting ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  Submitting...
                </>
              ) : (
                <>
                  <Send className="w-5 h-5" />
                  Submit Report
                </>
              )}
            </button>
          )}
        </div>
      </div>

      {/* Photo Viewer Modal */}
      {selectedPhoto && (
        <div
          className="fixed inset-0 z-60 bg-black/90 flex items-center justify-center p-4"
          onClick={() => setSelectedPhoto(null)}
        >
          <img
            src={selectedPhoto.url}
            alt="Damage detail"
            className="max-w-full max-h-full object-contain rounded-lg"
          />
          <button
            aria-label="Icon button" onClick={() => setSelectedPhoto(null)}
            className="absolute top-4 right-4 w-10 h-10 bg-white/10 rounded-full flex items-center justify-center text-white hover:bg-white/20"
          >
            <X className="w-6 h-6" />
          </button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback, Suspense, lazy, useTransition } from 'react';
import {
  LayoutDashboard,
  Package,
  Calendar,
  Heart,
  MessageSquare,
  Settings,
  Star,
  MapPin,
  Clock,
  ChevronRight,
  Plus,
  TrendingUp,
  TrendingDown,
  DollarSign,
  ArrowLeft,
  CheckCircle2,
  XCircle,
  AlertCircle,
  Shield,
  Eye,
  Activity,
  Loader2,
  Search,
  Edit,
  Trash2,
  Check,
  X,
  Send,
  Phone,
  Mail,
  BadgeCheck,
  Lock,
  Smartphone,
  FileText,
  Building,
  RefreshCw,
  Users,
} from 'lucide-react';
import AISettings from '../settings/AISettings';
import type { Equipment, Booking, UserAnalytics, Notification, Conversation, Message } from '../../types';
import { useAuth } from '../../contexts/AuthContext';
import {
  getBookings,
  getEquipment,
  getFavorites,
  removeFavorite,
  getNotifications,
  markNotificationRead,
  markAllNotificationsRead,
  getConversations,
  getMessages,
  sendMessage,
  getUserAnalytics,
  updateProfile,
  updateBookingStatus,
} from '../../services/database';
import ReferralProgram from '../referral/ReferralProgram';

// Lazy load components for better performance
const AnalyticsCharts = lazy(() => import('./AnalyticsCharts'));
const NotificationSettings = lazy(() => import('../settings/NotificationSettings'));

interface DashboardProps {
  onBack: () => void;
  onEquipmentClick: (equipment: Equipment) => void;
  onListEquipment: () => void;
}

type TabType = 'overview' | 'bookings' | 'listings' | 'favorites' | 'messages' | 'notifications' | 'security' | 'settings' | 'referral';
type BookingFilter = 'all' | 'pending' | 'confirmed' | 'active' | 'completed' | 'cancelled';

export default function Dashboard({
  onBack,
  onEquipmentClick,
  onListEquipment,
}: DashboardProps) {
  const { user, profile, refreshProfile } = useAuth();
  const [activeTab, setActiveTab] = useState<TabType>('overview');
  const [loading, setLoading] = useState(true);
  const [analytics, setAnalytics] = useState<UserAnalytics | null>(null);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [myListings, setMyListings] = useState<Equipment[]>([]);
  const [favorites, setFavorites] = useState<Equipment[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [bookingFilter, setBookingFilter] = useState<BookingFilter>('all');
  const [settingsForm, setSettingsForm] = useState({
    full_name: '',
    phone: '',
    location: '',
    bio: '',
  });
  const [saving, setSaving] = useState(false);
  const [ownerBookings, setOwnerBookings] = useState<Booking[]>([]);
  const [showNotificationSettings, setShowNotificationSettings] = useState(false);

  // Use transition for non-urgent updates
  const [, startTransition] = useTransition();

  const loadDashboardData = useCallback(async () => {
    if (!user) return;

    setLoading(true);
    try {
      const [analyticsData, bookingsData, ownerBookingsData, listingsData, favoritesData, notificationsData, conversationsData] = await Promise.all([
        getUserAnalytics(user.id),
        getBookings({ renterId: user.id }),
        getBookings({ ownerId: user.id }),
        getEquipment({ ownerId: user.id }),
        getFavorites(user.id),
        getNotifications(user.id),
        getConversations(user.id),
      ]);

      // Use startTransition for non-urgent state updates
      startTransition(() => {
        setAnalytics(analyticsData);
        setBookings(bookingsData);
        setOwnerBookings(ownerBookingsData);
        setMyListings(listingsData.data);
        setFavorites(favoritesData.map(f => f.equipment!).filter(Boolean));
        setNotifications(notificationsData);
        setConversations(conversationsData);
      });
    } catch (error) {
      console.error('Failed to load dashboard data:', error);
    } finally {
      setLoading(false);
    }
  }, [user, startTransition]);

  useEffect(() => {
    loadDashboardData();
  }, [loadDashboardData]);

  useEffect(() => {
    if (profile) {
      setSettingsForm({
        full_name: profile.full_name || '',
        phone: profile.phone || '',
        location: profile.location || '',
        bio: profile.bio || '',
      });
    }
  }, [profile]);

  useEffect(() => {
    if (selectedConversation) {
      getMessages(selectedConversation).then(setMessages);
    }
  }, [selectedConversation]);

  const handleRemoveFavorite = async (equipmentId: string) => {
    if (!user) return;
    await removeFavorite(user.id, equipmentId);
    setFavorites(prev => prev.filter(e => e.id !== equipmentId));
  };

  const handleMarkNotificationRead = async (id: string) => {
    await markNotificationRead(id);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, is_read: true } : n));
  };

  const handleMarkAllRead = async () => {
    if (!user) return;
    await markAllNotificationsRead(user.id);
    setNotifications(prev => prev.map(n => ({ ...n, is_read: true })));
  };

  const handleSendMessage = async () => {
    if (!user || !selectedConversation || !newMessage.trim()) return;

    const conversation = conversations.find(c => c.id === selectedConversation);
    if (!conversation) return;

    const receiverId = conversation.participants?.find(p => p.user_id !== user.id)?.user_id;
    if (!receiverId) return;

    const message = await sendMessage({
      conversationId: selectedConversation,
      senderId: user.id,
      receiverId,
      content: newMessage.trim(),
    });

    setMessages(prev => [...prev, message]);
    setNewMessage('');
  };

  const handleSaveSettings = async () => {
    if (!user) return;

    setSaving(true);
    try {
      await updateProfile(user.id, settingsForm);
      await refreshProfile();
    } catch (error) {
      console.error('Failed to save settings:', error);
    } finally {
      setSaving(false);
    }
  };

  const handleBookingAction = async (bookingId: string, action: 'confirm' | 'cancel') => {
    const status = action === 'confirm' ? 'confirmed' : 'cancelled';
    await updateBookingStatus(bookingId, status);
    setOwnerBookings(prev => prev.map(b => b.id === bookingId ? { ...b, status } : b));
  };

  const filteredBookings = bookings.filter(b => bookingFilter === 'all' || b.status === bookingFilter);
  const pendingOwnerBookings = ownerBookings.filter(b => b.status === 'pending');

  const tabs = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
    { id: 'bookings', label: 'My Bookings', icon: Calendar, badge: bookings.filter(b => b.status === 'pending').length },
    { id: 'listings', label: 'My Listings', icon: Package, badge: pendingOwnerBookings.length },
    { id: 'favorites', label: 'Favorites', icon: Heart, badge: favorites.length },
    { id: 'messages', label: 'Messages', icon: MessageSquare },
    { id: 'notifications', label: 'Notifications', icon: Activity, badge: notifications.filter(n => !n.is_read).length },
    { id: 'security', label: 'Security', icon: Shield },
    { id: 'settings', label: 'Settings', icon: Settings },
    { id: 'referral', label: 'Referrals', icon: Users },
  ];

  const getStatusBadge = (status: string) => {
    const styles: Record<string, { bg: string; text: string; icon: typeof CheckCircle2 }> = {
      confirmed: { bg: 'bg-green-50', text: 'text-green-700', icon: CheckCircle2 },
      pending: { bg: 'bg-amber-50', text: 'text-amber-700', icon: AlertCircle },
      active: { bg: 'bg-blue-50', text: 'text-blue-700', icon: Activity },
      completed: { bg: 'bg-gray-50', text: 'text-gray-700', icon: CheckCircle2 },
      cancelled: { bg: 'bg-red-50', text: 'text-red-700', icon: XCircle },
    };

    const style = styles[status] || styles.pending;
    const Icon = style.icon;

    return (
      <span className={`flex items-center gap-1.5 px-3 py-1 ${style.bg} ${style.text} rounded-full text-sm font-medium`}>
        <Icon className="w-4 h-4" />
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  const formatRelativeTime = (date: string) => {
    const diff = Date.now() - new Date(date).getTime();
    const minutes = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (minutes < 60) return `${minutes}m ago`;
    if (hours < 24) return `${hours}h ago`;
    return `${days}d ago`;
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 pt-20 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-8 h-8 text-teal-500 animate-spin" />
          <p className="text-gray-600">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pt-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex items-center gap-4 mb-8">
          <button
            onClick={onBack}
            className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
            aria-label="Go back"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div className="flex-1">
            <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
            <p className="text-gray-600">Manage your rentals, listings, and account</p>
          </div>
          <button
            onClick={loadDashboardData}
            className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
            aria-label="Reload dashboard data"
          >
            <RefreshCw className="w-5 h-5" />
          </button>
        </div>

        <div className="flex flex-col lg:flex-row gap-8">
          <div className="lg:w-64 flex-shrink-0">
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 mb-6">
              <div className="flex items-center gap-4 mb-6">
                <div className="w-16 h-16 rounded-full bg-gradient-to-br from-teal-400 to-emerald-500 flex items-center justify-center text-white text-2xl font-bold">
                  {profile?.full_name?.charAt(0) || user?.email?.charAt(0)?.toUpperCase() || 'U'}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-gray-900 truncate">{profile?.full_name || 'User'}</p>
                  <p className="text-sm text-gray-500">Member since {new Date(profile?.created_at || '').getFullYear()}</p>
                </div>
              </div>
              <div className="space-y-2">
                <div className="flex items-center gap-2 text-sm text-gray-500">
                  <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                  <span>{profile?.rating?.toFixed(1) || '0.0'} rating ({profile?.total_reviews || 0} reviews)</span>
                </div>
                {profile?.is_verified && (
                  <div className="flex items-center gap-2 text-sm text-green-600">
                    <BadgeCheck className="w-4 h-4" />
                    <span>Verified Account</span>
                  </div>
                )}
              </div>
            </div>

            <nav className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              {tabs.map((tab) => (
                <button
                  key={tab.id}
                  aria-label="Icon button" onClick={() => setActiveTab(tab.id as TabType)}
                  className={`w-full flex items-center justify-between px-6 py-4 text-left transition-colors ${
                    activeTab === tab.id
                      ? 'bg-teal-50 text-teal-700 border-l-4 border-teal-500'
                      : 'text-gray-600 hover:bg-gray-50 border-l-4 border-transparent'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <tab.icon className="w-5 h-5" />
                    {tab.label}
                  </div>
                  {tab.badge !== undefined && tab.badge > 0 && (
                    <span className="px-2 py-0.5 bg-teal-500 text-white text-xs font-medium rounded-full">
                      {tab.badge}
                    </span>
                  )}
                </button>
              ))}
            </nav>
          </div>

          <div className="flex-1 min-w-0">
            {activeTab === 'overview' && (
              <div className="space-y-6">
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                  <StatCard
                    label="Total Earned"
                    value={`$${(analytics?.total_earned || 0).toLocaleString()}`}
                    icon={DollarSign}
                    color="bg-green-500"
                    trend={12}
                  />
                  <StatCard
                    label="Total Spent"
                    value={`$${(analytics?.total_spent || 0).toLocaleString()}`}
                    icon={TrendingUp}
                    color="bg-blue-500"
                  />
                  <StatCard
                    label="Active Listings"
                    value={myListings.length.toString()}
                    icon={Package}
                    color="bg-amber-500"
                  />
                  <StatCard
                    label="Response Rate"
                    value={`${analytics?.response_rate || 0}%`}
                    icon={Activity}
                    color="bg-teal-500"
                  />
                </div>

                {/* Enhanced Analytics Charts - NEW */}
                <Suspense fallback={
                  <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 flex items-center justify-center h-64">
                    <Loader2 className="w-8 h-8 text-teal-500 animate-spin" />
                  </div>
                }>
                  <AnalyticsCharts
                    userId={user?.id || ''}
                    analytics={undefined}
                  />
                </Suspense>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
                    <div className="flex items-center justify-between mb-6">
                      <h2 className="text-lg font-semibold text-gray-900">Performance Overview</h2>
                      <select aria-label="Select time range" className="text-sm border-0 text-gray-500 focus:ring-0">
                        <option>Last 30 days</option>
                        <option>Last 90 days</option>
                        <option>This year</option>
                      </select>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-2 mb-2">
                          <Eye className="w-4 h-4 text-gray-500" />
                          <span className="text-sm text-gray-500">Profile Views</span>
                        </div>
                        <p className="text-2xl font-bold text-gray-900">{analytics?.profile_views || 0}</p>
                      </div>
                      <div className="p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-2 mb-2">
                          <Users className="w-4 h-4 text-gray-500" />
                          <span className="text-sm text-gray-500">Total Rentals</span>
                        </div>
                        <p className="text-2xl font-bold text-gray-900">{analytics?.total_rentals || 0}</p>
                      </div>
                      <div className="p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-2 mb-2">
                          <Star className="w-4 h-4 text-gray-500" />
                          <span className="text-sm text-gray-500">Reviews Given</span>
                        </div>
                        <p className="text-2xl font-bold text-gray-900">{analytics?.reviews_given || 0}</p>
                      </div>
                      <div className="p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-2 mb-2">
                          <Clock className="w-4 h-4 text-gray-500" />
                          <span className="text-sm text-gray-500">Avg Response</span>
                        </div>
                        <p className="text-2xl font-bold text-gray-900">{analytics?.avg_response_time_hours || 0}h</p>
                      </div>
                    </div>
                  </div>

                  <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
                    <div className="flex items-center justify-between mb-6">
                      <h2 className="text-lg font-semibold text-gray-900">Recent Bookings</h2>
                      <button
                        aria-label="Icon button" onClick={() => setActiveTab('bookings')}
                        className="text-teal-600 text-sm font-medium hover:text-teal-700"
                      >
                        View All
                      </button>
                    </div>
                    {bookings.length === 0 ? (
                      <div className="text-center py-8">
                        <Calendar className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                        <p className="text-gray-500">No bookings yet</p>
                      </div>
                    ) : (
                      <div className="space-y-3">
                        {bookings.slice(0, 3).map((booking) => (
                          <div
                            key={booking.id}
                            className="flex items-center gap-4 p-3 bg-gray-50 rounded-xl"
                          >
                            <img
                              src={booking.equipment?.images[0] || 'https://images.pexels.com/photos/162553/keys-workshop-mechanic-tools-162553.jpeg'}
                              alt=""
                              className="w-12 h-12 rounded-lg object-cover"
                            />
                            <div className="flex-1 min-w-0">
                              <p className="font-medium text-gray-900 truncate">{booking.equipment?.title}</p>
                              <p className="text-sm text-gray-500">{formatDate(booking.start_date)}</p>
                            </div>
                            {getStatusBadge(booking.status)}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {pendingOwnerBookings.length > 0 && (
                  <div className="bg-amber-50 border border-amber-200 rounded-2xl p-6">
                    <div className="flex items-start gap-4">
                      <div className="w-12 h-12 bg-amber-100 rounded-xl flex items-center justify-center flex-shrink-0">
                        <AlertCircle className="w-6 h-6 text-amber-600" aria-hidden="true" />
                      </div>
                      <div className="flex-1">
                        <h3 className="font-semibold text-amber-900 mb-1">Pending Booking Requests</h3>
                        <p className="text-amber-700 text-sm mb-4">
                          You have {pendingOwnerBookings.length} booking request{pendingOwnerBookings.length > 1 ? 's' : ''} waiting for your approval.
                        </p>
                        <button
                          aria-label="Icon button" onClick={() => setActiveTab('listings')}
                          className="px-4 py-2 bg-amber-600 text-white font-medium rounded-lg hover:bg-amber-700 transition-colors"
                        >
                          Review Requests
                        </button>
                      </div>
                    </div>
                  </div>
                )}

                <div className="bg-gradient-to-br from-teal-500 to-emerald-600 rounded-2xl p-8 text-white">
                  <h2 className="text-xl font-bold mb-2">Start Earning Today</h2>
                  <p className="text-white/80 mb-6">
                    List your equipment and earn extra income when you're not using it.
                  </p>
                  <button
                    onClick={onListEquipment}
                    className="flex items-center gap-2 px-6 py-3 bg-white text-teal-600 font-semibold rounded-xl hover:bg-gray-100 transition-colors"
                   aria-label="Icon button">
                    <Plus className="w-5 h-5" aria-hidden="true" />
                    List Equipment
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'bookings' && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-lg font-semibold text-gray-900">My Bookings</h2>
                  <div className="flex items-center gap-2">
                    <select
                      aria-label="Filter bookings"
                      value={bookingFilter}
                      onChange={(e) => setBookingFilter(e.target.value as BookingFilter)}
                      className="px-4 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:border-teal-500"
                    >
                      <option value="all">All Bookings</option>
                      <option value="pending">Pending</option>
                      <option value="confirmed">Confirmed</option>
                      <option value="active">Active</option>
                      <option value="completed">Completed</option>
                      <option value="cancelled">Cancelled</option>
                    </select>
                  </div>
                </div>

                {filteredBookings.length === 0 ? (
                  <div className="bg-white rounded-2xl p-12 shadow-sm border border-gray-100 text-center">
                    <Calendar className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                    <h3 className="text-xl font-semibold text-gray-900 mb-2">No bookings found</h3>
                    <p className="text-gray-600 mb-6">Start renting equipment to see your bookings here.</p>
                    <button
                      onClick={onBack}
                      className="px-6 py-3 bg-teal-500 text-white font-semibold rounded-xl hover:bg-teal-600 transition-colors"
                     aria-label="Icon button">
                      Browse Equipment
                    </button>
                  </div>
                ) : (
                  <div className="bg-white rounded-2xl shadow-sm border border-gray-100 divide-y divide-gray-100">
                    {filteredBookings.map((booking) => (
                      <div key={booking.id} className="p-6">
                        <div className="flex items-start gap-4">
                          <img
                            src={booking.equipment?.images[0] || 'https://images.pexels.com/photos/162553/keys-workshop-mechanic-tools-162553.jpeg'}
                            alt={booking.equipment?.title || 'Equipment image'}
                            className="w-24 h-24 rounded-xl object-cover flex-shrink-0"
                          />
                          <div className="flex-1 min-w-0">
                            <div className="flex items-start justify-between mb-2">
                              <div>
                                <h3 className="font-semibold text-gray-900">{booking.equipment?.title}</h3>
                                <p className="text-sm text-gray-500 flex items-center gap-1.5">
                                  <MapPin className="w-4 h-4" aria-hidden="true" />
                                  {booking.equipment?.location}
                                </p>
                              </div>
                              {getStatusBadge(booking.status)}
                            </div>
                            <div className="flex items-center gap-6 text-sm text-gray-500 mb-4">
                              <span className="flex items-center gap-1.5">
                                <Calendar className="w-4 h-4" aria-hidden="true" />
                                {formatDate(booking.start_date)} - {formatDate(booking.end_date)}
                              </span>
                              <span className="flex items-center gap-1.5">
                                <Clock className="w-4 h-4" aria-hidden="true" />
                                {booking.total_days} days
                              </span>
                            </div>
                            <div className="flex items-center justify-between">
                              <p className="text-lg font-semibold text-gray-900">${booking.total_amount.toFixed(2)}</p>
                              <button
                                aria-label="Icon button"> booking.equipment && onEquipmentClick(booking.equipment)}
                                className="flex items-center gap-2 px-4 py-2 text-teal-600 font-medium hover:bg-teal-50 rounded-xl transition-colors"
                              >
                                View Details
                                <ChevronRight className="w-4 h-4" aria-hidden="true" />
                              </button>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'listings' && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h2 className="text-lg font-semibold text-gray-900">My Listings ({myListings.length})</h2>
                  <button
                    onClick={onListEquipment}
                    className="flex items-center gap-2 px-4 py-2 bg-teal-500 text-white font-medium rounded-xl hover:bg-teal-600 transition-colors"
                   aria-label="Icon button">
                    <Plus className="w-5 h-5" aria-hidden="true" />
                    Add New
                  </button>
                </div>

                {pendingOwnerBookings.length > 0 && (
                  <div className="bg-white rounded-2xl shadow-sm border border-gray-100">
                    <div className="p-4 border-b border-gray-100">
                      <h3 className="font-semibold text-gray-900">Pending Requests ({pendingOwnerBookings.length})</h3>
                    </div>
                    <div className="divide-y divide-gray-100">
                      {pendingOwnerBookings.map((booking) => (
                        <div key={booking.id} className="p-4">
                          <div className="flex items-center gap-4">
                            <img
                              src={booking.equipment?.images[0] || ''}
                              alt={booking.equipment?.title || 'Equipment image'}
                              className="w-16 h-16 rounded-lg object-cover"
                            />
                            <div className="flex-1">
                              <p className="font-medium text-gray-900">{booking.equipment?.title}</p>
                              <p className="text-sm text-gray-500">
                                {formatDate(booking.start_date)} - {formatDate(booking.end_date)} ({booking.total_days} days)
                              </p>
                              <p className="text-sm font-medium text-gray-900">${booking.total_amount.toFixed(2)}</p>
                            </div>
                            <div className="flex items-center gap-2">
                              <button
                                aria-label="Icon button" onClick={() => handleBookingAction(booking.id, 'confirm')}
                                className="p-2 bg-green-100 text-green-600 rounded-lg hover:bg-green-200 transition-colors"
                                aria-label="Approve request"
                              >
                                <Check className="w-5 h-5" aria-hidden="true" />
                              </button>
                              <button
                                aria-label="Icon button" onClick={() => handleBookingAction(booking.id, 'cancel')}
                                className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 transition-colors"
                                aria-label="Reject request"
                              >
                                <X className="w-5 h-5" aria-hidden="true" />
                              </button>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {myListings.length === 0 ? (
                  <div className="bg-white rounded-2xl p-12 shadow-sm border border-gray-100 text-center">
                    <Package className="w-16 h-16 text-gray-300 mx-auto mb-4" aria-hidden="true" />
                    <h3 className="text-xl font-semibold text-gray-900 mb-2">No listings yet</h3>
                    <p className="text-gray-600 mb-6 max-w-md mx-auto">
                      Start earning money by listing your equipment. It's free to list and you set your own prices.
                    </p>
                    <button
                      onClick={onListEquipment}
                      className="inline-flex items-center gap-2 px-6 py-3 bg-teal-500 text-white font-semibold rounded-xl hover:bg-teal-600 transition-colors"
                     aria-label="Icon button">
                      <Plus className="w-5 h-5" />
                      Create Your First Listing
                    </button>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {myListings.map((item) => (
                      <div key={item.id} className="bg-white rounded-2xl overflow-hidden border border-gray-100 shadow-sm">
                        <div className="relative">
                          <img
                            src={item.images[0]}
                            alt={item.title}
                            className="w-full h-40 object-cover"
                          />
                          <div className="absolute top-3 right-3">
                            <span className={`px-2 py-1 text-xs font-medium rounded-lg ${
                              item.is_active ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'
                            }`}>
                              {item.is_active ? 'Active' : 'Inactive'}
                            </span>
                          </div>
                        </div>
                        <div className="p-4">
                          <h3 className="font-semibold text-gray-900 mb-1">{item.title}</h3>
                          <p className="text-sm text-gray-500 mb-3">{item.location}</p>
                          <div className="flex items-center justify-between mb-4">
                            <p className="font-semibold text-gray-900">${item.daily_rate}/day</p>
                            <div className="flex items-center gap-1 text-sm text-gray-500">
                              <Eye className="w-4 h-4" />
                              <span>{item.total_bookings} bookings</span>
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <button
                              aria-label="Icon button" onClick={() => onEquipmentClick(item)}
                              className="flex-1 px-4 py-2 bg-teal-500 text-white text-sm font-medium rounded-lg hover:bg-teal-600 transition-colors"
                            >
                              View
                            </button>
                            <button className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors" aria-label="Edit booking">
                              <Edit className="w-5 h-5" />
                            </button>
                            <button aria-label="Delete item" className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors">
                              <Trash2 className="w-5 h-5" />
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'favorites' && (
              <div className="space-y-6">
                <h2 className="text-lg font-semibold text-gray-900">Saved Equipment ({favorites.length})</h2>

                {favorites.length === 0 ? (
                  <div className="bg-white rounded-2xl p-12 shadow-sm border border-gray-100 text-center">
                    <Heart className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                    <h3 className="text-xl font-semibold text-gray-900 mb-2">No favorites yet</h3>
                    <p className="text-gray-600 mb-6">Save equipment you're interested in to easily find them later</p>
                    <button
                      onClick={onBack}
                      className="px-6 py-3 bg-teal-500 text-white font-semibold rounded-xl hover:bg-teal-600 transition-colors"
                     aria-label="Icon button">
                      Browse Equipment
                    </button>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {favorites.map((item) => (
                      <div key={item.id} className="bg-white rounded-2xl overflow-hidden border border-gray-100 flex">
                        <img src={item.images[0]} alt={item.title} className="w-32 h-32 object-cover" />
                        <div className="flex-1 p-4">
                          <h3 className="font-semibold text-gray-900 mb-1">{item.title}</h3>
                          <p className="text-sm text-gray-500 mb-2">{item.location}</p>
                          <p className="font-semibold text-gray-900 mb-3">${item.daily_rate}/day</p>
                          <div className="flex items-center gap-2">
                            <button
                              aria-label="Icon button" onClick={() => onEquipmentClick(item)}
                              className="px-4 py-2 bg-teal-500 text-white text-sm font-medium rounded-lg hover:bg-teal-600 transition-colors"
                            >
                              View
                            </button>
                            <button
                              aria-label="Icon button" onClick={() => handleRemoveFavorite(item.id)}
                              className="px-4 py-2 border border-gray-200 text-gray-600 text-sm font-medium rounded-lg hover:bg-gray-50 transition-colors"
                            >
                              Remove
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'messages' && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="flex h-[600px]">
                  <div className="w-80 border-r border-gray-100 flex flex-col">
                    <div className="p-4 border-b border-gray-100">
                      <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                        <input
                          type="text"
                          placeholder="Search conversations..."
                          aria-label="Search conversations"
                          className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-teal-500"
                        />
                      </div>
                    </div>
                    <div className="flex-1 overflow-y-auto">
                      {conversations.length === 0 ? (
                        <div className="p-8 text-center">
                          <MessageSquare className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                          <p className="text-gray-500 text-sm">No conversations yet</p>
                        </div>
                      ) : (
                        conversations.map((conv) => (
                          <button
                            key={conv.id}
                            aria-label="Icon button" onClick={() => setSelectedConversation(conv.id)}
                            className={`w-full p-4 text-left hover:bg-gray-50 transition-colors ${
                              selectedConversation === conv.id ? 'bg-teal-50' : ''
                            }`}
                          >
                            <div className="flex items-center gap-3">
                              <div className="w-10 h-10 rounded-full bg-gray-200 flex items-center justify-center">
                                <Users className="w-5 h-5 text-gray-500" />
                              </div>
                              <div className="flex-1 min-w-0">
                                <p className="font-medium text-gray-900 truncate">
                                  {conv.equipment?.title || 'Conversation'}
                                </p>
                                <p className="text-sm text-gray-500 truncate">
                                  {conv.last_message?.content || 'No messages'}
                                </p>
                              </div>
                              {conv.unread_count && conv.unread_count > 0 && (
                                <span className="w-5 h-5 bg-teal-500 text-white text-xs rounded-full flex items-center justify-center">
                                  {conv.unread_count}
                                </span>
                              )}
                            </div>
                          </button>
                        ))
                      )}
                    </div>
                  </div>

                  <div className="flex-1 flex flex-col">
                    {selectedConversation ? (
                      <>
                        <div className="p-4 border-b border-gray-100">
                          <h3 className="font-semibold text-gray-900">Conversation</h3>
                        </div>
