          >
            <Bell className="w-5 h-5" />
            {notifications ? 'Notifications On' : 'Notifications Off'}
          </button>
          <button
            onClick={onViewDetails}
            className="flex-1 py-3 bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-xl flex items-center justify-center gap-2"
           aria-label="Icon button">
            <Package className="w-5 h-5" />
            View Booking
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Camera, RotateCcw, ZoomIn, ZoomOut, Maximize2, X, Ruler, Move3D } from 'lucide-react';

interface Equipment3DViewerProps {
  images: string[];
  title: string;
  onClose?: () => void;
}

export default function Equipment3DViewer({ images, title, onClose }: Equipment3DViewerProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isRotating, setIsRotating] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [zoom, setZoom] = useState(1);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [showMeasurements, setShowMeasurements] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const autoRotateRef = useRef<NodeJS.Timeout | null>(null);

  // Auto-rotate through images to simulate 360° view
  useEffect(() => {
    if (isRotating && images.length > 1) {
      autoRotateRef.current = setInterval(() => {
        setCurrentIndex((prev) => (prev + 1) % images.length);
        setRotation((prev) => (prev + 360 / images.length) % 360);
      }, 100);
    } else if (autoRotateRef.current) {
      clearInterval(autoRotateRef.current);
    }

    return () => {
      if (autoRotateRef.current) clearInterval(autoRotateRef.current);
    };
  }, [isRotating, images.length]);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setPosition({
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y,
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleZoomIn = () => {
    setZoom((prev) => Math.min(prev + 0.25, 3));
  };

  const handleZoomOut = () => {
    setZoom((prev) => Math.max(prev - 0.25, 0.5));
  };

  const handleReset = () => {
    setZoom(1);
    setPosition({ x: 0, y: 0 });
    setRotation(0);
    setCurrentIndex(0);
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (e.deltaY < 0) {
      handleZoomIn();
    } else {
      handleZoomOut();
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/95 flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-gray-800">
        <div className="flex items-center gap-3">
          <Move3D className="w-6 h-6 text-teal-400" />
          <div>
            <h2 className="text-white font-semibold">{title}</h2>
            <p className="text-gray-400 text-sm">360° Interactive View</p>
          </div>
        </div>
        
        <button
          onClick={onClose}
          className="p-2 hover:bg-gray-800 rounded-lg transition-colors"
        >
          <X className="w-6 h-6 text-gray-400" />
        </button>
      </div>

      {/* Main Viewer */}
      <div
        ref={containerRef}
        className="flex-1 relative overflow-hidden cursor-grab active:cursor-grabbing"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onWheel={handleWheel}
      >
        {/* Image */}
        <div
          className="absolute inset-0 flex items-center justify-center transition-transform duration-100"
          style={{
            transform: `translate(${position.x}px, ${position.y}px) scale(${zoom}) rotate(${rotation}deg)`,
          }}
        >
          <img
            src={images[currentIndex]}
            alt={`${title} - View ${currentIndex + 1}`}
            className="max-w-full max-h-full object-contain select-none"
            draggable={false}
          />

          {/* Measurement Overlay */}
          {showMeasurements && (
            <div className="absolute inset-0 pointer-events-none">
              {/* Horizontal measurement */}
              <div className="absolute left-1/4 right-1/4 top-1/2 flex items-center">
                <div className="flex-1 h-0.5 bg-teal-400" />
                <span className="px-2 py-1 bg-teal-500 text-white text-xs rounded mx-1">
                  ~48"
                </span>
                <div className="flex-1 h-0.5 bg-teal-400" />
              </div>
              {/* Vertical measurement */}
              <div className="absolute top-1/4 bottom-1/4 left-1/2 flex flex-col items-center">
                <div className="flex-1 w-0.5 bg-teal-400" />
                <span className="px-2 py-1 bg-teal-500 text-white text-xs rounded my-1 whitespace-nowrap">
                  ~36"
                </span>
                <div className="flex-1 w-0.5 bg-teal-400" />
              </div>
            </div>
          )}
        </div>

        {/* Rotation indicator */}
        <div className="absolute bottom-24 left-1/2 transform -translate-x-1/2">
          <div className="flex items-center gap-2 px-4 py-2 bg-gray-900/80 rounded-full backdrop-blur-sm">
            <div 
              className="w-4 h-4 border-2 border-teal-400 rounded-full relative"
              style={{ transform: `rotate(${rotation}deg)` }}
            >
              <div className="absolute top-0 left-1/2 w-0.5 h-2 bg-teal-400 -translate-x-1/2 -translate-y-1" />
            </div>
            <span className="text-gray-400 text-sm">{Math.round(rotation)}°</span>
          </div>
        </div>

        {/* Image counter */}
        <div className="absolute top-4 left-1/2 transform -translate-x-1/2">
          <div className="flex items-center gap-2 px-4 py-2 bg-gray-900/80 rounded-full backdrop-blur-sm">
            <Camera className="w-4 h-4 text-teal-400" />
            <span className="text-white text-sm">
              {currentIndex + 1} / {images.length}
            </span>
          </div>
        </div>

        {/* Zoom level */}
        <div className="absolute top-4 right-4">
          <div className="px-3 py-1.5 bg-gray-900/80 rounded-full backdrop-blur-sm">
            <span className="text-white text-sm">{Math.round(zoom * 100)}%</span>
          </div>
        </div>
      </div>

      {/* Image Thumbnails */}
      <div className="p-4 border-t border-gray-800">
        <div className="flex items-center justify-center gap-2 overflow-x-auto pb-2">
          {images.map((img, index) => (
            <button
              key={index}
              aria-label="Icon button"> {
                setCurrentIndex(index);
                setRotation((index / images.length) * 360);
              }}
              className={`flex-shrink-0 w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${
                index === currentIndex ? 'border-teal-400 scale-110' : 'border-transparent opacity-60 hover:opacity-100'
              }`}
            >
              <img src={img} alt={`Thumbnail ${index + 1}`} className="w-full h-full object-cover" />
            </button>
          ))}
        </div>
      </div>

      {/* Controls */}
      <div className="p-4 border-t border-gray-800">
        <div className="flex items-center justify-center gap-3">
          <button
            aria-label="Icon button" onClick={() => setIsRotating(!isRotating)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
              isRotating
                ? 'bg-teal-500 text-white'
                : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
            }`}
          >
            <RotateCcw className={`w-5 h-5 ${isRotating ? 'animate-spin' : ''}`} />
            <span>{isRotating ? 'Stop' : 'Auto Rotate'}</span>
          </button>

          <div className="flex items-center bg-gray-800 rounded-lg">
            <button
              onClick={handleZoomOut}
              className="p-2 hover:bg-gray-700 rounded-l-lg transition-colors"
            >
              <ZoomOut className="w-5 h-5 text-gray-300" />
            </button>
            <div className="w-px h-6 bg-gray-700" />
            <button
              onClick={handleZoomIn}
              className="p-2 hover:bg-gray-700 rounded-r-lg transition-colors"
             aria-label="Icon button">
              <ZoomIn className="w-5 h-5 text-gray-300" />
            </button>
          </div>

          <button
            aria-label="Icon button" onClick={() => setShowMeasurements(!showMeasurements)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
              showMeasurements
                ? 'bg-purple-500 text-white'
                : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
            }`}
          >
            <Ruler className="w-5 h-5" />
            <span>Measurements</span>
          </button>

          <button
            onClick={handleReset}
            className="flex items-center gap-2 px-4 py-2 bg-gray-800 text-gray-300 rounded-lg hover:bg-gray-700 transition-colors"
           aria-label="Icon button">
            <Maximize2 className="w-5 h-5" />
            <span>Reset</span>
          </button>
        </div>

        <p className="text-center text-gray-500 text-sm mt-3">
          Drag to pan • Scroll to zoom • Click thumbnails to navigate
        </p>
      </div>
    </div>
  );
}

import { useState, memo } from 'react';
import { Heart, Star, MapPin, Shield, Clock, Eye, Zap, Plus } from 'lucide-react';
import type { Equipment } from '../../types';
import { RatingBadge, FeaturedBadge, VerifiedBadge, ConditionBadge } from '../ui/Badge';

interface EquipmentCardProps {
  equipment: Equipment;
  onEquipmentClick: (equipment: Equipment) => void;
  onFavoriteClick: (equipmentId: string) => void;
  isFavorite: boolean;
  variant?: 'default' | 'compact' | 'horizontal';
  showQuickBook?: boolean;
  onAddToComparison?: (equipment: Equipment) => void;
  showCompareButton?: boolean;
}

const EquipmentCard = memo(function EquipmentCard({
  equipment,
  onEquipmentClick,
  onFavoriteClick,
  isFavorite,
  variant = 'default',
  showQuickBook = false,
  onAddToComparison,
  showCompareButton = false,
}: EquipmentCardProps) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);

  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onFavoriteClick(equipment.id);
  };

  const handleCompareClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onAddToComparison?.(equipment);
  };

  if (variant === 'horizontal') {
    return (
      <div
        onClick={() => onEquipmentClick(equipment)}
        className="group bg-white rounded-2xl overflow-hidden border border-gray-100 hover:border-gray-200 hover:shadow-xl transition-all duration-300 flex cursor-pointer"
      >
        <div className="relative w-48 flex-shrink-0">
          {!imageLoaded && !imageError && (
            <div className="absolute inset-0 bg-gray-200 animate-pulse" />
          )}
          <img
            src={equipment.images[0]}
            alt={equipment.title}
            onLoad={() => setImageLoaded(true)}
            onError={() => setImageError(true)}
            className={`w-full h-full object-cover ${imageLoaded ? 'opacity-100' : 'opacity-0'} transition-opacity`}
          />
          {equipment.is_featured && (
            <div className="absolute top-3 left-3">
              <FeaturedBadge size="sm" />
            </div>
          )}
        </div>
        <div className="flex-1 p-4 flex flex-col justify-between">
          <div>
            <div className="flex items-start justify-between gap-2 mb-2">
              <h3 className="font-semibold text-gray-900 line-clamp-1 group-hover:text-teal-600 transition-colors">
                {equipment.title}
              </h3>
              <button
                onClick={handleFavoriteClick}
                className={`p-1.5 rounded-full transition-all ${
                  isFavorite
                    ? 'bg-red-50 text-red-500'
                    : 'text-gray-400 hover:text-red-500'
                } aria-label="Icon button">
                <Heart className={`w-4 h-4 ${isFavorite ? 'fill-red-500' : ''}`} />
              </button>
            </div>
            <div className="flex items-center gap-2 text-sm text-gray-500 mb-2">
              <MapPin className="w-4 h-4 flex-shrink-0" />
              <span className="line-clamp-1">{equipment.location}</span>
            </div>
            <div className="flex items-center gap-3">
              <RatingBadge rating={equipment.rating} reviews={equipment.total_reviews} size="sm" />
              {equipment.owner?.is_verified && <VerifiedBadge size="sm" />}
            </div>
          </div>
          <div className="flex items-center justify-between pt-3 border-t border-gray-100 mt-3">
            <div>
              <span className="text-xl font-bold text-gray-900">${equipment.daily_rate}</span>
              <span className="text-gray-500 text-sm">/day</span>
            </div>
            {showQuickBook && (
              <button className="px-4 py-2 bg-teal-500 text-white text-sm font-medium rounded-lg hover:bg-teal-600 transition-colors" aria-label="Icon button">
                Quick Book
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (variant === 'compact') {
    return (
      <div
        onClick={() => onEquipmentClick(equipment)}
        className="group bg-white rounded-xl overflow-hidden border border-gray-100 hover:border-gray-200 hover:shadow-lg transition-all duration-300 cursor-pointer"
      >
        <div className="relative aspect-square overflow-hidden">
          {!imageLoaded && !imageError && (
            <div className="absolute inset-0 bg-gray-200 animate-pulse" />
          )}
          <img
            src={equipment.images[0]}
            alt={equipment.title}
            onLoad={() => setImageLoaded(true)}
            onError={() => setImageError(true)}
            className={`w-full h-full object-cover group-hover:scale-105 transition-transform duration-300 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
          />
          <button
            onClick={handleFavoriteClick}
            className={`absolute top-2 right-2 w-8 h-8 rounded-full flex items-center justify-center transition-all ${
              isFavorite
                ? 'bg-red-500 text-white'
                : 'bg-white/90 text-gray-600 hover:text-red-500'
            } aria-label="Icon button">
            <Heart className={`w-4 h-4 ${isFavorite ? 'fill-white' : ''}`} />
          </button>
        </div>
        <div className="p-3">
          <h3 className="font-medium text-gray-900 text-sm line-clamp-1">{equipment.title}</h3>
          <div className="flex items-center justify-between mt-2">
            <span className="font-bold text-gray-900">${equipment.daily_rate}</span>
            <div className="flex items-center gap-1 text-xs text-gray-500">
              <Star className="w-3 h-3 text-amber-500 fill-amber-500" />
              {equipment.rating.toFixed(1)}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Default variant
  return (
    <div
      onClick={() => onEquipmentClick(equipment)}
      className="group bg-white rounded-2xl overflow-hidden border border-gray-100 hover:border-gray-200 hover:shadow-xl transition-all duration-300 cursor-pointer"
    >
      <div className="relative aspect-[4/3] overflow-hidden">
        {!imageLoaded && !imageError && (
          <div className="absolute inset-0 bg-gray-200 animate-pulse" />
        )}
        <img
          src={equipment.images[0]}
          alt={equipment.title}
          onLoad={() => setImageLoaded(true)}
          onError={() => setImageError(true)}
          className={`w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent" />

        {/* Action Buttons */}
        <div className="absolute top-4 right-4 flex flex-col gap-2">
          <button
            onClick={handleFavoriteClick}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 ${
              isFavorite
                ? 'bg-red-500 text-white scale-110'
                : 'bg-white/90 text-gray-600 hover:bg-white hover:text-red-500'
            } aria-label="Icon button">
            <Heart className={`w-5 h-5 ${isFavorite ? 'fill-white' : ''}`} />
          </button>
          {showCompareButton && onAddToComparison && (
            <button
              onClick={handleCompareClick}
              className="w-10 h-10 rounded-full bg-white/90 text-gray-600 hover:bg-purple-500 hover:text-white flex items-center justify-center transition-all duration-300"
              title="Add to comparison"
            >
              <Plus className="w-5 h-5" />
            </button>
          )}
        </div>

        {/* Featured Badge */}
        {equipment.is_featured && (
          <div className="absolute top-4 left-4">
            <div className="px-3 py-1.5 bg-gradient-to-r from-amber-500 to-orange-500 rounded-full text-xs font-semibold text-white flex items-center gap-1.5 shadow-lg">
              <Zap className="w-3.5 h-3.5 fill-white" />
              Featured
            </div>
          </div>
        )}

        {/* Bottom Badges */}
        <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between">
          <RatingBadge rating={equipment.rating} reviews={equipment.total_reviews} />
          {equipment.owner?.is_verified && (
            <div className="flex items-center gap-1.5 px-3 py-1.5 bg-white/90 backdrop-blur-sm rounded-full">
              <Shield className="w-4 h-4 text-teal-500" />
              <span className="text-xs font-medium text-gray-700">Verified</span>
            </div>
          )}
        </div>
      </div>

      <div className="p-5">
        <div className="flex items-start justify-between gap-2 mb-2">
          <h3 className="font-semibold text-gray-900 line-clamp-1 group-hover:text-teal-600 transition-colors">
            {equipment.title}
          </h3>
        </div>

        <div className="flex items-center gap-2 text-sm text-gray-500 mb-3">
          <MapPin className="w-4 h-4 flex-shrink-0" />
          <span className="line-clamp-1">{equipment.location}</span>
        </div>

        <div className="flex items-center gap-3 text-sm text-gray-500 mb-4">
          <div className="flex items-center gap-1.5">
            <Clock className="w-4 h-4" />
            <span>{equipment.min_rental_days}-{equipment.max_rental_days} days</span>
          </div>
          <ConditionBadge condition={equipment.condition} size="sm" />
        </div>

        <div className="flex items-end justify-between pt-4 border-t border-gray-100">
          <div>
            <span className="text-2xl font-bold text-gray-900">${equipment.daily_rate}</span>
            <span className="text-gray-500">/day</span>
          </div>
          <div className="flex items-center gap-3 text-sm text-gray-500">
            {equipment.weekly_rate && (
              <span>${equipment.weekly_rate}/wk</span>
            )}
            <div className="flex items-center gap-1">
              <Eye className="w-4 h-4" />
              <span>{equipment.total_bookings}</span>
            </div>
          </div>
        </div>

        {showQuickBook && (
          <button
            onClick={(e) = aria-label="Icon button"> {
              e.stopPropagation();
              onEquipmentClick(equipment);
            }}
            className="w-full mt-4 py-3 bg-gradient-to-r from-teal-500 to-emerald-500 text-white font-semibold rounded-xl hover:shadow-lg transition-all"
          >
            View & Book
          </button>
        )}
      </div>
    </div>
  );
});

export default EquipmentCard;

import { useState } from 'react';
import {
  X,
  Heart,
  Share2,
  Star,
  MapPin,
  Shield,
  CheckCircle2,
  Calendar,
  ChevronLeft,
  ChevronRight,
  MessageSquare,
  Award,
  Truck,
  AlertCircle,
  Info,
  DollarSign,
} from 'lucide-react';
import type { Equipment } from '../../types';
import ShareEquipment from './ShareEquipment';
import PriceNegotiator from '../negotiation/PriceNegotiator';
import MaintenancePredictor from '../predictive/MaintenancePredictor';

interface EquipmentDetailProps {
  equipment: Equipment;
  onClose: () => void;
  onBook: (equipment: Equipment, dates: { start: string; end: string }) => void;
  onMessage: (equipment: Equipment) => void;
  isFavorite: boolean;
  onFavoriteToggle: () => void;
}

export default function EquipmentDetail({
  equipment,
  onClose,
  onBook,
  onMessage,
  isFavorite,
  onFavoriteToggle,
}: EquipmentDetailProps) {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [showShareModal, setShowShareModal] = useState(false);
  const [showNegotiator, setShowNegotiator] = useState(false);
  const [showMaintenance, setShowMaintenance] = useState(false);

  const nextImage = () => {
    setCurrentImageIndex((prev) =>
      prev === equipment.images.length - 1 ? 0 : prev + 1
    );
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) =>
      prev === 0 ? equipment.images.length - 1 : prev - 1
    );
  };

  const calculateTotal = () => {
    if (!startDate || !endDate) return null;
    const start = new Date(startDate);
    const end = new Date(endDate);
    const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
    if (days <= 0) return null;

    const subtotal = days * equipment.daily_rate;
    const serviceFee = subtotal * 0.12;
    const total = subtotal + serviceFee + equipment.deposit_amount;

    return { days, subtotal, serviceFee, total };
  };

  const pricing = calculateTotal();

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={onClose} />

      <div className="relative w-full max-w-6xl max-h-[90vh] bg-white rounded-3xl shadow-2xl overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <button
            onClick={onClose}
            className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
           aria-label="Icon button">
            <ChevronLeft className="w-5 h-5" />
            Back to results
          </button>
          <div className="flex items-center gap-2">
            <button
              onClick={onFavoriteToggle}
              className={`p-2.5 rounded-full transition-colors ${
                isFavorite
                  ? 'bg-red-50 text-red-500'
                  : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              } aria-label="Icon button">
              <Heart className={`w-5 h-5 ${isFavorite ? 'fill-red-500' : ''}`} />
            </button>
            <button
              aria-label="Icon button" onClick={() => setShowShareModal(true)}
              className="p-2.5 rounded-full bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors"
            >
              <Share2 className="w-5 h-5" />
            </button>
            <button
              onClick={onClose}
              className="p-2.5 rounded-full bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        <div className="grid lg:grid-cols-5 overflow-y-auto max-h-[calc(90vh-70px)]">
          <div className="lg:col-span-3 p-6">
            <div className="relative aspect-[4/3] rounded-2xl overflow-hidden mb-4">
              <img
                src={equipment.images[currentImageIndex]}
                alt={equipment.title}
                className="w-full h-full object-cover"
              />
              {equipment.images.length > 1 && (
                <>
                  <button
                    onClick={prevImage}
                    className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white/90 flex items-center justify-center text-gray-800 hover:bg-white transition-colors shadow-lg"
                  >
                    <ChevronLeft className="w-6 h-6" />
                  </button>
                  <button
                    onClick={nextImage}
                    className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white/90 flex items-center justify-center text-gray-800 hover:bg-white transition-colors shadow-lg"
                   aria-label="Icon button">
                    <ChevronRight className="w-6 h-6" />
                  </button>
                  <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2">
                    {equipment.images.map((_, index) => (
                      <button
                        key={index}
                        aria-label="Icon button" onClick={() => setCurrentImageIndex(index)}
                        className={`w-2 h-2 rounded-full transition-all ${
                          index === currentImageIndex
                            ? 'bg-white w-6'
                            : 'bg-white/50 hover:bg-white/75'
                        }`}
                      />
                    ))}
                  </div>
                </>
              )}
            </div>

            {equipment.images.length > 1 && (
              <div className="flex gap-2 overflow-x-auto pb-2">
                {equipment.images.map((image, index) => (
                  <button
                    key={index}
                    aria-label="Icon button" onClick={() => setCurrentImageIndex(index)}
                    className={`flex-shrink-0 w-20 h-20 rounded-lg overflow-hidden border-2 transition-all ${
                      index === currentImageIndex
                        ? 'border-teal-500'
                        : 'border-transparent opacity-60 hover:opacity-100'
                    }`}
                  >
                    <img
                      src={image}
                      alt={`${equipment.title} ${index + 1}`}
                      className="w-full h-full object-cover"
                    />
                  </button>
                ))}
              </div>
            )}

            <div className="mt-6">
              <div className="flex items-start justify-between gap-4 mb-4">
                <div>
                  <h1 className="text-2xl font-bold text-gray-900 mb-2">
                    {equipment.title}
                  </h1>
                  <div className="flex items-center gap-4 text-sm">
                    <div className="flex items-center gap-1">
                      <Star className="w-5 h-5 text-amber-500 fill-amber-500" />
                      <span className="font-semibold text-gray-900">
                        {equipment.rating.toFixed(1)}
                      </span>
                      <span className="text-gray-500">
                        ({equipment.total_reviews} reviews)
                      </span>
                    </div>
                    <div className="flex items-center gap-1 text-gray-500">
                      <MapPin className="w-4 h-4" />
                      {equipment.location}
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex flex-wrap gap-2 mb-6">
                {equipment.is_featured && (
                  <span className="flex items-center gap-1.5 px-3 py-1.5 bg-amber-50 text-amber-700 rounded-full text-sm font-medium">
                    <Award className="w-4 h-4" />
                    Featured
                  </span>
                )}
                <span className="flex items-center gap-1.5 px-3 py-1.5 bg-teal-50 text-teal-700 rounded-full text-sm font-medium">
                  <Shield className="w-4 h-4" />
                  Verified Owner
                </span>
                <span className="flex items-center gap-1.5 px-3 py-1.5 bg-green-50 text-green-700 rounded-full text-sm font-medium capitalize">
                  <CheckCircle2 className="w-4 h-4" />
                  {equipment.condition} Condition
                </span>
                <span className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-50 text-blue-700 rounded-full text-sm font-medium">
                  <Truck className="w-4 h-4" />
                  Delivery Available
                </span>
              </div>

              <div className="border-t border-gray-100 pt-6">
                <h2 className="text-lg font-semibold text-gray-900 mb-3">Description</h2>
                <p className="text-gray-600 leading-relaxed">{equipment.description}</p>
              </div>

              {equipment.features.length > 0 && (
                <div className="border-t border-gray-100 pt-6 mt-6">
                  <h2 className="text-lg font-semibold text-gray-900 mb-3">Features</h2>
                  <div className="grid grid-cols-2 gap-3">
                    {equipment.features.map((feature, index) => (
                      <div
                        key={index}
                        className="flex items-center gap-2 text-gray-600"
                      >
                        <CheckCircle2 className="w-5 h-5 text-teal-500 flex-shrink-0" />
                        {feature}
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {Object.keys(equipment.specifications).length > 0 && (
                <div className="border-t border-gray-100 pt-6 mt-6">
                  <h2 className="text-lg font-semibold text-gray-900 mb-3">
                    Specifications
                  </h2>
                  <div className="grid grid-cols-2 gap-4">
                    {Object.entries(equipment.specifications).map(([key, value]) => (
                      <div key={key} className="flex justify-between py-2 border-b border-gray-50">
                        <span className="text-gray-500 capitalize">{key}</span>
                        <span className="font-medium text-gray-900">{value}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              <div className="border-t border-gray-100 pt-6 mt-6">
                <div className="flex items-center justify-between mb-3">
                  <h2 className="text-lg font-semibold text-gray-900">
                    Maintenance Status
                  </h2>
                  <button
                    aria-label="Icon button" onClick={() => setShowMaintenance(true)}
                    className="text-teal-600 hover:text-teal-700 text-sm font-medium"
                  >
                    View Details →
                  </button>
                </div>
                <div className="flex items-center gap-3 p-4 bg-green-50 rounded-xl">
                  <CheckCircle2 className="w-6 h-6 text-green-600" />
                  <div>
                    <p className="font-medium text-green-800">Equipment is in good condition</p>
                    <p className="text-sm text-green-600">Last maintenance: 2 weeks ago</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:col-span-2 bg-gray-50 p-6">
            <div className="sticky top-6">
              <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
                <div className="flex items-end justify-between mb-6">
                  <div>
                    <span className="text-3xl font-bold text-gray-900">
                      ${equipment.daily_rate}
                    </span>
                    <span className="text-gray-500">/day</span>
                  </div>
                  <div className="text-right text-sm text-gray-500">
                    {equipment.weekly_rate && (
                      <p>${equipment.weekly_rate}/week</p>
                    )}
                    {equipment.monthly_rate && (
                      <p>${equipment.monthly_rate}/month</p>
                    )}
                  </div>
                </div>

                <div className="space-y-4 mb-6">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        Start Date
                      </label>
                      <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                        <input
                          type="date"
                          value={startDate}
                          onChange={(e) => setStartDate(e.target.value)}
                          className="w-full pl-10 pr-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                        />
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        End Date
                      </label>
                      <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                        <input
                          type="date"
                          value={endDate}
                          onChange={(e) => setEndDate(e.target.value)}
                          className="w-full pl-10 pr-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
                        />
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-2 px-4 py-3 bg-blue-50 rounded-xl text-sm text-blue-700">
                    <Info className="w-5 h-5 flex-shrink-0" />
                    <span>
                      Min {equipment.min_rental_days} days, max {equipment.max_rental_days} days rental
                    </span>
                  </div>
                </div>

                {pricing && (
                  <div className="border-t border-gray-100 pt-4 mb-6 space-y-3">
                    <div className="flex justify-between text-gray-600">
                      <span>
                        ${equipment.daily_rate} x {pricing.days} days
                      </span>
                      <span>${pricing.subtotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-gray-600">
                      <span>Service fee (12%)</span>
                      <span>${pricing.serviceFee.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-gray-600">
                      <span>Refundable deposit</span>
                      <span>${equipment.deposit_amount.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-lg font-semibold text-gray-900 pt-3 border-t border-gray-100">
                      <span>Total</span>
                      <span>${pricing.total.toFixed(2)}</span>
                    </div>
                  </div>
                )}

                <button
                  aria-label="Icon button" onClick={() => onBook(equipment, { start: startDate, end: endDate })}
                  disabled={!pricing}
                  className="w-full py-4 bg-gradient-to-r from-teal-500 to-emerald-500 text-white font-semibold rounded-xl hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed mb-3"
                >
                  {pricing ? 'Reserve Now' : 'Select Dates to Book'}
                </button>

                <button
                  aria-label="Icon button" onClick={() => onMessage(equipment)}
                  className="w-full py-4 border border-gray-200 text-gray-700 font-semibold rounded-xl hover:bg-gray-50 transition-colors flex items-center justify-center gap-2"
                >
                  <MessageSquare className="w-5 h-5" />
                  Message Owner
                </button>

                <button
                  aria-label="Icon button" onClick={() => setShowNegotiator(true)}
                  className="w-full py-4 border border-orange-200 text-orange-700 font-semibold rounded-xl hover:bg-orange-50 transition-colors flex items-center justify-center gap-2"
                >
                  <DollarSign className="w-5 h-5" />
                  Negotiate Price
                </button>

                <div className="mt-6 p-4 bg-gray-50 rounded-xl">
                  <div className="flex items-start gap-3">
                    <div className="w-12 h-12 rounded-full bg-gradient-to-br from-teal-400 to-emerald-500 flex items-center justify-center text-white font-bold">
                      {equipment.owner?.full_name?.charAt(0) || 'O'}
                    </div>
                    <div className="flex-1">
                      <p className="font-semibold text-gray-900">
                        {equipment.owner?.full_name || 'Owner'}
                      </p>
                      <div className="flex items-center gap-2 text-sm text-gray-500">
                        <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                        <span>
                          {equipment.owner?.rating?.toFixed(1) || '5.0'} (
                          {equipment.owner?.total_reviews || 0} reviews)
                        </span>
                      </div>
                      {equipment.owner?.is_verified && (
                        <span className="inline-flex items-center gap-1 text-sm text-teal-600 mt-1">
                          <Shield className="w-4 h-4" />
                          Verified
                        </span>
                      )}
                    </div>
                  </div>
                </div>

                <div className="mt-4 flex items-start gap-2 text-sm text-gray-500">
                  <AlertCircle className="w-5 h-5 flex-shrink-0 text-gray-400" />
                  <p>
                    Free cancellation up to 48 hours before pickup. Deposit fully
                    refundable upon return.
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Share Equipment Modal */}
      <ShareEquipment
        equipmentId={equipment.id}
        equipmentTitle={equipment.title}
        equipmentImage={equipment.images[0]}
        isOpen={showShareModal}
        onClose={() => setShowShareModal(false)}
      />

      {showNegotiator && pricing && (
        <PriceNegotiator
          equipmentId={equipment.id}
          equipmentTitle={equipment.title}
          originalDailyRate={equipment.daily_rate}
          ownerId={equipment.owner_id}
          ownerName={equipment.owner?.full_name || 'Owner'}
          rentalDays={pricing.days}
          onAccepted={() => {
            // Handle accepted negotiation
            setShowNegotiator(false);
            // Could update the booking with negotiated price
          }}

          onRejected={() => setShowNegotiator(false)}
          onClose={() => setShowNegotiator(false)}
        />
      )}

      {showMaintenance && (
        <MaintenancePredictor
          equipmentId={equipment.id}
          equipmentTitle={equipment.title}
          category={equipment.category_id ?? ''}
          hoursUsed={500} // Mock data
          lastMaintenanceDate={new Date(Date.now() - 14 * 24 * 60 * 60 * 1000)} // 2 weeks ago
          onScheduleMaintenance={() => {
            // Handle scheduling
            setShowMaintenance(false);
          }}
          onClose={() => setShowMaintenance(false)}
        />
      )}
    </div>
  );
}

import { useState } from 'react';
import {
  Share2,
  Copy,
  Mail,
  MessageCircle,
  Facebook,
  Twitter,
  Instagram,
  X,
  Check,
  ExternalLink,
} from 'lucide-react';
import { Button } from '../ui/Button';
import { useToast } from '../ui/Toast';

interface ShareEquipmentProps {
  equipmentId: string;
  equipmentTitle: string;
  equipmentImage?: string;
  isOpen: boolean;
  onClose: () => void;
}

export default function ShareEquipment({
  equipmentId,
  equipmentTitle,
  equipmentImage,
  isOpen,
  onClose
}: ShareEquipmentProps) {  const { success } = useToast();  const [copied, setCopied] = useState(false);

  if (!isOpen) return null;

  const shareUrl = `${window.location.origin}/equipment/${equipmentId}`;
  const shareText = `Check out this equipment for rent: ${equipmentTitle}`;
  const encodedUrl = encodeURIComponent(shareUrl);
  const encodedText = encodeURIComponent(shareText);

  const shareOptions = [
    {
      name: 'Copy Link',
      icon: Copy,
      action: async () => {
        try {
          await navigator.clipboard.writeText(shareUrl);
          setCopied(true);
          success('Link copied to clipboard!');
          setTimeout(() => setCopied(false), 2000);
        } catch (_error) { // eslint-disable-line @typescript-eslint/no-unused-vars
          // Fallback for older browsers
          const textArea = document.createElement('textarea');
          textArea.value = shareUrl;
          document.body.appendChild(textArea);
          textArea.select();
          document.execCommand('copy');
          document.body.removeChild(textArea);
          setCopied(true);
          success('Link copied to clipboard!');
          setTimeout(() => setCopied(false), 2000);
        }
      },
      color: 'bg-gray-100 hover:bg-gray-200 text-gray-700',
    },
    {
      name: 'Email',
      icon: Mail,
      action: () => {
        const subject = encodeURIComponent(`Equipment Rental: ${equipmentTitle}`);
        const body = encodeURIComponent(`${shareText}\n\n${shareUrl}`);
        window.open(`mailto:?subject=${subject}&body=${body}`);
      },
      color: 'bg-red-100 hover:bg-red-200 text-red-700',
    },
    {
      name: 'Facebook',
      icon: Facebook,
      action: () => {
        window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}`, '_blank');
      },
      color: 'bg-blue-100 hover:bg-blue-200 text-blue-700',
    },
    {
      name: 'Twitter',
      icon: Twitter,
      action: () => {
        window.open(`https://twitter.com/intent/tweet?text=${encodedText}&url=${encodedUrl}`, '_blank');
      },
      color: 'bg-sky-100 hover:bg-sky-200 text-sky-700',
    },
    {
      name: 'WhatsApp',
      icon: MessageCircle,
      action: () => {
        window.open(`https://wa.me/?text=${encodedText}%20${encodedUrl}`, '_blank');
      },
      color: 'bg-green-100 hover:bg-green-200 text-green-700',
    },
    {
      name: 'Instagram',
      icon: Instagram,
      action: () => {
        // Instagram doesn't support direct sharing, so we'll copy to clipboard
        navigator.clipboard.writeText(`${shareText} ${shareUrl}`);
        success('Content copied! You can now paste it in Instagram.');
      },
      color: 'bg-pink-100 hover:bg-pink-200 text-pink-700',
    },
  ];

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg shadow-xl max-w-md w-full">
        <div className="flex items-center justify-between p-6 border-b">
          <div className="flex items-center space-x-2">
            <Share2 className="h-6 w-6 text-teal-600" />
            <h2 className="text-xl font-semibold text-gray-900">Share Equipment</h2>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600"
          >
            <X className="h-6 w-6" />
          </button>
        </div>

        <div className="p-6">
          {/* Equipment Preview */}
          <div className="flex items-center space-x-3 mb-6 p-3 bg-gray-50 rounded-lg">
            {equipmentImage && (
              <img
                src={equipmentImage}
                alt={equipmentTitle}
                className="w-12 h-12 rounded-lg object-cover"
              />
            )}
            <div className="flex-1">
              <h3 className="font-medium text-gray-900 text-sm">{equipmentTitle}</h3>
              <p className="text-xs text-gray-500">Available for rent on Islakayd</p>
            </div>
          </div>

          {/* Share URL */}
          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Share Link
            </label>
            <div className="flex space-x-2">
              <input
                type="text"
                value={shareUrl}
                readOnly
                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-sm bg-gray-50"
              />
              <Button
                onClick={async () => {
                  try {
                    await navigator.clipboard.writeText(shareUrl);
                    setCopied(true);
                    success('Link copied!');
                    setTimeout(() => setCopied(false), 2000);
                  } catch (copyError) {
                    console.error('Failed to copy link:', copyError);
                  }
                }}
                variant="outline"
                size="sm"
                className="flex items-center space-x-1"
              >
                {copied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                <span>{copied ? 'Copied!' : 'Copy'}</span>
              </Button>
            </div>
          </div>

          {/* Share Options */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-3">
              Share via
            </label>
            <div className="grid grid-cols-2 gap-3">
              {shareOptions.map((option) => (
                <button
                  key={option.name}
                  onClick={option.action}
                  className={`flex items-center space-x-2 p-3 rounded-lg transition-colors ${option.color} aria-label="Icon button">
                  <option.icon className="w-5 h-5" />
                  <span className="text-sm font-medium">{option.name}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Additional Actions */}
          <div className="mt-6 pt-4 border-t">
            <button
              aria-label="Icon button" onClick={() => window.open(shareUrl, '_blank')}
              className="flex items-center space-x-2 text-teal-600 hover:text-teal-700 text-sm font-medium"
            >
              <ExternalLink className="w-4 h-4" />
              <span>Open in new tab</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useMemo } from 'react';
import {
  Heart,
  Plus,
  Folder,
  FolderPlus,
  Edit2,
  Trash2,
  MoreVertical,
  X,
  Check,
  Share2,
  Lock,
  Globe,
  Image,
  Package,
  Star,
  ChevronRight,
  Search,
  Grid3X3,
  List,
} from 'lucide-react';

interface Equipment {
  id: string;
  title: string;
  daily_rate: number;
  image_url: string;
  rating: number;
  location: string;
}

interface WishlistCollection {
  id: string;
  name: string;
  description?: string;
  coverImage?: string;
  items: Equipment[];
  isPrivate: boolean;
  createdAt: Date;
  updatedAt: Date;
}

interface WishlistCollectionsProps {
  collections?: WishlistCollection[];
  allFavorites?: Equipment[];
  onCreateCollection: (name: string, description?: string, isPrivate?: boolean) => Promise<void>;
  onDeleteCollection: (id: string) => Promise<void>;
  onUpdateCollection: (id: string, data: Partial<WishlistCollection>) => Promise<void>;
  onAddToCollection: (collectionId: string, equipmentId: string) => Promise<void>;
  onRemoveFromCollection: (collectionId: string, equipmentId: string) => Promise<void>;
  onEquipmentClick: (equipment: Equipment) => void;
  className?: string;
}

const demoCollections: WishlistCollection[] = [
  {
    id: 'c1',
    name: 'Construction Project',
    description: 'Equipment for the summer construction site',
    items: [
      { id: 'e1', title: 'CAT 320 Excavator', daily_rate: 450, image_url: 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=400', rating: 4.9, location: 'San Francisco, CA' },
      { id: 'e2', title: 'Bobcat S650 Skid Steer', daily_rate: 275, image_url: 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=400', rating: 4.7, location: 'Oakland, CA' },
    ],
    isPrivate: false,
    createdAt: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000),
    updatedAt: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
  },
  {
    id: 'c2',
    name: 'Landscaping Tools',
    description: 'For the backyard renovation',
    items: [
      { id: 'e3', title: 'Mini Excavator', daily_rate: 195, image_url: 'https://images.unsplash.com/photo-1580256081112-e49377338b7f?w=400', rating: 4.8, location: 'San Jose, CA' },
    ],
    isPrivate: true,
    createdAt: new Date(Date.now() - 15 * 24 * 60 * 60 * 1000),
    updatedAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000),
  },
];

export default function WishlistCollections({
  collections = demoCollections,
  allFavorites = [],
  onCreateCollection,
  onDeleteCollection,
  onUpdateCollection,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  onAddToCollection: _onAddToCollection,
  onRemoveFromCollection,
  onEquipmentClick,
  className = '',
}: WishlistCollectionsProps) {
  const [selectedCollection, setSelectedCollection] = useState<WishlistCollection | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingCollection, setEditingCollection] = useState<WishlistCollection | null>(null);
  const [menuOpen, setMenuOpen] = useState<string | null>(null);

  // New collection form state
  const [newName, setNewName] = useState('');
  const [newDescription, setNewDescription] = useState('');
  const [newIsPrivate, setNewIsPrivate] = useState(false);

  const filteredCollections = useMemo(() => {
    if (!searchQuery) return collections;
    const query = searchQuery.toLowerCase();
    return collections.filter(
      (c) =>
        c.name.toLowerCase().includes(query) ||
        c.description?.toLowerCase().includes(query)
    );
  }, [collections, searchQuery]);

  const handleCreateCollection = async () => {
    if (!newName.trim()) return;
    await onCreateCollection(newName, newDescription, newIsPrivate);
    setShowCreateModal(false);
    setNewName('');
    setNewDescription('');
    setNewIsPrivate(false);
  };

  const handleEditCollection = async () => {
    if (!editingCollection || !newName.trim()) return;
    await onUpdateCollection(editingCollection.id, {
      name: newName,
      description: newDescription,
      isPrivate: newIsPrivate,
    });
    setShowEditModal(false);
    setEditingCollection(null);
  };

  const openEditModal = (collection: WishlistCollection) => {
    setEditingCollection(collection);
    setNewName(collection.name);
    setNewDescription(collection.description || '');
    setNewIsPrivate(collection.isPrivate);
    setShowEditModal(true);
    setMenuOpen(null);
  };

  const handleDeleteCollection = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this collection?')) {
      await onDeleteCollection(id);
    }
    setMenuOpen(null);
  };

  const shareCollection = (collection: WishlistCollection) => {
    const url = `${window.location.origin}/wishlist/${collection.id}`;
    navigator.clipboard.writeText(url);
    alert('Collection link copied to clipboard!');
    setMenuOpen(null);
  };

  return (
    <div className={`bg-white dark:bg-gray-800 rounded-2xl shadow-xl overflow-hidden ${className}`}>
      {/* Header */}
      <div className="p-6 border-b dark:border-gray-700">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-red-100 dark:bg-red-900/30 rounded-xl flex items-center justify-center">
              <Heart className="w-6 h-6 text-red-600 fill-red-600" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                {selectedCollection ? selectedCollection.name : 'My Collections'}
              </h2>
              <p className="text-sm text-gray-500 dark:text-gray-400">
                {selectedCollection
                  ? `${selectedCollection.items.length} items`
                  : `${collections.length} collections • ${allFavorites.length} total items`}
              </p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            {selectedCollection ? (
              <button
                aria-label="Icon button" onClick={() => setSelectedCollection(null)}
                className="px-4 py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
              >
                Back to Collections
              </button>
            ) : (
              <>
                <button
                  aria-label="Icon button" onClick={() => setShowCreateModal(true)}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700"
                >
                  <FolderPlus className="w-5 h-5" />
                  New Collection
                </button>
              </>
            )}
          </div>
        </div>

        {/* Search and View Toggle */}
        <div className="flex items-center gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder={selectedCollection ? 'Search items...' : 'Search collections...'}
              className="w-full pl-10 pr-4 py-2 border dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 dark:text-white"
            />
          </div>
          <div className="flex items-center gap-1 bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
            <button
              aria-label="Icon button" onClick={() => setViewMode('grid')}
              className={`p-2 rounded ${
                viewMode === 'grid'
                  ? 'bg-white dark:bg-gray-600 shadow'
                  : 'hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              <Grid3X3 className="w-5 h-5 text-gray-600 dark:text-gray-300" />
            </button>
            <button
              aria-label="Icon button" onClick={() => setViewMode('list')}
              className={`p-2 rounded ${
                viewMode === 'list'
                  ? 'bg-white dark:bg-gray-600 shadow'
                  : 'hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              <List className="w-5 h-5 text-gray-600 dark:text-gray-300" />
            </button>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="p-6 max-h-[600px] overflow-y-auto">
        {!selectedCollection ? (
          /* Collections Grid */
          filteredCollections.length === 0 ? (
            <div className="text-center py-12">
              <Folder className="w-16 h-16 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
                {searchQuery ? 'No collections found' : 'No collections yet'}
              </h3>
              <p className="text-gray-500 dark:text-gray-400 mb-4">
                {searchQuery
                  ? 'Try a different search term'
                  : 'Create a collection to organize your favorites'}
              </p>
              {!searchQuery && (
                <button
                  aria-label="Icon button" onClick={() => setShowCreateModal(true)}
                  className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700"
                >
                  <Plus className="w-5 h-5" />
                  Create First Collection
                </button>
              )}
            </div>
          ) : viewMode === 'grid' ? (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {filteredCollections.map((collection) => (
                <div
                  key={collection.id}
                  className="group relative bg-gray-50 dark:bg-gray-700/50 rounded-xl overflow-hidden cursor-pointer hover:shadow-lg transition-shadow"
                  onClick={() => setSelectedCollection(collection)}
                >
                  {/* Cover Image Grid */}
                  <div className="aspect-square relative">
                    {collection.items.length > 0 ? (
                      <div className="grid grid-cols-2 gap-0.5 h-full">
                        {collection.items.slice(0, 4).map((item, i) => (
                          <div
                            key={item.id}
                            className={`bg-gray-200 dark:bg-gray-600 ${
                              collection.items.length === 1 ? 'col-span-2 row-span-2' :
                              collection.items.length === 2 ? 'row-span-2' :
                              collection.items.length === 3 && i === 0 ? 'row-span-2' : ''
                            }`}
                          >
                            <img
                              src={item.image_url}
                              alt={item.title}
                              className="w-full h-full object-cover"
                            />
                          </div>
                        ))}
                        {collection.items.length < 4 && collection.items.length !== 1 && collection.items.length !== 2 && (
                          [...Array(4 - collection.items.length)].map((_, i) => (
                            <div key={`empty-${i}`} className="bg-gray-200 dark:bg-gray-600 flex items-center justify-center">
                              <Image className="w-8 h-8 text-gray-400" />
                            </div>
                          ))
                        )}
                      </div>
                    ) : (
                      <div className="w-full h-full bg-gray-200 dark:bg-gray-600 flex items-center justify-center">
                        <Folder className="w-16 h-16 text-gray-400" />
                      </div>
                    )}

                    {/* Privacy Badge */}
                    {collection.isPrivate && (
                      <div className="absolute top-2 left-2 px-2 py-1 bg-black/50 rounded-full flex items-center gap-1">
                        <Lock className="w-3 h-3 text-white" />
                        <span className="text-xs text-white">Private</span>
                      </div>
                    )}

                    {/* Menu Button */}
                    <button
                      onClick={(e) = aria-label="Icon button"> {
                        e.stopPropagation();
                        setMenuOpen(menuOpen === collection.id ? null : collection.id);
                      }}
                      className="absolute top-2 right-2 w-8 h-8 bg-black/50 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <MoreVertical className="w-4 h-4 text-white" />
                    </button>

                    {/* Dropdown Menu */}
                    {menuOpen === collection.id && (
                      <div
                        className="absolute top-12 right-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg py-1 z-10 min-w-[140px]"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <button
                          aria-label="Icon button" onClick={() => openEditModal(collection)}
                          className="w-full px-4 py-2 text-left text-sm hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center gap-2"
                        >
                          <Edit2 className="w-4 h-4" />
                          Edit
                        </button>
                        {!collection.isPrivate && (
                          <button
                            aria-label="Icon button" onClick={() => shareCollection(collection)}
                            className="w-full px-4 py-2 text-left text-sm hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center gap-2"
                          >
                            <Share2 className="w-4 h-4" />
                            Share
                          </button>
                        )}
                        <button
                          aria-label="Icon button" onClick={() => handleDeleteCollection(collection.id)}
                          className="w-full px-4 py-2 text-left text-sm hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center gap-2 text-red-600"
                        >
                          <Trash2 className="w-4 h-4" />
                          Delete
                        </button>
                      </div>
                    )}
                  </div>

                  {/* Collection Info */}
                  <div className="p-3">
                    <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                      {collection.name}
                    </h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      {collection.items.length} items
                    </p>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            /* List View */
            <div className="space-y-3">
              {filteredCollections.map((collection) => (
                <div
                  key={collection.id}
                  className="flex items-center gap-4 p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                  onClick={() => setSelectedCollection(collection)}
                >
                  <div className="w-16 h-16 rounded-lg overflow-hidden flex-shrink-0">
                    {collection.items.length > 0 ? (
                      <img
                        src={collection.items[0].image_url}
                        alt={collection.name}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <div className="w-full h-full bg-gray-200 dark:bg-gray-600 flex items-center justify-center">
                        <Folder className="w-8 h-8 text-gray-400" />
                      </div>
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                        {collection.name}
                      </h3>
                      {collection.isPrivate && (
                        <Lock className="w-4 h-4 text-gray-400" />
                      )}
                    </div>
                    <p className="text-sm text-gray-500 dark:text-gray-400 truncate">
                      {collection.description || `${collection.items.length} items`}
                    </p>
                  </div>
                  <ChevronRight className="w-5 h-5 text-gray-400" />
                </div>
              ))}
            </div>
          )
        ) : (
          /* Collection Items */
          selectedCollection.items.length === 0 ? (
            <div className="text-center py-12">
              <Package className="w-16 h-16 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
                No items in this collection
              </h3>
              <p className="text-gray-500 dark:text-gray-400">
                Browse equipment and add favorites to this collection
              </p>
            </div>
          ) : viewMode === 'grid' ? (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {selectedCollection.items.map((item) => (
                <div
                  key={item.id}
                  className="group bg-gray-50 dark:bg-gray-700/50 rounded-xl overflow-hidden cursor-pointer hover:shadow-lg transition-shadow"
                  onClick={() => onEquipmentClick(item)}
                >
                  <div className="aspect-square relative">
                    <img
                      src={item.image_url}
                      alt={item.title}
                      className="w-full h-full object-cover"
                    />
                    <button
                      onClick={(e) = aria-label="Icon button"> {
                        e.stopPropagation();
                        onRemoveFromCollection(selectedCollection.id, item.id);
                      }}
                      className="absolute top-2 right-2 w-8 h-8 bg-white/80 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-white"
                    >
                      <Heart className="w-4 h-4 text-red-500 fill-red-500" />
                    </button>
                  </div>
                  <div className="p-3">
                    <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                      {item.title}
                    </h3>
                    <div className="flex items-center justify-between mt-1">
                      <span className="text-emerald-600 font-bold">${item.daily_rate}/day</span>
                      <div className="flex items-center gap-1 text-sm text-gray-500">
                        <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                        {item.rating}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="space-y-3">
              {selectedCollection.items.map((item) => (
                <div
                  key={item.id}
                  className="flex items-center gap-4 p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                  onClick={() => onEquipmentClick(item)}
                >
                  <img
                    src={item.image_url}
                    alt={item.title}
                    className="w-20 h-20 object-cover rounded-lg"
                  />
                  <div className="flex-1 min-w-0">
                    <h3 className="font-semibold text-gray-900 dark:text-white">
                      {item.title}
                    </h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      {item.location}
                    </p>
                    <div className="flex items-center gap-3 mt-1">
                      <span className="text-emerald-600 font-bold">${item.daily_rate}/day</span>
                      <div className="flex items-center gap-1 text-sm text-gray-500">
                        <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                        {item.rating}
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={(e) = aria-label="Icon button"> {
                      e.stopPropagation();
                      onRemoveFromCollection(selectedCollection.id, item.id);
                    }}
                    className="p-2 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-lg"
                  >
                    <Heart className="w-5 h-5 text-red-500 fill-red-500" />
                  </button>
                </div>
              ))}
            </div>
          )
        )}
      </div>

      {/* Create/Edit Modal */}
      {(showCreateModal || showEditModal) && (
        <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl w-full max-w-md p-6">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white">
                {showCreateModal ? 'Create Collection' : 'Edit Collection'}
              </h3>
              <button
                aria-label="Icon button"> {
                  setShowCreateModal(false);
                  setShowEditModal(false);
                  setEditingCollection(null);
                }}
                className="w-8 h-8 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 flex items-center justify-center"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Name *
                </label>
                <input
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="e.g., Construction Equipment"
                  className="w-full px-4 py-2 border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Description
                </label>
                <textarea
                  value={newDescription}
                  onChange={(e) => setNewDescription(e.target.value)}
                  placeholder="What is this collection for?"
                  rows={3}
                  className="w-full px-4 py-2 border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white resize-none"
                />
              </div>

              <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-gray-700/50 rounded-lg">
                <div className="flex items-center gap-3">
                  {newIsPrivate ? (
                    <Lock className="w-5 h-5 text-gray-600 dark:text-gray-400" />
                  ) : (
                    <Globe className="w-5 h-5 text-gray-600 dark:text-gray-400" />
                  )}
                  <div>
                    <p className="font-medium text-gray-900 dark:text-white">
                      {newIsPrivate ? 'Private' : 'Public'}
                    </p>
                    <p className="text-xs text-gray-500 dark:text-gray-400">
                      {newIsPrivate ? 'Only you can see this' : 'Anyone with the link can view'}
                    </p>
                  </div>
                </div>
                <button
                  aria-label="Icon button" onClick={() => setNewIsPrivate(!newIsPrivate)}
                  className={`w-12 h-6 rounded-full transition-colors ${
                    newIsPrivate ? 'bg-emerald-600' : 'bg-gray-300 dark:bg-gray-600'
                  }`}
                >
                  <div
                    className={`w-5 h-5 bg-white rounded-full shadow transform transition-transform ${
                      newIsPrivate ? 'translate-x-6' : 'translate-x-0.5'
                    }`}
                  />
                </button>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button
                aria-label="Icon button"> {
                  setShowCreateModal(false);
                  setShowEditModal(false);
                }}
                className="flex-1 py-2 border dark:border-gray-600 rounded-lg text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700"
              >
                Cancel
              </button>
              <button
                onClick={showCreateModal ? handleCreateCollection : handleEditCollection}
                disabled={!newName.trim()}
                className="flex-1 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 disabled:opacity-50 flex items-center justify-center gap-2"
               aria-label="Icon button">
                <Check className="w-5 h-5" />
                {showCreateModal ? 'Create' : 'Save'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import {
  Trophy,
  Star,
  Award,
  Medal,
  Crown,
  Zap,
  Heart,
  Users,
  Calendar,
  TrendingUp,
  Gift,
  Lock,
  CheckCircle,
} from 'lucide-react';
// No additional types needed
import { getBookings } from '../../services/database';
import { useAuth } from '../../contexts/AuthContext';

interface GamificationHubProps {
  className?: string;
}

interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: typeof Trophy;
  color: string;
  bgColor: string;
  unlocked: boolean;
  progress: number;
  maxProgress: number;
  reward: string;
  rarity: 'common' | 'rare' | 'epic' | 'legendary';
}

interface UserStats {
  totalBookings: number;
  totalRevenue: number;
  averageRating: number;
  streakDays: number;
  referralCount: number;
  badgesEarned: number;
  level: number;
  experience: number;
  nextLevelExp: number;
}

export default function GamificationHub({ className = '' }: GamificationHubProps) {
  const { user } = useAuth();
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [userStats, setUserStats] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedTab, setSelectedTab] = useState<'achievements' | 'leaderboard' | 'rewards'>('achievements');

  useEffect(() => {
    const loadGamificationData = async () => {
      if (!user) return;

      try {
        const bookings = await getBookings({ renterId: user.id });

        // Calculate user stats
        const totalBookings = bookings.length;
        const totalRevenue = bookings
          .filter(b => b.status === 'completed')
          .reduce((sum, b) => sum + b.total_amount, 0);

        const averageRating = bookings.length > 0
          ? bookings.reduce((sum, b) => sum + (b.equipment?.rating || 0), 0) / bookings.length
          : 0;

        // Calculate experience and level
        const experience = totalBookings * 10 + Math.floor(totalRevenue / 10) + Math.floor(averageRating * 20);
        const level = Math.floor(experience / 100) + 1;
        const nextLevelExp = level * 100;

        setUserStats({
          totalBookings,
          totalRevenue,
          averageRating,
          streakDays: 7, // Mock data
          referralCount: 3, // Mock data
          badgesEarned: 0,
          level,
          experience,
          nextLevelExp,
        });

        // Define achievements
        const achievementList: Achievement[] = [
          {
            id: 'first-booking',
            title: 'First Steps',
            description: 'Complete your first equipment booking',
            icon: Star,
            color: 'text-yellow-600',
            bgColor: 'bg-yellow-100',
            unlocked: totalBookings >= 1,
            progress: Math.min(totalBookings, 1),
            maxProgress: 1,
            reward: '10% off next booking',
            rarity: 'common',
          },
          {
            id: 'booking-streak',
            title: 'Consistent Renter',
            description: 'Book equipment for 7 consecutive days',
            icon: Calendar,
            color: 'text-blue-600',
            bgColor: 'bg-blue-100',
            unlocked: false, // Mock logic
            progress: 5,
            maxProgress: 7,
            reward: 'Free delivery',
            rarity: 'rare',
          },
          {
            id: 'high-ratings',
            title: 'Five-Star Customer',
            description: 'Maintain a 4.8+ average rating',
            icon: Award,
            color: 'text-purple-600',
            bgColor: 'bg-purple-100',
            unlocked: averageRating >= 4.8,
            progress: Math.floor(averageRating * 10),
            maxProgress: 48,
            reward: 'Priority support',
            rarity: 'epic',
          },
          {
            id: 'revenue-milestone',
            title: 'Revenue Champion',
            description: 'Generate $10,000+ in total bookings',
            icon: TrendingUp,
            color: 'text-green-600',
            bgColor: 'bg-green-100',
            unlocked: totalRevenue >= 10000,
            progress: Math.min(Math.floor(totalRevenue), 10000),
            maxProgress: 10000,
            reward: 'Exclusive equipment access',
            rarity: 'legendary',
          },
          {
            id: 'referral-master',
            title: 'Referral Guru',
            description: 'Refer 10 friends who make bookings',
            icon: Users,
            color: 'text-indigo-600',
            bgColor: 'bg-indigo-100',
            unlocked: false, // Mock
            progress: 3,
            maxProgress: 10,
            reward: '$50 bonus credit',
            rarity: 'epic',
          },
          {
            id: 'loyal-customer',
            title: 'Loyal Customer',
            description: 'Complete 50+ bookings',
            icon: Heart,
            color: 'text-red-600',
            bgColor: 'bg-red-100',
            unlocked: totalBookings >= 50,
            progress: Math.min(totalBookings, 50),
            maxProgress: 50,
            reward: 'VIP membership',
            rarity: 'legendary',
          },
        ];

        setAchievements(achievementList);

      } catch (error) {
        console.error('Failed to load gamification data:', error);
      } finally {
        setLoading(false);
      }
    };

    loadGamificationData();
  }, [user]);

  const unlockedAchievements = useMemo(() =>
    achievements.filter(a => a.unlocked),
    [achievements]
  );

  const lockedAchievements = useMemo(() =>
    achievements.filter(a => !a.unlocked),
    [achievements]
  );

  const getRarityColor = (rarity: Achievement['rarity']) => {
    switch (rarity) {
      case 'common': return 'text-gray-600 bg-gray-100';
      case 'rare': return 'text-blue-600 bg-blue-100';
      case 'epic': return 'text-purple-600 bg-purple-100';
      case 'legendary': return 'text-yellow-600 bg-yellow-100';
    }
  };

  if (loading) {
    return (
      <div className={`animate-pulse ${className}`}>
        <div className="bg-white rounded-xl p-6 border border-gray-100">
          <div className="h-8 bg-gray-200 rounded w-64 mb-6"></div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-20 bg-gray-200 rounded"></div>
            ))}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="h-32 bg-gray-200 rounded"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (!userStats) {
    return (
      <div className={`bg-white rounded-xl p-6 border border-gray-100 ${className}`}>
        <div className="text-center text-gray-500">
          <Trophy className="w-12 h-12 mx-auto mb-4 text-gray-300" />
          <p>Unable to load gamification data at this time.</p>
        </div>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Header with Level */}
      <div className="bg-gradient-to-r from-purple-600 to-blue-600 rounded-xl p-6 text-white mb-6">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h2 className="text-2xl font-bold">Gamification Hub</h2>
            <p className="text-purple-100">Earn badges, unlock rewards, and level up!</p>
          </div>
          <div className="text-right">
            <div className="text-3xl font-bold">Level {userStats.level}</div>
            <div className="text-sm text-purple-100">
              {userStats.experience} / {userStats.nextLevelExp} XP
            </div>
          </div>
        </div>
        <div className="w-full bg-purple-700 rounded-full h-3">
          <div
            className="bg-white h-3 rounded-full transition-all duration-500"
            style={{ width: `${(userStats.experience / userStats.nextLevelExp) * 100}%` }}
          ></div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white rounded-lg p-4 border border-gray-100 text-center">
          <div className="text-2xl font-bold text-blue-600">{userStats.totalBookings}</div>
          <div className="text-sm text-gray-600">Total Bookings</div>
        </div>
        <div className="bg-white rounded-lg p-4 border border-gray-100 text-center">
          <div className="text-2xl font-bold text-green-600">${userStats.totalRevenue.toLocaleString()}</div>
          <div className="text-sm text-gray-600">Total Spent</div>
        </div>
        <div className="bg-white rounded-lg p-4 border border-gray-100 text-center">
          <div className="text-2xl font-bold text-yellow-600">{userStats.averageRating.toFixed(1)}</div>
          <div className="text-sm text-gray-600">Avg Rating</div>
        </div>
        <div className="bg-white rounded-lg p-4 border border-gray-100 text-center">
          <div className="text-2xl font-bold text-purple-600">{unlockedAchievements.length}</div>
          <div className="text-sm text-gray-600">Badges Earned</div>
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="flex border-b border-gray-200 mb-6">
        {[
          { id: 'achievements', label: 'Achievements', icon: Trophy },
          { id: 'leaderboard', label: 'Leaderboard', icon: Crown },
          { id: 'rewards', label: 'Rewards', icon: Gift },
        ].map((tab) => {
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              aria-label="Icon button" onClick={() => setSelectedTab(tab.id as typeof selectedTab)}
              className={`flex items-center gap-2 px-4 py-3 border-b-2 font-medium text-sm transition-colors ${
                selectedTab === tab.id
                  ? 'border-purple-600 text-purple-600'
                  : 'border-transparent text-gray-600 hover:text-gray-900'
              }`}
            >
              <Icon className="w-4 h-4" />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Achievements Tab */}
      {selectedTab === 'achievements' && (
        <div className="space-y-6">
          {/* Unlocked Achievements */}
          {unlockedAchievements.length > 0 && (
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
                <CheckCircle className="w-5 h-5 text-green-600" />
                Unlocked Achievements ({unlockedAchievements.length})
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {unlockedAchievements.map((achievement) => {
                  const Icon = achievement.icon;
                  return (
                    <div
                      key={achievement.id}
                      className="bg-white border border-gray-100 rounded-lg p-4 hover:shadow-md transition-shadow"
                    >
                      <div className="flex items-start gap-3">
                        <div className={`p-2 rounded-lg ${achievement.bgColor}`}>
                          <Icon className={`w-6 h-6 ${achievement.color}`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                            <h4 className="font-medium text-gray-900">{achievement.title}</h4>
                            <span className={`px-2 py-0.5 text-xs rounded-full ${getRarityColor(achievement.rarity)}`}>
                              {achievement.rarity}
                            </span>
                          </div>
                          <p className="text-sm text-gray-600 mb-2">{achievement.description}</p>
                          <div className="text-xs text-green-600 font-medium">{achievement.reward}</div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Locked Achievements */}
          {lockedAchievements.length > 0 && (
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
                <Lock className="w-5 h-5 text-gray-400" />
                Locked Achievements ({lockedAchievements.length})
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {lockedAchievements.map((achievement) => {
                  const Icon = achievement.icon;
                  const progressPercent = (achievement.progress / achievement.maxProgress) * 100;
                  return (
                    <div
                      key={achievement.id}
                      className="bg-gray-50 border border-gray-200 rounded-lg p-4 opacity-75"
                    >
                      <div className="flex items-start gap-3">
                        <div className="p-2 rounded-lg bg-gray-200">
                          <Icon className="w-6 h-6 text-gray-400" />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                            <h4 className="font-medium text-gray-700">{achievement.title}</h4>
                            <span className={`px-2 py-0.5 text-xs rounded-full ${getRarityColor(achievement.rarity)}`}>
                              {achievement.rarity}
                            </span>
                          </div>
                          <p className="text-sm text-gray-500 mb-2">{achievement.description}</p>
                          <div className="text-xs text-gray-500 font-medium mb-2">{achievement.reward}</div>
                          <div className="w-full bg-gray-200 rounded-full h-2">
                            <div
                              className="bg-gray-400 h-2 rounded-full transition-all duration-500"
                              style={{ width: `${progressPercent}%` }}
                            ></div>
                          </div>
                          <div className="text-xs text-gray-500 mt-1">
                            {achievement.progress} / {achievement.maxProgress}
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Leaderboard Tab */}
      {selectedTab === 'leaderboard' && (
        <div className="bg-white rounded-xl border border-gray-100 p-6">
          <div className="flex items-center gap-2 mb-6">
            <Crown className="w-5 h-5 text-yellow-600" />
            <h3 className="text-lg font-semibold text-gray-900">Top Renters</h3>
          </div>
          <div className="space-y-4">
            {[
              { rank: 1, name: 'You', points: userStats.experience, avatar: '👤' },
              { rank: 2, name: 'Sarah M.', points: 2450, avatar: '👩' },
              { rank: 3, name: 'Mike R.', points: 2230, avatar: '👨' },
              { rank: 4, name: 'Emma L.', points: 2100, avatar: '👩' },
              { rank: 5, name: 'David K.', points: 1980, avatar: '👨' },
            ].map((user) => (
              <div
                key={user.rank}
                className={`flex items-center gap-4 p-3 rounded-lg ${
                  user.rank === 1 ? 'bg-yellow-50 border border-yellow-200' : 'bg-gray-50'
                }`}
              >
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${
                  user.rank === 1 ? 'bg-yellow-500 text-white' :
                  user.rank === 2 ? 'bg-gray-400 text-white' :
                  user.rank === 3 ? 'bg-amber-600 text-white' :
                  'bg-gray-200 text-gray-600'
                }`}>
                  {user.rank}
                </div>
                <div className="text-2xl">{user.avatar}</div>
                <div className="flex-1">
                  <div className="font-medium text-gray-900">{user.name}</div>
                  <div className="text-sm text-gray-600">{user.points} XP</div>
                </div>
                {user.rank <= 3 && (
                  <Medal className={`w-5 h-5 ${
                    user.rank === 1 ? 'text-yellow-500' :
                    user.rank === 2 ? 'text-gray-400' :
                    'text-amber-600'
                  }`} />
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Rewards Tab */}
      {selectedTab === 'rewards' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white rounded-xl border border-gray-100 p-6">
            <div className="flex items-center gap-2 mb-4">
              <Gift className="w-5 h-5 text-purple-600" />
              <h3 className="text-lg font-semibold text-gray-900">Available Rewards</h3>
            </div>
            <div className="space-y-3">
              {[
                { title: '10% Off Next Booking', cost: 500, available: userStats.experience >= 500 },
                { title: 'Free Delivery', cost: 750, available: userStats.experience >= 750 },
                { title: 'Priority Support', cost: 1000, available: userStats.experience >= 1000 },
                { title: '$25 Credit', cost: 1200, available: userStats.experience >= 1200 },
              ].map((reward, index) => (
                <div
                  key={index}
                  className={`flex items-center justify-between p-3 rounded-lg border ${
                    reward.available
                      ? 'border-purple-200 bg-purple-50'
                      : 'border-gray-200 bg-gray-50 opacity-50'
                  }`}
                >
                  <div>
                    <div className="font-medium text-gray-900">{reward.title}</div>
                    <div className="text-sm text-gray-600">{reward.cost} XP</div>
                  </div>
                  <button
                    disabled={!reward.available}
                    className={`px-3 py-1 text-sm rounded font-medium ${
                      reward.available
                        ? 'bg-purple-600 text-white hover:bg-purple-700'
                        : 'bg-gray-300 text-gray-500 cursor-not-allowed'
                    } aria-label="Icon button">
                    {reward.available ? 'Redeem' : 'Locked'}
                  </button>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white rounded-xl border border-gray-100 p-6">
            <div className="flex items-center gap-2 mb-4">
              <Zap className="w-5 h-5 text-blue-600" />
              <h3 className="text-lg font-semibold text-gray-900">How to Earn XP</h3>
            </div>
            <div className="space-y-3">
              {[
                { action: 'Complete a booking', xp: '+10 XP' },
                { action: 'Leave a review', xp: '+5 XP' },
                { action: 'Refer a friend', xp: '+25 XP' },
                { action: 'Maintain 5-star rating', xp: '+20 XP/month' },
                { action: 'Book during off-peak', xp: '+15 XP' },
              ].map((item, index) => (
                <div key={index} className="flex items-center justify-between py-2">
                  <span className="text-sm text-gray-700">{item.action}</span>
                  <span className="text-sm font-medium text-blue-600">{item.xp}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Monitor, Maximize, Minimize, RotateCcw, Settings, Volume2, VolumeX, Zap, Eye } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';

declare global {
  interface Window { webkitAudioContext?: typeof AudioContext; }
}
import { getEquipment, getBookings } from '../../services/database';
import type { Equipment, Booking } from '../../types';

interface HologramProjection {
  id: string;
  type: 'equipment' | 'analytics' | 'simulation' | 'communication';
  title: string;
  description: string;
  data?: import('../../types').Equipment | Record<string, unknown>;
  position: { x: number; y: number; z: number };
  rotation: { x: number; y: number; z: number };
  scale: number;
  opacity: number;
  interactive: boolean;
}

interface HolographicInterface {
  id: string;
  name: string;
  description: string;
  projections: HologramProjection[];
  layout: 'grid' | 'spiral' | 'orbital' | 'custom';
  theme: 'default' | 'cyberpunk' | 'minimal' | 'neon';
  audioEnabled: boolean;
  gestureControls: boolean;
}


export default function HolographicInterface() {
  const { user } = useAuth();
  const [interfaces, setInterfaces] = useState<HolographicInterface[]>([]);
  const [activeInterface, setActiveInterface] = useState<HolographicInterface | null>(null);
  const [equipment, setEquipment] = useState<Equipment[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [fullscreen, setFullscreen] = useState(false);
  const [audioEnabled, setAudioEnabled] = useState(true);
  const [gestureControls, setGestureControls] = useState(true);
  const [selectedProjection, setSelectedProjection] = useState<HologramProjection | null>(null);

  // Holographic controls
  const [projectionMode, setProjectionMode] = useState<'3d' | '2d' | 'mixed'>('3d');
  const [renderQuality, setRenderQuality] = useState<'low' | 'medium' | 'high' | 'ultra'>('high');
  const [ambientLighting, setAmbientLighting] = useState(true);
  const [particleEffects, setParticleEffects] = useState(true);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const animationRef = useRef<number>();

  useEffect(() => {
    if (user) {
      loadData();
      initializeHolographicSystem();
    }
  }, [user]);

  const loadData = async () => {
    if (!user) return;

    try {
      const [equipmentData, bookingsData] = await Promise.all([
        getEquipment({ ownerId: user.id }),
        getBookings({ renterId: user.id })
      ]);

      setEquipment(Array.isArray(equipmentData) ? equipmentData : ((equipmentData as { data?: import('../../types').Equipment[] })?.data ?? []));
      setBookings(Array.isArray(bookingsData) ? bookingsData : ((bookingsData as { data?: import('../../types').Booking[] })?.data ?? []));

