            'bg-red-100 text-red-700'
          }`}>
            {Math.round(recommendation.confidence * 100)}% confidence
          </div>
        </div>
      </div>

      {/* Current vs Recommended Price */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        <div className="text-center p-4 bg-gray-50 rounded-lg">
