    switch (platform) {
      case 'twitter':
        window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(message)}&url=${encodeURIComponent(url)}`);
        break;
      case 'facebook':
        window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(url)}`);
        break;
      case 'email':
        window.open(`mailto:?subject=Join Islakayd!&body=${encodeURIComponent(message + '\n' + url)}`);
        break;
      case 'sms':
        window.open(`sms:?body=${encodeURIComponent(message + ' ' + url)}`);
        break;
    }
  };

  const getTierColor = (tier: ReferralStats['tier']) => {
    switch (tier) {
      case 'bronze': return 'from-amber-600 to-orange-700';
      case 'silver': return 'from-gray-400 to-gray-500';
      case 'gold': return 'from-yellow-400 to-amber-500';
      case 'platinum': return 'from-violet-500 to-purple-600';
    }
  };

  const getStatusColor = (status: Referral['status']) => {
    switch (status) {
      case 'pending': return 'bg-gray-100 text-gray-700';
      case 'signed_up': return 'bg-blue-100 text-blue-700';
      case 'first_rental': return 'bg-green-100 text-green-700';
      case 'active': return 'bg-teal-100 text-teal-700';
    }
  };

  if (loading) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-8 text-center">
        <div className="w-16 h-16 border-4 border-pink-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
        <p className="text-gray-600">Loading referral program...</p>
      </div>
    );
  }

  if (!stats) return null;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden">
      {/* Header */}
      <div className={`p-6 bg-gradient-to-r ${getTierColor(stats.tier)} text-white`}>
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
              <Gift className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Referral Program</h2>
              <p className="text-sm text-white/80 capitalize">{stats.tier} Member</p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-3xl font-bold">${stats.totalEarnings}</p>
            <p className="text-sm text-white/80">Total Earned</p>
          </div>
        </div>

        {/* Referral Code */}
        <div className="bg-white/10 rounded-xl p-4">
          <p className="text-sm text-white/70 mb-2">Your Referral Code</p>
          <div className="flex items-center gap-2">
            <div className="flex-1 bg-white/20 rounded-lg px-4 py-2 font-mono font-bold text-lg">
              {stats.referralCode}
            </div>
            <button
              aria-label="Icon button" onClick={() => copyToClipboard(stats.referralCode)}
              className="p-3 bg-white/20 rounded-lg hover:bg-white/30 transition-colors"
            >
              {copied ? <CheckCircle2 className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
            </button>
          </div>
        </div>

        {/* Progress to Next Tier */}
        <div className="mt-4">
          <div className="flex items-center justify-between text-sm mb-1">
            <span className="text-white/70">{stats.referralsToNextTier} more referrals to next tier</span>
            <span className="capitalize">{stats.tier === 'platinum' ? 'Max Level' : 
              stats.tier === 'gold' ? '→ Platinum' :
              stats.tier === 'silver' ? '→ Gold' : '→ Silver'}</span>
          </div>
          <div className="bg-white/20 rounded-full h-2 overflow-hidden">
            <div
              className="h-full bg-white rounded-full transition-all"
              style={{ width: `${((15 - stats.referralsToNextTier) / 15) * 100}%` }}
            />
          </div>
        </div>
      </div>

      {/* Share Options */}
      <div className="p-4 bg-gray-50 border-b border-gray-100">
        <p className="text-sm text-gray-600 mb-3">Share your link</p>
        <div className="flex gap-2">
          <button
            aria-label="Icon button" onClick={() => shareVia('twitter')}
            className="flex-1 py-3 bg-[#1DA1F2] text-white rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity"
          >
            <Twitter className="w-5 h-5" />
          </button>
          <button
            aria-label="Icon button" onClick={() => shareVia('facebook')}
            className="flex-1 py-3 bg-[#4267B2] text-white rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity"
          >
            <Facebook className="w-5 h-5" />
          </button>
          <button
            aria-label="Icon button" onClick={() => shareVia('email')}
            className="flex-1 py-3 bg-gray-700 text-white rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity"
          >
            <Mail className="w-5 h-5" />
          </button>
          <button
            aria-label="Icon button" onClick={() => shareVia('sms')}
            className="flex-1 py-3 bg-green-600 text-white rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity"
          >
            <MessageSquare className="w-5 h-5" />
          </button>
          <button
            aria-label="Icon button" onClick={() => copyToClipboard(stats.referralLink)}
            className="flex-1 py-3 bg-gray-200 text-gray-700 rounded-xl flex items-center justify-center gap-2 hover:bg-gray-300 transition-colors"
          >
            <Link2 className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-100">
        {(['overview', 'referrals', 'leaderboard'] as const).map((tab) => (
          <button
            key={tab}
            aria-label="Icon button" onClick={() => setActiveTab(tab)}
            className={`flex-1 py-4 text-sm font-medium transition-colors ${
              activeTab === tab
                ? 'text-pink-600 border-b-2 border-pink-500'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="p-4 max-h-80 overflow-y-auto">
        {activeTab === 'overview' && (
          <div className="space-y-4">
            {/* Stats Grid */}
            <div className="grid grid-cols-3 gap-3">
              <div className="bg-gray-50 rounded-xl p-4 text-center">
                <Users className="w-6 h-6 mx-auto mb-2 text-pink-500" />
                <p className="text-2xl font-bold text-gray-900">{stats.totalReferrals}</p>
                <p className="text-xs text-gray-500">Total Referrals</p>
              </div>
              <div className="bg-gray-50 rounded-xl p-4 text-center">
                <CheckCircle2 className="w-6 h-6 mx-auto mb-2 text-green-500" />
                <p className="text-2xl font-bold text-gray-900">{stats.successfulReferrals}</p>
                <p className="text-xs text-gray-500">Successful</p>
              </div>
              <div className="bg-gray-50 rounded-xl p-4 text-center">
                <DollarSign className="w-6 h-6 mx-auto mb-2 text-amber-500" />
                <p className="text-2xl font-bold text-gray-900">${stats.totalEarnings}</p>
                <p className="text-xs text-gray-500">Earned</p>
              </div>
            </div>

            {/* How it Works */}
            <div className="bg-pink-50 rounded-xl p-4">
              <h3 className="font-semibold text-gray-900 mb-3">How It Works</h3>
              <div className="space-y-3">
                {[
                  { step: '1', text: 'Share your unique referral code or link', reward: '' },
                  { step: '2', text: 'Friend signs up with your code', reward: '+$25 credit' },
                  { step: '3', text: 'Friend completes first rental', reward: '+$25 credit' },
                  { step: '4', text: 'Both of you earn rewards!', reward: '🎉' },
                ].map((item, index) => (
                  <div key={index} className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-pink-500 text-white rounded-full flex items-center justify-center font-bold text-sm">
                      {item.step}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm text-gray-700">{item.text}</p>
                    </div>
                    {item.reward && (
                      <span className="text-sm font-medium text-pink-600">{item.reward}</span>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Invite by Email */}
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">Invite by Email</h3>
              <div className="flex gap-2">
                <input
                  type="email"
                  value={inviteEmail}
                  onChange={(e) => setInviteEmail(e.target.value)}
                  placeholder="friend@email.com"
                  className="flex-1 px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:border-pink-500"
                />
                <button
                  onClick={sendInvite}
                  disabled={!inviteEmail || inviteSent}
                  className="px-6 py-3 bg-pink-600 text-white rounded-xl font-medium hover:bg-pink-700 disabled:opacity-50 transition-colors"
                 aria-label="Icon button">
                  {inviteSent ? 'Sending...' : 'Invite'}
                </button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'referrals' && (
          <div className="space-y-2">
            {referrals.length === 0 ? (
              <div className="text-center py-8">
                <Users className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                <p className="text-gray-500">No referrals yet. Start sharing your code!</p>
              </div>
            ) : (
              referrals.map((referral) => (
                <div key={referral.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-pink-100 rounded-full flex items-center justify-center">
                      <span className="text-pink-600 font-semibold">{referral.name.charAt(0)}</span>
                    </div>
                    <div>
                      <p className="font-medium text-gray-900">{referral.name}</p>
                      <p className="text-sm text-gray-500">{referral.date.toLocaleDateString()}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(referral.status)}`}>
                      {referral.status.replace('_', ' ')}
                    </span>
                    {referral.earnings > 0 && (
                      <p className="text-sm font-medium text-green-600 mt-1">+${referral.earnings}</p>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        )}

        {activeTab === 'leaderboard' && (
          <div className="space-y-2">
            {leaderboard.map((entry) => (
              <div
                key={entry.rank}
                className={`flex items-center justify-between p-4 rounded-xl ${
                  entry.isCurrentUser ? 'bg-pink-50 border-2 border-pink-200' : 'bg-gray-50'
                }`}
              >
                <div className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    entry.rank === 1 ? 'bg-amber-400 text-white' :
                    entry.rank === 2 ? 'bg-gray-300 text-white' :
                    entry.rank === 3 ? 'bg-amber-600 text-white' :
                    'bg-gray-200 text-gray-600'
                  }`}>
                    {entry.rank <= 3 ? (
                      <Trophy className="w-5 h-5" />
                    ) : (
                      <span className="font-bold">{entry.rank}</span>
                    )}
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">
                      {entry.name} {entry.isCurrentUser && '(You)'}
                    </p>
                    <p className="text-sm text-gray-500">{entry.referrals} referrals</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-bold text-gray-900">${entry.earnings}</p>
                  <p className="text-xs text-gray-500">earned</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Star, ThumbsUp, Camera, Shield, Award, TrendingUp, MessageSquare } from 'lucide-react';

interface EnhancedReviewSystemProps {
  equipmentId: string;
  equipmentTitle: string;
  bookingId?: string;
  onSubmit: (review: ReviewData) => Promise<void>;
  onClose: () => void;
}

interface ReviewData {
  rating: number;
  title: string;
  comment: string;
  aspectRatings: {
    condition: number;
    cleanliness: number;
    accuracy: number;
    communication: number;
    value: number;
  };
  photos?: string[];
  wouldRecommend: boolean;
}

export default function EnhancedReviewSystem({
  equipmentId,
  equipmentTitle,
  bookingId,
  onSubmit,
  onClose,
}: EnhancedReviewSystemProps) {
  const [step, setStep] = useState<'rating' | 'aspects' | 'details' | 'photos'  >('rating');
  const [overallRating, setOverallRating] = useState(0);
  const [aspectRatings, setAspectRatings] = useState({
    condition: 0,
    cleanliness: 0,
    accuracy: 0,
    communication: 0,
    value: 0,
  });
  const [title, setTitle] = useState('');
  const [comment, setComment] = useState('');
  const [selectedPhotos, setSelectedPhotos] = useState<File[]>([]);
  const [photoUrls, setPhotoUrls] = useState<string[]>([]);
  const [wouldRecommend, setWouldRecommend] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  
  // Debug: Track review context
  if (import.meta.env.DEV) {
    console.log('EnhancedReviewSystem:', { equipmentId, bookingId });
  }

  const aspects = [
    { key: 'condition' as const, label: 'Equipment Condition', icon: <Shield className="w-5 h-5" /> },
    { key: 'cleanliness' as const, label: 'Cleanliness', icon: <Star className="w-5 h-5" /> },
    { key: 'accuracy' as const, label: 'Listing Accuracy', icon: <Award className="w-5 h-5" /> },
    { key: 'communication' as const, label: 'Owner Communication', icon: <MessageSquare className="w-5 h-5" /> },
    { key: 'value' as const, label: 'Value for Money', icon: <TrendingUp className="w-5 h-5" /> },
  ];

  const ratingLabels = ['Poor', 'Fair', 'Good', 'Very Good', 'Excellent'];

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    
    if (files.length + selectedPhotos.length > 5) {
      alert('Maximum 5 photos per review');
      return;
    }

    const validFiles = files.filter(file => {
      if (file.size > 5 * 1024 * 1024) {
        alert(`${file.name} is too large (max 5MB)`);
        return false;
      }
      return file.type.startsWith('image/');
    });

    setSelectedPhotos(prev => [...prev, ...validFiles]);
    
    validFiles.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => setPhotoUrls(prev => [...prev, reader.result as string]);
      reader.readAsDataURL(file);
    });
  };

  const handleSubmit = async () => {
    if (overallRating === 0) {
      alert('Please select an overall rating');
      return;
    }

    if (!title.trim() || !comment.trim()) {
      alert('Please provide a title and comment');
      return;
    }

    setIsSubmitting(true);
    try {
      await onSubmit({
        rating: overallRating,
        title,
        comment,
        aspectRatings,
        photos: photoUrls,
        wouldRecommend,
      });
      onClose();
    } catch (error) {
      console.error('Failed to submit review:', error);
      alert('Failed to submit review. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const canProceed = () => {
    if (step === 'rating') return overallRating > 0;
    if (step === 'aspects') return Object.values(aspectRatings).every(r => r > 0);
    if (step === 'details') return title.trim() && comment.trim();
    return true;
  };

  const StarRating = ({ 
    value, 
    onChange, 
    size = 'large' 
  }: { 
    value: number; 
    onChange: (rating: number) => void; 
    size?: 'small' | 'large';
  }) => {
    const [hover, setHover] = useState(0);
    const starSize = size === 'large' ? 'w-12 h-12' : 'w-8 h-8';

    return (
      <div className="flex gap-2">
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            type="button"
            aria-label="Icon button" onClick={() => onChange(star)}
            onMouseEnter={() => setHover(star)}
            onMouseLeave={() => setHover(0)}
            className="transition-transform hover:scale-110"
          >
            <Star
              className={`${starSize} transition-colors ${
                star <= (hover || value)
                  ? 'fill-amber-400 text-amber-400'
                  : 'text-gray-300'
              }`}
            />
          </button>
        ))}
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

      <div className="relative z-10 w-full max-w-2xl bg-white rounded-3xl shadow-2xl overflow-hidden">
        {/* Progress Bar */}
        <div className="h-1 bg-gray-200">
          <div 
            className="h-full bg-gradient-to-r from-teal-500 to-emerald-500 transition-all duration-300"
            style={{ width: `${((['rating', 'aspects', 'details', 'photos'].indexOf(step) + 1) / 4) * 100}%` }}
          />
        </div>

        {/* Header */}
        <div className="px-6 py-5 border-b border-gray-100">
          <h2 className="text-2xl font-bold text-gray-900">Review Your Experience</h2>
          <p className="text-gray-600 mt-1">{equipmentTitle}</p>
        </div>

        <div className="p-6 max-h-[600px] overflow-y-auto">
          {/* Step 1: Overall Rating */}
          {step === 'rating' && (
            <div className="text-center space-y-6">
              <div className="w-20 h-20 mx-auto rounded-full bg-gradient-to-br from-teal-500 to-emerald-500 flex items-center justify-center">
                <Star className="w-10 h-10 text-white fill-white" />
              </div>
              <div>
                <h3 className="text-2xl font-bold text-gray-900 mb-2">How was your rental?</h3>
                <p className="text-gray-600">Rate your overall experience</p>
              </div>
              
              <div className="flex justify-center">
                <StarRating value={overallRating} onChange={setOverallRating} />
              </div>
              
              {overallRating > 0 && (
                <p className="text-lg font-semibold text-teal-600 animate-in fade-in slide-in-from-bottom-4">
                  {ratingLabels[overallRating - 1]}!
                </p>
              )}
            </div>
          )}

          {/* Step 2: Aspect Ratings */}
          {step === 'aspects' && (
            <div className="space-y-6">
              <div className="text-center mb-6">
                <h3 className="text-xl font-bold text-gray-900 mb-2">Rate Specific Aspects</h3>
                <p className="text-gray-600">Help others know what to expect</p>
              </div>

              {aspects.map((aspect) => (
                <div key={aspect.key} className="p-4 bg-gray-50 rounded-xl">
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-white flex items-center justify-center text-teal-600">
                        {aspect.icon}
                      </div>
                      <span className="font-semibold text-gray-900">{aspect.label}</span>
                    </div>
                    {aspectRatings[aspect.key] > 0 && (
                      <span className="text-sm font-semibold text-teal-600">
                        {ratingLabels[aspectRatings[aspect.key] - 1]}
                      </span>
                    )}
                  </div>
                  <StarRating
                    value={aspectRatings[aspect.key]}
                    onChange={(rating) => setAspectRatings(prev => ({ ...prev, [aspect.key]: rating }))}
                    size="small"
                  />
                </div>
              ))}
            </div>
          )}

          {/* Step 3: Written Review */}
          {step === 'details' && (
            <div className="space-y-6">
              <div className="text-center mb-6">
                <h3 className="text-xl font-bold text-gray-900 mb-2">Share Your Experience</h3>
                <p className="text-gray-600">Help others make informed decisions</p>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Review Title *
                </label>
                <input
                  type="text"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="e.g., Great excavator, worked perfectly!"
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-400 focus:ring-2 focus:ring-teal-100"
                  maxLength={80}
                />
                <p className="text-xs text-gray-500 mt-1">{title.length}/80 characters</p>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Your Review *
                </label>
                <textarea
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  placeholder="Tell us about your experience with this equipment..."
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-400 focus:ring-2 focus:ring-teal-100 resize-none"
                  rows={6}
                  maxLength={1000}
                />
                <p className="text-xs text-gray-500 mt-1">{comment.length}/1000 characters</p>
              </div>

              <div className="p-4 bg-blue-50 rounded-xl">
                <label className="flex items-start gap-3 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={wouldRecommend}
                    onChange={(e) => setWouldRecommend(e.target.checked)}
                    className="mt-1 w-5 h-5 text-teal-500 rounded focus:ring-2 focus:ring-teal-400"
                  />
                  <div>
                    <p className="font-semibold text-gray-900 flex items-center gap-2">
                      <ThumbsUp className="w-5 h-5 text-blue-600" />
                      I would recommend this equipment
                    </p>
                    <p className="text-sm text-gray-600 mt-1">
                      Help others find quality equipment they can trust
                    </p>
                  </div>
                </label>
              </div>
            </div>
          )}

          {/* Step 4: Photos */}
          {step === 'photos' && (
            <div className="space-y-6">
              <div className="text-center mb-6">
                <div className="w-16 h-16 mx-auto rounded-full bg-gradient-to-br from-violet-500 to-purple-500 flex items-center justify-center mb-4">
                  <Camera className="w-8 h-8 text-white" />
                </div>
                <h3 className="text-xl font-bold text-gray-900 mb-2">Add Photos (Optional)</h3>
                <p className="text-gray-600">Show others what to expect</p>
              </div>

              <div className="grid grid-cols-3 gap-3">
                {photoUrls.map((url, idx) => (
                  <div key={idx} className="relative group aspect-square">
                    <img
                      src={url}
                      alt={`Review ${idx + 1}`}
                      className="w-full h-full object-cover rounded-xl"
                    />
                    <button
                      aria-label="Icon button"> {
                        setSelectedPhotos(prev => prev.filter((_, i) => i !== idx));
                        setPhotoUrls(prev => prev.filter((_, i) => i !== idx));
                      }}
                      className="absolute top-2 right-2 w-8 h-8 bg-red-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      ×
                    </button>
                  </div>
                ))}
                
                {photoUrls.length < 5 && (
                  <label className="aspect-square border-2 border-dashed border-gray-300 rounded-xl hover:border-teal-400 hover:bg-teal-50 transition-all cursor-pointer flex flex-col items-center justify-center">
                    <Camera className="w-8 h-8 text-gray-400 mb-2" />
                    <span className="text-sm text-gray-600">Add Photo</span>
                    <input
                      type="file"
                      accept="image/*"
                      multiple
                      onChange={handlePhotoSelect}
                      className="hidden"
                    />
                  </label>
                )}
              </div>

              <div className="p-4 bg-amber-50 rounded-xl flex items-start gap-3">
                <Camera className="w-5 h-5 text-amber-600 mt-0.5 flex-shrink-0" />
                <div className="text-sm text-amber-800">
                  <p className="font-semibold mb-1">Photo Guidelines</p>
                  <ul className="list-disc list-inside space-y-1">
                    <li>Show equipment condition clearly</li>
                    <li>Include any issues or damages</li>
                    <li>Max 5 photos, 5MB each</li>
                  </ul>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-gray-100 flex items-center justify-between">
          <button
            aria-label="Icon button"> {
              const steps = ['rating', 'aspects', 'details', 'photos'] as const;
              const currentIndex = steps.indexOf(step);
              if (currentIndex > 0) {
                setStep(steps[currentIndex - 1] as 'rating' | 'aspects' | 'details' | 'photos');
              } else {
                onClose();
              }
            }}
            className="px-6 py-2.5 rounded-xl border border-gray-200 text-gray-700 font-medium hover:bg-gray-50 transition-colors"
          >
            {step === 'rating' ? 'Cancel' : 'Back'}
          </button>

          <button
            aria-label="Icon button"> {
              const steps = ['rating', 'aspects', 'details', 'photos'] as const;
              const currentIndex = steps.indexOf(step);
              if (currentIndex < steps.length - 1) {
                setStep(steps[currentIndex + 1] as 'rating' | 'aspects' | 'details' | 'photos');
              } else {
                handleSubmit();
              }
            }}
            disabled={!canProceed() || isSubmitting}
            className="px-6 py-2.5 rounded-xl bg-gradient-to-r from-teal-500 to-emerald-500 text-white font-medium hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isSubmitting ? 'Submitting...' : step === 'photos' ? 'Submit Review' : 'Next'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import {
  X,
  Flashlight,
  FlashlightOff,
  SwitchCamera,
  QrCode,
  CheckCircle,
  AlertCircle,
  Package,
  Calendar,
  Info,
  ChevronRight,
  History,
  Loader2,
} from 'lucide-react';

interface ScanResult {
  type: 'equipment' | 'booking' | 'user' | 'unknown';
  id: string;
  data?: Record<string, unknown>;
}

interface QRCodeScannerProps {
  isOpen: boolean;
  onClose: () => void;
  onScan: (result: ScanResult) => void;
  className?: string;
}

export default function QRCodeScanner({
  isOpen,
  onClose,
  onScan,
  className = '',
}: QRCodeScannerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  
  const [isScanning, setIsScanning] = useState(false);
  const [hasFlash, setHasFlash] = useState(false);
  const [flashOn, setFlashOn] = useState(false);
  const [cameras, setCameras] = useState<MediaDeviceInfo[]>([]);
  const [currentCamera, setCurrentCamera] = useState(0);
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [recentScans, setRecentScans] = useState<ScanResult[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Initialize camera
  useEffect(() => {
    if (!isOpen) return;

    const initCamera = async () => {
      try {
        // Get available cameras
        const devices = await navigator.mediaDevices.enumerateDevices();
        const videoDevices = devices.filter(d => d.kind === 'videoinput');
        setCameras(videoDevices);

        // Start camera stream
        const constraints: MediaStreamConstraints = {
          video: {
            facingMode: currentCamera === 0 ? 'environment' : 'user',
            width: { ideal: 1280 },
            height: { ideal: 720 },
          },
        };

        const stream = await navigator.mediaDevices.getUserMedia(constraints);
        streamRef.current = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          await videoRef.current.play();
          setIsScanning(true);

          // Check for flash capability
          const track = stream.getVideoTracks()[0];
          const capabilities = track.getCapabilities?.() as MediaTrackCapabilities & { torch?: boolean };
          setHasFlash(capabilities?.torch === true);
        }
      } catch (err) {
        console.error('Camera error:', err);
        setError('Unable to access camera. Please grant camera permissions.');
      }
    };

    initCamera();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, [isOpen, currentCamera]);

  // Scan for QR codes
  useEffect(() => {
    if (!isScanning || !videoRef.current || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationId: number;
    let lastScanTime = 0;

    const scanFrame = () => {
      const now = Date.now();
      if (now - lastScanTime < 200) {
        animationId = requestAnimationFrame(scanFrame);
        return;
      }
      lastScanTime = now;

      const video = videoRef.current;
      if (!video || video.readyState !== video.HAVE_ENOUGH_DATA) {
        animationId = requestAnimationFrame(scanFrame);
        return;
      }

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

      // Simulated QR detection (in production, use a library like jsQR)
      // This simulates finding a QR code after scanning
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const detected = simulateQRDetection(imageData);
      
      if (detected) {
        handleScanResult(detected);
      }

      animationId = requestAnimationFrame(scanFrame);
    };

    animationId = requestAnimationFrame(scanFrame);

    return () => {
      cancelAnimationFrame(animationId);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isScanning]);

  // Simulate QR detection (replace with actual QR library in production)
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const simulateQRDetection = (_imageData: ImageData): string | null => {
    // In production, use jsQR or similar library
    // This is a placeholder that randomly "detects" QR codes for demo
    if (Math.random() < 0.001) { // Very low probability for demo
      const types = ['equipment', 'booking', 'user'];
      const type = types[Math.floor(Math.random() * types.length)];
      return `islakayd://${type}/demo-${Date.now()}`;
    }
    return null;
  };

  // Parse and handle scan result
  const handleScanResult = useCallback((qrData: string) => {
    setIsScanning(false);

    // Parse QR code format: islakayd://type/id or JSON
    let result: ScanResult;

    try {
      if (qrData.startsWith('islakayd://')) {
        const [, path] = qrData.split('://');
        const [type, id] = path.split('/');
        result = {
          type: type as ScanResult['type'],
          id,
        };
      } else if (qrData.startsWith('{')) {
        const data = JSON.parse(qrData);
        result = {
          type: data.type || 'unknown',
          id: data.id || 'unknown',
          data,
        };
      } else {
        result = {
          type: 'unknown',
          id: qrData,
        };
      }

      setScanResult(result);
      setRecentScans(prev => [result, ...prev.slice(0, 9)]);

      // Vibrate on successful scan
      if (navigator.vibrate) {
        navigator.vibrate(100);
      }
    } catch {
      setError('Invalid QR code format');
      setIsScanning(true);
    }
  }, []);

  // Toggle flash
  const toggleFlash = async () => {
    if (!streamRef.current) return;

    const track = streamRef.current.getVideoTracks()[0];
    try {
      await track.applyConstraints({
        advanced: [{ torch: !flashOn } as MediaTrackConstraintSet],
      });
      setFlashOn(!flashOn);
    } catch (err) {
      console.error('Flash toggle error:', err);
    }
  };

  // Switch camera
  const switchCamera = () => {
    setCurrentCamera(prev => (prev + 1) % cameras.length);
  };

  // Confirm scan result
  const confirmScan = () => {
    if (scanResult) {
      onScan(scanResult);
      setScanResult(null);
      onClose();
    }
  };

  // Continue scanning
  const continueScan = () => {
    setScanResult(null);
    setIsScanning(true);
  };

  // Manual QR input (for demo)
  const manualScan = () => {
    const demoTypes: ScanResult['type'][] = ['equipment', 'booking', 'user'];
    const type = demoTypes[Math.floor(Math.random() * demoTypes.length)];
    handleScanResult(`islakayd://${type}/demo-${Date.now()}`);
  };

  if (!isOpen) return null;

  return (
    <div className={`fixed inset-0 z-50 bg-black ${className}`}>
      {/* Camera View */}
      <div className="relative w-full h-full">
        <video
          ref={videoRef}
          className="w-full h-full object-cover"
          playsInline
          muted
        />
        <canvas ref={canvasRef} className="hidden" />

        {/* Scanning Overlay */}
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="relative">
            {/* Scan Frame */}
            <div className="w-64 h-64 relative">
              {/* Corner markers */}
              <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-emerald-500 rounded-tl-lg" />
              <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-emerald-500 rounded-tr-lg" />
              <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-emerald-500 rounded-bl-lg" />
              <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-emerald-500 rounded-br-lg" />

              {/* Scanning line animation */}
              {isScanning && (
                <div className="absolute inset-x-4 top-4 h-0.5 bg-emerald-500 animate-scan-line" />
              )}
            </div>

            {/* Instruction text */}
            <p className="absolute -bottom-12 left-1/2 -translate-x-1/2 text-white text-center whitespace-nowrap">
              {isScanning ? 'Point camera at QR code' : 'Processing...'}
            </p>
          </div>
        </div>

        {/* Dark overlay outside scan area */}
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute inset-0 bg-black/60" />
          <div 
            className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-transparent"
            style={{ boxShadow: '0 0 0 9999px rgba(0,0,0,0.6)' }}
          />
        </div>

        {/* Top Controls */}
        <div className="absolute top-0 left-0 right-0 p-4 flex items-center justify-between">
          <button
            onClick={onClose}
            className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center text-white"
          >
            <X className="w-5 h-5" />
          </button>

          <div className="flex items-center gap-3">
            {hasFlash && (
              <button
                onClick={toggleFlash}
                className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center text-white"
               aria-label="Icon button">
                {flashOn ? (
                  <Flashlight className="w-5 h-5 text-yellow-400" />
                ) : (
                  <FlashlightOff className="w-5 h-5" />
                )}
              </button>
            )}

            {cameras.length > 1 && (
              <button
                onClick={switchCamera}
                className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center text-white"
               aria-label="Icon button">
                <SwitchCamera className="w-5 h-5" />
              </button>
            )}

            <button
              aria-label="Icon button" onClick={() => setShowHistory(!showHistory)}
              className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center text-white"
            >
              <History className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Bottom Controls */}
        <div className="absolute bottom-0 left-0 right-0 p-6 pb-safe">
          <div className="flex items-center justify-center gap-6">
            <button
              onClick={manualScan}
              className="px-6 py-3 bg-white/20 backdrop-blur rounded-full text-white flex items-center gap-2"
             aria-label="Icon button">
              <QrCode className="w-5 h-5" />
              Demo Scan
            </button>
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="absolute top-20 left-4 right-4">
            <div className="bg-red-500/90 backdrop-blur rounded-xl p-4 flex items-center gap-3 text-white">
              <AlertCircle className="w-5 h-5 flex-shrink-0" />
              <p className="flex-1">{error}</p>
              <button aria-label="Icon button" onClick={() => setError(null)}>
                <X className="w-5 h-5" />
              </button>
            </div>
          </div>
        )}

        {/* Recent Scans Panel */}
        {showHistory && recentScans.length > 0 && (
          <div className="absolute top-16 right-4 w-64 bg-white rounded-xl shadow-xl overflow-hidden">
            <div className="p-3 bg-gray-50 border-b">
              <h3 className="font-medium text-gray-900">Recent Scans</h3>
            </div>
            <div className="max-h-64 overflow-y-auto">
              {recentScans.map((scan, i) => (
                <button
                  key={i}
                  aria-label="Icon button"> {
                    setScanResult(scan);
                    setShowHistory(false);
                  }}
                  className="w-full p-3 flex items-center gap-3 hover:bg-gray-50 border-b last:border-0"
                >
                  {scan.type === 'equipment' && <Package className="w-4 h-4 text-emerald-600" />}
                  {scan.type === 'booking' && <Calendar className="w-4 h-4 text-blue-600" />}
                  {scan.type === 'user' && <Info className="w-4 h-4 text-violet-600" />}
                  {scan.type === 'unknown' && <QrCode className="w-4 h-4 text-gray-600" />}
                  <div className="flex-1 text-left">
                    <p className="text-sm font-medium text-gray-900 capitalize">{scan.type}</p>
                    <p className="text-xs text-gray-500 truncate">{scan.id}</p>
                  </div>
                  <ChevronRight className="w-4 h-4 text-gray-400" />
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Scan Result Modal */}
        {scanResult && (
          <div className="absolute inset-0 bg-black/80 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden">
              {/* Success Header */}
              <div className="p-6 text-center bg-gradient-to-b from-emerald-50 to-white">
                <div className="w-16 h-16 mx-auto bg-emerald-100 rounded-full flex items-center justify-center mb-4">
                  <CheckCircle className="w-8 h-8 text-emerald-600" />
                </div>
                <h3 className="text-xl font-bold text-gray-900">QR Code Scanned!</h3>
                <p className="text-gray-500 mt-1 capitalize">{scanResult.type} detected</p>
              </div>

              {/* Result Details */}
              <div className="p-4 border-t">
                <div className="space-y-3">
                  <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                    {scanResult.type === 'equipment' && <Package className="w-5 h-5 text-emerald-600" />}
                    {scanResult.type === 'booking' && <Calendar className="w-5 h-5 text-blue-600" />}
                    {scanResult.type === 'user' && <Info className="w-5 h-5 text-violet-600" />}
                    {scanResult.type === 'unknown' && <QrCode className="w-5 h-5 text-gray-600" />}
                    <div>
                      <p className="text-sm text-gray-500">Type</p>
                      <p className="font-medium text-gray-900 capitalize">{scanResult.type}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
                    <Info className="w-5 h-5 text-gray-400" />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-gray-500">ID</p>
                      <p className="font-medium text-gray-900 truncate">{scanResult.id}</p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Actions */}
              <div className="p-4 border-t flex gap-3">
                <button
                  onClick={continueScan}
                  className="flex-1 py-3 border-2 border-gray-200 rounded-xl font-medium text-gray-700 hover:bg-gray-50"
                 aria-label="Icon button">
                  Scan Another
                </button>
                <button
                  onClick={confirmScan}
                  className="flex-1 py-3 bg-emerald-600 rounded-xl font-medium text-white hover:bg-emerald-700"
                 aria-label="Icon button">
                  View Details
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Loading State */}
        {!isScanning && !scanResult && !error && (
          <div className="absolute inset-0 bg-black/80 flex items-center justify-center">
            <div className="text-center text-white">
              <Loader2 className="w-8 h-8 animate-spin mx-auto mb-3" />
              <p>Initializing camera...</p>
            </div>
          </div>
        )}
      </div>

      {/* CSS for scanning animation */}
      <style>{`
        @keyframes scan-line {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(240px); }
        }
        .animate-scan-line {
          animation: scan-line 2s ease-in-out infinite;
        }
        .pb-safe {
          padding-bottom: max(1.5rem, env(safe-area-inset-bottom));
        }
      `}</style>
    </div>
  );
}

import { useState, useEffect, useMemo, useCallback } from 'react';
import {
  Calendar,
  TrendingUp,
  DollarSign,
  AlertCircle,
  CheckCircle,
  Zap,
  Target,
  Settings,
} from 'lucide-react';
import type { Equipment, Booking } from '../../types';
import { getEquipment, getBookings } from '../../services/database';
import { useAuth } from '../../contexts/AuthContext';

interface SchedulingOptimizerProps {
  equipment?: Equipment[];
  bookings?: Booking[];
  className?: string;
}

interface ScheduleOptimization {
  equipmentId: string;
  equipmentName: string;
  currentUtilization: number;
  optimalUtilization: number;
  revenuePotential: number;
  maintenanceImpact: number;
  demandScore: number;
  recommendations: string[];
  priority: 'high' | 'medium' | 'low';
}

interface TimeSlot {
  startTime: Date;
  endTime: Date;
  availability: number; // percentage
  demand: number; // scale 0-10
  price: number;
}

export default function SchedulingOptimizer({
  equipment: propEquipment,
  bookings: propBookings,
  className = ''
}: SchedulingOptimizerProps) {
  const { user } = useAuth();
  const [optimizations, setOptimizations] = useState<ScheduleOptimization[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTimeframe, setSelectedTimeframe] = useState<'week' | 'month' | 'quarter'>('week');
  const [viewMode, setViewMode] = useState<'overview' | 'detailed' | 'calendar'>('overview');
  const [autoOptimize, setAutoOptimize] = useState(false);

  const calculateUtilization = useCallback((eqBookings: Booking[]): number => {
    const now = new Date();
    const timeframeDays = selectedTimeframe === 'week' ? 7 : selectedTimeframe === 'month' ? 30 : 90;
    const startDate = new Date(now.getTime() - timeframeDays * 24 * 60 * 60 * 1000);

    const bookedDays = eqBookings
      .filter(b => new Date(b.start_date) >= startDate && b.status === 'confirmed')
      .reduce((total, booking) => {
        const start = new Date(booking.start_date);
        const end = new Date(booking.end_date);
        const days = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
        return total + days;
      }, 0);

    return Math.min(100, (bookedDays / timeframeDays) * 100);
  }, [selectedTimeframe]);

  const calculateDemand = useCallback((eq: Equipment, eqBookings: Booking[]): number => {
    // Simple demand calculation based on booking frequency and ratings
    const recentBookings = eqBookings.filter(b => {
      const bookingDate = new Date(b.created_at);
      const daysAgo = (Date.now() - bookingDate.getTime()) / (1000 * 60 * 60 * 24);
      return daysAgo <= 30;
    });

    const bookingFrequency = recentBookings.length / 30; // bookings per day
    const rating = eq.owner?.rating || 4.0;

    // Demand score from 0-10
    return Math.min(10, (bookingFrequency * 2) + (rating - 3));
  }, []);

  const calculateRevenuePotential = useCallback((eq: Equipment, utilization: number, demand: number): number => {
    const baseRate = eq.daily_rate || 50;
    const optimalUtilization = 85;
    const utilizationGap = Math.max(0, optimalUtilization - utilization);
    const demandMultiplier = demand / 10;

    // Potential additional revenue from increased utilization
    const timeframeDays = selectedTimeframe === 'week' ? 7 : selectedTimeframe === 'month' ? 30 : 90;
    const potentialBookedDays = (utilizationGap / 100) * timeframeDays * demandMultiplier;

    return Math.round(potentialBookedDays * baseRate);
  }, [selectedTimeframe]);

  const calculateMaintenanceImpact = useCallback((eq: Equipment): number => {
    // Simplified maintenance impact calculation
    // In a real app, this would consider actual maintenance schedules
    // For now, use total_bookings as a proxy for usage
    const usage = eq.total_bookings || 0;

    // Higher impact for heavily used equipment
    return Math.min(100, (usage / 10) + 20); // Base impact of 20, increases with usage
  }, []);

  const generateRecommendations = useCallback((_eq: Equipment, utilization: number, demand: number, maintenance: number): string[] => {
    const recommendations: string[] = [];

    if (utilization < 60) {
      recommendations.push('Increase marketing efforts for this equipment');
      recommendations.push('Consider price optimization to boost bookings');
    }

    if (demand > 7) {
      recommendations.push('High demand - consider adding similar equipment');
      recommendations.push('Implement dynamic pricing for peak periods');
    }

    if (maintenance > 70) {
      recommendations.push('Schedule maintenance to prevent downtime');
      recommendations.push('Consider equipment replacement planning');
    }

    if (utilization > 90) {
      recommendations.push('Equipment is over-utilized - monitor for wear');
      recommendations.push('Consider fleet expansion');
    }

    if (recommendations.length === 0) {
      recommendations.push('Equipment performance is optimal');
    }

    return recommendations;
  }, []);

  const getPriority = useCallback((utilization: number, demand: number, maintenance: number): 'high' | 'medium' | 'low' => {
    if (maintenance > 80 || utilization < 30 || demand > 8) return 'high';
    if (maintenance > 60 || utilization < 50 || demand > 6) return 'medium';
    return 'low';
  }, []);

  const generateOptimizations = useCallback((equipmentList: Equipment[], bookingsList: Booking[]): ScheduleOptimization[] => {
    return equipmentList.map(eq => {
      const eqBookings = bookingsList.filter(b => b.equipment_id === eq.id);
      const utilization = calculateUtilization(eqBookings);
      const demand = calculateDemand(eq, eqBookings);
      const revenue = calculateRevenuePotential(eq, utilization, demand);
      const maintenance = calculateMaintenanceImpact(eq);

      const recommendations = generateRecommendations(eq, utilization, demand, maintenance);

      return {
        equipmentId: eq.id,
        equipmentName: eq.title,
        currentUtilization: utilization,
        optimalUtilization: Math.min(85, utilization + 15), // Target 85% utilization
        revenuePotential: revenue,
        maintenanceImpact: maintenance,
        demandScore: demand,
        recommendations,
        priority: getPriority(utilization, demand, maintenance),
      };
    }).sort((a, b) => {
      // Sort by priority and revenue potential
      const priorityOrder = { high: 3, medium: 2, low: 1 };
      const aPriority = priorityOrder[a.priority];
      const bPriority = priorityOrder[b.priority];

      if (aPriority !== bPriority) return bPriority - aPriority;
      return b.revenuePotential - a.revenuePotential;
    });
  }, [calculateUtilization, calculateDemand, calculateRevenuePotential, calculateMaintenanceImpact, generateRecommendations, getPriority]);

  useEffect(() => {
    const loadData = async () => {
      if (!user) return;

      try {
        const [equipmentData, bookingsData] = await Promise.all([
          propEquipment || getEquipment({ ownerId: user.id }),
          propBookings || getBookings({ ownerId: user.id })
        ]);

        // Generate optimizations
        const equipmentList = Array.isArray(equipmentData) ? equipmentData : (equipmentData as { data?: Equipment[] })?.data || [];
        const bookingsList = Array.isArray(bookingsData) ? bookingsData : (bookingsData as { data?: Booking[] })?.data || [];
        const opts = generateOptimizations(equipmentList, bookingsList);
        setOptimizations(opts);
      } catch (error) {
        console.error('Failed to load scheduling data:', error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [user, propEquipment, propBookings, generateOptimizations]);

  const timeSlots = useMemo(() => {
    const slots: TimeSlot[] = [];
    const now = new Date();
    const days = selectedTimeframe === 'week' ? 7 : selectedTimeframe === 'month' ? 30 : 90;

    for (let i = 0; i < days; i++) {
      const date = new Date(now.getTime() + i * 24 * 60 * 60 * 1000);

      // Generate hourly slots for the day
      for (let hour = 8; hour < 18; hour++) {
        const startTime = new Date(date);
        startTime.setHours(hour, 0, 0, 0);
        const endTime = new Date(startTime);
        endTime.setHours(hour + 1, 0, 0, 0);

        // Calculate availability and demand for this slot
        const availability = Math.random() * 100; // Mock data
        const demand = Math.random() * 10; // Mock data
        const basePrice = 50;
        const price = basePrice * (1 + (demand / 10) * 0.5); // Dynamic pricing

        slots.push({
          startTime,
          endTime,
          availability,
          demand,
          price,
        });
      }
    }

    return slots;
  }, [selectedTimeframe]);

  const stats = useMemo(() => {
    const totalRevenue = optimizations.reduce((sum, opt) => sum + opt.revenuePotential, 0);
    const avgUtilization = optimizations.reduce((sum, opt) => sum + opt.currentUtilization, 0) / optimizations.length;
    const highPriorityCount = optimizations.filter(opt => opt.priority === 'high').length;
    const optimalEquipment = optimizations.filter(opt => opt.currentUtilization >= 80).length;

    return {
      totalRevenue,
      avgUtilization: Math.round(avgUtilization),
      highPriorityCount,
      optimalEquipment,
    };
  }, [optimizations]);

  const handleAutoOptimize = () => {
    setAutoOptimize(!autoOptimize);
    // In a real app, this would trigger automatic price adjustments and scheduling
  };

  if (loading) {
    return (
      <div className={`animate-pulse ${className}`}>
        <div className="bg-white rounded-xl p-6 border border-gray-100">
          <div className="h-8 bg-gray-200 rounded w-64 mb-6"></div>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="h-20 bg-gray-200 rounded"></div>
            ))}
          </div>
          <div className="space-y-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-32 bg-gray-200 rounded"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Header */}
      <div className="bg-white rounded-xl p-6 border border-gray-100 mb-6">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900">Smart Scheduler</h2>
            <p className="text-gray-600">AI-powered scheduling optimization</p>
          </div>
          <div className="flex items-center gap-3">
            <select
              value={selectedTimeframe}
              onChange={(e) => setSelectedTimeframe(e.target.value as typeof selectedTimeframe)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="week">This Week</option>
              <option value="month">This Month</option>
              <option value="quarter">This Quarter</option>
            </select>

            <button
              onClick={handleAutoOptimize}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                autoOptimize
                  ? 'bg-green-600 text-white hover:bg-green-700'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              } aria-label="Icon button">
              <Zap className="w-4 h-4" />
              {autoOptimize ? 'Auto-Optimizing' : 'Auto Optimize'}
            </button>

            <button className="p-2 text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-lg transition-colors">
              <Settings className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
            <div className="flex items-center gap-2 mb-2">
              <DollarSign className="w-5 h-5 text-blue-600" />
              <span className="text-sm font-medium text-blue-800">Revenue Potential</span>
            </div>
            <div className="text-2xl font-bold text-blue-900">${stats.totalRevenue.toLocaleString()}</div>
          </div>

          <div className="bg-green-50 p-4 rounded-lg border border-green-200">
            <div className="flex items-center gap-2 mb-2">
              <TrendingUp className="w-5 h-5 text-green-600" />
              <span className="text-sm font-medium text-green-800">Avg Utilization</span>
            </div>
            <div className="text-2xl font-bold text-green-900">{stats.avgUtilization}%</div>
          </div>

          <div className="bg-orange-50 p-4 rounded-lg border border-orange-200">
            <div className="flex items-center gap-2 mb-2">
              <AlertCircle className="w-5 h-5 text-orange-600" />
              <span className="text-sm font-medium text-orange-800">High Priority</span>
            </div>
            <div className="text-2xl font-bold text-orange-900">{stats.highPriorityCount}</div>
          </div>

          <div className="bg-purple-50 p-4 rounded-lg border border-purple-200">
            <div className="flex items-center gap-2 mb-2">
              <Target className="w-5 h-5 text-purple-600" />
              <span className="text-sm font-medium text-purple-800">Optimal Equipment</span>
            </div>
            <div className="text-2xl font-bold text-purple-900">{stats.optimalEquipment}</div>
          </div>
        </div>
      </div>

      {/* View Toggle */}
      <div className="bg-white rounded-xl p-4 border border-gray-100 mb-6">
        <div className="flex items-center gap-2">
          {(['overview', 'detailed', 'calendar'] as const).map((mode) => (
            <button
              key={mode}
              aria-label="Icon button" onClick={() => setViewMode(mode)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                viewMode === mode
                  ? 'bg-blue-100 text-blue-700'
                  : 'text-gray-600 hover:bg-gray-100'
              }`}
            >
              {mode.charAt(0).toUpperCase() + mode.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Overview View */}
      {viewMode === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Optimization Cards */}
          <div className="space-y-4">
            {optimizations.slice(0, 5).map((opt) => (
              <div key={opt.equipmentId} className="bg-white rounded-xl p-6 border border-gray-100">
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <h3 className="font-semibold text-gray-900">{opt.equipmentName}</h3>
                    <div className="flex items-center gap-2 mt-1">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                        opt.priority === 'high' ? 'bg-red-100 text-red-700' :
                        opt.priority === 'medium' ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        {opt.priority} priority
                      </span>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-lg font-bold text-green-600">
                      +${opt.revenuePotential}
                    </div>
                    <div className="text-sm text-gray-600">potential</div>
                  </div>
                </div>

                <div className="space-y-3 mb-4">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Current Utilization</span>
                    <span className="font-medium">{Math.round(opt.currentUtilization)}%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div
                      className="bg-blue-600 h-2 rounded-full"
                      style={{ width: `${opt.currentUtilization}%` }}
                    ></div>
                  </div>

                  <div className="flex justify-between text-sm">
                    <span className="text-gray-600">Demand Score</span>
                    <span className="font-medium">{opt.demandScore.toFixed(1)}/10</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div
                      className="bg-green-600 h-2 rounded-full"
                      style={{ width: `${(opt.demandScore / 10) * 100}%` }}
                    ></div>
                  </div>
                </div>

                <div className="space-y-2">
                  <h4 className="text-sm font-medium text-gray-900">Recommendations:</h4>
                  {opt.recommendations.slice(0, 2).map((rec, index) => (
                    <div key={index} className="flex items-start gap-2 text-sm text-gray-600">
                      <CheckCircle className="w-4 h-4 text-green-500 mt-0.5 flex-shrink-0" />
                      <span>{rec}</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

          {/* Time Slot Optimization */}
          <div className="bg-white rounded-xl p-6 border border-gray-100">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Optimal Time Slots</h3>
            <div className="space-y-3">
              {timeSlots.slice(0, 10).map((slot, index) => (
                <div key={index} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div>
                    <div className="text-sm font-medium text-gray-900">
                      {slot.startTime.toLocaleDateString()} {slot.startTime.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </div>
                    <div className="text-xs text-gray-600">
                      Availability: {Math.round(slot.availability)}% | Demand: {slot.demand.toFixed(1)}
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-sm font-semibold text-green-600">
                      ${Math.round(slot.price)}
                    </div>
                    <div className="text-xs text-gray-600">optimal price</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Detailed View */}
      {viewMode === 'detailed' && (
        <div className="bg-white rounded-xl p-6 border border-gray-100">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-gray-200">
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Equipment</th>
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Utilization</th>
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Demand</th>
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Revenue Potential</th>
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Priority</th>
                  <th className="text-left py-3 px-4 font-medium text-gray-900">Actions</th>
                </tr>
              </thead>
              <tbody>
                {optimizations.map((opt) => (
                  <tr key={opt.equipmentId} className="border-b border-gray-100">
                    <td className="py-3 px-4">
                      <div className="font-medium text-gray-900">{opt.equipmentName}</div>
                    </td>
                    <td className="py-3 px-4">
                      <div className="flex items-center gap-2">
                        <div className="w-16 bg-gray-200 rounded-full h-2">
                          <div
                            className="bg-blue-600 h-2 rounded-full"
                            style={{ width: `${opt.currentUtilization}%` }}
                          ></div>
                        </div>
                        <span className="text-sm font-medium">{Math.round(opt.currentUtilization)}%</span>
                      </div>
                    </td>
                    <td className="py-3 px-4">
                      <span className="text-sm font-medium">{opt.demandScore.toFixed(1)}/10</span>
                    </td>
                    <td className="py-3 px-4">
                      <span className="text-sm font-semibold text-green-600">
                        +${opt.revenuePotential}
                      </span>
                    </td>
                    <td className="py-3 px-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                        opt.priority === 'high' ? 'bg-red-100 text-red-700' :
                        opt.priority === 'medium' ? 'bg-yellow-100 text-yellow-700' :
                        'bg-green-100 text-green-700'
                      }`}>
                        {opt.priority}
                      </span>
                    </td>
                    <td className="py-3 px-4">
                      <button className="text-blue-600 hover:text-blue-800 text-sm font-medium" aria-label="Icon button">
                        Optimize
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Calendar View */}
      {viewMode === 'calendar' && (
        <div className="bg-white rounded-xl p-6 border border-gray-100">
          <div className="text-center text-gray-500">
            <Calendar className="w-12 h-12 mx-auto mb-4" />
            <p>Calendar view coming soon!</p>
            <p className="text-sm">View scheduling optimizations in calendar format.</p>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import {
  Calendar,
  Zap,
  Sparkles,
  ChevronLeft,
  ChevronRight,
  Star,
} from 'lucide-react';

interface SmartSchedulerProps {
  equipmentId: string;
  equipmentTitle: string;
  dailyRate: number;
  onSelectDates: (start: Date, end: Date, discount: number) => void;
  onClose: () => void;
}

interface TimeSlot {
  date: Date;
  available: boolean;
  demand: 'low' | 'medium' | 'high';
  discount: number;
  price: number;
  recommended: boolean;
  reason?: string;
}

interface AIRecommendation {
  startDate: Date;
  endDate: Date;
  totalSavings: number;
  reason: string;
  confidence: number;
}

export default function SmartScheduler({
  equipmentTitle,
  dailyRate,
  onSelectDates,
}: SmartSchedulerProps) {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedStart, setSelectedStart] = useState<Date | null>(null);
  const [selectedEnd, setSelectedEnd] = useState<Date | null>(null);
  const [timeSlots, setTimeSlots] = useState<TimeSlot[]>([]);
  const [recommendations, setRecommendations] = useState<AIRecommendation[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<'calendar' | 'recommendations'>('calendar');

  useEffect(() => {
    loadSmartData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentMonth]);

  const loadSmartData = async () => {
    setLoading(true);
    await new Promise(resolve => setTimeout(resolve, 800));

    // Generate smart time slots
    const slots: TimeSlot[] = [];
    const startOfMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1);
    const endOfMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0);
    
    for (let d = new Date(startOfMonth); d <= endOfMonth; d.setDate(d.getDate() + 1)) {
      const dayOfWeek = d.getDay();
      const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
      const dayOfMonth = d.getDate();
      
      // Simulate demand patterns
      let demand: TimeSlot['demand'] = 'medium';
      let discount = 0;
      let recommended = false;
      let reason: string | undefined;
      
      // Weekdays generally lower demand
      if (!isWeekend) {
        demand = 'low';
        discount = 15;
        if (dayOfWeek === 2 || dayOfWeek === 3) { // Tue/Wed best
          discount = 20;
          recommended = true;
          reason = 'Best day of the week - 20% off';
        }
      } else {
        demand = 'high';
        discount = 0;
      }
      
      // End of month often less busy
      if (dayOfMonth >= 25) {
        discount = Math.max(discount, 10);
        if (!isWeekend) {
          recommended = true;
          reason = 'End of month special';
        }
      }
      
      // Future dates only
      const available = d >= new Date();
      
      slots.push({
        date: new Date(d),
        available,
        demand,
        discount,
        price: Math.round(dailyRate * (1 - discount / 100)),
        recommended,
        reason,
      });
    }

    // Generate AI recommendations
    const recs: AIRecommendation[] = [
      {
        startDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 15),
        endDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 18),
        totalSavings: 85,
        reason: 'Mid-week booking with 20% discount. Lowest demand period.',
        confidence: 95,
      },
      {
        startDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 27),
        endDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1),
        totalSavings: 120,
        reason: 'End of month pricing + weekend rates. Great value!',
        confidence: 88,
      },
      {
        startDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 8),
        endDate: new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 10),
        totalSavings: 45,
        reason: 'Popular dates but still 15% off for weekday portion.',
        confidence: 75,
      },
    ];

    setTimeSlots(slots);
    setRecommendations(recs);
    setLoading(false);
  };

  const handleDateClick = (slot: TimeSlot) => {
    if (!slot.available) return;

    if (!selectedStart || (selectedStart && selectedEnd)) {
      setSelectedStart(slot.date);
      setSelectedEnd(null);
    } else {
      if (slot.date < selectedStart) {
        setSelectedStart(slot.date);
      } else {
        setSelectedEnd(slot.date);
      }
    }
  };

  const calculateTotal = () => {
    if (!selectedStart || !selectedEnd) return null;

    let total = 0;
    let savings = 0;
    let days = 0;

    for (const slot of timeSlots) {
      if (slot.date >= selectedStart && slot.date <= selectedEnd && slot.available) {
        total += slot.price;
        savings += dailyRate - slot.price;
        days++;
      }
    }

    return { total, savings, days, avgDiscount: Math.round((savings / (days * dailyRate)) * 100) };
  };

  const totals = calculateTotal();

  const isDateInRange = (date: Date) => {
    if (!selectedStart) return false;
    const end = selectedEnd || selectedStart;
    return date >= selectedStart && date <= end;
  };

  const prevMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1));
  };

  const applyRecommendation = (rec: AIRecommendation) => {
    setSelectedStart(rec.startDate);
    setSelectedEnd(rec.endDate);
    setViewMode('calendar');
  };

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const monthNames = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ];

  if (loading) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-8 text-center">
        <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
        <p className="text-gray-600">Analyzing best times to book...</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-2xl w-full">
      {/* Header */}
      <div className="p-6 bg-gradient-to-r from-indigo-600 to-purple-600 text-white">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
              <Sparkles className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Smart Scheduler</h2>
              <p className="text-sm text-white/80">{equipmentTitle}</p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold">${dailyRate}/day</p>
            <p className="text-sm text-white/80">Base rate</p>
          </div>
        </div>

        {/* View Toggle */}
        <div className="flex bg-white/10 rounded-xl p-1">
          <button
            aria-label="Icon button" onClick={() => setViewMode('calendar')}
            className={`flex-1 py-2 rounded-lg text-sm font-medium transition-colors ${
              viewMode === 'calendar' ? 'bg-white text-indigo-600' : 'text-white/80'
            }`}
          >
            <Calendar className="w-4 h-4 inline mr-2" />
            Calendar
          </button>
          <button
            aria-label="Icon button" onClick={() => setViewMode('recommendations')}
            className={`flex-1 py-2 rounded-lg text-sm font-medium transition-colors ${
              viewMode === 'recommendations' ? 'bg-white text-indigo-600' : 'text-white/80'
            }`}
          >
            <Zap className="w-4 h-4 inline mr-2" />
            AI Picks
          </button>
        </div>
      </div>

      {viewMode === 'calendar' ? (
        <>
          {/* Calendar Navigation */}
          <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <button
              onClick={prevMonth}
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <ChevronLeft className="w-5 h-5 text-gray-600" />
            </button>
            <h3 className="font-semibold text-gray-900">
              {monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}
            </h3>
            <button
              onClick={nextMonth}
              className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <ChevronRight className="w-5 h-5 text-gray-600" />
            </button>
          </div>

          {/* Calendar Grid */}
          <div className="p-4">
            <div className="grid grid-cols-7 gap-1 mb-2">
              {dayNames.map((day) => (
                <div key={day} className="text-center text-xs font-medium text-gray-500 py-2">
                  {day}
                </div>
              ))}
            </div>

            <div className="grid grid-cols-7 gap-1">
              {/* Empty cells for start of month */}
              {Array.from({ length: timeSlots[0]?.date.getDay() || 0 }).map((_, i) => (
                <div key={`empty-${i}`} className="aspect-square" />
              ))}
              
              {timeSlots.map((slot) => {
                const inRange = isDateInRange(slot.date);
                const isStart = selectedStart?.toDateString() === slot.date.toDateString();
                const isEnd = selectedEnd?.toDateString() === slot.date.toDateString();

                return (
                  <button
                    key={slot.date.toISOString()}
                    aria-label="Icon button" onClick={() => handleDateClick(slot)}
                    disabled={!slot.available}
                    className={`
                      relative aspect-square flex flex-col items-center justify-center rounded-lg text-sm
                      transition-all
                      ${!slot.available ? 'text-gray-300 cursor-not-allowed' : 'cursor-pointer'}
                      ${isStart || isEnd ? 'bg-indigo-600 text-white' : ''}
                      ${inRange && !isStart && !isEnd ? 'bg-indigo-100 text-indigo-700' : ''}
                      ${!inRange && slot.available ? 'hover:bg-gray-100' : ''}
                      ${slot.recommended && !inRange ? 'ring-2 ring-green-400 ring-offset-1' : ''}
                    `}
                  >
                    <span className="font-medium">{slot.date.getDate()}</span>
                    {slot.available && slot.discount > 0 && !isStart && !isEnd && (
                      <span className={`text-xs ${inRange ? 'text-indigo-600' : 'text-green-600'}`}>
                        -{slot.discount}%
                      </span>
                    )}
                    {slot.recommended && !inRange && (
                      <Star className="absolute top-0.5 right-0.5 w-3 h-3 text-green-500 fill-green-500" />
                    )}
                  </button>
                );
              })}
            </div>

            {/* Legend */}
            <div className="flex items-center justify-center gap-4 mt-4 text-xs text-gray-500">
              <span className="flex items-center gap-1">
                <span className="w-3 h-3 bg-green-100 rounded border border-green-400" />
                Low demand
              </span>
              <span className="flex items-center gap-1">
                <span className="w-3 h-3 bg-amber-100 rounded border border-amber-400" />
                Normal
              </span>
              <span className="flex items-center gap-1">
                <span className="w-3 h-3 bg-red-100 rounded border border-red-400" />
                High demand
              </span>
              <span className="flex items-center gap-1">
                <Star className="w-3 h-3 text-green-500 fill-green-500" />
                Recommended
              </span>
            </div>
          </div>
        </>
      ) : (
        /* AI Recommendations */
        <div className="p-4 max-h-80 overflow-y-auto">
          <p className="text-sm text-gray-600 mb-4">
            Based on demand patterns and pricing, here are the best times to book:
          </p>
          <div className="space-y-3">
            {recommendations.map((rec, index) => (
              <div
                key={index}
                className="p-4 bg-gradient-to-r from-green-50 to-emerald-50 rounded-xl border border-green-200"
              >
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="text-lg font-semibold text-gray-900">
                        {rec.startDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - {rec.endDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                      </span>
                      <span className="px-2 py-0.5 bg-green-200 text-green-800 rounded-full text-xs font-medium">
                        Save ${rec.totalSavings}
                      </span>
                    </div>
                    <p className="text-sm text-gray-600 mt-1">{rec.reason}</p>
                  </div>
                  <div className="text-right">
                    <div className="flex items-center gap-1 text-green-600">
                      <Zap className="w-4 h-4" />
                      <span className="font-medium">{rec.confidence}%</span>
                    </div>
                    <span className="text-xs text-gray-500">confidence</span>
                  </div>
                </div>
                <button
                  aria-label="Icon button" onClick={() => applyRecommendation(rec)}
                  className="w-full mt-2 py-2 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 transition-colors"
                >
                  Select These Dates
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Selection Summary */}
      {totals && (
        <div className="p-4 border-t border-gray-100 bg-gray-50">
          <div className="flex items-center justify-between mb-3">
            <div>
              <p className="text-sm text-gray-600">
                {selectedStart?.toLocaleDateString()} - {selectedEnd?.toLocaleDateString()}
              </p>
              <p className="text-lg font-bold text-gray-900">
                {totals.days} days • ${totals.total} total
              </p>
            </div>
            {totals.savings > 0 && (
              <div className="text-right">
                <p className="text-green-600 font-semibold">You save ${totals.savings}</p>
                <p className="text-xs text-gray-500">Avg {totals.avgDiscount}% off</p>
              </div>
            )}
          </div>
          <button
            aria-label="Icon button" onClick={() => onSelectDates(selectedStart!, selectedEnd!, totals.avgDiscount)}
            className="w-full py-3 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-semibold hover:shadow-lg transition-all"
          >
            Confirm These Dates
          </button>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Search, Sparkles, Mic, X, TrendingUp, MapPin, DollarSign, Calendar } from 'lucide-react';

interface AISearchEngineProps {
  onSearch: (query: string, filters: SearchFilters) => void;
  onClose: () => void;
}

interface SearchFilters {
  query: string;
  location?: string;
  priceRange?: { min: number; max: number };
  dates?: { start: string; end: string };
  category?: string;
}

interface SearchSuggestion {
  text: string;
  intent: string;
  filters: Partial<SearchFilters>;
  confidence: number;
}

export default function AISearchEngine({ onSearch, onClose }: AISearchEngineProps) {
  const [query, setQuery] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [suggestions, setSuggestions] = useState<SearchSuggestion[]>([]);
  const [aiInsights, setAiInsights] = useState<string[]>([]);

  // AI Natural Language Processing
  const analyzeQuery = async (searchQuery: string) => {
    if (!searchQuery.trim()) {
      setSuggestions([]);
      setAiInsights([]);
      return;
    }

    setIsAnalyzing(true);
    
    // Simulate AI processing (in production, this would call your AI service)
    await new Promise(resolve => setTimeout(resolve, 800));

    const lowerQuery = searchQuery.toLowerCase();
    const newSuggestions: SearchSuggestion[] = [];
    const insights: string[] = [];

    // Intent detection patterns
    if (lowerQuery.includes('dig') || lowerQuery.includes('excavat') || lowerQuery.includes('trench')) {
      newSuggestions.push({
        text: 'Excavators and Digging Equipment',
        intent: 'construction_digging',
        filters: { category: 'Construction', query: 'excavator' },
        confidence: 0.95,
      });
      insights.push('💡 Based on "dig", I found construction equipment');
    }

    if (lowerQuery.includes('pool') || lowerQuery.includes('pond') || lowerQuery.includes('foundation')) {
      newSuggestions.push({
        text: 'Heavy Equipment for Large Projects',
        intent: 'large_excavation',
        filters: { category: 'Construction', query: 'excavator backhoe' },
        confidence: 0.88,
      });
      insights.push('🏗️ Large project detected - showing heavy machinery');
    }

    if (lowerQuery.includes('wedding') || lowerQuery.includes('party') || lowerQuery.includes('event')) {
      newSuggestions.push({
        text: 'Event Equipment & Party Supplies',
        intent: 'event_planning',
        filters: { category: 'Events', query: 'tent lighting' },
        confidence: 0.92,
      });
      insights.push('🎉 Event equipment recommended for your occasion');
    }

    if (lowerQuery.includes('photo') || lowerQuery.includes('camera') || lowerQuery.includes('video')) {
      newSuggestions.push({
        text: 'Photography & Video Equipment',
        intent: 'photography',
        filters: { category: 'Photography', query: 'camera lens' },
        confidence: 0.90,
      });
      insights.push('📸 Professional photography gear available');
    }

    if (lowerQuery.match(/\$\d+/) || lowerQuery.includes('cheap') || lowerQuery.includes('budget')) {
      const priceMatch = lowerQuery.match(/\$(\d+)/);
      const maxPrice = priceMatch ? parseInt(priceMatch[1]) : 100;
      newSuggestions.push({
        text: `Equipment Under $${maxPrice}/day`,
        intent: 'budget_search',
        filters: { priceRange: { min: 0, max: maxPrice } },
        confidence: 0.85,
      });
      insights.push(`💰 Filtering by your budget: $${maxPrice}/day max`);
    }

    if (lowerQuery.includes('near') || lowerQuery.includes('around') || lowerQuery.match(/\d{5}/)) {
      const locationMatch = lowerQuery.match(/near\s+([a-z\s]+)|around\s+([a-z\s]+)|(\d{5})/i);
      const location = locationMatch ? locationMatch[1] || locationMatch[2] || locationMatch[3] : '';
      newSuggestions.push({
        text: `Equipment Near ${location}`,
        intent: 'location_search',
        filters: { location: location.trim() },
        confidence: 0.87,
      });
      insights.push('📍 Showing equipment in your area');
    }

    if (lowerQuery.includes('weekend') || lowerQuery.includes('week') || lowerQuery.includes('month')) {
      const duration = lowerQuery.includes('weekend') ? '2 days' : 
                      lowerQuery.includes('week') ? '7 days' : '30 days';
      insights.push(`📅 Rental duration: ${duration} - weekly/monthly discounts available`);
    }

    if (lowerQuery.includes('pro') || lowerQuery.includes('professional') || lowerQuery.includes('commercial')) {
      newSuggestions.push({
        text: 'Professional-Grade Equipment',
        intent: 'professional',
        filters: { query: lowerQuery + ' professional commercial' },
        confidence: 0.83,
      });
      insights.push('⭐ Showing verified professional equipment');
    }

    // Generic fallback
    if (newSuggestions.length === 0) {
      newSuggestions.push({
        text: `Search for "${searchQuery}"`,
        intent: 'generic',
        filters: { query: searchQuery },
        confidence: 0.70,
      });
      insights.push('🔍 Searching all available equipment');
    }

    setSuggestions(newSuggestions);
    setAiInsights(insights);
    setIsAnalyzing(false);
  };

  const handleInputChange = (value: string) => {
    setQuery(value);
    analyzeQuery(value);
  };

  const handleSuggestionClick = (suggestion: SearchSuggestion) => {
    onSearch(suggestion.filters.query || query, suggestion.filters as SearchFilters);
    onClose();
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      const bestSuggestion = suggestions[0];
      if (bestSuggestion) {
        handleSuggestionClick(bestSuggestion);
      } else {
        onSearch(query, { query });
        onClose();
      }
    }
  };

  const trendingSearches = [
    { icon: '🏗️', text: 'Construction Equipment', query: 'excavator bulldozer' },
    { icon: '📸', text: 'Photography Gear', query: 'camera dslr mirrorless' },
    { icon: '🎉', text: 'Event Supplies', query: 'tent lighting tables' },
    { icon: '🔧', text: 'Power Tools', query: 'drill saw power tools' },
  ];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

      <div className="relative z-10 w-full max-w-3xl bg-white rounded-3xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-r from-teal-500 via-emerald-500 to-cyan-500 px-6 py-5 text-white">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 rounded-full bg-white/20 flex items-center justify-center">
                <Sparkles className="w-7 h-7" />
              </div>
              <div>
                <h2 className="text-2xl font-bold">AI-Powered Search</h2>
                <p className="text-teal-100 text-sm">Ask naturally, we'll understand</p>
              </div>
            </div>
            <button
              onClick={onClose}
              className="w-8 h-8 rounded-full bg-white/20 hover:bg-white/30 flex items-center justify-center transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Search Input */}
          <form onSubmit={handleSubmit}>
            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/60" />
              <input
                type="text"
                value={query}
                onChange={(e) => handleInputChange(e.target.value)}
                placeholder='Try "I need something to dig a pool" or "camera for wedding this weekend"'
                className="w-full pl-12 pr-24 py-4 rounded-2xl bg-white/20 text-white placeholder-white/60 focus:outline-none focus:bg-white/30 transition-colors text-lg"
              />
              <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-2">
                {isAnalyzing && (
                  <div className="flex items-center gap-2 px-3 py-1.5 bg-white/20 rounded-full">
                    <div className="w-2 h-2 bg-white rounded-full animate-pulse" />
                    <span className="text-sm">AI analyzing...</span>
                  </div>
                )}
                {!isAnalyzing && (
                  <button
                    type="button"
                    className="p-2 rounded-full bg-white/20 hover:bg-white/30 transition-colors"
                    title="Voice search"
                  >
                    <Mic className="w-5 h-5" />
                  </button>
                )}
              </div>
            </div>
          </form>
        </div>

        <div className="max-h-[500px] overflow-y-auto">
          {/* AI Insights */}
          {aiInsights.length > 0 && (
            <div className="px-6 py-4 bg-blue-50 border-b border-blue-100">
              <div className="space-y-2">
                {aiInsights.map((insight, idx) => (
                  <div key={idx} className="flex items-start gap-2 text-sm text-blue-800">
                    <Sparkles className="w-4 h-4 mt-0.5 flex-shrink-0" />
                    <span>{insight}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* AI Suggestions */}
          {suggestions.length > 0 && (
            <div className="p-6 border-b border-gray-100">
              <h3 className="text-sm font-semibold text-gray-500 mb-3">AI SUGGESTIONS</h3>
              <div className="space-y-2">
                {suggestions.map((suggestion, idx) => (
                  <button
                    key={idx}
                    aria-label="Icon button" onClick={() => handleSuggestionClick(suggestion)}
                    className="w-full flex items-center justify-between px-4 py-3 rounded-xl hover:bg-gray-50 transition-colors text-left group"
                  >
                    <div className="flex-1">
                      <p className="font-medium text-gray-900 group-hover:text-teal-600 transition-colors">
                        {suggestion.text}
                      </p>
                      <div className="flex items-center gap-3 mt-1">
                        <span className="text-xs text-gray-500 capitalize">{suggestion.intent.replace('_', ' ')}</span>
                        <div className="flex items-center gap-1">
                          <div className="w-16 h-1.5 bg-gray-200 rounded-full overflow-hidden">
                            <div 
                              className="h-full bg-teal-500 rounded-full"
                              style={{ width: `${suggestion.confidence * 100}%` }}
                            />
                          </div>
                          <span className="text-xs text-gray-500">{Math.round(suggestion.confidence * 100)}%</span>
                        </div>
                      </div>
                    </div>
                    <div className="ml-4 w-8 h-8 rounded-full bg-teal-50 flex items-center justify-center group-hover:bg-teal-100 transition-colors">
                      <Search className="w-4 h-4 text-teal-600" />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Trending Searches */}
          {!query && (
            <div className="p-6">
              <div className="flex items-center gap-2 text-sm text-gray-500 mb-4">
                <TrendingUp className="w-4 h-4" />
                Trending Searches
              </div>
              <div className="grid grid-cols-2 gap-3">
                {trendingSearches.map((trend, idx) => (
                  <button
                    key={idx}
                    aria-label="Icon button"> {
                      setQuery(trend.query);
                      analyzeQuery(trend.query);
                    }}
                    className="flex items-center gap-3 px-4 py-3 rounded-xl bg-gray-50 hover:bg-gray-100 transition-colors text-left"
                  >
                    <span className="text-2xl">{trend.icon}</span>
                    <div>
                      <p className="font-medium text-gray-900 text-sm">{trend.text}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Examples */}
          {!query && (
            <div className="px-6 pb-6">
              <h3 className="text-sm font-semibold text-gray-500 mb-3">TRY ASKING...</h3>
              <div className="space-y-2">
                {[
                  { icon: <MapPin className="w-4 h-4" />, text: 'Find excavators near Los Angeles under $300/day' },
                  { icon: <Calendar className="w-4 h-4" />, text: 'Camera equipment for weekend wedding shoot' },
                  { icon: <DollarSign className="w-4 h-4" />, text: 'Cheapest power tools for home renovation' },
                  { icon: <Sparkles className="w-4 h-4" />, text: 'Professional DJ equipment for party on Saturday' },
                ].map((example, idx) => (
                  <button
                    key={idx}
                    aria-label="Icon button"> {
                      setQuery(example.text);
                      analyzeQuery(example.text);
                    }}
                    className="w-full flex items-center gap-3 px-4 py-2.5 rounded-lg hover:bg-gray-50 transition-colors text-left text-sm text-gray-600"
                  >
                    <div className="text-teal-500">{example.icon}</div>
                    <span>"{example.text}"</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-4 bg-gray-50 border-t border-gray-100">
          <div className="flex items-center justify-between text-sm text-gray-500">
            <div className="flex items-center gap-4">
              <span className="flex items-center gap-1">
                <kbd className="px-2 py-1 bg-white rounded border border-gray-200 text-xs">Enter</kbd>
                to search
              </span>
              <span className="flex items-center gap-1">
                <kbd className="px-2 py-1 bg-white rounded border border-gray-200 text-xs">Esc</kbd>
                to close
              </span>
            </div>
            <span className="flex items-center gap-1">
              <Sparkles className="w-4 h-4 text-teal-500" />
              Powered by AI
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { SlidersHorizontal, X, Check, DollarSign, Star, Zap, Shield } from 'lucide-react';

interface AdvancedFiltersProps {
  onApply: (filters: FilterOptions) => void;
  onClose: () => void;
}

export interface FilterOptions {
  priceRange: [number, number];
  availability: {
    startDate: string;
    endDate: string;
  } | null;
  location: {
    address: string;
    radius: number;
  } | null;
  rating: number | null;
  features: string[];
  condition: string[];
  deliveryOptions: string[];
  instantBook: boolean;
  verifiedOwners: boolean;
  insurance: boolean;
}

export default function AdvancedFilters({ onApply, onClose }: AdvancedFiltersProps) {
  const [filters, setFilters] = useState<FilterOptions>({
    priceRange: [0, 1000],
    availability: null,
    location: null,
    rating: null,
    features: [],
    condition: [],
    deliveryOptions: [],
    instantBook: false,
    verifiedOwners: false,
    insurance: false,
  });

  const featuresList = [
    'GPS Tracking',
    'Climate Control',
    'Safety Equipment',
    'Remote Start',
    'Bluetooth',
    'Backup Camera',
    'Power Steering',
    'Air Conditioning',
  ];

  const conditionOptions = ['New', 'Excellent', 'Good', 'Fair'];
  // const deliveryOptionsList = ['Self Pickup', 'Owner Delivery', 'Third-Party Courier'];

  const handleApply = () => {
    onApply(filters);
    onClose();
  };

  const handleReset = () => {
    setFilters({
      priceRange: [0, 1000],
      availability: null,
      location: null,
      rating: null,
      features: [],
      condition: [],
      deliveryOptions: [],
      instantBook: false,
      verifiedOwners: false,
      insurance: false,
    });
  };

  const activeFiltersCount = [
    filters.rating !== null,
    filters.features.length > 0,
    filters.condition.length > 0,
    filters.deliveryOptions.length > 0,
    filters.instantBook,
    filters.verifiedOwners,
    filters.insurance,
  ].filter(Boolean).length;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      
      <div className="relative w-full max-w-2xl max-h-[90vh] bg-white rounded-3xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 bg-gradient-to-r from-teal-50 to-emerald-50">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-teal-500 to-emerald-500 flex items-center justify-center">
              <SlidersHorizontal className="w-5 h-5 text-white" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900">Advanced Filters</h2>
              <p className="text-sm text-gray-600">
                {activeFiltersCount} filter{activeFiltersCount !== 1 ? 's' : ''} active
              </p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-full hover:bg-gray-100 transition-colors"
          >
            <X className="w-6 h-6 text-gray-500" />
          </button>
        </div>

        {/* Content */}
        <div className="overflow-y-auto p-6 space-y-6" style={{ maxHeight: 'calc(90vh - 180px)' }}>
          {/* Price Range */}
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <DollarSign className="w-5 h-5 text-teal-600" />
              <h3 className="font-semibold text-gray-900">Price Range (per day)</h3>
            </div>
            <div className="flex items-center gap-4">
              <input
                type="number"
                value={filters.priceRange[0]}
                onChange={(e) =>
                  setFilters({
                    ...filters,
                    priceRange: [Number(e.target.value), filters.priceRange[1]],
                  })
                }
                placeholder="Min"
                className="flex-1 px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
              />
              <span className="text-gray-400">-</span>
              <input
                type="number"
                value={filters.priceRange[1]}
                onChange={(e) =>
                  setFilters({
                    ...filters,
                    priceRange: [filters.priceRange[0], Number(e.target.value)],
                  })
                }
                placeholder="Max"
                className="flex-1 px-4 py-2.5 rounded-xl border border-gray-200 focus:outline-none focus:border-teal-500"
              />
            </div>
            <input
              type="range"
              min="0"
              max="2000"
              step="50"
              value={filters.priceRange[1]}
              onChange={(e) =>
                setFilters({
                  ...filters,
                  priceRange: [filters.priceRange[0], Number(e.target.value)],
                })
              }
              className="w-full accent-teal-500"
            />
          </div>

          {/* Rating */}
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <Star className="w-5 h-5 text-teal-600" />
              <h3 className="font-semibold text-gray-900">Minimum Rating</h3>
            </div>
            <div className="flex gap-2">
              {[4.5, 4.0, 3.5, 3.0].map((rating) => (
                <button
                  key={rating}
                  aria-label="Icon button" onClick={() => setFilters({
                      ...filters,
                      rating: filters.rating === rating ? null : rating,
                    })}
                  className={`flex-1 px-4 py-2.5 rounded-xl border transition-all ${
                    filters.rating === rating
                      ? 'border-teal-500 bg-teal-50 text-teal-700'
                      : 'border-gray-200 text-gray-600 hover:border-gray-300'
                  }`}
                >
                  <span className="font-semibold">{rating}+</span>
                  <Star className="w-3 h-3 inline ml-1 fill-current" />
                </button>
              ))}
            </div>
          </div>

          {/* Features */}
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <Zap className="w-5 h-5 text-teal-600" />
              <h3 className="font-semibold text-gray-900">Features</h3>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {featuresList.map((feature) => (
                <button
                  key={feature}
                  aria-label="Icon button"> {
                    const newFeatures = filters.features.includes(feature)
                      ? filters.features.filter((f) => f !== feature)
                      : [...filters.features, feature];
                    setFilters({ ...filters, features: newFeatures });
                  }}
                  className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-sm transition-all ${
                    filters.features.includes(feature)
                      ? 'border-teal-500 bg-teal-50 text-teal-700'
                      : 'border-gray-200 text-gray-600 hover:border-gray-300'
                  }`}
                >
                  <div
                    className={`w-4 h-4 rounded border flex items-center justify-center ${
                      filters.features.includes(feature)
                        ? 'bg-teal-500 border-teal-500'
                        : 'border-gray-300'
                    }`}
                  >
                    {filters.features.includes(feature) && (
                      <Check className="w-3 h-3 text-white" />
                    )}
                  </div>
                  {feature}
                </button>
              ))}
            </div>
          </div>

          {/* Condition */}
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <Shield className="w-5 h-5 text-teal-600" />
              <h3 className="font-semibold text-gray-900">Condition</h3>
            </div>
            <div className="flex gap-2">
              {conditionOptions.map((condition) => (
                <button
                  key={condition}
                  aria-label="Icon button"> {
                    const newConditions = filters.condition.includes(condition)
                      ? filters.condition.filter((c) => c !== condition)
                      : [...filters.condition, condition];
                    setFilters({ ...filters, condition: newConditions });
                  }}
                  className={`flex-1 px-4 py-2.5 rounded-xl border text-sm transition-all ${
                    filters.condition.includes(condition)
                      ? 'border-teal-500 bg-teal-50 text-teal-700'
                      : 'border-gray-200 text-gray-600 hover:border-gray-300'
                  }`}
                >
                  {condition}
                </button>
              ))}
            </div>
          </div>

          {/* Quick Toggles */}
          <div className="space-y-3">
            <h3 className="font-semibold text-gray-900">Quick Options</h3>
            <div className="space-y-2">
              <label className="flex items-center justify-between p-4 rounded-xl border border-gray-200 hover:border-gray-300 cursor-pointer transition-all">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-teal-50 flex items-center justify-center">
                    <Zap className="w-5 h-5 text-teal-600" />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Instant Book</p>
                    <p className="text-sm text-gray-500">Book without waiting for approval</p>
                  </div>
                </div>
                <input
                  type="checkbox"
                  checked={filters.instantBook}
                  onChange={(e) =>
                    setFilters({ ...filters, instantBook: e.target.checked })
                  }
                  className="w-5 h-5 rounded accent-teal-500"
                />
              </label>

              <label className="flex items-center justify-between p-4 rounded-xl border border-gray-200 hover:border-gray-300 cursor-pointer transition-all">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center">
                    <Shield className="w-5 h-5 text-blue-600" />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Verified Owners Only</p>
                    <p className="text-sm text-gray-500">Equipment from verified accounts</p>
                  </div>
                </div>
                <input
                  type="checkbox"
                  checked={filters.verifiedOwners}
                  onChange={(e) =>
                    setFilters({ ...filters, verifiedOwners: e.target.checked })
                  }
                  className="w-5 h-5 rounded accent-teal-500"
                />
              </label>

              <label className="flex items-center justify-between p-4 rounded-xl border border-gray-200 hover:border-gray-300 cursor-pointer transition-all">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-green-50 flex items-center justify-center">
                    <Shield className="w-5 h-5 text-green-600" />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Insurance Available</p>
                    <p className="text-sm text-gray-500">Equipment with damage protection</p>
                  </div>
                </div>
                <input
                  type="checkbox"
                  checked={filters.insurance}
                  onChange={(e) =>
                    setFilters({ ...filters, insurance: e.target.checked })
                  }
                  className="w-5 h-5 rounded accent-teal-500"
                />
              </label>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-gray-100 bg-gray-50 flex items-center gap-3">
          <button
            onClick={handleReset}
            className="flex-1 py-3 rounded-xl border border-gray-200 text-gray-700 font-medium hover:bg-gray-100 transition-colors"
           aria-label="Icon button">
            Reset All
          </button>
          <button
            onClick={handleApply}
            className="flex-1 py-3 rounded-xl bg-gradient-to-r from-teal-500 to-emerald-500 text-white font-semibold hover:shadow-lg transition-all"
           aria-label="Icon button">
            Apply Filters ({activeFiltersCount})
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, useDeferredValue } from 'react';
import {
  Search,
  MapPin,
  DollarSign,
  Star,
  Sparkles,
  SlidersHorizontal,
} from 'lucide-react';
import type { Equipment, Booking } from '../../types';
import { getEquipment, getBookings } from '../../services/database';
import { useAuth } from '../../contexts/AuthContext';

interface AdvancedSearchProps {
  onEquipmentSelect?: (equipment: Equipment) => void;
  className?: string;
}

interface SearchFilters {
  query: string;
  category: string;
  location: string;
  priceRange: [number, number];
  rating: number;
  availability: string;
  features: string[];
  sortBy: 'relevance' | 'price_low' | 'price_high' | 'rating' | 'distance' | 'newest';
  dateRange?: {
    start: Date;
    end: Date;
  };
}

interface AISuggestion {
  type: 'popular' | 'trending' | 'similar' | 'seasonal' | 'personalized';
  title: string;
  description: string;
  equipment?: Equipment[];
  query?: string;
}

export default function AdvancedSearch({ onEquipmentSelect, className = '' }: AdvancedSearchProps) {
  const { user } = useAuth();
  const [equipment, setEquipment] = useState<Equipment[]>([]);
  const [loading, setLoading] = useState(true);
  const [showFilters, setShowFilters] = useState(false);
  const [aiSuggestions, setAiSuggestions] = useState<AISuggestion[]>([]);

  const [filters, setFilters] = useState<SearchFilters>({
    query: '',
    category: '',
    location: '',
    priceRange: [0, 1000],
    rating: 0,
    availability: '',
    features: [],
    sortBy: 'relevance',
  });

  const deferredQuery = useDeferredValue(filters.query);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [equipmentData, bookingsData] = await Promise.all([
          getEquipment({ limit: 200 }),
          getBookings({}),
        ]);

        setEquipment(equipmentData.data);

        // Generate AI suggestions
        generateAISuggestions(equipmentData.data, bookingsData);
      } catch (error) {
        console.error('Failed to load search data:', error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const generateAISuggestions = (equipmentList: Equipment[], bookingsList: Booking[]) => {
    const suggestions: AISuggestion[] = [];

    // Popular equipment
    const popularEquipment = equipmentList
      .sort((a, b) => (b.rating || 0) - (a.rating || 0))
      .slice(0, 3);

    if (popularEquipment.length > 0) {
      suggestions.push({
        type: 'popular',
        title: 'Most Popular Equipment',
        description: 'Highly rated equipment trusted by our community',
        equipment: popularEquipment,
      });
    }

    // Trending based on recent bookings
    const lastWeek = new Date();
    lastWeek.setDate(lastWeek.getDate() - 7);

    const recentBookings = bookingsList.filter(b =>
      new Date(b.created_at) > lastWeek
    );

    const trendingIds = [...new Set(recentBookings.map(b => b.equipment_id))];
    const trendingEquipment = equipmentList
      .filter(eq => trendingIds.includes(eq.id))
      .slice(0, 3);

    if (trendingEquipment.length > 0) {
      suggestions.push({
        type: 'trending',
        title: 'Trending This Week',
        description: 'Equipment getting lots of attention recently',
        equipment: trendingEquipment,
      });
    }

    // Seasonal suggestions
    const currentMonth = new Date().getMonth();
    const seasonalEquipment = equipmentList
      .filter(eq => {
        // Construction equipment more popular in spring/summer
        if ([2, 3, 4, 5].includes(currentMonth)) {
          return eq.category?.name?.toLowerCase().includes('construction');
        }
        // Landscaping in spring/fall
        if ([2, 3, 8, 9].includes(currentMonth)) {
          return eq.category?.name?.toLowerCase().includes('landscaping');
        }
        return false;
      })
      .slice(0, 3);

    if (seasonalEquipment.length > 0) {
      suggestions.push({
        type: 'seasonal',
        title: 'Seasonal Favorites',
        description: 'Perfect equipment for this time of year',
        equipment: seasonalEquipment,
      });
    }

    // Personalized suggestions based on user history
    if (user) {
      const userBookings = bookingsList.filter(b => b.renter_id === user.id);
      const userCategories = [...new Set(
        userBookings
          .map(b => b.equipment?.category?.name)
          .filter(Boolean)
      )];

      const personalizedEquipment = equipmentList
        .filter(eq =>
          userCategories.some(cat =>
            !!cat && eq.category?.name?.toLowerCase().includes(cat.toLowerCase())
          )
        )
        .slice(0, 3);

      if (personalizedEquipment.length > 0) {
        suggestions.push({
          type: 'personalized',
          title: 'Recommended for You',
          description: 'Based on your rental history',
          equipment: personalizedEquipment,
        });
      }
    }

    setAiSuggestions(suggestions);
  };

  const filteredEquipment = useMemo(() => {
    const results = equipment.filter(eq => {
      // Text search
      if (deferredQuery) {
        const searchTerm = deferredQuery.toLowerCase();
        const matchesQuery =
          eq.title.toLowerCase().includes(searchTerm) ||
          (eq.description || '').toLowerCase().includes(searchTerm) ||
          (eq.category?.name || '').toLowerCase().includes(searchTerm) ||
          (eq.location || '').toLowerCase().includes(searchTerm) ||
          eq.features.some(feature => feature.toLowerCase().includes(searchTerm));

        if (!matchesQuery) return false;
      }

      // Category filter
      if (filters.category && eq.category?.name !== filters.category) {
        return false;
      }

      // Location filter
      if (filters.location && !eq.location?.toLowerCase().includes(filters.location.toLowerCase())) {
        return false;
      }

      // Price range
      if (eq.daily_rate < filters.priceRange[0] || eq.daily_rate > filters.priceRange[1]) {
        return false;
      }

      // Rating filter
      if (filters.rating > 0 && (eq.rating || 0) < filters.rating) {
        return false;
      }

      // Features filter
      if (filters.features.length > 0) {
        const hasAllFeatures = filters.features.every(feature =>
          eq.features.some(eqFeature =>
            eqFeature.toLowerCase().includes(feature.toLowerCase())
          )
        );
        if (!hasAllFeatures) return false;
      }

      return true;
    });

    // Sorting
    results.sort((a, b) => {
      switch (filters.sortBy) {
        case 'price_low':
          return a.daily_rate - b.daily_rate;
        case 'price_high':
          return b.daily_rate - a.daily_rate;
        case 'rating':
          return (b.rating || 0) - (a.rating || 0);
        case 'newest':
          return new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime();
        case 'distance':
          // Mock distance sorting - in real app would use geolocation
          return Math.random() - 0.5;
        default:
          return 0;
      }
    });

    return results;
  }, [equipment, deferredQuery, filters]);

  const categories = useMemo(() => {
    return [...new Set(equipment.map(eq => eq.category?.name).filter(Boolean))];
  }, [equipment]);

  const availableFeatures = useMemo(() => {
    const allFeatures = equipment.flatMap(eq => eq.features);
    return [...new Set(allFeatures)].sort();
  }, [equipment]);

  const handleSuggestionClick = (suggestion: AISuggestion) => {
    if (suggestion.query) {
      setFilters(prev => ({ ...prev, query: suggestion.query! }));
    } else if (suggestion.equipment && suggestion.equipment.length > 0) {
      onEquipmentSelect?.(suggestion.equipment[0]);
    }
  };

  const clearFilters = () => {
    setFilters({
      query: '',
      category: '',
      location: '',
      priceRange: [0, 1000],
      rating: 0,
      availability: '',
      features: [],
      sortBy: 'relevance',
    });
  };

  if (loading) {
    return (
      <div className={`animate-pulse ${className}`}>
        <div className="bg-white rounded-xl p-6 border border-gray-100">
          <div className="h-12 bg-gray-200 rounded mb-6"></div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {[...Array(6)].map((_, i) => (
              <div key={i} className="h-48 bg-gray-200 rounded"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Search Header */}
      <div className="bg-white rounded-xl p-6 border border-gray-100 mb-6">
        <div className="flex items-center gap-4 mb-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
            <input
              type="text"
              placeholder="Search equipment, features, locations..."
              value={filters.query}
              onChange={(e) => setFilters(prev => ({ ...prev, query: e.target.value }))}
              className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
          <button
            aria-label="Icon button" onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center gap-2 px-4 py-3 rounded-lg border transition-colors ${
              showFilters
                ? 'bg-blue-100 text-blue-700 border-blue-300'
                : 'bg-gray-100 text-gray-700 border-gray-300 hover:bg-gray-200'
            }`}
          >
            <SlidersHorizontal className="w-4 h-4" />
            Filters
          </button>
        </div>

        {/* AI Suggestions */}
        {aiSuggestions.length > 0 && !filters.query && (
          <div className="mb-4">
            <div className="flex items-center gap-2 mb-3">
              <Sparkles className="w-4 h-4 text-purple-600" />
              <span className="text-sm font-medium text-gray-700">AI Suggestions</span>
            </div>
            <div className="flex gap-2 overflow-x-auto pb-2">
              {aiSuggestions.map((suggestion, index) => (
                <button
                  key={index}
                  aria-label="Icon button" onClick={() => handleSuggestionClick(suggestion)}
                  className="flex-shrink-0 bg-purple-50 hover:bg-purple-100 text-purple-700 px-4 py-2 rounded-lg text-sm font-medium transition-colors border border-purple-200"
                >
                  {suggestion.title}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Active Filters */}
        {(filters.category || filters.location || filters.rating > 0 || filters.features.length > 0) && (
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-sm text-gray-600">Active filters:</span>
            {filters.category && (
              <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-xs">
                {filters.category}
              </span>
            )}
            {filters.location && (
              <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs">
                📍 {filters.location}
              </span>
            )}
            {filters.rating > 0 && (
              <span className="bg-yellow-100 text-yellow-700 px-2 py-1 rounded text-xs">
                ⭐ {filters.rating}+ stars
              </span>
            )}
            {filters.features.map((feature, index) => (
              <span key={index} className="bg-purple-100 text-purple-700 px-2 py-1 rounded text-xs">
                {feature}
              </span>
            ))}
            <button
              onClick={clearFilters}
              className="text-sm text-gray-500 hover:text-gray-700 underline"
             aria-label="Icon button">
              Clear all
            </button>
          </div>
        )}
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="bg-white rounded-xl p-6 border border-gray-100 mb-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Category */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Category
              </label>
              <select
                value={filters.category}
                onChange={(e) => setFilters(prev => ({ ...prev, category: e.target.value }))}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="">All Categories</option>
                {categories.map((category) => (
                  <option key={category} value={category}>{category}</option>
                ))}
              </select>
            </div>

            {/* Location */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Location
              </label>
              <div className="relative">
                <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                <input
                  type="text"
                  placeholder="Enter location"
                  value={filters.location}
                  onChange={(e) => setFilters(prev => ({ ...prev, location: e.target.value }))}
                  className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>

            {/* Price Range */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Daily Rate: ${filters.priceRange[0]} - ${filters.priceRange[1]}
              </label>
              <div className="px-2">
                <input
                  type="range"
                  min="0"
                  max="2000"
                  step="50"
                  value={filters.priceRange[1]}
                  onChange={(e) => setFilters(prev => ({
                    ...prev,
                    priceRange: [prev.priceRange[0], parseInt(e.target.value)]
                  }))}
                  className="w-full"
                />
              </div>
            </div>

            {/* Rating */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Minimum Rating
              </label>
              <div className="flex items-center gap-2">
                {[1, 2, 3, 4, 5].map((rating) => (
                  <button
                    key={rating}
                    aria-label="Icon button"> setFilters(prev => ({ ...prev, rating: prev.rating === rating ? 0 : rating }))}
                    className={`flex items-center gap-1 px-2 py-1 rounded ${
                      filters.rating >= rating
                        ? 'bg-yellow-100 text-yellow-700'
                        : 'bg-gray-100 text-gray-400'
                    }`}
                  >
                    <Star className={`w-4 h-4 ${filters.rating >= rating ? 'fill-current' : ''}`} />
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Features */}
          <div className="mt-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Features
            </label>
            <div className="flex flex-wrap gap-2">
              {availableFeatures.slice(0, 12).map((feature) => (
                <button
                  key={feature}
                  aria-label="Icon button"> setFilters(prev => ({
                    ...prev,
                    features: prev.features.includes(feature)
                      ? prev.features.filter(f => f !== feature)
                      : [...prev.features, feature]
                  }))}
                  className={`px-3 py-1 rounded-full text-sm transition-colors ${
                    filters.features.includes(feature)
                      ? 'bg-blue-100 text-blue-700 border border-blue-300'
                      : 'bg-gray-100 text-gray-700 border border-gray-300 hover:bg-gray-200'
                  }`}
                >
                  {feature}
                </button>
              ))}
            </div>
          </div>

          {/* Sort Options */}
          <div className="mt-6 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <label className="text-sm font-medium text-gray-700">Sort by:</label>
              <select
                value={filters.sortBy}
                onChange={(e) => setFilters(prev => ({ ...prev, sortBy: e.target.value as SearchFilters['sortBy'] }))}
                className="px-3 py-1 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="relevance">Relevance</option>
                <option value="price_low">Price: Low to High</option>
                <option value="price_high">Price: High to Low</option>
                <option value="rating">Highest Rated</option>
                <option value="distance">Distance</option>
                <option value="newest">Newest</option>
              </select>
            </div>
            <div className="text-sm text-gray-600">
              {filteredEquipment.length} results found
            </div>
          </div>
        </div>
      )}

      {/* Results */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredEquipment.map((eq) => (
          <div
            key={eq.id}
            onClick={() => onEquipmentSelect?.(eq)}
            className="bg-white rounded-xl border border-gray-100 p-6 hover:shadow-lg transition-all cursor-pointer group"
          >
            <div className="relative mb-4">
              <img
                src={eq.images[0] || '/placeholder-equipment.jpg'}
                alt={eq.title}
                className="w-full h-48 object-cover rounded-lg group-hover:scale-105 transition-transform"
              />
              <div className="absolute top-2 right-2 bg-white/90 backdrop-blur-sm px-2 py-1 rounded-full">
                <div className="flex items-center gap-1">
                  <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
                  <span className="text-sm font-medium">{eq.rating?.toFixed(1) || 'N/A'}</span>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <div>
                <h3 className="font-semibold text-gray-900 group-hover:text-blue-600 transition-colors">
                  {eq.title}
                </h3>
                <p className="text-sm text-gray-600">{eq.category?.name}</p>
              </div>

              <div className="flex items-center gap-2 text-sm text-gray-600">
                <MapPin className="w-4 h-4" />
                <span>{eq.location || 'Location not specified'}</span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-1">
                  <DollarSign className="w-4 h-4 text-green-600" />
                  <span className="text-lg font-bold text-gray-900">${eq.daily_rate}</span>
                  <span className="text-sm text-gray-600">/day</span>
                </div>
                <button className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium" aria-label="Icon button">
                  View Details
                </button>
              </div>

              <div className="flex flex-wrap gap-1">
                {eq.features.slice(0, 3).map((feature, index) => (
                  <span
                    key={index}
                    className="bg-gray-100 text-gray-700 px-2 py-1 rounded text-xs"
                  >
                    {feature}
                  </span>
                ))}
                {eq.features.length > 3 && (
                  <span className="bg-gray-100 text-gray-700 px-2 py-1 rounded text-xs">
                    +{eq.features.length - 3} more
                  </span>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredEquipment.length === 0 && (
        <div className="text-center py-12">
          <Search className="w-12 h-12 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No equipment found</h3>
          <p className="text-gray-600 mb-4">Try adjusting your search criteria or filters.</p>
          <button
            onClick={clearFilters}
            className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
           aria-label="Icon button">
            Clear Filters
          </button>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import {
  Fingerprint,
  Scan,
  Shield,
  CheckCircle,
  AlertCircle,
  Smartphone,
  Key,
  Lock,
  X,
  Loader2,
} from 'lucide-react';

interface BiometricAuthProps {
  onSuccess: () => void;
  onCancel: () => void;
  mode?: 'register' | 'authenticate';
}

export default function BiometricAuth({ onSuccess, onCancel, mode = 'authenticate' }: BiometricAuthProps) {
  const [status, setStatus] = useState<'idle' | 'scanning' | 'success' | 'error'>('idle');
  const [biometricType, setBiometricType] = useState<'fingerprint' | 'face' | 'none'>('none');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isSupported, setIsSupported] = useState<boolean | null>(null);

  // Check if biometric authentication is available
  useEffect(() => {
    checkBiometricSupport();
  }, []);

  const checkBiometricSupport = async () => {
    try {
      // Check if WebAuthn is available
      if (window.PublicKeyCredential) {
        const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
        setIsSupported(available);
        if (available) {
          // Determine the likely biometric type based on platform
          const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
          const isApple = /iPhone|iPad|iPod|Mac/i.test(navigator.userAgent);
          setBiometricType(isApple && isMobile ? 'face' : 'fingerprint');
        }
      } else {
        setIsSupported(false);
      }
    } catch {
      setIsSupported(false);
    }
  };

  const startBiometricAuth = async () => {
    setStatus('scanning');
    setErrorMessage(null);

    try {
      // Simulate biometric authentication
      // In production, use WebAuthn API
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      // Simulate success (80% success rate for demo)
      const isSuccess = Math.random() > 0.2;
      
      if (isSuccess) {
        setStatus('success');
        setTimeout(() => {
          onSuccess();
        }, 1500);
      } else {
        throw new Error('Authentication failed. Please try again.');
      }
    } catch (err) {
      setStatus('error');
      setErrorMessage(err instanceof Error ? err.message : 'Authentication failed');
    }
  };

  const BiometricIcon = biometricType === 'face' ? Scan : Fingerprint;

  return (
    <div className="bg-white rounded-2xl shadow-xl max-w-md w-full overflow-hidden">
      {/* Header */}
      <div className="bg-gradient-to-r from-teal-600 to-emerald-600 p-6 text-white">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-3 bg-white/20 rounded-xl">
              <Shield className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">
                {mode === 'register' ? 'Set Up Biometrics' : 'Biometric Login'}
              </h2>
              <p className="text-teal-100 text-sm">
                {mode === 'register' ? 'Secure your account with biometrics' : 'Quick and secure authentication'}
              </p>
            </div>
          </div>
          <button
            onClick={onCancel}
            className="p-2 hover:bg-white/20 rounded-lg transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="p-6">
        {isSupported === null ? (
          <div className="text-center py-8">
            <Loader2 className="w-12 h-12 text-teal-600 animate-spin mx-auto mb-4" />
            <p className="text-gray-600">Checking device compatibility...</p>
          </div>
        ) : !isSupported ? (
          <div className="text-center py-8">
            <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertCircle className="w-8 h-8 text-amber-600" />
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">Not Supported</h3>
            <p className="text-gray-600 mb-6">
              Biometric authentication is not available on this device. Please use your password to log in.
            </p>
            <button
              onClick={onCancel}
              className="px-6 py-3 bg-teal-600 text-white rounded-xl font-semibold hover:bg-teal-700 transition-colors"
             aria-label="Icon button">
              Use Password Instead
            </button>
          </div>
        ) : (
          <>
            {/* Biometric Visualization */}
            <div className="text-center py-8">
              <div className={`relative w-32 h-32 mx-auto mb-6 ${status === 'scanning' ? 'animate-pulse' : ''}`}>
                {/* Outer ring */}
                <div className={`absolute inset-0 rounded-full border-4 transition-colors duration-300 ${
                  status === 'idle' ? 'border-gray-200' :
                  status === 'scanning' ? 'border-teal-300 animate-ping' :
                  status === 'success' ? 'border-green-500' :
                  'border-red-500'
                }`} />
                
                {/* Inner circle */}
                <div className={`absolute inset-4 rounded-full flex items-center justify-center transition-colors duration-300 ${
                  status === 'idle' ? 'bg-gray-100' :
                  status === 'scanning' ? 'bg-teal-50' :
                  status === 'success' ? 'bg-green-50' :
                  'bg-red-50'
                }`}>
                  {status === 'success' ? (
                    <CheckCircle className="w-12 h-12 text-green-500" />
                  ) : status === 'error' ? (
                    <AlertCircle className="w-12 h-12 text-red-500" />
                  ) : (
                    <BiometricIcon className={`w-12 h-12 ${
                      status === 'scanning' ? 'text-teal-600 animate-pulse' : 'text-gray-400'
                    }`} />
                  )}
                </div>

                {/* Scanning animation rings */}
                {status === 'scanning' && (
                  <>
                    <div className="absolute inset-0 rounded-full border-2 border-teal-400 animate-ping opacity-75" style={{ animationDelay: '0s' }} />
                    <div className="absolute inset-0 rounded-full border-2 border-teal-400 animate-ping opacity-50" style={{ animationDelay: '0.5s' }} />
                  </>
                )}
              </div>

              {/* Status Text */}
              <h3 className={`text-lg font-semibold mb-2 ${
                status === 'success' ? 'text-green-600' :
                status === 'error' ? 'text-red-600' :
                'text-gray-900'
              }`}>
                {status === 'idle' && (biometricType === 'face' ? 'Face ID Ready' : 'Touch ID Ready')}
                {status === 'scanning' && 'Scanning...'}
                {status === 'success' && 'Authentication Successful!'}
                {status === 'error' && 'Authentication Failed'}
              </h3>

              <p className="text-gray-600 text-sm">
                {status === 'idle' && `Tap the button below to authenticate with ${biometricType === 'face' ? 'Face ID' : 'Touch ID'}`}
                {status === 'scanning' && `Place your ${biometricType === 'face' ? 'face' : 'finger'} on the sensor`}
                {status === 'success' && 'You have been successfully authenticated'}
                {status === 'error' && errorMessage}
              </p>
            </div>

            {/* Actions */}
            {status !== 'success' && (
              <div className="space-y-3">
                <button
                  onClick={startBiometricAuth}
                  disabled={status === 'scanning'}
                  className={`w-full py-4 rounded-xl font-semibold flex items-center justify-center gap-3 transition-all ${
                    status === 'scanning'
                      ? 'bg-teal-100 text-teal-600 cursor-not-allowed'
                      : 'bg-teal-600 text-white hover:bg-teal-700'
                  } aria-label="Icon button">
                  {status === 'scanning' ? (
                    <>
                      <Loader2 className="w-5 h-5 animate-spin" />
                      Authenticating...
                    </>
                  ) : (
                    <>
                      <BiometricIcon className="w-5 h-5" />
                      {biometricType === 'face' ? 'Use Face ID' : 'Use Touch ID'}
                    </>
                  )}
                </button>

                <button
                  onClick={onCancel}
                  className="w-full py-3 text-gray-600 hover:text-gray-900 font-medium flex items-center justify-center gap-2"
                 aria-label="Icon button">
                  <Key className="w-4 h-4" />
                  Use Password Instead
                </button>
              </div>
            )}

            {/* Security Info */}
            <div className="mt-6 p-4 bg-gray-50 rounded-xl">
              <h4 className="font-medium text-gray-900 mb-2 flex items-center gap-2">
                <Lock className="w-4 h-4 text-teal-600" />
                Security Information
              </h4>
              <ul className="text-sm text-gray-600 space-y-1">
                <li className="flex items-start gap-2">
                  <CheckCircle className="w-4 h-4 text-green-500 mt-0.5 flex-shrink-0" />
                  <span>Your biometric data never leaves your device</span>
                </li>
                <li className="flex items-start gap-2">
                  <CheckCircle className="w-4 h-4 text-green-500 mt-0.5 flex-shrink-0" />
                  <span>256-bit end-to-end encryption</span>
                </li>
                <li className="flex items-start gap-2">
                  <CheckCircle className="w-4 h-4 text-green-500 mt-0.5 flex-shrink-0" />
                  <span>Compliant with FIDO2 security standards</span>
                </li>
              </ul>
            </div>
          </>
        )}
      </div>

      {/* Device Support Note */}
      <div className="px-6 pb-6">
        <div className="flex items-center gap-2 text-xs text-gray-500">
          <Smartphone className="w-4 h-4" />
          <span>Supported devices: iPhone (Face ID/Touch ID), iPad, Mac, Windows Hello, Android Fingerprint</span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import {
  Mail,
  Bell,
  MessageSquare,
  Star,
  DollarSign,
  Megaphone,
  Calendar,
  CheckCircle2,
  AlertCircle,
  Loader2,
} from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../lib/supabase';
import type { EmailPreferences as EmailPreferencesType } from '../../types';

interface EmailPreferencesProps {
  className?: string;
}

interface PreferenceOption {
  key: keyof Omit<EmailPreferencesType, 'id' | 'user_id' | 'created_at' | 'updated_at'>;
  label: string;
  description: string;
  icon: React.ReactNode;
  category: 'transactions' | 'communications' | 'marketing';
}

const preferenceOptions: PreferenceOption[] = [
  {
    key: 'booking_confirmations',
    label: 'Booking Confirmations',
    description: 'Receive confirmation emails when bookings are made, confirmed, or cancelled',
    icon: <CheckCircle2 className="w-5 h-5" />,
    category: 'transactions',
  },
  {
    key: 'booking_reminders',
    label: 'Booking Reminders',
    description: 'Get reminded about upcoming pickups and returns',
    icon: <Calendar className="w-5 h-5" />,
    category: 'transactions',
  },
  {
    key: 'new_messages',
    label: 'New Messages',
    description: 'Receive email notifications when you get new messages',
    icon: <MessageSquare className="w-5 h-5" />,
    category: 'communications',
  },
  {
    key: 'new_reviews',
    label: 'New Reviews',
    description: 'Get notified when someone leaves a review on your equipment or profile',
    icon: <Star className="w-5 h-5" />,
    category: 'communications',
  },
  {
    key: 'price_alerts',
    label: 'Price Alerts',
    description: 'Receive alerts when saved equipment has price changes',
    icon: <DollarSign className="w-5 h-5" />,
    category: 'communications',
  },
  {
    key: 'marketing_emails',
    label: 'Marketing & Promotions',
    description: 'Receive special offers, promotions, and announcements',
    icon: <Megaphone className="w-5 h-5" />,
    category: 'marketing',
  },
  {
    key: 'weekly_digest',
    label: 'Weekly Digest',
    description: 'Get a weekly summary of your activity and recommended equipment',
    icon: <Mail className="w-5 h-5" />,
    category: 'marketing',
  },
];

export default function EmailPreferences({ className = '' }: EmailPreferencesProps) {
  const { user } = useAuth();
  const [preferences, setPreferences] = useState<EmailPreferencesType | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (user) {
      loadPreferences();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  const loadPreferences = async () => {
    if (!user) return;

    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('email_preferences')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (error) {
        // If no preferences exist, create defaults
        if (error.code === 'PGRST116') {
          const { data: newData, error: insertError } = await supabase
            .from('email_preferences')
            .insert({ user_id: user.id })
            .select()
            .single();

          if (insertError) throw insertError;
          setPreferences(newData);
        } else {
          throw error;
        }
      } else {
        setPreferences(data);
      }
    } catch (err) {
      console.error('Error loading email preferences:', err);
      setError('Failed to load email preferences');
    } finally {
      setIsLoading(false);
    }
  };

  const handleToggle = async (key: PreferenceOption['key']) => {
    if (!preferences || !user) return;

    const newValue = !preferences[key];
    
    // Optimistically update UI
    setPreferences(prev => prev ? { ...prev, [key]: newValue } : null);
    
    setIsSaving(true);
    setSaveStatus('idle');

    try {
      const { error } = await supabase
        .from('email_preferences')
        .update({ [key]: newValue, updated_at: new Date().toISOString() })
        .eq('user_id', user.id);

      if (error) throw error;
      setSaveStatus('success');
      setTimeout(() => setSaveStatus('idle'), 2000);
    } catch (err) {
      console.error('Error updating preference:', err);
      // Revert on error
      setPreferences(prev => prev ? { ...prev, [key]: !newValue } : null);
      setSaveStatus('error');
      setTimeout(() => setSaveStatus('idle'), 3000);
    } finally {
      setIsSaving(false);
    }
  };

  const handleEnableAll = async () => {
    if (!user || !preferences) return;

    const updates = preferenceOptions.reduce((acc, opt) => {
      acc[opt.key] = true;
      return acc;
    }, {} as Record<string, boolean>);

    setIsSaving(true);
    try {
      const { error } = await supabase
        .from('email_preferences')
        .update({ ...updates, updated_at: new Date().toISOString() })
        .eq('user_id', user.id);

      if (error) throw error;
      setPreferences(prev => prev ? { ...prev, ...updates } : null);
      setSaveStatus('success');
      setTimeout(() => setSaveStatus('idle'), 2000);
    } catch (err) {
      console.error('Error enabling all preferences:', err);
      setSaveStatus('error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleDisableAll = async () => {
    if (!user || !preferences) return;

    const updates = preferenceOptions.reduce((acc, opt) => {
      acc[opt.key] = false;
      return acc;
    }, {} as Record<string, boolean>);

    setIsSaving(true);
    try {
      const { error } = await supabase
        .from('email_preferences')
        .update({ ...updates, updated_at: new Date().toISOString() })
        .eq('user_id', user.id);

      if (error) throw error;
      setPreferences(prev => prev ? { ...prev, ...updates } : null);
      setSaveStatus('success');
      setTimeout(() => setSaveStatus('idle'), 2000);
    } catch (err) {
      console.error('Error disabling all preferences:', err);
      setSaveStatus('error');
    } finally {
      setIsSaving(false);
    }
  };

  const renderCategory = (category: string, title: string) => {
    const items = preferenceOptions.filter(opt => opt.category === category);
    
    return (
      <div key={category} className="mb-8">
        <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wide mb-4">
          {title}
        </h3>
        <div className="space-y-4">
          {items.map((option) => (
            <div
              key={option.key}
              className="flex items-start justify-between p-4 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors"
            >
              <div className="flex items-start gap-4">
                <div className="p-2 bg-white rounded-lg text-teal-500 shadow-sm">
                  {option.icon}
                </div>
                <div>
                  <p className="font-medium text-gray-900">{option.label}</p>
                  <p className="text-sm text-gray-500 mt-1">{option.description}</p>
                </div>
              </div>
              <button
                onClick={() =>  handleToggle(option.key)}
                disabled={isSaving || !preferences}
                className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-teal-500 focus:ring-offset-2 ${
                  preferences?.[option.key]
                    ? 'bg-teal-500'
                    : 'bg-gray-200'
                } ${isSaving ? 'opacity-50 cursor-not-allowed' : ''}`}
                aria-pressed={preferences?.[option.key]}
                aria-label={`Toggle ${option.label}`}
              >
                <span
                  className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${
                    preferences?.[option.key] ? 'translate-x-5' : 'translate-x-0'
                  }`}
                />
              </button>
            </div>
          ))}
        </div>
      </div>
    );
  };

  if (isLoading) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <Loader2 className="w-8 h-8 text-teal-500 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className={`text-center py-12 ${className}`}>
        <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-4" />
        <p className="text-gray-600">{error}</p>
        <button
          onClick={loadPreferences}
          className="mt-4 px-4 py-2 bg-teal-500 text-white rounded-lg hover:bg-teal-600 transition-colors"
         aria-label="Icon button">
          Try Again
        </button>
      </div>
    );
  }

  return (
    <div className={className}>
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <div className="p-3 bg-gradient-to-br from-teal-500 to-emerald-500 rounded-xl text-white">
            <Bell className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-gray-900">Email Notifications</h2>
            <p className="text-gray-500 text-sm">Manage your email preferences</p>
          </div>
        </div>
        
        {/* Save Status Indicator */}
        {saveStatus !== 'idle' && (
          <div
            className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium ${
              saveStatus === 'success'
                ? 'bg-green-100 text-green-700'
                : 'bg-red-100 text-red-700'
            }`}
          >
            {saveStatus === 'success' ? (
              <>
                <CheckCircle2 className="w-4 h-4" />
                Saved
              </>
            ) : (
              <>
                <AlertCircle className="w-4 h-4" />
                Error saving
              </>
            )}
          </div>
        )}
      </div>

      {/* Quick Actions */}
      <div className="flex items-center gap-3 mb-6">
        <button
          onClick={handleEnableAll}
          disabled={isSaving}
          className="flex items-center gap-2 px-4 py-2 bg-teal-50 text-teal-700 rounded-lg hover:bg-teal-100 transition-colors disabled:opacity-50"
         aria-label="Icon button">
          <CheckCircle2 className="w-4 h-4" />
          Enable All
        </button>
        <button
          onClick={handleDisableAll}
          disabled={isSaving}
          className="flex items-center gap-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors disabled:opacity-50"
         aria-label="Icon button">
          <Bell className="w-4 h-4" />
          Disable All
        </button>
        {isSaving && (
          <div className="flex items-center gap-2 text-gray-500">
            <Loader2 className="w-4 h-4 animate-spin" />
            <span className="text-sm">Saving...</span>
          </div>
        )}
      </div>

      {/* Preference Categories */}
      {renderCategory('transactions', 'Transactions')}
      {renderCategory('communications', 'Communications')}
      {renderCategory('marketing', 'Marketing & Updates')}

      {/* Unsubscribe Note */}
      <div className="mt-8 p-4 bg-gray-50 rounded-xl">
        <p className="text-sm text-gray-500">
          <strong>Note:</strong> You will always receive important account and security emails 
          regardless of these settings. You can unsubscribe from all marketing emails at any time 
          by clicking the unsubscribe link in any email.
        </p>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import {
  Bell,
  BellOff,
  BellRing,
  Smartphone,
  Moon,
  Clock,
  MessageSquare,
  Calendar,
  Star,
  Tag,
  Megaphone,
  AlertCircle,
  CheckCircle2,
  Loader2,
  Globe,
} from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../lib/supabase';
import {
  isPushSupported,
  getNotificationPermission,
  subscribeToPush,
  unsubscribeFromPush,
  isPushSubscribed,
  showLocalNotification,
} from '../../services/pushNotifications';

interface NotificationPreferences {
  push_enabled: boolean;
  push_booking_requests: boolean;
  push_booking_updates: boolean;
  push_messages: boolean;
  push_reviews: boolean;
  push_price_alerts: boolean;
  push_promotions: boolean;
  push_reminders: boolean;
  quiet_hours_enabled: boolean;
  quiet_hours_start: string;
  quiet_hours_end: string;
  timezone: string;
}

const defaultPreferences: NotificationPreferences = {
  push_enabled: true,
  push_booking_requests: true,
  push_booking_updates: true,
  push_messages: true,
  push_reviews: true,
  push_price_alerts: true,
  push_promotions: false,
  push_reminders: true,
  quiet_hours_enabled: false,
  quiet_hours_start: '22:00',
  quiet_hours_end: '08:00',
  timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
};

export default function NotificationSettings() {
  const { user } = useAuth();
  const [preferences, setPreferences] = useState<NotificationPreferences>(defaultPreferences);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [subscriptionStatus, setSubscriptionStatus] = useState<'loading' | 'subscribed' | 'unsubscribed' | 'unsupported' | 'denied'>('loading');
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  // Check push support and subscription status on mount
  useEffect(() => {
    checkSubscriptionStatus();
    loadPreferences();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const checkSubscriptionStatus = async () => {
    if (!isPushSupported()) {
      setSubscriptionStatus('unsupported');
      return;
    }

    const permission = getNotificationPermission();
    if (permission === 'denied') {
      setSubscriptionStatus('denied');
      return;
    }

    const subscribed = await isPushSubscribed();
    setSubscriptionStatus(subscribed ? 'subscribed' : 'unsubscribed');
  };

  const loadPreferences = async () => {
    if (!user) return;

    try {
      const { data, error } = await supabase
        .from('notification_preferences')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (error && error.code !== 'PGRST116') {
        throw error;
      }

      if (data) {
        setPreferences({
          push_enabled: data.push_enabled ?? true,
          push_booking_requests: data.push_booking_requests ?? true,
          push_booking_updates: data.push_booking_updates ?? true,
          push_messages: data.push_messages ?? true,
          push_reviews: data.push_reviews ?? true,
          push_price_alerts: data.push_price_alerts ?? true,
          push_promotions: data.push_promotions ?? false,
          push_reminders: data.push_reminders ?? true,
          quiet_hours_enabled: data.quiet_hours_enabled ?? false,
          quiet_hours_start: data.quiet_hours_start ?? '22:00',
          quiet_hours_end: data.quiet_hours_end ?? '08:00',
          timezone: data.timezone ?? Intl.DateTimeFormat().resolvedOptions().timeZone,
        });
      }
    } catch (error) {
      console.error('Failed to load preferences:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const savePreferences = async (newPrefs: NotificationPreferences) => {
    if (!user) return;

    setIsSaving(true);
    try {
      const { error } = await supabase
        .from('notification_preferences')
        .upsert({
          user_id: user.id,
          ...newPrefs,
          updated_at: new Date().toISOString(),
        });

      if (error) throw error;

      setMessage({ type: 'success', text: 'Preferences saved!' });
      setTimeout(() => setMessage(null), 3000);
    } catch (error) {
      console.error('Failed to save preferences:', error);
      setMessage({ type: 'error', text: 'Failed to save preferences' });
    } finally {
      setIsSaving(false);
    }
  };

  const updatePreference = (key: keyof NotificationPreferences, value: boolean | string) => {
    const newPrefs = { ...preferences, [key]: value };
    setPreferences(newPrefs);
    savePreferences(newPrefs);
  };

  const handleEnablePush = async () => {
    if (!user) return;

    setSubscriptionStatus('loading');
    try {
      const success = await subscribeToPush(user.id);
      if (success) {
        setSubscriptionStatus('subscribed');
        updatePreference('push_enabled', true);
        showLocalNotification('Notifications Enabled! 🔔', {
          body: 'You will now receive push notifications from Islakayd',
        });
      } else {
        setSubscriptionStatus('unsubscribed');
        setMessage({ type: 'error', text: 'Failed to enable notifications' });
      }
    } catch (error) {
      console.error('Enable push failed:', error);
      setSubscriptionStatus('unsubscribed');
      setMessage({ type: 'error', text: 'Failed to enable notifications' });
    }
  };

  const handleDisablePush = async () => {
    setSubscriptionStatus('loading');
    try {
      await unsubscribeFromPush();
      setSubscriptionStatus('unsubscribed');
      updatePreference('push_enabled', false);
    } catch (error) {
      console.error('Disable push failed:', error);
    }
  };

  const testNotification = () => {
    showLocalNotification('Test Notification 🎉', {
      body: 'If you see this, notifications are working!',
      icon: '/icons/icon-192x192.png',
    });
  };

  if (isLoading) {
    return (
      <div className="p-6 flex items-center justify-center">
        <Loader2 className="w-6 h-6 animate-spin text-teal-500" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Status Message */}
      {message && (
        <div
          className={`p-4 rounded-xl flex items-center gap-3 ${
            message.type === 'success'
              ? 'bg-green-50 text-green-700'
              : 'bg-red-50 text-red-700'
          }`}
        >
          {message.type === 'success' ? (
            <CheckCircle2 className="w-5 h-5" />
          ) : (
            <AlertCircle className="w-5 h-5" />
          )}
          {message.text}
        </div>
      )}

      {/* Main Push Toggle */}
      <div className="bg-gradient-to-r from-teal-500 to-emerald-500 rounded-2xl p-6 text-white">
