import { useState, useEffect } from 'react';
import {
  Users,
  TrendingUp,
  MapPin,
  Clock,
  Star,
  ShoppingBag,
  Eye,
  MessageCircle,
  Zap,
  Award,
} from 'lucide-react';

interface SocialProofProps {
  equipmentId?: string;
  className?: string;
  onClose?: () => void;
}

interface LiveActivity {
  id: string;
  type: 'booking' | 'viewing' | 'inquiry' | 'review' | 'saved';
  user: string;
  location: string;
  timeAgo: string;
  equipment?: string;
  message?: string;
}

export default function SocialProof({ equipmentId: _equipmentId, className = '' }: SocialProofProps) {
  // equipmentId reserved for filtering activities
  const [activities, setActivities] = useState<LiveActivity[]>([]);
  const [currentActivity, setCurrentActivity] = useState<LiveActivity | null>(null);
  const [stats, setStats] = useState({
    viewingNow: 12,
    bookedToday: 47,
    bookedThisWeek: 234,
    averageRating: 4.8,
  });
  const [showNotification, setShowNotification] = useState(false);

  // Sample activities - in production, these would come from real-time database
  const sampleActivities: LiveActivity[] = [
    { id: '1', type: 'booking', user: 'Michael R.', location: 'Los Angeles, CA', timeAgo: '2 min ago', equipment: 'CAT Excavator' },
    { id: '2', type: 'viewing', user: 'Sarah K.', location: 'San Francisco, CA', timeAgo: 'Just now', equipment: 'Sony Camera Kit' },
    { id: '3', type: 'inquiry', user: 'James T.', location: 'Austin, TX', timeAgo: '5 min ago', equipment: 'DeWalt Tool Set' },
    { id: '4', type: 'review', user: 'Emily D.', location: 'Miami, FL', timeAgo: '8 min ago', message: 'Left a 5-star review' },
    { id: '5', type: 'saved', user: 'David M.', location: 'Seattle, WA', timeAgo: '3 min ago', equipment: 'DJ Equipment Package' },
    { id: '6', type: 'booking', user: 'Lisa W.', location: 'Denver, CO', timeAgo: '12 min ago', equipment: 'John Deere Tractor' },
    { id: '7', type: 'viewing', user: 'Chris P.', location: 'Nashville, TN', timeAgo: 'Just now', equipment: 'Wedding Tent Package' },
    { id: '8', type: 'booking', user: 'Anna S.', location: 'Phoenix, AZ', timeAgo: '7 min ago', equipment: 'Pressure Washer' },
  ];

  useEffect(() => {
    setActivities(sampleActivities);

    // Rotate through activities
    let index = 0;
    const interval = setInterval(() => {
      setCurrentActivity(sampleActivities[index]);
      setShowNotification(true);
      
      setTimeout(() => setShowNotification(false), 4000);
      
      index = (index + 1) % sampleActivities.length;
    }, 8000);

    // Update stats periodically
    const statsInterval = setInterval(() => {
      setStats(prev => ({
        ...prev,
        viewingNow: prev.viewingNow + Math.floor(Math.random() * 3) - 1,
        bookedToday: prev.bookedToday + (Math.random() > 0.7 ? 1 : 0),
      }));
    }, 15000);

    return () => {
      clearInterval(interval);
      clearInterval(statsInterval);
    };
  }, []);

  const getActivityIcon = (type: LiveActivity['type']) => {
    switch (type) {
      case 'booking': return <ShoppingBag className="w-4 h-4" />;
      case 'viewing': return <Eye className="w-4 h-4" />;
      case 'inquiry': return <MessageCircle className="w-4 h-4" />;
      case 'review': return <Star className="w-4 h-4" />;
      case 'saved': return <Award className="w-4 h-4" />;
    }
  };

  const getActivityColor = (type: LiveActivity['type']) => {
    switch (type) {
      case 'booking': return 'bg-green-500';
      case 'viewing': return 'bg-blue-500';
      case 'inquiry': return 'bg-purple-500';
      case 'review': return 'bg-amber-500';
      case 'saved': return 'bg-pink-500';
    }
  };

  const getActivityText = (activity: LiveActivity) => {
    switch (activity.type) {
      case 'booking': return `just booked ${activity.equipment}`;
      case 'viewing': return `is viewing ${activity.equipment}`;
      case 'inquiry': return `asked about ${activity.equipment}`;
      case 'review': return activity.message;
      case 'saved': return `saved ${activity.equipment}`;
    }
  };

  return (
    <div className={className}>
      {/* Stats Bar */}
      <div className="bg-gradient-to-r from-gray-900 to-gray-800 text-white py-2 px-4 rounded-xl mb-4">
        <div className="flex items-center justify-between text-sm">
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-1.5">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
              <Users className="w-4 h-4" />
              <strong>{stats.viewingNow}</strong> viewing now
            </span>
            <span className="hidden sm:flex items-center gap-1.5">
              <TrendingUp className="w-4 h-4 text-green-400" />
              <strong>{stats.bookedToday}</strong> booked today
            </span>
          </div>
          <div className="flex items-center gap-1">
            <Star className="w-4 h-4 text-amber-400 fill-amber-400" />
            <span>{stats.averageRating} avg rating</span>
          </div>
        </div>
      </div>

      {/* Live Activity Notification */}
      {showNotification && currentActivity && (
        <div className="fixed bottom-24 left-6 z-50 animate-in slide-in-from-left duration-300">
          <div className="bg-white rounded-xl shadow-2xl border border-gray-100 p-4 max-w-sm">
            <div className="flex items-start gap-3">
              <div className={`w-10 h-10 ${getActivityColor(currentActivity.type)} rounded-full flex items-center justify-center text-white`}>
                {getActivityIcon(currentActivity.type)}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm text-gray-900">
                  <strong>{currentActivity.user}</strong>{' '}
                  <span className="text-gray-600">{getActivityText(currentActivity)}</span>
                </p>
                <p className="text-xs text-gray-500 flex items-center gap-2 mt-1">
                  <MapPin className="w-3 h-3" />
                  {currentActivity.location}
                  <span>•</span>
                  <Clock className="w-3 h-3" />
                  {currentActivity.timeAgo}
                </p>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Urgency Indicators */}
      <div className="flex flex-wrap gap-2 mb-4">
        <span className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-red-50 text-red-700 rounded-full text-sm font-medium">
          <Zap className="w-4 h-4" />
          High demand - book now!
        </span>
        <span className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-amber-50 text-amber-700 rounded-full text-sm font-medium">
          <Clock className="w-4 h-4" />
          Only 3 available this week
        </span>
      </div>

      {/* Recent Activity Feed (Optional) */}
      <div className="bg-gray-50 rounded-xl p-4">
        <h4 className="text-sm font-semibold text-gray-900 mb-3 flex items-center gap-2">
          <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
          Live Activity
        </h4>
        <div className="space-y-2 max-h-32 overflow-y-auto">
          {activities.slice(0, 4).map((activity) => (
            <div key={activity.id} className="flex items-center gap-2 text-sm">
              <div className={`w-6 h-6 ${getActivityColor(activity.type)} rounded-full flex items-center justify-center text-white text-xs`}>
                {getActivityIcon(activity.type)}
              </div>
              <span className="text-gray-600 truncate flex-1">
                <strong className="text-gray-900">{activity.user}</strong>{' '}
                {getActivityText(activity)}
              </span>
              <span className="text-xs text-gray-400">{activity.timeAgo}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useState, useMemo } from 'react';
import {
  Leaf,
  TreeDeciduous,
  Droplets,
  Factory,
  TrendingDown,
  BarChart3,
  Share2,
  Download,
  ChevronDown,
  Award,
  Car,
  Battery,
  Sun,
  Wind,
  Recycle,
  Target,
  Sparkles,
} from 'lucide-react';

interface CarbonData {
  co2Emissions: number; // kg CO2
  fuelUsed: number; // liters
  hoursOperated: number;
  distanceTraveled?: number; // km
  equipmentType: string;
}

interface CarbonSavings {
  vsOwnership: number;
  vsOlderModel: number;
  fromSharedUse: number;
  total: number;
}

interface ImpactEquivalent {
  icon: typeof TreeDeciduous;
  label: string;
  value: string;
  description: string;
}

interface RentalCarbonData {
  bookingId: string;
  equipmentName: string;
  startDate: Date;
  endDate: Date;
  carbonData: CarbonData;
  savings: CarbonSavings;
}

interface CarbonFootprintCalculatorProps {
  rentals?: RentalCarbonData[];
  equipmentType?: string;
  estimatedHours?: number;
  onCalculate?: (result: CarbonData) => void;
  className?: string;
}

// Emission factors (kg CO2 per unit)
const emissionFactors: Record<string, { perHour: number; perLiter: number; name: string }> = {
  excavator: { perHour: 25, perLiter: 2.68, name: 'Excavator' },
  bulldozer: { perHour: 35, perLiter: 2.68, name: 'Bulldozer' },
  crane: { perHour: 20, perLiter: 2.68, name: 'Crane' },
  loader: { perHour: 18, perLiter: 2.68, name: 'Loader' },
  forklift: { perHour: 8, perLiter: 2.68, name: 'Forklift' },
  generator: { perHour: 15, perLiter: 2.68, name: 'Generator' },
  compressor: { perHour: 5, perLiter: 2.68, name: 'Compressor' },
  truck: { perHour: 12, perLiter: 2.68, name: 'Truck' },
  concrete_mixer: { perHour: 10, perLiter: 2.68, name: 'Concrete Mixer' },
  default: { perHour: 15, perLiter: 2.68, name: 'Equipment' },
};

// Demo rental history
const demoRentals: RentalCarbonData[] = [
  {
    bookingId: 'BK-001',
    equipmentName: 'CAT 320 Excavator',
    startDate: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
    endDate: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000),
    carbonData: {
      co2Emissions: 875,
      fuelUsed: 326,
      hoursOperated: 35,
      equipmentType: 'excavator',
    },
    savings: {
      vsOwnership: 150,
      vsOlderModel: 220,
      fromSharedUse: 95,
      total: 465,
    },
  },
  {
    bookingId: 'BK-002',
    equipmentName: 'Komatsu D65 Bulldozer',
    startDate: new Date(Date.now() - 21 * 24 * 60 * 60 * 1000),
    endDate: new Date(Date.now() - 18 * 24 * 60 * 60 * 1000),
    carbonData: {
      co2Emissions: 525,
      fuelUsed: 196,
      hoursOperated: 15,
      equipmentType: 'bulldozer',
    },
    savings: {
      vsOwnership: 85,
      vsOlderModel: 130,
      fromSharedUse: 55,
      total: 270,
    },
  },
  {
    bookingId: 'BK-003',
    equipmentName: 'Toyota 8FGU25 Forklift',
    startDate: new Date(Date.now() - 45 * 24 * 60 * 60 * 1000),
    endDate: new Date(Date.now() - 40 * 24 * 60 * 60 * 1000),
    carbonData: {
      co2Emissions: 160,
      fuelUsed: 60,
      hoursOperated: 20,
      equipmentType: 'forklift',
    },
    savings: {
      vsOwnership: 40,
      vsOlderModel: 55,
      fromSharedUse: 30,
      total: 125,
    },
  },
];

export default function CarbonFootprintCalculator({
  rentals = demoRentals,
  equipmentType,
  estimatedHours,
  onCalculate,
  className = '',
}: CarbonFootprintCalculatorProps) {
  const [selectedEquipment, setSelectedEquipment] = useState(equipmentType || 'excavator');
  const [hours, setHours] = useState(estimatedHours || 8);
  const [showCalculator, setShowCalculator] = useState(!rentals.length);
  const [activeView, setActiveView] = useState<'overview' | 'history' | 'tips'>('overview');

  // Calculate totals
  const totals = useMemo(() => {
    return rentals.reduce(
      (acc, rental) => ({
        co2Emissions: acc.co2Emissions + rental.carbonData.co2Emissions,
        fuelUsed: acc.fuelUsed + rental.carbonData.fuelUsed,
        hoursOperated: acc.hoursOperated + rental.carbonData.hoursOperated,
        totalSavings: acc.totalSavings + rental.savings.total,
      }),
      { co2Emissions: 0, fuelUsed: 0, hoursOperated: 0, totalSavings: 0 }
    );
  }, [rentals]);

  // Calculate estimate for new rental
  const estimate = useMemo(() => {
    const factor = emissionFactors[selectedEquipment] || emissionFactors.default;
    const co2 = factor.perHour * hours;
    const fuel = co2 / factor.perLiter;
    return {
      co2Emissions: Math.round(co2),
      fuelUsed: Math.round(fuel),
      hoursOperated: hours,
      equipmentType: selectedEquipment,
    };
  }, [selectedEquipment, hours]);

  // Impact equivalents
  const getImpactEquivalents = (co2Kg: number): ImpactEquivalent[] => {
    return [
      {
        icon: TreeDeciduous,
        label: 'Trees needed to offset',
        value: Math.round(co2Kg / 21).toString(),
        description: 'Trees needed to absorb CO2 in one year',
      },
      {
        icon: Car,
        label: 'Equivalent car miles',
        value: Math.round(co2Kg / 0.404).toLocaleString(),
        description: 'Miles driven in an average car',
      },
      {
        icon: Droplets,
        label: 'Gallons of gasoline',
        value: Math.round(co2Kg / 8.887).toString(),
        description: 'Equivalent gasoline burned',
      },
      {
        icon: Battery,
        label: 'Smartphone charges',
        value: Math.round(co2Kg * 121).toLocaleString(),
        description: 'Full smartphone battery charges',
      },
    ];
  };

  const ecoTips = [
    {
      icon: Sun,
      title: 'Choose newer equipment',
      description: 'Newer models are up to 25% more fuel efficient',
    },
    {
      icon: Target,
      title: 'Plan efficient routes',
      description: 'Reduce transport emissions by optimizing delivery',
    },
    {
      icon: Recycle,
      title: 'Rent instead of own',
      description: 'Sharing equipment reduces total manufacturing impact',
    },
    {
      icon: Battery,
      title: 'Consider electric options',
      description: 'Electric equipment produces zero direct emissions',
    },
    {
      icon: Wind,
      title: 'Regular maintenance',
      description: 'Well-maintained equipment runs more efficiently',
    },
  ];

  return (
    <div className={`bg-white dark:bg-gray-800 rounded-2xl shadow-xl overflow-hidden ${className}`}>
      {/* Header */}
      <div className="bg-gradient-to-r from-green-600 to-emerald-600 p-6 text-white">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
              <Leaf className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Carbon Footprint</h2>
              <p className="text-white/70 text-sm">Track your environmental impact</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button className="p-2 bg-white/20 rounded-lg hover:bg-white/30">
              <Share2 className="w-5 h-5" />
            </button>
            <button className="p-2 bg-white/20 rounded-lg hover:bg-white/30" aria-label="Icon button">
              <Download className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="grid grid-cols-3 gap-4">
          <div className="bg-white/10 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-1">
              <Factory className="w-4 h-4" />
              <span className="text-xs uppercase">Total CO2</span>
            </div>
            <p className="text-2xl font-bold">{totals.co2Emissions.toLocaleString()} kg</p>
          </div>
          <div className="bg-white/10 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-1">
              <TrendingDown className="w-4 h-4 text-green-300" />
              <span className="text-xs uppercase">Saved</span>
            </div>
            <p className="text-2xl font-bold text-green-300">
              {totals.totalSavings.toLocaleString()} kg
            </p>
          </div>
          <div className="bg-white/10 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-1">
              <TreeDeciduous className="w-4 h-4" />
              <span className="text-xs uppercase">Trees to Offset</span>
            </div>
            <p className="text-2xl font-bold">
              {Math.round(totals.co2Emissions / 21)}
            </p>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b dark:border-gray-700">
        {[
          { id: 'overview', label: 'Overview', icon: BarChart3 },
          { id: 'history', label: 'History', icon: Factory },
          { id: 'tips', label: 'Eco Tips', icon: Leaf },
        ].map(tab => (
          <button
            key={tab.id}
            aria-label="Icon button" onClick={() => setActiveView(tab.id as typeof activeView)}
            className={`flex-1 py-3 flex items-center justify-center gap-2 border-b-2 transition-colors ${
              activeView === tab.id
                ? 'border-green-600 text-green-600'
                : 'border-transparent text-gray-500 dark:text-gray-400'
            }`}
          >
            <tab.icon className="w-4 h-4" />
            <span className="font-medium text-sm">{tab.label}</span>
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="p-6">
        {/* Overview Tab */}
        {activeView === 'overview' && (
          <div className="space-y-6">
            {/* Impact Equivalents */}
            <div>
              <h3 className="font-semibold text-gray-900 dark:text-white mb-4">
                Your Impact Explained
              </h3>
              <div className="grid grid-cols-2 gap-4">
                {getImpactEquivalents(totals.co2Emissions).map((item, index) => (
                  <div
                    key={index}
                    className="p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl"
                  >
                    <div className="flex items-center gap-2 mb-2">
                      <item.icon className="w-5 h-5 text-green-600" />
                      <span className="text-sm text-gray-500 dark:text-gray-400">
                        {item.label}
                      </span>
                    </div>
                    <p className="text-2xl font-bold text-gray-900 dark:text-white">
                      {item.value}
                    </p>
                    <p className="text-xs text-gray-400 mt-1">{item.description}</p>
                  </div>
                ))}
              </div>
            </div>

            {/* Savings Breakdown */}
            <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-xl">
              <div className="flex items-center gap-2 mb-4">
                <Award className="w-5 h-5 text-green-600" />
                <h3 className="font-semibold text-green-900 dark:text-green-100">
                  Your Carbon Savings
                </h3>
              </div>
              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <span className="text-green-700 dark:text-green-300">
                    vs. Equipment Ownership
                  </span>
                  <span className="font-medium text-green-900 dark:text-green-100">
                    {rentals.reduce((sum, r) => sum + r.savings.vsOwnership, 0)} kg CO2
                  </span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-green-700 dark:text-green-300">
                    vs. Older Equipment
                  </span>
                  <span className="font-medium text-green-900 dark:text-green-100">
                    {rentals.reduce((sum, r) => sum + r.savings.vsOlderModel, 0)} kg CO2
                  </span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-green-700 dark:text-green-300">
                    From Shared Use
                  </span>
                  <span className="font-medium text-green-900 dark:text-green-100">
                    {rentals.reduce((sum, r) => sum + r.savings.fromSharedUse, 0)} kg CO2
                  </span>
                </div>
                <div className="pt-3 border-t border-green-200 dark:border-green-800 flex justify-between items-center">
                  <span className="font-semibold text-green-900 dark:text-green-100">
                    Total Savings
                  </span>
                  <span className="font-bold text-xl text-green-600">
                    {totals.totalSavings} kg CO2
                  </span>
                </div>
              </div>
            </div>

            {/* Quick Calculator */}
            <div>
              <button
                aria-label="Icon button" onClick={() => setShowCalculator(!showCalculator)}
                className="w-full flex items-center justify-between py-3 text-gray-600 dark:text-gray-400"
              >
                <span className="font-medium">Estimate New Rental</span>
                <ChevronDown
                  className={`w-5 h-5 transition-transform ${showCalculator ? 'rotate-180' : ''}`}
                />
              </button>

              {showCalculator && (
                <div className="p-4 bg-gray-50 dark:bg-gray-700/50 rounded-xl space-y-4">
                  <div>
                    <label className="block text-sm text-gray-500 dark:text-gray-400 mb-2">
                      Equipment Type
                    </label>
                    <select
                      value={selectedEquipment}
                      onChange={(e) => setSelectedEquipment(e.target.value)}
                      className="w-full p-3 border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white"
                    >
                      {Object.entries(emissionFactors).map(([key, value]) => (
                        key !== 'default' && (
                          <option key={key} value={key}>
                            {value.name}
                          </option>
                        )
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm text-gray-500 dark:text-gray-400 mb-2">
                      Estimated Hours of Use: {hours}
                    </label>
                    <input
                      type="range"
                      min="1"
                      max="100"
                      value={hours}
                      onChange={(e) => setHours(parseInt(e.target.value))}
                      className="w-full"
                    />
                    <div className="flex justify-between text-xs text-gray-400">
                      <span>1 hour</span>
                      <span>100 hours</span>
                    </div>
                  </div>

                  {/* Estimate Result */}
                  <div className="p-4 bg-white dark:bg-gray-800 rounded-lg">
                    <p className="text-sm text-gray-500 dark:text-gray-400 mb-2">
                      Estimated Emissions
                    </p>
                    <p className="text-3xl font-bold text-gray-900 dark:text-white">
                      {estimate.co2Emissions} kg CO2
                    </p>
                    <p className="text-sm text-gray-400 mt-1">
                      ~{estimate.fuelUsed} liters of fuel
                    </p>
                  </div>

                  <button
                    aria-label="Icon button"> onCalculate?.(estimate)}
                    className="w-full py-3 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700"
                  >
                    Use This Estimate
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {/* History Tab */}
        {activeView === 'history' && (
          <div className="space-y-4">
            {rentals.map((rental) => (
              <div
                key={rental.bookingId}
                className="p-4 border dark:border-gray-700 rounded-xl"
              >
                <div className="flex items-center justify-between mb-3">
                  <div>
                    <h4 className="font-medium text-gray-900 dark:text-white">
                      {rental.equipmentName}
                    </h4>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      {rental.startDate.toLocaleDateString()} -{' '}
                      {rental.endDate.toLocaleDateString()}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-gray-900 dark:text-white">
                      {rental.carbonData.co2Emissions} kg
                    </p>
                    <p className="text-sm text-green-600">
                      -{rental.savings.total} kg saved
                    </p>
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-2 text-center">
                  <div className="p-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg">
                    <p className="text-xs text-gray-500 dark:text-gray-400">Hours</p>
                    <p className="font-medium text-gray-900 dark:text-white">
                      {rental.carbonData.hoursOperated}
                    </p>
                  </div>
                  <div className="p-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg">
                    <p className="text-xs text-gray-500 dark:text-gray-400">Fuel</p>
                    <p className="font-medium text-gray-900 dark:text-white">
                      {rental.carbonData.fuelUsed}L
                    </p>
                  </div>
                  <div className="p-2 bg-gray-50 dark:bg-gray-700/50 rounded-lg">
                    <p className="text-xs text-gray-500 dark:text-gray-400">kg/hr</p>
                    <p className="font-medium text-gray-900 dark:text-white">
                      {Math.round(rental.carbonData.co2Emissions / rental.carbonData.hoursOperated)}
                    </p>
                  </div>
                </div>
              </div>
            ))}

            {rentals.length === 0 && (
              <div className="text-center py-8">
                <Leaf className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                <p className="text-gray-500 dark:text-gray-400">
                  No rental history yet
                </p>
              </div>
            )}
          </div>
        )}

        {/* Tips Tab */}
        {activeView === 'tips' && (
          <div className="space-y-4">
            <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-xl">
              <div className="flex items-center gap-2 mb-2">
                <Sparkles className="w-5 h-5 text-green-600" />
                <h3 className="font-semibold text-green-900 dark:text-green-100">
                  Eco-Friendly Renting
                </h3>
              </div>
              <p className="text-sm text-green-700 dark:text-green-300">
                By renting equipment instead of owning, you're already making an eco-conscious
                choice. Here are more ways to reduce your impact:
              </p>
            </div>

            {ecoTips.map((tip, index) => (
              <div
                key={index}
                className="flex items-start gap-4 p-4 border dark:border-gray-700 rounded-xl"
              >
                <div className="w-10 h-10 bg-green-100 dark:bg-green-900/30 rounded-xl flex items-center justify-center flex-shrink-0">
                  <tip.icon className="w-5 h-5 text-green-600" />
                </div>
                <div>
                  <h4 className="font-medium text-gray-900 dark:text-white">
                    {tip.title}
                  </h4>
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    {tip.description}
                  </p>
                </div>
              </div>
            ))}

            {/* Carbon Offset CTA */}
            <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl">
              <div className="flex items-center gap-3 mb-3">
                <TreeDeciduous className="w-6 h-6 text-blue-600" />
                <h3 className="font-semibold text-blue-900 dark:text-blue-100">
                  Offset Your Carbon
                </h3>
              </div>
              <p className="text-sm text-blue-700 dark:text-blue-300 mb-3">
                Want to go carbon neutral? Offset your {totals.co2Emissions} kg CO2 emissions by
                supporting verified reforestation projects.
              </p>
              <button className="w-full py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700" aria-label="Icon button">
                Learn About Carbon Offsets
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars, react-hooks/exhaustive-deps */
import { useState, useEffect } from 'react';
import {
  Leaf,
  TrendingDown,
  Share2,
  Info,
  TreeDeciduous,
  Zap,
  Droplets,
  XCircle,
  CheckCircle2,
} from 'lucide-react';

interface CarbonFootprintTrackerProps {
  userId: string;
  bookings: BookingCarbonData[];
  onClose?: () => void;
}

interface BookingCarbonData {
  id: string;
  equipmentTitle: string;
  category: string;
  rentalDays: number;
  date: Date;
  carbonSaved: number; // kg CO2
  treesEquivalent: number;
}

interface CarbonStats {
  totalSaved: number;
  treesEquivalent: number;
  waterSaved: number; // liters
  energySaved: number; // kWh
  rankPercentile: number;
  monthlyTrend: { month: string; saved: number }[];
  achievements: Achievement[];
}

interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  unlockedAt?: Date;
  progress: number;
  target: number;
}

export default function CarbonFootprintTracker({
  bookings,
  onClose,
}: CarbonFootprintTrackerProps) {
  // userId reserved for future API integration
  const [stats, setStats] = useState<CarbonStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'history' | 'achievements'>('overview');
  const [shareMessage, setShareMessage] = useState('');

  useEffect(() => {
    calculateStats();
  }, [bookings]);

  const calculateStats = async () => {
    setLoading(true);

    // Simulate calculation
    await new Promise(resolve => setTimeout(resolve, 1000));

    const totalSaved = bookings.reduce((sum, b) => sum + b.carbonSaved, 0);
    
    const monthlyData: { [key: string]: number } = {};
    bookings.forEach(b => {
      const month = b.date.toLocaleString('default', { month: 'short' });
      monthlyData[month] = (monthlyData[month] || 0) + b.carbonSaved;
    });

    const calculatedStats: CarbonStats = {
      totalSaved,
      treesEquivalent: Math.round(totalSaved / 21), // ~21kg CO2 per tree per year
      waterSaved: Math.round(totalSaved * 50), // Estimated water saved through sharing
      energySaved: Math.round(totalSaved * 2.5), // kWh equivalent
      rankPercentile: Math.min(95, Math.round(50 + totalSaved / 10)),
      monthlyTrend: Object.entries(monthlyData).map(([month, saved]) => ({
        month,
        saved,
      })),
      achievements: [
        {
          id: '1',
          title: 'First Rental',
          description: 'Complete your first equipment rental',
          icon: '🌱',
          unlockedAt: new Date(),
          progress: 1,
          target: 1,
        },
        {
          id: '2',
          title: 'Tree Saver',
          description: 'Save the equivalent of 5 trees',
          icon: '🌳',
          unlockedAt: totalSaved >= 105 ? new Date() : undefined,
          progress: Math.min(5, Math.round(totalSaved / 21)),
          target: 5,
        },
        {
          id: '3',
          title: 'Eco Warrior',
          description: 'Save 500kg of CO2',
          icon: '🦸',
          unlockedAt: totalSaved >= 500 ? new Date() : undefined,
          progress: Math.min(500, totalSaved),
          target: 500,
        },
        {
          id: '4',
          title: 'Community Champion',
          description: 'Complete 10 rentals',
          icon: '🏆',
          unlockedAt: bookings.length >= 10 ? new Date() : undefined,
          progress: Math.min(10, bookings.length),
          target: 10,
        },
        {
          id: '5',
          title: 'Carbon Neutral',
          description: 'Save 1 ton of CO2',
          icon: '🌍',
          unlockedAt: totalSaved >= 1000 ? new Date() : undefined,
          progress: Math.min(1000, totalSaved),
          target: 1000,
        },
      ],
    };

    setStats(calculatedStats);
    setLoading(false);
  };

  const handleShare = async () => {
    const message = `I've saved ${stats?.totalSaved.toFixed(1)}kg of CO2 by renting equipment on Islakayd instead of buying new! That's like planting ${stats?.treesEquivalent} trees 🌳 #SharingEconomy #Sustainability`;
    
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'My Carbon Savings',
          text: message,
          url: 'https://islakayd.com',
        });
      } catch (err) {
        console.log('Share cancelled');
      }
    } else {
      navigator.clipboard.writeText(message);
      setShareMessage('Copied to clipboard!');
      setTimeout(() => setShareMessage(''), 3000);
    }
  };

  const getCarbonEquivalent = (kg: number) => {
    if (kg < 10) return `${kg.toFixed(1)} kg CO₂`;
    if (kg < 1000) return `${kg.toFixed(0)} kg CO₂`;
    return `${(kg / 1000).toFixed(2)} tons CO₂`;
  };

  if (loading) {
    return (
      <div className="bg-white rounded-3xl shadow-xl p-8 text-center">
        <div className="w-16 h-16 border-4 border-green-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
        <p className="text-gray-600">Calculating your environmental impact...</p>
      </div>
    );
  }

  if (!stats) return null;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden">
      {/* Header */}
      <div className="p-6 bg-gradient-to-r from-green-500 to-emerald-600 text-white">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
              <Leaf className="w-6 h-6" />
            </div>
            <div>
              <h2 className="text-xl font-bold">Carbon Footprint Tracker</h2>
              <p className="text-sm text-white/80">Your environmental impact</p>
            </div>
          </div>
          {onClose && (
            <button
              onClick={onClose}
              className="p-2 hover:bg-white/20 rounded-full transition-colors"
            >
              <XCircle className="w-6 h-6" />
            </button>
          )}
        </div>

        {/* Main Stats */}
        <div className="bg-white/10 rounded-2xl p-6 text-center">
          <div className="text-5xl font-bold mb-2">
            {getCarbonEquivalent(stats.totalSaved)}
          </div>
          <p className="text-white/80 mb-4">Carbon dioxide saved by renting</p>
          
          <div className="flex items-center justify-center gap-2">
            <span className="inline-flex items-center gap-1 px-3 py-1 bg-white/20 rounded-full text-sm">
              <TrendingDown className="w-4 h-4" />
              Top {100 - stats.rankPercentile}% of users
            </span>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-100">
        {(['overview', 'history', 'achievements'] as const).map((tab) => (
          <button
            key={tab}
            aria-label="Icon button" onClick={() => setActiveTab(tab)}
            className={`flex-1 py-4 text-sm font-medium transition-colors ${
              activeTab === tab
                ? 'text-green-600 border-b-2 border-green-500'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="p-6">
        {activeTab === 'overview' && (
          <>
            {/* Impact Cards */}
            <div className="grid grid-cols-3 gap-4 mb-6">
              <div className="bg-green-50 rounded-xl p-4 text-center">
                <TreeDeciduous className="w-8 h-8 text-green-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-green-700">{stats.treesEquivalent}</div>
                <div className="text-xs text-green-600">Trees equivalent</div>
              </div>
              <div className="bg-blue-50 rounded-xl p-4 text-center">
                <Droplets className="w-8 h-8 text-blue-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-blue-700">{stats.waterSaved.toLocaleString()}</div>
                <div className="text-xs text-blue-600">Liters saved</div>
              </div>
              <div className="bg-amber-50 rounded-xl p-4 text-center">
                <Zap className="w-8 h-8 text-amber-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-amber-700">{stats.energySaved}</div>
                <div className="text-xs text-amber-600">kWh saved</div>
              </div>
            </div>

            {/* Monthly Trend */}
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Monthly Savings</h3>
              <div className="h-40 flex items-end gap-2">
                {stats.monthlyTrend.map((item, index) => {
                  const maxSaved = Math.max(...stats.monthlyTrend.map(m => m.saved));
                  const height = (item.saved / maxSaved) * 100;
                  return (
                    <div key={index} className="flex-1 flex flex-col items-center gap-1">
                      <div
                        className="w-full bg-gradient-to-t from-green-500 to-emerald-400 rounded-t-lg transition-all"
                        style={{ height: `${Math.max(height, 10)}%` }}
                      />
                      <span className="text-xs text-gray-500">{item.month}</span>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Info Box */}
            <div className="bg-gray-50 rounded-xl p-4 mb-6">
              <div className="flex items-start gap-3">
                <Info className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-600">
                    <strong className="text-gray-900">How we calculate:</strong> Renting equipment instead of buying new reduces manufacturing emissions, shipping, and disposal waste. Each rental saves an average of 15-50kg CO₂ depending on equipment type.
                  </p>
                </div>
              </div>
            </div>

            {/* Share Button */}
            <button
              onClick={handleShare}
              className="w-full py-4 bg-gradient-to-r from-green-500 to-emerald-500 text-white font-semibold rounded-xl hover:shadow-lg transition-all flex items-center justify-center gap-2"
             aria-label="Icon button">
              <Share2 className="w-5 h-5" />
              Share Your Impact
            </button>
            {shareMessage && (
              <p className="text-center text-green-600 text-sm mt-2">{shareMessage}</p>
            )}
          </>
        )}

        {activeTab === 'history' && (
          <div className="space-y-3 max-h-[400px] overflow-y-auto">
            {bookings.length === 0 ? (
              <div className="text-center py-8">
                <Leaf className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                <p className="text-gray-500">No rentals yet. Start saving CO₂ today!</p>
              </div>
            ) : (
              bookings.map((booking) => (
                <div
                  key={booking.id}
                  className="flex items-center gap-4 p-4 bg-gray-50 rounded-xl"
                >
