                <div className="flex items-center justify-center gap-1 mt-1 text-xs text-blue-600">
                  <Droplets className="w-3 h-3" />
                  {Math.round(day.precipitation)}%
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Detailed Info (Expanded) */}
      {expanded && forecast.length > 0 && (
        <div className="px-4 pb-4">
          <div className="grid grid-cols-4 gap-3 p-4 bg-gray-50 rounded-xl">
            <div className="text-center">
              <Thermometer className="w-5 h-5 text-red-500 mx-auto mb-1" />
              <p className="text-sm font-semibold text-gray-900">
                {Math.round(Math.max(...forecast.map(f => f.tempHigh)))}°F
              </p>
              <p className="text-xs text-gray-500">Max Temp</p>
            </div>
            <div className="text-center">
              <Wind className="w-5 h-5 text-teal-500 mx-auto mb-1" />
              <p className="text-sm font-semibold text-gray-900">
                {Math.round(Math.max(...forecast.map(f => f.windSpeed)))} mph
              </p>
              <p className="text-xs text-gray-500">Max Wind</p>
            </div>
            <div className="text-center">
              <Umbrella className="w-5 h-5 text-blue-500 mx-auto mb-1" />
              <p className="text-sm font-semibold text-gray-900">
                {forecast.filter(f => f.precipitation > 30).length} days
              </p>
              <p className="text-xs text-gray-500">Rain Expected</p>
            </div>
            <div className="text-center">
              <Sun className="w-5 h-5 text-amber-500 mx-auto mb-1" />
              <p className="text-sm font-semibold text-gray-900">
                {Math.round(Math.max(...forecast.map(f => f.uvIndex)))}
              </p>
              <p className="text-xs text-gray-500">UV Index</p>
            </div>
          </div>

          <div className="mt-4 p-3 bg-blue-50 rounded-xl flex items-start gap-2">
            <Info className="w-4 h-4 text-blue-500 flex-shrink-0 mt-0.5" />
            <p className="text-sm text-blue-700">
              Weather data is updated hourly. Conditions may change - we'll notify you of any significant weather alerts.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

/* eslint-disable react-refresh/only-export-components */
import { createContext, useContext, useEffect, useState, useCallback, type ReactNode } from 'react';
import { supabase } from '../lib/supabase';
import type { User, Session } from '@supabase/supabase-js';
import type { Profile, UserAnalytics } from '../types';
import { getProfile, getUserAnalytics, getUnreadNotificationCount, subscribeToNotifications, logAuditEvent } from '../services/database';
import { 
  signInWithRetry, 
  signUpWithRetry,
  getAuthErrorMessage,
  isEmailConfirmationRequired,
} from '../services/authHelpers';

interface AuthState {
  user: User | null;
  session: Session | null;
  profile: Profile | null;
  analytics: UserAnalytics | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  unreadNotifications: number;
}

interface AuthContextType extends AuthState {
  signIn: (email: string, password: string) => Promise<void>;
  signUp: (email: string, password: string, fullName: string) => Promise<void>;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<void>;
  updatePassword: (password: string) => Promise<void>;
  refreshProfile: () => Promise<void>;
  refreshNotifications: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [state, setState] = useState<AuthState>({
    user: null,
    session: null,
    profile: null,
    analytics: null,
    isLoading: true,
    isAuthenticated: false,
    unreadNotifications: 0,
  });

  const loadUserData = useCallback(async (userId: string) => {
    try {
      const [profile, analytics, unreadCount] = await Promise.all([
        getProfile(userId),
        getUserAnalytics(userId),
        getUnreadNotificationCount(userId),
      ]);

      setState(prev => ({
        ...prev,
        profile,
        analytics,
        unreadNotifications: unreadCount,
      }));

      // sync server-side AI preference to local storage so UI toggles reflect user's saved preference
      try {
        if (profile?.ai_assistant_enabled !== undefined && typeof window !== 'undefined') {
          window.localStorage.setItem('ai_assistant_enabled', JSON.stringify(!!profile.ai_assistant_enabled));
        }
      } catch (e) {
        /* ignore localStorage errors */
      }
    } catch (error) {
      if (import.meta.env.DEV) {
        console.error('Failed to load user data:', error);
      }
      // Track error in analytics and error monitoring
      if (import.meta.env.VITE_ENABLE_ANALYTICS === 'true') {
        const { analytics: analyticsService } = await import('../services/analytics');
        analyticsService.trackError(`Auth data load failed: ${(error as Error).message}`, false);
      }
      // Send to Sentry if configured
      const { errorMonitoring } = await import('../services/errorMonitoring');
      errorMonitoring.captureException(error as Error, {
        context: 'AuthContext.loadUserData',
        userId,
      });
    }
  }, []);

  const refreshProfile = useCallback(async () => {
    if (state.user) {
      const profile = await getProfile(state.user.id);
      setState(prev => ({ ...prev, profile }));
    }
  }, [state.user]);

  const refreshNotifications = useCallback(async () => {
    if (state.user) {
      const count = await getUnreadNotificationCount(state.user.id);
      setState(prev => ({ ...prev, unreadNotifications: count }));
    }
  }, [state.user]);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setState(prev => ({
        ...prev,
        session,
        user: session?.user ?? null,
        isAuthenticated: !!session,
        isLoading: false,
      }));

      if (session?.user) {
        loadUserData(session.user.id);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setState(prev => ({
        ...prev,
        session,
        user: session?.user ?? null,
        isAuthenticated: !!session,
        isLoading: false,
        profile: session ? prev.profile : null,
        analytics: session ? prev.analytics : null,
        unreadNotifications: session ? prev.unreadNotifications : 0,
      }));

      if (session?.user) {
        (async () => {
          await loadUserData(session.user.id);
        })();
      }
    });

    return () => subscription.unsubscribe();
  }, [loadUserData]);

  useEffect(() => {
    if (!state.user) return;

    const channel = subscribeToNotifications(state.user.id, () => {
      setState(prev => ({
        ...prev,
        unreadNotifications: prev.unreadNotifications + 1,
      }));
    });

    return () => {
      channel.unsubscribe();
    };
  }, [state.user]);

  const signIn = async (email: string, password: string) => {
    try {
      const data = await signInWithRetry(email, password, { maxAttempts: 3, delayMs: 1000 });

      if (data.user) {
        await supabase.from('profiles').update({ last_login: new Date().toISOString() }).eq('id', data.user.id);
        await logAuditEvent({
          userId: data.user.id,
          action: 'sign_in',
          metadata: { method: 'email' },
        });
        
        // Track sign in event
        if (import.meta.env.VITE_ENABLE_ANALYTICS === 'true') {
          const { analytics } = await import('../services/analytics');
          analytics.event('login', { method: 'email' });
          analytics.setUserId(data.user.id);
        }
        // Set user context in error monitoring
        const { errorMonitoring } = await import('../services/errorMonitoring');
        errorMonitoring.setUser({ id: data.user.id, email: data.user.email });
      }
    } catch (error) {
      const message = getAuthErrorMessage(error as Error);
      throw new Error(message);
    }
  };

  const signUp = async (email: string, password: string, fullName: string) => {
    try {
      const data = await signUpWithRetry(
        email, 
        password, 
        { full_name: fullName },
        { maxAttempts: 3, delayMs: 1000 }
      );

      if (data.user) {
        // Create profile (may fail if email confirmation required)
        try {
          await supabase.from('profiles').upsert({
            id: data.user.id,
            full_name: fullName,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
          });
        } catch (profileError) {
          console.warn('Profile creation deferred until email confirmation:', profileError);
        }

        await logAuditEvent({
          userId: data.user.id,
          action: 'sign_up',
          metadata: { method: 'email', email_confirmed: !!data.session },
        });
        
        // Track signup event
        if (import.meta.env.VITE_ENABLE_ANALYTICS === 'true') {
          const { analytics } = await import('../services/analytics');
          analytics.trackSignUp('email');
          analytics.setUserId(data.user.id);
        }
        // Set user context in error monitoring
        const { errorMonitoring } = await import('../services/errorMonitoring');
        errorMonitoring.setUser({ id: data.user.id, email: data.user.email });

        // Check if email confirmation is required
        const needsConfirmation = await isEmailConfirmationRequired();
        if (needsConfirmation && !data.session) {
          throw new Error('EMAIL_CONFIRMATION_REQUIRED');
        }
      }
    } catch (error) {
      const errorMsg = (error as Error).message;
      if (errorMsg === 'EMAIL_CONFIRMATION_REQUIRED') {
        throw new Error('Please check your email to confirm your account before signing in.');
      }
      const message = getAuthErrorMessage(error as Error);
      throw new Error(message);
    }
  };

  const signInWithGoogle = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: `${window.location.origin}/`,
        queryParams: {
          access_type: 'offline',
          prompt: 'consent',
        },
      },
    });
    
    if (error) throw error;
    
    // Analytics will be tracked after redirect when auth state changes
  };

  const signOut = async () => {
    if (state.user) {
      await logAuditEvent({
        userId: state.user.id,
        action: 'sign_out',
      });
    }

    // Clear user context from error monitoring
    const { errorMonitoring } = await import('../services/errorMonitoring');
    errorMonitoring.clearUser();

    const { error } = await supabase.auth.signOut();
    if (error) throw error;

    setState({
      user: null,
      session: null,
      profile: null,
      analytics: null,
      isLoading: false,
      isAuthenticated: false,
      unreadNotifications: 0,
    });
  };

  const resetPassword = async (email: string) => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/reset-password`,
    });
    if (error) throw error;
  };

  const updatePassword = async (password: string) => {
    const { error } = await supabase.auth.updateUser({ password });
    if (error) throw error;

    if (state.user) {
      await logAuditEvent({
        userId: state.user.id,
        action: 'password_changed',
      });
    }
  };

  return (
    <AuthContext.Provider
      value={{
        ...state,
        signIn,
        signUp,
        signInWithGoogle,
        signOut,
        resetPassword,
        updatePassword,
        refreshProfile,
        refreshNotifications,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useCallback, useEffect, useRef } from 'react';

// Generic debounce hook
export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

// Local storage hook with type safety
export function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T | ((prev: T) => T)) => void] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback((value: T | ((prev: T) => T)) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error('Error saving to localStorage:', error);
    }
  }, [key, storedValue]);

  return [storedValue, setValue];
}

// Session storage hook
export function useSessionStorage<T>(key: string, initialValue: T): [T, (value: T | ((prev: T) => T)) => void] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.sessionStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback((value: T | ((prev: T) => T)) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      window.sessionStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error('Error saving to sessionStorage:', error);
    }
  }, [key, storedValue]);

  return [storedValue, setValue];
}

// Toggle hook
export function useToggle(initialValue = false): [boolean, () => void, (value: boolean) => void] {
  const [value, setValue] = useState(initialValue);
  const toggle = useCallback(() => setValue(v => !v), []);
  return [value, toggle, setValue];
}

// Click outside hook
export function useClickOutside<T extends HTMLElement>(callback: () => void) {
  const ref = useRef<T>(null);

  useEffect(() => {
    const handleClick = (event: MouseEvent) => {
      if (ref.current && !ref.current.contains(event.target as Node)) {
        callback();
      }
    };

    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [callback]);

  return ref;
}

// Previous value hook
export function usePrevious<T>(value: T): T | undefined {
  const ref = useRef<T>();
  
  useEffect(() => {
    ref.current = value;
  }, [value]);

  return ref.current;
}

// Media query hook
export function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(() => {
    if (typeof window !== 'undefined') {
      return window.matchMedia(query).matches;
    }
    return false;
  });

  useEffect(() => {
    const mediaQuery = window.matchMedia(query);
    const handler = (event: MediaQueryListEvent) => setMatches(event.matches);
    
    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, [query]);

  return matches;
}

// Responsive breakpoint hooks
export function useIsMobile(): boolean {
  return useMediaQuery('(max-width: 768px)');
}

export function useIsTablet(): boolean {
  return useMediaQuery('(min-width: 769px) and (max-width: 1024px)');
}

export function useIsDesktop(): boolean {
  return useMediaQuery('(min-width: 1025px)');
}

// Async operation hook with loading and error states
interface AsyncState<T> {
  data: T | null;
  loading: boolean;
  error: Error | null;
}

export function useAsync<T>(asyncFn: () => Promise<T>, deps: unknown[] = []) {
  const [state, setState] = useState<AsyncState<T>>({
    data: null,
    loading: true,
    error: null,
  });

  const asyncFnRef = useRef(asyncFn);
  asyncFnRef.current = asyncFn;

  const execute = useCallback(async () => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const data = await asyncFnRef.current();
      setState({ data, loading: false, error: null });
      return data;
    } catch (error) {
      setState({ data: null, loading: false, error: error as Error });
      throw error;
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);

  useEffect(() => {
    execute();
  }, [execute]);

  return { ...state, refetch: execute };
}

// Countdown hook
export function useCountdown(targetDate: Date | null): {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
  isExpired: boolean;
} {
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0,
    isExpired: true,
  });

  useEffect(() => {
    if (!targetDate) return;

    const calculateTimeLeft = () => {
      const difference = targetDate.getTime() - Date.now();
      
      if (difference <= 0) {
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0, isExpired: true });
        return;
      }

      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
        isExpired: false,
      });
    };

    calculateTimeLeft();
    const interval = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(interval);
  }, [targetDate]);

  return timeLeft;
}

// Intersection observer hook
export function useIntersectionObserver<T extends HTMLElement>(
  options?: IntersectionObserverInit
): [React.RefObject<T | null>, boolean] {
  const ref = useRef<T>(null);
  const [isIntersecting, setIsIntersecting] = useState(false);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const observer = new IntersectionObserver(([entry]) => {
      setIsIntersecting(entry.isIntersecting);
    }, options);

    observer.observe(element);
    return () => observer.disconnect();
  }, [options]);

  return [ref, isIntersecting];
}

// Copy to clipboard hook
export function useCopyToClipboard(): [(text: string) => Promise<boolean>, boolean] {
  const [copied, setCopied] = useState(false);

  const copy = useCallback(async (text: string): Promise<boolean> => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
      return true;
    } catch {
      return false;
    }
  }, []);

  return [copy, copied];
}

// Document title hook
export function useDocumentTitle(title: string): void {
  useEffect(() => {
    const previousTitle = document.title;
    document.title = title;
    return () => {
      document.title = previousTitle;
    };
  }, [title]);
}

// Online status hook
export function useOnlineStatus(): boolean {
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  return isOnline;
}

// Keyboard shortcut hook
export function useKeyboardShortcut(key: string, callback: () => void, modifiers?: {
  ctrl?: boolean;
  shift?: boolean;
  alt?: boolean;
  meta?: boolean;
}): void {
  useEffect(() => {
    const handler = (event: KeyboardEvent) => {
      if (event.key.toLowerCase() !== key.toLowerCase()) return;
      if (modifiers?.ctrl && !event.ctrlKey) return;
      if (modifiers?.shift && !event.shiftKey) return;
      if (modifiers?.alt && !event.altKey) return;
      if (modifiers?.meta && !event.metaKey) return;

      event.preventDefault();
      callback();
    };

    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [key, callback, modifiers]);
}

// Scroll position hook
export function useScrollPosition(): { x: number; y: number } {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleScroll = () => {
      setPosition({ x: window.scrollX, y: window.scrollY });
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return position;
}

// Window size hook
export function useWindowSize(): { width: number; height: number } {
  const [size, setSize] = useState({
    width: typeof window !== 'undefined' ? window.innerWidth : 0,
    height: typeof window !== 'undefined' ? window.innerHeight : 0,
  });

  useEffect(() => {
    const handleResize = () => {
      setSize({ width: window.innerWidth, height: window.innerHeight });
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  return size;
}

// Lock body scroll hook
export function useLockBodyScroll(lock: boolean): void {
  useEffect(() => {
    if (!lock) return;
    
    const originalStyle = window.getComputedStyle(document.body).overflow;
    document.body.style.overflow = 'hidden';
    
    return () => {
      document.body.style.overflow = originalStyle;
    };
  }, [lock]);
}

// Force update hook
export function useForceUpdate(): () => void {
  const [, setTick] = useState(0);
  return useCallback(() => setTick(tick => tick + 1), []);
}

// Mounted state hook
export function useIsMounted(): () => boolean {
  const mountedRef = useRef(false);

  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
    };
  }, []);

  return useCallback(() => mountedRef.current, []);
}

// Hover state hook
export function useHover<T extends HTMLElement>(): [React.RefObject<T | null>, boolean] {
  const ref = useRef<T>(null);
  const [isHovered, setIsHovered] = useState(false);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const handleMouseEnter = () => setIsHovered(true);
    const handleMouseLeave = () => setIsHovered(false);

    element.addEventListener('mouseenter', handleMouseEnter);
    element.addEventListener('mouseleave', handleMouseLeave);

    return () => {
      element.removeEventListener('mouseenter', handleMouseEnter);
      element.removeEventListener('mouseleave', handleMouseLeave);
    };
  }, []);

  return [ref, isHovered];
}

// Focus state hook
export function useFocus<T extends HTMLElement>(): [React.RefObject<T | null>, boolean] {
  const ref = useRef<T>(null);
  const [isFocused, setIsFocused] = useState(false);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const handleFocus = () => setIsFocused(true);
    const handleBlur = () => setIsFocused(false);

    element.addEventListener('focus', handleFocus);
    element.addEventListener('blur', handleBlur);

    return () => {
      element.removeEventListener('focus', handleFocus);
      element.removeEventListener('blur', handleBlur);
    };
  }, []);

  return [ref, isFocused];
}

// Dev-only accessibility fixes for Vite's error overlay
// Marks the overlay inert/aria-hidden so dev-only UI doesn't trigger Axe violations.

function hideOverlay(overlay: Element) {
  try {
    overlay.setAttribute('aria-hidden', 'true');
    // If the browser supports inert, use it to make the subtree non-interactive
    // @ts-ignore
    if ('inert' in HTMLElement.prototype) {
      // @ts-ignore
      (overlay as HTMLElement).inert = true;
    } else {
      // Fallback: remove tabindex from any focusable descendants
      const els = overlay.querySelectorAll('[tabindex], a, button, input, textarea, select');
      els.forEach((el) => {
        try { (el as HTMLElement).removeAttribute('tabindex'); } catch (e) {}
      });
    }
  } catch (e) {
    // swallow errors in dev-only helper
    // eslint-disable-next-line no-console
    console.debug('dev-overlay-a11y: failed to hide overlay', e);
  }
}

function observeOverlay() {
  const process = () => {
    const overlay = document.querySelector('vite-error-overlay');
    if (overlay) {
      hideOverlay(overlay);
    }
  };

  // Run once immediately
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    process();
  } else {
    window.addEventListener('DOMContentLoaded', process, { once: true });
  }

  // Observe DOM so overlay created later is handled
  const mo = new MutationObserver(() => process());
  mo.observe(document.documentElement || document.body, { childList: true, subtree: true });

  // Keep a periodic check as a last resort
  const id = setInterval(process, 1000);
  // Stop interval after 30s
  setTimeout(() => clearInterval(id), 30_000);
}

// Initialize immediately on import
observeOverlay();

